/**********************************************************************************************
Name	: [BI].[pr_133_LowProducerRedKPI_SQRMParam]
Author	: Akin Yavuz
Date	: 14.04.2022
 			
Stored procedure written for SSRS report.

*********************************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_133_LowProducerRedKPI_SQRMParam]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Low Producer Red KPI Report param'
set @StoredProcName		= object_name(@@procid)

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
Select distinct ProductShortName as ShortCode, case when RegulationCategory = 'SpInv' then 'SI' else RegulationCategory end as 'LOB' 
into #LOBCodes
From dbo.mi_insight_ConfigProductTypeReplacement order by ProductShortName;

WITH lic AS(

select 
CASE WHEN LEFT(TT.uid,2) = '00' THEN '00' + TT.uid
	 WHEN LEFT(TT.uid,1) = '0' THEN '000' + TT.uid
	 ELSE TT.uid
	 END as uid
,case when ah.AgentCategoryDescription = 'Administrator' then 'NASP'
	  when (TT.cob>0 and TT.mcob>0 and TT.icob >0) or (TT.cob>0 and TT.mcob>0) then 'CMCOB'
	  when (TT.cob>0 and TT.icob >0) or TT.cob>0 then 'COB'
	  when TT.ICOB_GI>0 then 'ICOB GI ONLY'
	  when (TT.mcob>0 and TT.icob >0) or TT.mcob>0 then 'MCOB'
	  when TT.ICOB_Owl >0 then 'ICOB_Owl'
	  else 'ICOB' end [business area]
from

(select uid 
,sum(case when (BusinessArea like 'cob%' AND CF30Status <> 'Not Set') then 1 else 0 end) COB
,sum(case when BusinessArea like 'mcob%' then 1 else 0 end) MCOB
,sum(case when BusinessArea like 'icob%' AND BusinessArea NOT LIKE '%Owl%' then 1 else 0 end) ICOB
,sum(case when BusinessArea like 'icob GI%' then 1 else 0 end) ICOB_GI
,sum(case when BusinessArea like '%Owl%' then 1 else 0 end) ICOB_Owl

 from
	(select distinct case when UD.USR_ExternalID = '0072' then '1008203' when UD.USR_ExternalID = '1003604' then '1005181' when UD.USR_ExternalID = '1010321' then '1010897'
						  when UD.USR_ExternalID = '1010364' then '1010744' when UD.USR_ExternalID = '4001674' then '1011586' else UD.USR_ExternalID end UID 
					,CD.Code_Description BusinessArea, CD2.Code_Description AS CF30Status
					,UC.UC_Status Status 
					,Max(UC.UC_CompetencyLevel) Level
	from dbo.sa_insight_Licence L inner join
		dbo.sa_insight_UserLicence UL on L.LIC_ID = UL.ULIC_LicenceID right join
		dbo.sa_insight_Staff S inner join
		dbo.sa_insight_UserDetails UD on S.STAF_UserID = UD.USR_ID inner join
		dbo.sa_insight_UserCompetency UC on UD.USR_ID = UC.UC_OwnerID on UL.ULIC_UserID = UD.USR_ID left join
		dbo.sa_insight_CodeDescription CD on UC.UC_BusinessArea = CD.Code_Code and CD.Code_CodeType = 534 LEFT JOIN
		dbo.sa_insight_CodeDescription AS CD2 ON S.STAF_CustomerFunction = CD2.Code_Code AND CD2.Code_CodeType = 530
	where	UC_Status <> 1	and UC.UC_BusinessArea <=9
	group by UD.USR_ExternalID, UC.UC_Status, CD.Code_Description, CD2.Code_Description
	) T
							
group by uid, CF30Status) TT

left join dbo.cscv_AgentsHierarchy ah on ah.Agentcode = TT.UID),

CTE_AQTCHECK As (
	select saca.CASE_CaseReference as Advice
		  ,CASE_AdviserID as AdviserGUID
		  ,'Not Checked' as CaseOutcome
		  ,prty.PROD_ShortName     as Product  
		  ,'Not Checked' as InitialResult
		  ,'Not Checked' as FinalResult
		  ,'Not Checked' as FinalWorkflow
		  ,null as FinalCheck
		  ,null AS AssessorUID
		  ,null AS Assessor
		  ,CASE_SubmitDate as Submitted
		  ,lob.LOB
		  ,marh.AdviserUID
		  ,marh.Adviser
		  ,marh.BusinessUID
		  ,marh.FirmName
		  ,marh.AQMName [SQRM]
		  ,marh.BQMName [QRM]
	FROM mi_aqt_ReportingHierarchy marh
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_SalesCase] saca on marh.AdviserGUID = saca.CASE_AdviserID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_BasicPolicy] bapa     on bapa.BPOL_ParentID = saca.CASE_ID
	JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_insight_ProductType] prty on prty.PROD_Code = bapa.BPOL_ProductType
	join #LOBCODES lob on lob.ShortCode = PROD_ShortName 
	WHERE
	--marh.AdviserUID = '4007774' and
	      saca.CASE_SubmitDate >= '01-DEC-2013'
	AND   saca.CASE_SubmitDate >= DATEADD(mm,-12,GETDATE())
	AND   saca.CASE_CaseReference != '0'
	AND   (PROD_ShortName not like 'X%' or PROD_ShortName = 'DUP')
	AND   not exists (select 1
					  from   mi_insight_CaseCheckOutcomes aqto
					  where  aqto.Advice = saca.CASE_CaseReference)
	UNION ALL
	Select
	Advice,
	agt.AdviserGUID,
	CaseOutcome,
	product,
	InitialResult,
	FinalResult,
	FinalWorkflow,
	FinalCheck,
	AssessorUID,
	Assessor,
	Submitted,
	lob.LOB,
	cco.AdviserUID,
	cco.Adviser,
	cco.BUID,
	agt.FirmName,
	agt.AQMName [SQRM],
	agt.BQMName [QRM]
	from mi_insight_CaseCheckOutcomes cco
	join mi_aqt_ReportingHierarchy agt on agt.AdviserUID = cco.AdviserUID
	join #LOBCODES lob on lob.ShortCode = Product 
	Where 
	      --cco.AdviserUID = '4007774' and
	      cco.Submitted >= '01-DEC-2013'
	AND   cco.Submitted >= DATEADD(mm,-12,GETDATE())
	AND   cco.Advice != '0'
	
),

CTE_Submitted AS(
	select
	AQTO.AdviserUID [Adviser UID],
	AQTO.Adviser [Adviser Name],
	AQTO.BusinessUID [Firm UID],
	AQTO.FirmName [Firm Name],
	AQTO.SQRM,
	AQTO.QRM,
	nullif(count( CASE aqto.LOB WHEN 'COBI' THEN AQTO.Advice
						 WHEN 'COBP' THEN AQTO.Advice
						 WHEN 'SI'   THEN AQTO.Advice
						 WHEN 'RPB'	 THEN AQTO.Advice ELSE NULL END ),0) AS [COB Submitted],

	nullif(count( CASE aqto.LOB WHEN 'MCOB' THEN AQTO.Advice ELSE NULL END ),0) AS [MCOB Submitted], 

	nullif(count( CASE aqto.LOB WHEN 'ICOB' THEN AQTO.Advice ELSE NULL END ),0) AS [ICOB Submitted],

	lic.[business area] [Business Area]
	from      CTE_AQTCHECK AQTO
	left join dbo.mi_aqt_ReportingHierarchy AQTH on AQTH.AdviserGUID = AQTO.AdviserGUID
	left join lic lic on lic.uid = AQTH.AdviserUID
	group by AQTO.AdviserUID, AQTO.BusinessUID, AQTO.Adviser, AQTO.FirmName, AQTO.SQRM, AQTO.QRM, lic.[business area]
	)
	select 
	distinct
	SQRM
	from CTE_Submitted
/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

/****************************************************************************

			E N D															

****************************************************************************/
GO
