/****** Object:  StoredProcedure [BI].[pr_135_OwlNewEntrants]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_135_OwlNewEntrants]
Author	: Sam Campbell
Date	: 13/05/2022
 			
Stored procedure written for SSRS report.
Shows OWL New Entrants (advisers) along with their competencies and submitted case totals
Only show advisers with 'AQT New Entrant - Advised Replacement Owl' assessment pending and sales cases with Advised Replacement set to 'yes'

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

********************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_135_OwlNewEntrants]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int


set	@ReportName			= 'New Entrants Report'
set @StoredProcName		= object_name(@@procid)




/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

----**************************************************************************
-- Advisers who have the AQT New Entrant - Advised Replacements Owl assigned and pending
drop table if exists #ValidIndividuals
select ud.USR_ExternalID as 'AdviserUID', up.UPS_JobTitle as 'JobTitle',  ae.ase_date as 'AssBookingDate', up.UPS_DateFrom as 'DateAppointed', up.UPS_ID
into #ValidIndividuals
from sa_insight_AssessmentBooking ab 
inner join sa_insight_AssessmentEvent ae on ab.ASB_EventID = ae.ASE_ID
inner join sa_insight_Assessment a on a.ASS_ID = ae.ASE_TypeID
inner join sa_insight_UserDetails ud on ud.USR_ID = ab.ASB_AttendeeID
inner join sa_Insight_UserPosition up ON ud.USR_ID = up.UPS_UserID 
inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
where up.UPS_UserType in (3) -- Adviser/Seller
 and up.UPS_ContractStatus in (1) -- Currently under contract
 and up.UPS_DateTo is null  -- Current UserPosition
and a.ass_id = '7C1F1718-35A1-4E00-B47E-CB725F71135E'  -- 'AQT New Entrant - Advised Replacement Owl'
and ae.ASE_Status = 0  -- Pending

--**************************************************************************
 -- Advised Replacement Sales made by advisers above

drop table if exists #Sales
select
s.SaleID, n.AdviserUID, n.JobTitle, pmv.ProductType, p.PolicyID, p.InternalProductID, s.DateSubmitted
into #Sales
from sa_ows_sale s 
inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
inner join PolicyOneLink.sa_ows_ProtectionProductSummary pps on pps.PolicyId = p.PolicyID
inner join #ValidIndividuals n on s.AdviserUID = n.AdviserUID
left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
where  s.DateSubmitted is not null
and s.DateSubmitted > n.AssBookingDate -- only cases submitted since the assessment has been allocated
and pps.AnyReplacementsId = 19 -- yes, product is a replacement


--**************************************************************************
 -- Get count of sales for each adviser above by business area (COB, ICOB etc...)
 
drop table if exists #SaleCount
select  s.AdviserUID, pmv.ProductType,  'OWL ICOB' as 'Competency',count(*) as 'Number Sold'
into #SaleCount
from sa_ows_sale s 
inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
inner join PolicyOneLink.sa_ows_ProtectionProductSummary pps on pps.PolicyId = p.PolicyID
inner join #ValidIndividuals n on s.AdviserUID = n.AdviserUID
left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
where  s.DateSubmitted is not null
and s.DateSubmitted > n.AssBookingDate -- only cases submitted since the assessment has been allocated
and pps.AnyReplacementsId = 19 
group by s.AdviserUID,pmv.ProductType




--**************************************************************************
-- Case checks on above sales
drop table if exists #CaseCheckCount
select 
pol.AdviserUID, count(*) as 'CasesChecked',
case when pmv.producttype = 'Protection'  and  n.JobTitle not in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'ICOB'  
when pmv.producttype = 'Protection'  and  n.JobTitle  in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'OWL ICOB'
when pmv.producttype = 'Mortgage' then 'MCOB'
else 'COB'
end as 'ProductType'
into #CaseCheckCount
from sa_Insight_SalesCase sc inner join sa_Insight_BasicPolicy ibp on sc.CASE_id = ibp.BPOL_ParentID
left join sa_Insight_BusinessQuality bq on bq.BQ_ParentID = sc.CASE_ID and bq.BQ_StartedDate is not null
left join sa_Insight_CodeDescription code on code.code_code = bq.BQ_Status and Code_CodeType = 785
inner join #Sales pol on convert(varchar,pol.PolicyID) = ibp.BPOL_BackOfficeID
left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = pol.InternalProductID
left join sa_Insight_UserDetails ud on ud.usr_id = bq.BQ_CheckedBy
inner join sa_Insight_UserDetails udadv on udadv.USR_ExternalID = pol.AdviserUID
inner join #ValidIndividuals n on pol.AdviserUID = n.AdviserUID
where bq_status in (3,10,5) -- First time pass / First time pass with feedback / Action Required
group by pol.AdviserUID, pmv.ProductType, n.JobTitle
order by pol.AdviserUID


--**************************************************************************
--  Identify OWL ARs

drop table if exists #OWLAR
SELECT	USR_ExternalID 
			,STAF_Forename
			,STAF_SUrname
			,CASE WHEN STAF_NINumber IS NULL 
				THEN CONCAT(STAF_Surname,CONVERT(DATE,STAF_DOB,103)) 
				ELSE STAF_NINumber 
			END AS ID, asdname,
			ah.givesadvice
	into #OWLAR
	FROM	[dbo].[sa_Insight_Staff] S JOIN 
			dbo.sa_insight_UserDetails UD on UD.USR_ID = S.STAF_UserID JOIN
			cscv_AgentsHierarchy ah ON USR_ExternalID = ah.AgentCode AND (ah.ASDCode = '4019902' OR ah.FirmCode = '2016789')
	WHERE	ah.CompetentStatusDescription IN('Left', 'Active')
			and ah.GivesAdvice = 'Y'


--***********************
-- MAIN Report

--***********************

 SELECT 
 ud.USR_ExternalID as 'Adviser UID', ud.usr_name as 'Adviser Name', cdjob.Code_Description as 'Job Title', uh.BusinessUID as 'Firm UID', uh.BusinessCompanyName as 'Firm Name',
 uh.BQMUID as 'QRM UID', uh.BQMName as 'QRM Name', isnull(uh.SupervisorUID,'') as 'Supervisor UID', isnull(uh.SupervisorName,'') as 'Supervisor Name', chg.DateAppointed as 'Date of Appointment',
 cdcomp.Code_Description as 'Competency Held', 
case when oar.asdname is NULL then ''
     when oar.asdname ='ASD Pot Account' then 'Y'
	 when oar.asdname ='OWL AR' then 'Y'
else '' end as 'OWL AR?',
 isnull(sales.[Number Sold],0) as 'No. of Sales',
 isnull(ccc.CasesChecked,0) as 'No. of Checks'
 FROM sa_Insight_Staff s
 inner join sa_Insight_UserDetails ud ON s.STAF_UserID = ud.USR_ID
 inner join sa_Insight_UserPosition up ON s.STAF_UserID = up.UPS_UserID 
 inner join #ValidIndividuals chg on up.ups_id = chg.ups_id 
 left join sa_Insight_UserCompetency uc on uc.UC_OwnerID = s.STAF_UserID and UC_BusinessArea in (1,2,3,8,9) and UC_Status = 0 -- COB, ICOB, MCOB, ICOB GI only, OWL ICOB and competency is active
 inner join sa_Insight_CodeDescription cdcomp on cdcomp.Code_Code = uc.UC_BusinessArea and cdcomp.Code_CodeType = 960 -- Competency Name
 left join #CaseCheckCount ccc on ccc.AdviserUID = ud.USR_ExternalID and ccc.ProductType = cdcomp.code_description
 left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = ud.USR_ExternalID and up.UPS_DateFrom between uh.EffectiveStartDate and uh.EffectiveEndDate
 inner join #SaleCount sales on sales.AdviserUID = ud.USR_ExternalID and cdcomp.Code_Description = sales.Competency
 left join sa_Insight_CodeDescription cdjob on cdjob.Code_Code = chg.JobTitle and cdjob.Code_CodeType = 54  -- Job Titles
 left join #OWLAR oar on oar.USR_ExternalID = ud.USR_ExternalID
 where up.UPS_UserType in (3) -- Adviser/Seller
 and up.UPS_ContractStatus in (1) -- Currently under contract
 and up.UPS_DateTo is null  -- Current UserPosition
 order by [Adviser UID], cdcomp.Code_Description

 --drop table #Audit
 drop table #SaleCount
 --drop table #UnderContractChgs
 drop table #ValidIndividuals
 drop table #CaseCheckCount
 drop table #OWLAR
 drop table #Sales


/****************************************************************************


	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



