/**********************************************************************************************
Name	: [BI].[pr_137_OwlNewEntrantsDetails]
Author	: Sam Campbell
Date	: 09/06/2022
 			
Stored procedure written for SSRS report.
Shows New Entrants (Owl advisers) - replaces original top level and drilldown reports
Uses allocation of OWL Off Track assessment 'AQT New Entrant - Advised Replacement Owl' as a driver for selecting advisers

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
20/06/2022	S Campbell	Add additional processing - use Authorised/Licenced date from assessment booking result form to filter sales cases
********************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_137_OwlNewEntrantsDetails]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'New Entrants Details Report'
set @StoredProcName		= object_name(@@procid)



/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

-- Advisers who have the AQT New Entrant - Advised Replacements Owl assigned and pending

-- Get Authorised/Licenced Date from assessment for use in next temp table
drop table if exists #Authdate
select ab.ASB_AttendeeID, fad.FAD_Text as 'AuthDate'
into #AuthDate
from sa_Insight_AssessmentBooking ab 
inner join sa_Insight_Formdata f on ASB_FormID = f.FD_ID
inner join sa_insight_AssessmentEvent ae on ab.ASB_EventID = ae.ASE_ID
inner join sa_insight_Assessment a on a.ASS_ID = ae.ASE_TypeID
inner join sa_Insight_FormSectionData fsd on fsd.FSD_ParentID = f.FD_ID
inner join sa_Insight_FormSection fs on fs.FS_ID = fsd.FSD_FormSectionID
inner join sa_Insight_FormQuestion fq on fq.FQ_SectionID = fs.FS_ID and fq.FQ_SectionID = 'E1147106-CF0E-4CF3-B082-FFF41CBF1282' and FQ_QuestionCode = 3 -- Authorised / Licenced date from assessment result
inner join sa_Insight_FormAnswerData fad on fad.FAD_QuestionID = fq.FQ_ID and fad.FAD_ParentID = fsd.FSD_ID
where a.ass_id = '7C1F1718-35A1-4E00-B47E-CB725F71135E' -- AQT New Entrants - Owl Advised Replacements


drop table if exists #ValidIndividuals
select ud.USR_ExternalID as 'AdviserUID', up.UPS_JobTitle as 'JobTitle',  
ad.authdate,
convert(datetime,ad.AuthDate,103)  as 'AuthDateConverted', 
up.UPS_DateFrom as 'DateAppointed', up.UPS_ID
into #ValidIndividuals
from sa_insight_AssessmentBooking ab 
inner join sa_insight_AssessmentEvent ae on ab.ASB_EventID = ae.ASE_ID
inner join sa_insight_Assessment a on a.ASS_ID = ae.ASE_TypeID
inner join sa_insight_UserDetails ud on ud.USR_ID = ab.ASB_AttendeeID
inner join sa_Insight_UserPosition up ON ud.USR_ID = up.UPS_UserID 
inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
left join #AuthDate ad on ad.ASB_AttendeeID = ab.ASB_AttendeeID
where up.UPS_UserType in (3) -- Adviser/Seller
 and up.UPS_ContractStatus in (1) -- Currently under contract
 and up.UPS_DateTo is null  -- Current UserPosition
and a.ass_id = '7C1F1718-35A1-4E00-B47E-CB725F71135E'  -- 'AQT New Entrant - Advised Replacement Owl'
and ae.ASE_Status = 0  -- Pending

 
 -- Sales made by advisers above

drop table if exists #Sales
select s.SaleID, n.AdviserUID, n.JobTitle, pps.ApplicationDated as 'ApplicationDate', pmv.ProductType, p.PolicyID, p.InternalProductID, s.DateSubmitted
into #Sales
from sa_ows_sale s 
inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
inner join PolicyOneLink.sa_ows_ProtectionProductSummary pps on pps.PolicyId = p.PolicyID
inner join #ValidIndividuals n on s.AdviserUID = n.AdviserUID
left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
where  s.DateSubmitted is not null
and s.DateSubmitted > case n.AuthDateconverted when '1900-01-01 00:00:00.000' 
                                               then '9999-12-31 00:00:00.000'
											   else n.AuthDateConverted end    -- only cases submitted since the assessment has been allocated - case stmt added 20/06/2022
and pps.AnyReplacementsId = 19 -- yes, product is a replacement


--***********************
-- MAIN Report

--***********************


select pol.saleid as 'Advice ID', BPOL_BackOfficeID as 'Case ID', pol.AdviserUID as 'Adviser UID', udadv.USR_Name as 'Adviser',  
pmv.DisplayName as 'Product', 
pt.prod_shortname as 'Product Type',
case when pmv.ProductType = 'Mortgage' then 'MCOB'
when pmv.ProductType ='Investment' then 'COB'
when pmv.ProductType ='Pension' then 'COB'
when pmv.ProductType = 'Protection' and pol.JobTitle not in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'ICOB' 
when pmv.ProductType = 'Protection' and pol.JobTitle in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'OWL ICOB' 
else 'Unknown'
end as 'Licence',
pol.DateSubmitted as 'Submitted Date',
pol.applicationdate as 'Application Date',  CASE_CaseReference as 'Insight Case Check', 
isnull(case_description,'') as 'Description', 
isnull(convert(varchar,bq.bq_createddate,103),'') as 'Date Allocated', 
isnull(ud.USR_Name,'') as 'Allocated To', 
isnull(convert(varchar,out.initialcheck,103),'') as 'Initial Check Date', 
isnull(out.InitialResult,'') as 'Initial Check Result',
isnull(cd.Code_Description,'') as 'Final Workflow', 
isnull(convert(varchar,out.finalcheck,103),'') as  'Final CheckDate',
case when attl.ATTL_AttributeValue is null then ''
else 'Y' end as 'CIC Replacement?',
case when attl1.ATTL_AttributeValue is null then ''
else 'Y' end as 'Debt Con?'
from sa_Insight_SalesCase sc 
inner join sa_Insight_BasicPolicy ibp on sc.CASE_id = ibp.BPOL_ParentID
left join sa_Insight_BusinessQuality bq on bq.BQ_ParentID = sc.CASE_ID and bq.BQ_StartedDate is not null -- to work out who case is allocated to and date allocated
left join sa_Insight_CodeDescription code on code.code_code = bq.BQ_Status and Code_CodeType = 785
inner join #Sales pol on convert(varchar,pol.PolicyID) = ibp.BPOL_BackOfficeID
left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = pol.InternalProductID
left join sa_Insight_UserDetails ud on ud.usr_id = bq.BQ_CheckedBy
inner join sa_Insight_UserDetails udadv on udadv.USR_ExternalID = pol.AdviserUID
left join sa_insight_AttributeLink AS attl ON attl.ATTL_ParentID = ibp.BPOL_ID and attl.ATTL_AttributeValue like ('%CICR%')
left join sa_insight_AttributeLink AS attl1 ON attl1.ATTL_ParentID = ibp.BPOL_ID and attl1.ATTL_AttributeValue like ('%DebtC%')
left join mi_insight_CaseCheckOutcomes out on out.CaseID = ibp.BPOL_BackOfficeID
left join sa_insight_Attribute AS attr ON attr.ATT_ID = attl.ATTL_AttributeID and attr.ATT_Name = 'PRODUCT.rfc'
left join sa_Insight_ProductType pt on pt.PROD_Code = ibp.BPOL_ProductType
left join (select bq1.BQ_ParentID, max(bq1.BQ_CheckDate) as MaxBQCheckDate
		   from sa_insight_BusinessQuality bq1
		   group by bq1.BQ_ParentID) as LastStatus 	on LastStatus.BQ_ParentID = sc.Case_ID		
left join sa_insight_businessquality bq2 on bq2.bq_parentID = sc.Case_ID
															and bq2.BQ_CheckDate = laststatus.MaxBQCheckDate
left join sa_insight_codedescription cd on cd.code_codetype = 785   
															AND cd.code_code = bq2.bq_status
where isnull(bq.BQ_Status,3) in (2,3,10,5) -- Incomplete / First time pass / First time pass with feedback / Action Required - only used to find allocation date/team member -  where no checks exist, still bring back case ref
order by ibp.BPOL_BackOfficeID -- Case ID




 drop table #ValidIndividuals
 drop table #Sales
 drop table #AuthDate

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



