inner join sa_Insight_UserPosition up ON ud.USR_ID = up.UPS_UserID 
inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
left join sa_Insight_UserLicence ul on ul.ULIC_UserID = ud.USR_ID and ul.ULIC_LicenceID = '60B09E69-ECED-4A14-9938-DCC60D15EBF8' and ul.ULIC_Status = 2 -- LIC51/Granted
