inner join sa_insight_Assessment a on a.ASS_ID = ae.ASE_TypeID
inner join sa_insight_UserDetails ud on ud.USR_ID = ab.ASB_AttendeeID
inner join sa_Insight_UserPosition up ON ud.USR_ID = up.UPS_UserID 
inner join sa_insight_Staff s on s.STAF_UserID = ud.USR_ID
left join sa_Insight_UserLicence ul on ul.ULIC_UserID = ud.USR_ID and ul.ULIC_LicenceID = '0F127288-3940-44F3-BEF5-154135E39962' and ul.ULIC_Status = 2 -- LIC56/Granted
where up.UPS_UserType in (3) -- Adviser/Seller
and up.UPS_ContractStatus in (1) -- Currently under contract
and up.UPS_DateTo is null  -- Current UserPosition
and a.ass_id in ('E477C8CF-E69B-432A-BB2A-2B9CAA42D98C')
and ae.ASE_Status = 0  -- Pending



delete from BI.NewEntrantSales
begin
if @BusArea = 'RPB'
 insert into BI.NewEntrantSales
     select s.SaleID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', PolicyID,  s.DateSubmitted, pmv.InternalProductID, pmv.DisplayName
     from sa_ows_sale s 
     inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
	 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
	 inner join #RPBValidIndividuals r on s.AdviserUID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.PolicyID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('DRAW','DTOD','DRDW')
	 and s.DateSubmitted is not null
     and s.DateSubmitted > r.LicenceValid -- exclude cases from previous employment
else
if @BusArea = 'SI'
 insert into BI.NewEntrantSales
     select s.SaleID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', PolicyID,  s.DateSubmitted, pmv.InternalProductID, pmv.DisplayName
     from sa_ows_sale s 
     inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
	 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
	 inner join #SIValidIndividuals r on s.AdviserUID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.PolicyID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('VCT','VCTR','EIS','EISR','BPRL')
	 and s.DateSubmitted is not null
	 and s.DateSubmitted > r.LicenceValid -- exclude cases from previous employment
else
if @BusArea = 'COB'
 insert into BI.NewEntrantSales
     -- OWS Sales
     select s.SaleID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', PolicyID,  s.DateSubmitted, pmv.InternalProductID as 'InternalProductID', 
	 pmv.DisplayName as 'DisplayName'
     from sa_ows_sale s 
     inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
	 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
	 inner join #COBSValidIndividuals r on s.AdviserUID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.PolicyID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('ONIV','OIRP','OFIN','OFIR','PNSW','PENS','PNRP','TIP','IHT','CINV','ANNC','ANNS')
	 and s.DateSubmitted is not null
     and s.DateSubmitted > r.LicenceValid -- exclude cases from previous employment
	 -- ABS Sales
	 UNION ALL
     select s.ABSCaseID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', p.SwiftCaseID,  s.DateSubmitted, prod.ProductID, prod.DisplayName 
	 from sa_abs_ABS_Cases s 
     inner join sa_abs_ABS_ProductSales p on s.ABSCaseID = p.ABSCaseID and s.CaseStatusID in (2) -- submitted
	 left join sa_abs_ABS_Products prod on prod.ABSProductID = p.ProductID
	 inner join #COBSValidIndividuals r on s.AdviserID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.SwiftCaseID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('IHT')
	 and s.DateSubmitted is not null
     and s.DateSubmitted > r.LicenceValid 
	 order by SaleID        
else
if @BusArea = 'MCOB'
 insert into BI.NewEntrantSales
select s.SaleID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', PolicyID,  s.DateSubmitted, pmv.InternalProductID, pmv.DisplayName
     from sa_ows_sale s 
     inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
	 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
     inner join #MCOBValidIndividuals r on s.AdviserUID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.PolicyID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('MORT','BTL')
	 and s.DateSubmitted is not null
	 and s.DateSubmitted > r.LicenceValid -- exclude cases from previous employment
	 else
if @BusArea = 'ICOB'
 insert into BI.NewEntrantSales
	 -- OWS Sales
     select s.SaleID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', PolicyID,  s.DateSubmitted, pmv.InternalProductID as 'InternalProductID', 
	 pmv.DisplayName as 'DisplayName'
     from sa_ows_sale s 
     inner join sa_ows_Policies p on s.SaleID = p.SaleID and p.Status in (2) -- submitted
	 left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = p.InternalProductID
     inner join #ICOBValidIndividuals r on s.AdviserUID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.PolicyID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('ICOB','WOL','WOLR')
	 and s.DateSubmitted is not null
	 and s.DateSubmitted > r.LicenceValid -- exclude cases from previous employment
	 -- ABS Sales
     UNION ALL  
     select s.ABSCaseID, r.AdviserUID as 'AdviserUID', r.JobTitle as 'JobTitle', p.SwiftCaseID,  s.DateSubmitted, prod.ABSProductID, prod.DisplayName
	 from sa_abs_ABS_Cases s 
     inner join sa_abs_ABS_ProductSales p on s.ABSCaseID = p.ABSCaseID and s.CaseStatusID in (2) -- submitted
	 left join sa_abs_ABS_Products prod on prod.ABSProductID = p.ProductID
	 inner join #ICOBValidIndividuals r on s.AdviserID = r.AdviserUID
	 inner join sa_Insight_BasicPolicy bp on bp.BPOL_BackOfficeID = convert(varchar,p.SwiftCaseID)
     inner join sa_Insight_ProductType pt on bp.BPOL_ProductType = pt.PROD_Code
	 where pt.PROD_ShortName in ('ICOB','WOL','WOLR')
	 and s.DateSubmitted is not null
     and s.DateSubmitted > r.LicenceValid 
	 order by SaleID
end





--***********************
-- MAIN Report

--***********************
     select s.saleid as 'Advice ID', BPOL_BackOfficeID as 'Case ID', s.AdviserUID as 'Adviser UID', udadv.USR_Name as 'Adviser',  
     s.DisplayName as 'Product', 
     pt.prod_shortname as 'Product Type',
     case when pmv.ProductType = 'Mortgage' then 'MCOB'
          when coalesce(pmv.ProductType, absp.absproducttype) = 'Investment' then 'COB'
          when coalesce(pmv.ProductType, absp.absproducttype) = 'Pension' then 'COB'
          when coalesce(pmv.ProductType, absp.absproducttype) = 'Protection' and s.JobTitle not in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'ICOB' 
          when coalesce(pmv.ProductType, absp.absproducttype) = 'Protection' and s.JobTitle in  (51, 52, 53, 54, 55, 56, 57, 58, 61, 62, 63, 65) then 'OWL ICOB' 
          else 'Unknown'
     end as 'Licence',
     s.DateSubmitted as 'Submitted Date', CASE_CaseReference as 'Insight Case Check', 
     isnull(case_description,'') as 'Description', 
     isnull(convert(varchar,bq.bq_createddate,103),'') as 'Date Allocated', 
     isnull(ud.USR_Name,'') as 'Allocated To', 
     isnull(convert(varchar,out.initialcheck,103),'') as 'Initial Check Date', 
     isnull(out.InitialResult,'') as 'Initial Check Result',
     isnull(out.FinalWorkflow,'') as 'Final Workflow', 
	 isnull(convert(varchar,out.finalcheck,103),'') as  'Final CheckDate',
     case when attl.ATTL_AttributeValue is null then ''
     else 'Y' end as 'CIC Replacement?',
     case when attl1.ATTL_AttributeValue is null then ''
     else 'Y' end as 'Debt Con?'
     from sa_Insight_SalesCase sc 
     inner join sa_Insight_BasicPolicy ibp on sc.CASE_id = ibp.BPOL_ParentID
     left join sa_Insight_BusinessQuality bq on bq.BQ_ParentID = sc.CASE_ID and bq.BQ_StartedDate is not null -- to work out who case is allocated to and date allocated
    --left join sa_Insight_CodeDescription code on code.code_code = bq.BQ_Status and Code_CodeType = 785
     inner join bi.newentrantsales s on convert(varchar,s.PolicyID) = ibp.BPOL_BackOfficeID
     left join StaticData.sa_ows_ProductMergeView pmv on pmv.InternalProductID = s.InternalProductID
	 left join sa_abs_ABS_Products absp on absp.ABSProductID = s.InternalProductID
     left join sa_Insight_UserDetails ud on ud.usr_id = bq.BQ_CheckedBy
     inner join sa_Insight_UserDetails udadv on udadv.USR_ExternalID = s.AdviserUID
     left join sa_insight_AttributeLink AS attl ON attl.ATTL_ParentID = ibp.BPOL_ID and attl.ATTL_AttributeValue like ('%CICR%')
     left join sa_insight_AttributeLink AS attl1 ON attl1.ATTL_ParentID = ibp.BPOL_ID and attl1.ATTL_AttributeValue like ('%DebtC%')
     left join mi_insight_CaseCheckOutcomes out on out.CaseID = ibp.BPOL_BackOfficeID
     left join sa_insight_Attribute AS attr ON attr.ATT_ID = attl.ATTL_AttributeID and attr.ATT_Name = 'PRODUCT.rfc'
     left join sa_Insight_ProductType pt on pt.PROD_Code = ibp.BPOL_ProductType
     left join (select bq1.BQ_ParentID, max(bq1.BQ_CheckDate) as MaxBQCheckDate
				from prod_zurich_openwork_datawarehouse.dbo.sa_insight_BusinessQuality bq1
				group by bq1.BQ_ParentID) as LastStatus on LastStatus.BQ_ParentID = sc.Case_ID		
	 left join prod_zurich_openwork_datawarehouse.dbo.sa_insight_businessquality bq2 on bq2.bq_parentID = sc.Case_ID
					and bq2.BQ_CheckDate = laststatus.MaxBQCheckDate
	 --left join sa_insight_codedescription cd on cd.code_codetype = 785 AND cd.code_code = bq2.bq_status
     where isnull(bq.BQ_Status,3) in (2,3,10,5,7) -- Incomplete / First time pass / First time pass with feedback / Action Required / Action Taken - only used to find allocation date/team member -  where no checks exist, still bring back case ref
     order by BPOL_BackOfficeID -- Case ID


 --drop table #AllSales
 drop table #RPBValidIndividuals
 drop table #SIValidIndividuals
 drop table #COBSValidIndividuals
 drop table #MCOBValidIndividuals
 drop table #ICOBValidIndividuals
 --drop table #RPBSales
 --drop table #SISales
 --drop table #COBSales
 --drop table #MCOBSales
 --drop table #ICOBSales

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



