drop table if exists #ProtectionValidIndividuals
drop table if exists #MortgageValidIndividuals

select ud.USR_ExternalID as 'AdviserUID', up.UPS_JobTitle as 'JobTitle',  ul.ULIC_ValidFrom as 'LicenceValid', up.UPS_DateFrom as 'DateAppointed', up.UPS_ID
