/**********************************************************************************************
Name	: [BI].[pr_139_TestResponses]
Author	: Sam Campbell
Date	: 04/07/2022
 			
Stored procedure written for PBI report.
To show test responses, which questions were answered correctly, and which incorrectly


as a driver for selecting advisers

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

********************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_139_TestResponses] 

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
           

set	@ReportName			= 'Test Responses'
set @StoredProcName		= object_name(@@procid)



/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF


select
tct_id,
tb.TSB_ID,
track.TCT_Description as 'Track',
t.TST_Description as 'Test',
tb.TSB_AttendeeID as 'AttendeeID',
usr.USR_Name as 'Attendee',  
usr.USR_ExternalID as 'UID',
cdtestmode.Code_Description as 'Mode',
cdresult.Code_Description as 'Outcome',
TB.tsb_percentage as 'Mark Obtained', --passmark
TB.TSB_StartedDate as 'Date Started', -- time started
TB.TSB_CompletedDate as 'Date Completed',
Q.TQ_Name as 'Question Number', Q.TQ_Text as 'Question', A.TA_Text as 'Answer', 
case TA_Value when 0 then 'incorrect' when '1' then 'correct' end as 'Result'
from
sa_insight_UserTandCTrackModule as Um
join sa_insight_UserTandCTrack as UT on UM.USRTS_UserTrackID = UT.USRT_ID
JOIN sa_insight_TandCTrack as TRACK on UT.USRT_TrackID = TRACK.TCT_ID
Join sa_insight_UserTandCTrackEvent as TRKE on UM.USRTS_ID = TRKE.USRTE_ModuleID
join sa_insight_TestEvent as TE on TRKE.USRTE_BookingID = TE.TSE_ID
Join sa_insight_TestBooking as TB on TE.TSE_ID = TB.TSB_EventID
Join sa_Insight_TestEvent  E on TB.TSB_EventID = E.TSE_ID
Join sa_Insight_Test  T on E.TSE_TypeID = T.TST_ID
Join sa_Insight_TestProperties  P on T.TST_ID = P.TP_TestID
Join sa_Insight_UserDetails  usr on TB.TSB_AttendeeID = usr.USR_ID
Join sa_Insight_CodeDescription  cdresult on TB.TSB_Result = cdresult.Code_Code and cdresult.Code_CodeType = 29
Join sa_Insight_CodeDescription  cdtestmode on P.TP_Mode = cdtestmode.Code_Code and cdtestmode.Code_CodeType = 157
left Join sa_Insight_TestAllocatedQuestion  AQ on TB.TSB_ID = AQ.TAQ_TestBookingID
left join sa_Insight_TestQuestion  Q on AQ.TAQ_TestQuestionID = Q.TQ_ID
left join sa_Insight_TestAllocatedQuestionAnswer as QA on AQ.TAQ_ID = QA.TAQA_TestAllocatedQuestionID 
left join sa_Insight_TestAnswer  A on QA.TAQA_ChosenAnswerID = A.TA_ID
--where tct_id in ('9B93094D-0AEE-411C-995A-0B58EC980684','80D6B3EE-01EB-4DA3-AC40-DAF70B426763')  --  LT2 - ICOBS Pure Protection Only v3,  LT3 - GI & Pure Protection
--and TSB_AttendeeID in ('C459F4A0-4883-4D5F-8CF6-014BA67A7CFF','D186CF33-4DBD-4AD5-B8B0-01702C2927D5')
where ut.USRT_StartDate > '2022-01-01 00:00.000'

order by 4,3,2

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
