/**********************************************************************************************
Name	: [BI].[pr_141_PreVettingSummary]
Author	: Sam Campbell
Date	: 04/07/2022
 			
Stored procedure written for PBI report.
To show summary of who has sat tests and in which track


as a driver for selecting advisers/test

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
25/08/2022	S Campbell	Add Firm
29/09/2022	S Campbell	Left join to flat hierarchy table so that people with corrupt hierarchy rows still get included
********************************************************************************************************************************************/
CREATE PROCEDURE [BI].[pr_141_PreVettingSummary] 

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
           

set	@ReportName			= 'PreVetting Summary'
set @StoredProcName		= object_name(@@procid)



/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF


/* Test Outcomes from CodeDescription, CodeType 29

Cancelled
Not Taken
Did Not Attend
Failed
Passed
Pending*/

-- Create possible outcomes in order of precedence
drop table if exists #Outcomes
select 2 as 'Priority', 'Did Not Attend' as 'Outcome' into #Outcomes
insert into #Outcomes values (1,'Pending')
insert into #Outcomes values (3,'Failed')
insert into #Outcomes values (4,'Not Taken')
insert into #Outcomes values (5,'Cancelled')
insert into #Outcomes values (6,'Passed')


drop table if exists #summary1
select
tct_id,
tb.TSB_ID,
track.TCT_Description as 'Track',
t.TST_Description as 'Test',
ut.USRT_StartDate as 'Track Start Date',
tb.TSB_AttendeeID as 'AttendeeID',
usr.USR_Name as 'Attendee',  
usr.USR_ExternalID as 'UID',
udsup.USR_Name as 'Supervisor',
au.BusinessCompanyName as 'Firm',
cdtestmode.Code_Description as 'Mode',
cdresult.Code_Description as 'Outcome',
--TB.tsb_percentage as 'Mark Obtained', --passmark
TB.TSB_StartedDate as 'Date Started', -- time started
TB.TSB_CompletedDate as 'Date Completed',
--au.userdatefrom, au.userdateto,
--Q.TQ_Name as 'Question Number', Q.TQ_Text as 'Question', A.TA_Text as 'Answer', 
--case TA_Value when 0 then 'incorrect' when '1' then 'correct' end as 'Result'
ROW_NUMBER() OVER(PARTITION BY tb.tsb_attendeeid, t.tst_id ORDER BY tct_id,t.tst_id,tb.tsb_starteddate desc) as RowNumber
into #Summary1
from
sa_insight_UserTandCTrackModule as Um
join sa_insight_UserTandCTrack as UT on UM.USRTS_UserTrackID = UT.USRT_ID
JOIN sa_insight_TandCTrack as TRACK on UT.USRT_TrackID = TRACK.TCT_ID
Join sa_insight_UserTandCTrackEvent as TRKE on UM.USRTS_ID = TRKE.USRTE_ModuleID
join sa_insight_TestEvent as TE on TRKE.USRTE_BookingID = TE.TSE_ID
Join sa_insight_TestBooking as TB on TE.TSE_ID = TB.TSB_EventID
Join sa_Insight_TestEvent  E on TB.TSB_EventID = E.TSE_ID
Join sa_Insight_Test  T on E.TSE_TypeID = T.TST_ID
Join sa_Insight_TestProperties  P on T.TST_ID = P.TP_TestID
Join sa_Insight_UserDetails  usr on TB.TSB_AttendeeID = usr.USR_ID
left join mi_insight_UserHierarchyAllUsers au on au.UserUID = usr.USR_ExternalID and ut.USRT_StartDate between au.EffectiveStartDate and EffectiveEndDate
left join sa_Insight_UserDetails udsup on udsup.USR_ExternalID = coalesce(au.SupervisorUID,au.bqmuid,au.aqmuid)
Join sa_Insight_CodeDescription  cdresult on TB.TSB_Result = cdresult.Code_Code and cdresult.Code_CodeType = 29
Join sa_Insight_CodeDescription  cdtestmode on P.TP_Mode = cdtestmode.Code_Code and cdtestmode.Code_CodeType = 157
--left Join sa_Insight_TestAllocatedQuestion  AQ on TB.TSB_ID = AQ.TAQ_TestBookingID
--left join sa_Insight_TestQuestion  Q on AQ.TAQ_TestQuestionID = Q.TQ_ID
--left join sa_Insight_TestAllocatedQuestionAnswer as QA on AQ.TAQ_ID = QA.TAQA_TestAllocatedQuestionID 
--left join sa_Insight_TestAnswer  A on QA.TAQA_ChosenAnswerID = A.TA_ID
--where tct_id in ('9B93094D-0AEE-411C-995A-0B58EC980684','80D6B3EE-01EB-4DA3-AC40-DAF70B426763')  --  LT2 - ICOBS Pure Protection Only v3,  LT3 - GI & Pure Protection
--and TSB_AttendeeID in ('C459F4A0-4883-4D5F-8CF6-014BA67A7CFF','D186CF33-4DBD-4AD5-B8B0-01702C2927D5')
where ut.USRT_StartDate > '2021-12-01 00:00.000'
order by Attendee,Test, [Date Completed]


drop table if exists #Summary2  -- Derive Current Overall Track Outcome
select Track, [Track Start Date], [Date Started], attendeeid,test,s1.TCT_ID, s1.tsb_id  ,Attendee, Supervisor, Firm, s1.Outcome,
ROW_NUMBER() OVER(PARTITION BY attendeeid, tct_id ORDER BY o.Priority asc, [date Started] desc) as RowNumber
into #Summary2 
from #Summary1 s1 inner join #outcomes o on s1.Outcome = o.Outcome
where s1.RowNumber = 1
order by AttendeeID

drop table if exists #Summary3  -- Derive completed date of last test taken on the track
select s1.TCT_ID, s1.tsb_id, attendeeid, [Date Completed],
ROW_NUMBER() OVER(PARTITION BY attendeeid, tct_id ORDER BY [date completed] desc ) as RowNumber
into #Summary3 
from #Summary1 s1 
where s1.RowNumber = 1
order by AttendeeID

-- Data for PowerBI Summary page
select Track, [Track Start Date], [Date Started], s2.TSB_ID, s2.TCT_ID, s2.attendeeid, Attendee,Supervisor, Firm, s3.[Date Completed] as 'Date Last Track Test Completed', s2.Outcome 
from #Summary2 s2 inner join #Summary3 s3 on s2.AttendeeID = s3.AttendeeID and s2.TCT_ID = s3.TCT_ID and s3.RowNumber = 1
where s2.RowNumber = 1
order by s2.TCT_ID, s2.Attendee




/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



