SET ANSI_WARNINGS OFF


select abk.ASB_AttendeeID, 
ass.ASS_Description as 'Assessment', abk.ASB_CompletedOn as 'Completed', ud.USR_Name as 'Name', cdbkresult.Code_Description as 'Booking Result', cdassstatus.Code_Description as 'Assessment Status'
from sa_Insight_AssessmentEvent aev 
inner join sa_Insight_AssessmentBooking abk on abk.ASB_EventID = aev.ASE_ID
inner join sa_Insight_Assessment ass on ass.ASS_ID = aev.ASE_TypeID
inner join sa_Insight_UserDetails ud on ud.USR_ID = abk.ASB_AttendeeID
inner join sa_Insight_CodeDescription cdbkresult on cdbkresult.Code_Code = abk.ASB_Result and cdbkresult.Code_CodeType = 28
inner join sa_Insight_CodeDescription cdassstatus on cdassstatus.Code_Code = aev.ASE_Status and cdassstatus.Code_CodeType = 26
where abk.ASB_CompletedDate  > '2021-01-01 00:00:00.000'



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

