select kpir.KPID_UserID, pop.UserName as 'Name', pop.UserUID as 'UID', pop.SupervisorUserName as 'Supervisor', k.KPI_Name as 'KPI', kpir.KPID_Date as 'KPI Date', cdStatus.Code_Description as 'Result'
from sa_Insight_KPIResult  kpir
inner join sa_Insight_KPI k on k.KPI_ID = kpir.KPID_KPI_ID
inner join sa_Insight_CodeDescription cdStatus on cdStatus.Code_Code = KPID_Status and Code_CodeType = 500
left join mi_insight_KPIPopulation pop on pop.UserID = kpir.KPID_UserID
where KPID_Date between '2021-01-01 00:00:00.000' and '2021-12-31 23:59:59.999'
and k.KPI_Type = 1 -- Adviser Risk
and kpir.KPID_Status in (1,2,3,4) -- Green, Amber, Red, Red Flag



