set	@ReportName			= 'Active Users'
set @StoredProcName		= object_name(@@procid)



/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET ARITHABORT OFF
SET ANSI_WARNINGS OFF

select UserPTL.Field1Value as PTLCode, UserID.Field1Value as [UID], IH.UserName, CD.cd_email, IH.BusinessUID, IH.BusinessCompanyName,
IH.BusinessCategory, IH.UserContractStatus
from sa_ISL_SingleSignOnApplicationProfile UserID
inner join sa_ISL_SingleSignOnApplicationProfile UserPTL on  UserPTL.SingleSignOnUserId = UserID.SingleSignOnUserId
                                                             and  UserPTL.SingleSignOnApplicationID = 1
inner join mi_insight_UserHierarchy as IH on userid.Field1Value = IH.UserUID
left join sa_insight_Staff as STAF on IH.UserGUID = STAF.STAF_UserID
inner join sa_insight_ContactDetails as CD on STAF.STAF_ID = CD.CD_ParentID
where UserID.SingleSignOnApplicationID = 3
and UserContractStatusCode != 2 -- Out of Contract
and username not like 'BC Test%'
and username not like 'Concert Training%'
and username not like 'OWS Fine%'
and username not like 'OWS Test%'
and username not like 'Training%'
and username not like 'Pen Test%'



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

