/**********************************************************************************************
Name	: [BI].[pr_145_OwlGIReferrals] 
Author	: J Homer
Date	: 24/08/2022

GI payments in Openwork are made direct to the sellers by the providers, with Openwork receiving their override only from the GI providers. 
Because Owl not only pay the seller but also the hierarchy many of the GI providers cannot accommodate this, 
so Openwork pays GI override quarterly for ASMs and ESMs
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_145_OwlGIReferrals]

	@Month AS Date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Owl GI Referrals'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Select 
CommissionMonth, 
PolicyTermEffectiveDate, 
ClientName, 
GrossPremium, 
AdviserUID, 
AdviserName, 
UserName, 
OwlASMUID2, 
OwlASMName2, 
odp.Source,
case when OwlASMUID2 is not null then (case when odp.Source in ('L&G','Wessex','Vitality PHI') then GrossPremium *0.01 when odp.source = 'Bluedrop CIR' then GrossPremium*0.02 end) else 0 end as ESMDue, 
CASE WHEN odp.Source <> 'Wessex' THEN LEFT(odp.Source + ' ESM Commission - '+DateName(Month,CommissionMonth)+' '+Convert(varchar(4),Year(CommissionMonth)),50) 
	 Else LEFT(odp.Source + ' Wessex Commission - '+DateName(Month,CommissionMonth)+' '+Convert(varchar(4),Year(CommissionMonth)),50)
END as Description
into #LGDetails
from owt_OwlDirectPayments odp
join mi_insight_UserHierarchyAllUsers uhau on uhau.UserUID = odp.AdviserUID and odp.PolicyTermEffectiveDate between uhau.EffectiveStartDate and uhau.EffectiveEndDate
UNION
Select 
CommissionMonth, 
PolicyTermEffectiveDate, 
ClientName, 
GrossPremium, 
AdviserUID, 
AdviserName, 
UserName, 
OwlASMUID1, 
OwlASMName1, 
odp.Source,
case when OwlASMUID1 is not null and odp.Source = 'Bluedrop CIR' then GrossPremium*0.03  when odp.Source = 'VItality PHI' and OwlASMUID1 is not null then GrossPremium * 0.04 else 0 end as ESMDue, 
LEFT(odp.Source + ' ASM Commission - '+DateName(Month,CommissionMonth)+' '+Convert(varchar(4),Year(CommissionMonth)),50) as Description
--into #LGDetails
from owt_OwlDirectPayments odp
join mi_insight_UserHierarchyAllUsers uhau on uhau.UserUID = odp.AdviserUID and odp.PolicyTermEffectiveDate between uhau.EffectiveStartDate and uhau.EffectiveEndDate
where odp.Source in ('Vitality PHI','Bluedrop CIR')

Select
lgd.OwlASMUID2,
lgd.OwlASMName2,
uhau.BusinessUID,
cast(round(sum(ESMDue),2) as decimal(18,2)) as Amount,
Description,
lgd.Source,
CommissionMonth
into #ESMSummary
from #LGDetails lgd
join mi_insight_UserHierarchyAllUsers uhau on uhau.UserUID = lgd.OwlASMUID2 and LatestRowInd = 1
Group by lgd.OwlASMUID2, lgd.OwlASMName2,uhau.BusinessUID, Description, CommissionMonth, lgd.Source
Order by OwlASMName2


Select
--Source,
--CommissionMonth,
'0000049,'+BusinessUID+','+convert(varchar,GetDate(),103)+','+convert(varchar,Dateadd(day,2,GetDate()),103)+','+convert(varchar,Amount)+',6,'+Description as SODesc
from #ESMSummary
where CommissionMonth >= @Month
Order by Source, CommissionMonth

--Select * from #ESMSummary where CommissionMonth >= @Month

--Select * from #LGDetails where CommissionMonth >= @Month



Drop table #ESMSummary, #LGDetails



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

