/****** Object:  StoredProcedure [BI].[pr_149_PartnerRecognition]    Script Date: 7/3/2026 3:34:42 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_149_PartnerRecognition] 
Author	: J Homer
Date	: 26/09/2023

A report run by the Executive Assistant to the Executive Chairman and CEO to allow the business to recognise those partners
celebrating a significant anniversay with Openwork.  Significant Anniversaries begin with 10 years service and occur every
5 years thereafter.

This uses a simplified version of the Selling Headcount report with any elements not required for partner recognition, such 
as licence type, removed.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
29/08/2024	John Homer	Added in excluion clause to exclude 'Firms' set up as individuals

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_149_PartnerRecognition]

---DATE VARIABLE TO DETERMINE THE MONTH & YEAR THAT WE WANT TO SEE WHO HAS A SIGNIFICANT ANNIVERSARY.  VARIABLE TO SET BY USER VIA SSRS REPORT---
@Date as date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

set	@ReportName			= 'PartnerRecognition'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


DECLARE @Year AS Int, @Month AS INT

---MONTH AND YEAR VARIABLES DETERMINED BY @DATE VARIABLE.  **NOT USER DEFINED**---
SET @Year = YEAR(@Date)
SET @Month = Month(@Date)

---MAIN CODE TO BRING BACK LIST OF PARTNERS WITH SIGNIFICANT ANNIVERSARY---
SELECT	ah.AgentCode
		, LTRIM(RTRIM(ah.AgentDesc)) AgentName ---NAMES IN THE AGENTSHIERARCHY HAVE SUPERFLUOUS SPACES SO THEY NEED TO BE REMOVED---
		, ISNULL(s.STAF_KnownAs,LTRIM(RTRIM(ah.AgentDesc))) KnownAs ---INSIGHT HOLDS A FIELD CALLED 'ALIAS' AS SOME PARTNERS HAVE A NAME THEY PREFER TO BE KNOWN BY---
		, ah.AgentTypeDescription AgentType
		, ah.CompetentStatusDescription Status
		, ah.FirmDescn Firmname
		, @Year-YEAR(ah.AgentStartDate) Anniversary
		, CAST(DATEADD("YYYY",@Year-YEAR(ah.AgentStartDate), ah.AgentStartDate) AS DATE) AnniversaryDate ---AGENTSTARTDATE IS HELD AS DATETIME SO HERE WE MAKE SURE IT DISPLAYS AS JUST A DATE---
		, ins_con.CD_email ContactEmail --EMAIL TAKEN FROM THE INISGHT CONTACT DETAILS TABLE---

/*   IN THE EVENT THAT THERE ARE NO ACTIVE ADDRESSES ON INSIGHT, WE WILL TAKE THE CORRESPONDENCE ADDRESS FROM THE SWIFT CLIENT (MSIT_S_CLIENT) TABLE AND IF THAT IS NULL WE WILL TAKE THE ADDRESS 
	 FROM THE SWIFT AGENTS TABLE (MSTT_AGENTS). THE SWIFT ADDRESSES CONTAIN SUPERFLUOUS SPACES WHICH NEED TO BE REMOVED. THEY ALSO CONTAIN SPECIAL CHARACTERS SUCH AS TAB (9), NEW LINE/LINE BREAK (10)
	 AND CARRIAGE RETURN (13) WHICH CAUSE ISSUES WITH THE RESULTS SO ALSO NEED TO BE REMOVED. WE REPLACE THEM WITH ''
*/
		, ISNULL(addr.ADD_Line1,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrAddress1,ag.address1))), Char(9),''), Char(10),''), Char(13),''),'')) AddressLine1
		, ISNULL(addr.ADD_Line2,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrAddress2,ag.address2))), Char(9),''), Char(10),''), Char(13),''),'')) AddressLine2
		, ISNULL(addr.ADD_Line3,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrAddress3,ag.address3))), Char(9),''), Char(10),''), Char(13),''),'')) AddressLine3
		, ISNULL(addr.ADD_Line4,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrTown,ag.address4))), Char(9),''), Char(10),''), Char(13),''),'')) AddressLine4
		, ISNULL(addr.ADD_Line5,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrCounty,ag.address5))), Char(9),''), Char(10),''), Char(13),''),'')) AddressLine5
		, ISNULL(addr.ADD_Postcode,ISNULL(REPLACE(REPLACE(REPLACE(LTRIM(RTRIM(ISNULL(s_cl.CorrPostcode,ag.postcode))), Char(9),''), Char(10),''), Char(13),''),'')) Postcode
		, CD.Code_Description + ' Address' AddressType ---SHOW WHICH ADDRESS TYPE WE HAVE USED FROM INSIGHT--
FROM cscv_AgentsHierarchy ah LEFT JOIN 
	 dbo.sa_insight_UserDetails in_UD on (CASE WHEN USR_externalid = '0102' THEN '0000102' 
											   WHEN USR_externalid = '0132' THEN '0000132' 
											   WHEN USR_externalid = '0111' THEN '0000111'
											   ELSE USR_externalid 
										   END)  = ah.AgentCode LEFT JOIN
	 dbo.sa_insight_Staff S on s.STAF_UserID = in_UD.USR_ID LEFT JOIN
	 dbo.sa_insight_ContactDetails ins_con ON  ins_con.CD_ParentID = S.STAF_ID JOIN
	 dbo.mstt_Agents ag ON ag.CODE = ah.AgentCode LEFT JOIN 
	 dbo.mstt_Clients cl ON ah.AgentCode = cl.AgentCode JOIN 
	 dbo.msit_S_CLIENT s_cl on s_cl.CLIENT_NUM = cl.CLIENT_NUM LEFT JOIN
/*   INSIGHT HOLDS A NUMBER OF ADDRESSES FOR PARTNERS. THESE CAN BE MAIN, ALTERNATIVE, CORRESPONDENCE AND HOME.  CHECKED WITH JOANNE KNIGHT IN PROVIDER AND AGENY MANAGEMENT AND SHE
     CONFIRMED THAT IF CONTACTING PARTNERS WE SHOULD USE THE CORRESPONDENCE ADDRESS.  NOT ALL PARTNERS HAVE AN ACTIVE CORRESPONDENCE ADDRESS SO WHERE THAT IS THE CASE WE ARE USING
	 THE DEFAULT ADDRESS FROM INSIGHT. THE FOLLOWING SUB QUERY SELECTS ALL CORRESPONDENCE ADDRESSES THAT AREN'T THE DEFAULT ADDRESS. IT ORDERS THEM SO THAT WHERE THERE IS A CORRESPONDENCE 
	 ADDRESS THAT WILL BE ROW NUMBER 1 AND THE DEFAULT ADDRESS WILL ROW NUMBER 2. WHERE THERE IS NO CORRESPONDENCE ADDRESS, THE DEFAULT ADDRESS WILL BE ROW NUMBER 1.
*/
	 (SELECT *
	  FROM
		(
			SELECT	tt.*, 
					ROW_NUMBER() OVER (PARTITION BY tt.ADD_ParentID ORDER BY CASE WHEN tt.ADD_TYPE = 4 THEN 2 ELSE tt.Add_Type END DESC) ROW_Num ---SET A ROW NUMBER FOR EACH CLIENT ADDRESS AND MAKE
			FROM																																 ---ADD_TYPE 3 (CORRESPONDENCE) THE HIGHEST ADD-TYPE
				(Select * from 
								(select * from sa_Insight_Address addr 
								WHERE addr.ADD_DateTo IS NULL) t ---ADD_DATETO IS NULL = AN ACTIVE ADDRESS---
				WHERE t.ADD_Type = 3 AND t.ADD_Default = 0 ---ADD_TYPE 3 = CORRESPONDENCE & ADD_DEFAULT 0 = NOT DEFAULT---

				UNION ALL

				Select * from 
								(select * from sa_Insight_Address addr 
								where addr.ADD_DateTo IS NULL) t ---ADD_DATETO IS NULL = AN ACTIVE ADDRESS---
				WHERE t.ADD_Default = 1 ---ADD_DEFAULT 1 = IS DEFAULT---
				)tt
		)ttt
		WHERE ttt.ROW_Num = 1) addr ON addr.ADD_ParentID = s.STAF_ID LEFT JOIN
	 dbo.sa_Insight_CodeDescription CD ON CD.Code_Code = addr.ADD_Type AND CD.Code_CodeType = 58 

/*   THERE ARE A NUMBER OF ADVISER UIDS SET UP ON SWIFT THAT AREN'T REAL ADVISER RECORDS. THEY HAVE BEEN SET UP IN ERROR, ARE DUPLICATES, HAVE BEEN SET UP TO ALLOW
	 ACCESS TO OPENACCESS, ETC. THE REASONS FOR THESE CODES ARE LISTED AGAINST EACH ONE. THEY ALL NEED TO BE EXCLUDED FROM ANY HEADCOUNT RESULTS
*/
WHERE ah.AgentCode NOT IN(
'1005260', -- Pre-Appointment Business Not true Firm
'2001539', -- Duplicated
'1011607', -- OMS payments only
'1011608', -- OMS payments only
'1011609', -- Zurich Independent Wealth Limited OMS payments only
