)

/*   SOME ADVISER UIDS SET UP ON SWIFT AS SELLERS AREN'T ACTUALLY SELLING. THEY'VE BEEN SET UP FOR BUSINESS/COMMERCIAL REASONS AND ON INSIGHT HAVE BEEN 
	 SET UP WITH A DT30 - NON ADVISING INDIVIDUAL DEVELOPMENT TRACK. THESE ALSO NEED TO BE EXCLUDED FROM ANY RESULTS
*/
AND  ah.AgentCode NOT IN (SELECT UD.USR_ExternalID
						  FROM sa_Insight_UserTandCTrack  usrT JOIN 
							   sa_Insight_TandCTrack T ON T.TCT_ID = usrT.USRT_TrackID JOIN 
							   sa_Insight_UserDetails UD ON UD.USR_ID = usrT.USRT_UserID JOIN 
							   sa_Insight_CodeDescription CD ON CD.Code_Code = usrT.USRT_Status and CD.Code_CodeType = 507 LEFT JOIN
							   cscv_AgentsHierarchy ah on ah.AgentCode = UD.USR_ExternalID
						  WHERE usrT.USRT_TrackID = '44531ED2-0D60-4E44-8409-30CFFE257004' --DT30 Track in Insight---
						        AND usrT.USRT_Status = 1 AND ah.AgentTypeDescription <> 'Principal') 
AND @Year-YEAR(ah.AgentStartDate) IN (10,15,20,25,30,35,40,45,50,55,60,65,70) ---SIGNIFICANT ANNIVERSARY BEGINS AT 10 YEARS SERVICE AND OCCURS EVERY 5 YEARS THEREAFTER---
AND MONTH(ah.AgentStartdate) = @Month
AND ah.CompetentStatusDescription = 'Active' ---ONLY INCLUDE PARTNERS WHOSE STATUS IS ACTIVE---
AND ah.AgentTypeDescription IN ('Seller', 'Principal') ---ONLY LOOKING AT SELLERS AND PRINCIPALS WITHIN FIRMS---
AND ah.ASDCode NOT IN ('4005013','4021409') ---EXCLUDE OWL SELLERS AS WE ONLY WANT OPENWORK ADVISERS AT THIS POINT---
AND (ah.AgentDesc NOT LIKE '%Ltd%' AND ah.AgentDesc NOT LIKE '%Limited%')

ORDER BY @Year-YEAR(ah.AgentStartDate) ASC, ah.AgentStartdate ASC, ah.AgentDesc ---ORDER BY ANNIVERSAY, ANNIVERSARY DATE AND THEN AGENT NAME---


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
