/**********************************************************************************************
Name	: [BI].[pr_173_PennyGroupBuyOuts]
Author	: K Garcia
Date	: 30/05/2024

		PaymentsPending table used to look at payments for interest of The Penny Group buy outs
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_173_PennyGroupBuyOuts]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

@FirmName as varchar (200)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Declare @PaymentMonth date
Set @PaymentMonth = DATEADD(month, -12, getdate()) -- previous 12 months

SELECT [ID]
      ,[AGENT_CODE]
	  ,UserName
	  ,BusinessCompanyName AS FirmName
      ,[COMP_CODE]
      ,[AMOUNT]
      ,[CommissionType]
      ,[CommissionTypeDesc]
      ,[YTD]
      ,[STATEMENT]
      ,[PACC_ID]
      ,[AMOUNT_PAID]
      ,[DUE_DATE]
      ,[STATUS]
      ,[MEDONE]
      ,[Notes]
      ,[ContraID]
      ,[StandingOrderCode]
      ,[StandingOrderCodeDesc]
      ,[JournalEntryCode]
      ,[JournalEntryCodeDesc]
      ,[PaymentDueDate]
      ,[TransactionID]
      ,[TransactionDate]
      ,[PaymentBasis]
      ,[SubjectToVAT]
      ,[Authorised]
      ,[CreatedBy]
      ,[CreatedDate]
      ,[AuthorisedBy]
      ,[AuthorisedDate]
      ,[StandingOrderID]
      ,[BaseAmount]
      ,[UpliftAmount]
      ,[CreateDateTime]
      ,[TransAgentSplitHierarchyHistoryID]
      ,[StrategicAllianceAgentCode]
      ,[AccessAgentCode]
      ,[FranchiseAgentCode]
      ,[CompanyAgentCode]
      ,[OrganisationAgentCode]
      ,[DirectlyAuthorisedAgentCode]
      ,[Manager1Code]
      ,[Manager2Code]
      ,[Manager3Code]
      ,[Manager4Code]
      ,[AGENT_PERC]
      ,[FranchiseUpliftPercent]
      ,[CommissionMonth]
      ,[PolicyID]
      ,[CaseID]
      ,[ProviderRef]
      ,[FirstClientID] as SwiftClientID
      ,[SuspendCommInd]
      ,[TranProduct]
      ,[Firm]
	  ,[BACSDate]
      ,[ValidTASHH]
      ,[SR9Class]
      ,[FirmType]
      ,[DerivedAgentSplit]
      ,[DerivedMarginAmount]
  FROM [prod_zurich_openwork_datawarehouse].[dbo].[mstt_PaymentsPending] pp
  left join (select distinct UserUID, username, businesscompanyname from mi_insight_UserHierarchy) AgentHierarchy on AgentHierarchy.UserUID = pp.agent_code

  where DUE_DATE >= @PaymentMonth
  and BusinessCompanyName = @FirmName
  

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



