/**********************************************************************************************
Name	: [BI].[pr_174_FirmNameSelection]  
Author	: K Garcia
Date	: 30/05/2024

		Dinstinct list of firm names from user heirarchy
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
28/07/2025	KG			Added FirmUID
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_174_FirmNameSelection]  

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate



with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select distinct T2.AgentCode as FirmUID, T2.AgentDesc as  FirmName from owoa_sellerXref Xref
left join (select AgentDesc, AgentCode, ASDCode, CompetentStatus from cscv_AgentsHierarchy where AgentTypeDescription = 'Franchise'   ) T2 on xref.franchise = T2.AgentCode
where t2.AgentDesc is not null
and ASDCode <> '4021409'
and CompetentStatus = '1'

order by t2.AgentDesc
  

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



