SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_175_MissingUIDInSwift]
Author	: K Garcia
Date	: 05/06/2024

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
05/06/2024  K Garcia    Shows advisors with missing UIDs in Swift

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_175_MissingUIDInSwift]

@AgentUID as varchar (7)

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT DISTINCT 
agt.AGENT_CODE as AgentUID,
polm.PolicyRef ,
polm.CONT_NUM,
cl.FIRSTNAMES,
cl.NAME, 
pola.ServicingAgentCode,
polm.ProductCode,
polm.PLAN_CODE,
ccs.CalculationCode  
FROM
dbo.sa_swift_S_POLMAI polm
JOIN dbo.sa_swift_S_CLIENT cl ON polm.CLIENT_NUM = cl.CLIENT_NUM 
LEFT JOIN dbo.sa_swift_PolicyAgentsB30 pola ON pola.PolicyID = polm.POL_NUM 
INNER JOIN dbo.sa_swift_PolicyTransactions pt ON polm.POL_NUM = pt.PolicyID 
INNER JOIN dbo.sa_swift_S_AGTCOM agt ON agt.TransactionID = pt.ID 
INNER JOIN  dbo.sa_swift_CodeCommissionShape ccs ON pt.CodeCommissionShapeID = ccs.id 
WHERE 
agt.AGENT_CODE in (@AgentUID) --- SELECT ADVISER UID
ORDER BY
pola.ServicingAgentCode,
CL.NAME,
CL.FIRSTNAMES  


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



