		A version of the Finance report for R12 Trail but limited to Milecross
		and Milecross (Scotland) - 1004215 and 2014781, respectively
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
31/10/2025	J Homer		amend Branding to reflect the correct Firm based on where the adviser 
						was at the Create date of the policy or, where the create date is NULL,
						the Proposal date
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_180_IFRS_R12Trail - Milecross]


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

/***************************************************************************************
		CREATE TEMP TABLE FOR BRANDING
***************************************************************************************/
SELECT 								
			pol.POL_NUM,								
			CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'	
				 WHEN (ISNULL(uh.ADUID, uh2.ADUID) = '4021409' OR ISNULL(uh.ADUID, uh2.ADUID) = '4005013') AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'							
				 WHEN ISNULL(uh.BusinessUID, uh2.BusinessUID) = '2016789' OR ISNULL(uh.ADUID, uh2.ADUID) = '4019902' THEN 'Owl AR'							
				 ELSE 'Openwork'							
			END Brand,
			ISNULL(uh.BusinessUID, uh2.BusinessUID) BusinessUID
INTO		#UIDStaging								
FROM 
			mstt_policies pol								
			LEFT JOIN mstt_producthierarchy ph				ON ph.ProductCode			= pol.ProductCode 
																						  AND ph.RDRType IS NULL 
																						  AND ph.ProductGroupName != 'Mortgage'								
			LEFT JOIN mi_insight_UserHierarchyAllUsers uh	ON uh.UserUID				= pol.sellingagentcode	
																						  AND isnull(pol.createdate,pol.PROP_DATE) BETWEEN uh.EffectiveStartDate AND uh.EffectiveEndDate		
			LEFT JOIN mi_insight_UserHierarchy uh2			ON uh2.UserUID				= isnull(pol.sellingagentcode,pol.servicingagentcode)	
WHERE 
			ph.RDRType IS NULL 
			AND ph.ProductCategoryCode IN (1,4)								
GROUP BY 
			pol.POL_NUM,							
			CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'	
				 WHEN (ISNULL(uh.ADUID, uh2.ADUID) = '4021409' OR ISNULL(uh.ADUID, uh2.ADUID) = '4005013') AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'							
				 WHEN ISNULL(uh.BusinessUID, uh2.BusinessUID) = '2016789' OR ISNULL(uh.ADUID, uh2.ADUID) = '4019902' THEN 'Owl AR'							
				 ELSE 'Openwork'							
			END,							
			ISNULL(uh.BusinessUID, uh2.BusinessUID)	
/***************************************************************************************
		CREATE FINAL RESULTS, SUMMING AMOUNTS FOR RENEWALS, AND GROUPING BY PROVIDER, 
		PRODUCT, PROVIDER REF (POLICY NUMBER), DATE AND BRAND.  
***************************************************************************************/
SELECT
			--CASE WHEN st.BusinessUID IS NULL THEN ISNULL(pp.FranchiseAgentCode, pp.AGENT_CODE)
			--	 ELSE st.BusinessUID
			--END FirmUID,
			pp.COMP_CODE,
			pp.Tranproduct,
			pp.ProviderRef,
			CONVERT(DATE,pol.START_DATE,103) AS START_DATE,
			SUM(pp.amount) AS NetTrail,
			CASE WHEN st.Brand IS NULL THEN CASE WHEN pol.COMP_CODE LIKE '%Owl' THEN 'Owl'
												 ELSE 'Openwork'
											END
				 ELSE st.Brand
			END Brand
FROM
			mstt_Paymentspending pp
			JOIN mstt_policies pol		  on pol.POL_NUM		    = pp.PolicyID
			JOIN mstt_producthierarchy ph on ph.productcode			= pp.tranproduct 
																	  AND ph.rdrtype IS NULL
			LEFT JOIN #UIDStaging st		  on pol.POL_NUM			= st.POL_NUM
WHERE 
			pp.commissiontype IN (19,16,10) -- Adjustment Trail (19), Clawback Trail (16), Trail fee (10)
			AND CAST(pp.createdatetime AS date) >= CAST(DATEADD(YEAR,-1,GETDATE()) AS date)
			AND CASE WHEN st.BusinessUID IS NULL THEN ISNULL(pp.FranchiseAgentCode, pp.AGENT_CODE)
					 ELSE st.BusinessUID
				END IN ('1004215', '2014781')
GROUP BY
			--CASE WHEN st.BusinessUID IS NULL THEN ISNULL(pp.FranchiseAgentCode, pp.AGENT_CODE)
			--	 ELSE st.BusinessUID
			--END,
			pp.COMP_CODE,
			pp.Tranproduct,
			pp.ProviderRef,
			pol.START_DATE,
			CASE WHEN st.Brand IS NULL THEN CASE WHEN pol.COMP_CODE LIKE '%Owl' THEN 'Owl'
												 ELSE 'Openwork'
											END
				 ELSE st.Brand
			END

/****************************************************************************

	End Of Report
																	
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



