/**********************************************************************************************
Name	: [BI].[pr_183_Finstat5_MoniesInSuspense] 
Author	: K Garcia
Date	: 26/09/2025

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date			Author		Description
----			----		----

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_183_Finstat5_MoniesInSuspense] 

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

@Month  date

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
			

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Select 
datename(month,@Month) + ' ' + convert(varchar(4),datepart(year,@Month)) as FinancialPeriod,
PayType,
Statement,
mis.StatementDate,
case when Statement = 135577 then 'METLIFE' when Statement = 135984 then 'PRU' else (case when COMP_CODE is null then 'Scot Eq' else COMP_CODE end) end as COMP_CODE,
ProductCode,
RecAmt,
isnull(cm.Margin1, 0) as Margin,
case when RecAmt > 0 then RecAmt else 0 end as GrossDA,
case when RecAmt < 0 then RecAmt else 0 end as ClawbackDA,
case when RecAmt > 0 then RecAmt*(1-isnull(cm.Margin1, 1)) else 0 end as GrossComm,
case when RecAmt < 0 then RecAmt*(1-isnull(cm.Margin1, 1)) else 0 end as ClawbackComm,
Case when COMP_CODE in ('Zurich New', 'Zurich Pnl') then 'PROTECTION' when (COMP_CODE = 'Zurich Leg' or Statement in (137012, 139395, 136807)) then 'PENSIONS' 
	 when (COMP_CODE = 'ZURICH PLT' or Statement = 135984) then 'INVESTMENT' else (case when ProductCode is null then COMP_CODE else ProductCode end) end as ProductLookup,
(case when Statement = 135577 then 'METLIFE' when Statement = 135984 then 'PRU' else (case when COMP_CODE is null then 'Scot Eq' else COMP_CODE end) end) + ' ' +
(Case when COMP_CODE in ('Zurich New', 'Zurich Pnl') then 'PROTECTION' when (COMP_CODE = 'Zurich Leg' or Statement in (137012, 139395, 136807)) then 'PENSIONS' 
	 when (COMP_CODE = 'ZURICH PLT' or Statement = 135984) then 'INVESTMENT' else (case when ProductCode is null then COMP_CODE else ProductCode end) end) as Summary
from owt_Finance_MoniesInSuspense mis
left join logi.Finance_ConfigMargins cm on cm.ProviderCode = case when Statement = 135577 then 'METLIFE' when Statement = 135984 then 'PRU' else (case when COMP_CODE is null then 'Scot Eq' else COMP_CODE end) end
and Case when Statement = 116939 then '24-Jul-2012' when statement = 135577 then '28-Mar-2013' when Statement = 135984 then '04-04-2013'
	 when Statement in (136805,136807) then '12-Apr-2013' when Statement = 137012 then '16-Apr-2013' when Statement in (139395,139396) then '10-May-2013' 
	 when Statement = 139416 then '13-May-2013' else StatementDate end between cm.EffectiveStartDate and cm.EffectiveEndDate
where @Month between FinancialPeriodFromDate and FinancialPeriodToDate



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



