/**********************************************************************************************
Name	: [BI].[pr_185_finstats55New] 
Author	: J Homer
Date	: 23/10/2025

On the 1st of the month there is an automated run of the Finstat Reports, which support the Financial Reporting Team in their monthly reporting.

This is a new version of Finstat55 which alloctaes teh branding based on where the adviser was at the IRD date
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_185_finstats55New]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
		Select 	isnull(left(convert(varchar(20),IRD, 112),4),'') as IRDYear,
		isnull(left(convert(varchar(20),IRD, 110),2),'') as IRDMonth,
		Provider,
		sh.description as CommissionShape,
		Product,
		SUM(FinStatTot1inPeriod) as FinStatTot1inPeriod
		,case when (isnull(uh.ADUID,'111') = '4021409' or isnull(uh.ADUID,'111') = '4005013') and Product like '%Owl' then 'Owl' 
		      when (isnull(uh.ADUID,'111') = '4021409' or isnull(uh.ADUID,'111') = '4005013') then 'Owl Panel' 
			  when isnull(uh.BusinessUID, '111') = '2016789' or isnull(uh.ADUID,'111') = '4019902' then 'Owl AR' else 'Openwork' end as AdviserType
from	owhot_FinanceFutureExpectations fe
		left outer join mstt_ProductHierarchy ph on fe.product = ph.productcode 
		left outer join msit_CodeCommissionShape sh  on sh.id = fe.shapeid
		left join mstt_policytransactions pt on pt.id = tranid
		LEFT JOIN mi_insight_UserHierarchyAllUsers uh	ON uh.UserUID = pt.agentcode	
																		AND fe.IRD BETWEEN uh.EffectiveStartDate AND uh.EffectiveEndDate
		--left join mstt_agents agt on agt.code = pt.agentcode
where	basis = 'IT'
and		isnull(fe.IRD,'') <> ''
Group by	isnull(left(convert(varchar(20),IRD,112),4),''), 
			isnull(left(convert(varchar(20),IRD, 110),2),''), 
			Provider, 
			sh.description, 
			Product,
			case when (isnull(uh.ADUID,'111') = '4021409' or isnull(uh.ADUID,'111') = '4005013') and Product like '%Owl' then 'Owl' 
		      when (isnull(uh.ADUID,'111') = '4021409' or isnull(uh.ADUID,'111') = '4005013') then 'Owl Panel' 
			  when isnull(uh.BusinessUID, '111') = '2016789' or isnull(uh.ADUID,'111') = '4019902' then 'Owl AR' else 'Openwork' end

