/****** Object:  StoredProcedure [BI].[pr_190_IFRSFutureRenewalsNew]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_190_IFRSFutureRenewalsNew] 
Author	: J Homer
Date	: 24/10/2025

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_190_IFRSFutureRenewalsNew]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

DECLARE
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date

/***************************************************************************************
		DROP TABLES
***************************************************************************************/
DROP TABLE IF EXISTS  #TransType, #Staging

/***************************************************************************************
		SET VARIABLES
***************************************************************************************/
SET			@EndDate = DATEADD(MONTH, DATEDIFF(MONTH, -1, GETDATE())-1, -1) --Last Day of previous month

/***************************************************************************************
		CREATE TEMP TABLE FOR TRANSACTIONS
***************************************************************************************/

SELECT
			policyid,
			amount,
			comminitialperiod,
			pt.WrittenDate,
			pt.CreatedDate,
			pt.CreateDateTime,
			pt.AgentCode
INTO
			#TransType
FROM 
			mstt_policytransactions pt 
WHERE 
			pt.transtype NOT IN (117,39) 
			AND isnull(pt.CreateDateTime,pt.CreatedDate) < @EndDate
			AND id = (SELECT 
								min(id) 
					  FROM
								mstt_policytransactions pt2 
					  WHERE		pt2.PolicyID = pt.policyid 
								AND pt2.TransType NOT IN (117,39))

/***************************************************************************************
		CREATE TEMP TABLE AT A POLICY ID LEVEL, BY AGENT, ASSIGNING THE CORRECT
		BRAND TO EACH TRANSACTION BASED ON CREATEDATETIME AND USER HIERARCHY EFFECTIVE
		DATE FROM
***************************************************************************************/

SELECT 
			ISNULL(tt.AgentCode,ISNULL(pol.SellingAgentCode,pol.ServicingAgentCode)) Agent,
			uh.BusinessUID Firm,
			pol.COMP_CODE,
			YEAR(tt.writtendate) Year,
			MONTH(tt.writtendate)Month,
			tt.amount Premium,
			tt.policyid PolicyCount,
			--CASE WHEN comp_code like '%Owl' THEN 'Owl'
			--	 WHEN agt.manager2code = '1011671' AND COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'
			--	 WHEN agt.firm = '2016789' THEN 'Owl AR' --OLD CODE ONLY IDENTIFIED KALON (2016789) AS OWL AR
			--	 ELSE 'Openwork' 
			--END
			CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'
				 WHEN ISNULL(uh.ADUID,CASE WHEN uh.OwlASMUID1 IS NOT NULL THEN '4021409' ELSE '1'END) IN ('4021409', '4005013') -- Owl Sales Director and Pat Mckenna
				 AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'
				 WHEN uh.BusinessUID = '2016789' OR uh.ADUID = '4019902' THEN 'Owl AR'
				 ELSE 'Openwork'
			END Brand
INTO 
			#Staging
FROM 
			mstt_policies pol
			JOIN mstt_producthierarchy ph ON ph.ProductCode = pol.ProductCode AND ph.RDRType IS NULL AND ph.ProductGroupName != 'Mortgage'
			JOIN #transtype tt ON tt.PolicyID = pol.POL_NUM
			LEFT JOIN mi_insight_UserHierarchyAllUsers uh ON uh.UserUID = ISNULL(tt.AgentCode,ISNULL(pol.SellingAgentCode,pol.ServicingAgentCode)) AND CAST(ISNULL(tt.CreateDateTime, tt.CreatedDate) AS DATE) BETWEEN uh.EffectiveStartDate AND uh.EffectiveEndDate 
			LEFT JOIN (	SELECT DISTINCT UserUID 
						FROM mi_insight_UserHierarchyAllUsers
						 WHERE ADUID = '4021409'
					  ) AS uhOwl 
							ON uhOwl.UserUID = ISNULL(tt.AgentCode,ISNULL(pol.SellingAgentCode,pol.ServicingAgentCode))
WHERE 
			writtendate <= @EndDate AND DATEADD(MONTH,tt.CommInitialPeriod,createdate) > @EndDate
			AND pol.COMP_CODE IS NOT NULL
GROUP BY
			ISNULL(tt.AgentCode,ISNULL(pol.SellingAgentCode,pol.ServicingAgentCode)),
			uh.BusinessUID,
			pol.COMP_CODE,
			YEAR(tt.writtendate),
			MONTH(tt.writtendate),
			tt.amount,
			tt.policyid,
			CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'
				 WHEN ISNULL(uh.ADUID,CASE WHEN uh.OwlASMUID1 IS NOT NULL THEN '4021409' ELSE '1'END) IN ('4021409', '4005013') -- Owl Sales Director and Pat Mckenna
				 AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'
				 WHEN uh.BusinessUID = '2016789' OR uh.ADUID = '4019902' THEN 'Owl AR'
				 ELSE 'Openwork'
			END

/***************************************************************************************
		CREATE FINAL RESULTS, SUMMING PREMIUM AMOUNTS, COUNTING POLICY ID's AND
		GROUPING BY PROVIDER, BRAND, YEAR AND MONTH.  
		
		OUTPUT ORDERED BY PROVIDER (ASC), fIRM (ASC) THEN YEAR (ASC), MONTH (ASC) 
		AND BRAND (ASC)
***************************************************************************************/

SELECT 
			Firm,
			Comp_Code,
			Year,
			Month,
			SUM(Premium) as Premium,
			COUNT(PolicyCount) as PolicyCount,
			Brand
FROM
			#Staging
GROUP BY 
			Firm,
			Comp_Code,
			Year,
			Month,
			Brand
ORDER BY
			Comp_Code ASC,
			Firm ASC, 
			Year ASC,
			Month ASC,
			Brand ASC


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_191_RenewalAndTrailBreakdownNew]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_191_RenewalAndTrailBreakdownNew] 
Author	: J Homer
Date	: 24/10/2025

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_191_RenewalAndTrailBreakdownNew]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

DECLARE
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@EndDate				date,
			@Year					int

/***************************************************************************************
		DROP TABLES
***************************************************************************************/
DROP TABLE IF EXISTS  #Policies, #Staging

/***************************************************************************************
		SET VARIABLES
***************************************************************************************/
Set			@Year = YEAR(GETDATE())	
/***************************************************************************************
		CREATE TEMP TABLE FOR TRANSACTIONS
***************************************************************************************/

---Create Panel Banding Date Ranges #Staging					
					
					
SELECT 					
pol.POL_NUM,					
CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'					
	 WHEN (uh.ADUID = '4021409' OR uh.ADUID = '4005013') AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'				
	 WHEN uh.BusinessUID = '2016789' OR uh.ADUID = '4019902' THEN 'Owl AR'				
	 ELSE 'Openwork'				
		END Brand,			
year(isnull(createdate,pol.PROP_DATE)) as Year					
					
INTO #Staging					
FROM mstt_policies pol					
 JOIN mstt_producthierarchy ph ON ph.ProductCode = pol.ProductCode AND ph.RDRType IS NULL AND ph.ProductGroupName != 'Mortgage'					
 LEFT JOIN mi_insight_UserHierarchyAllUsers uh ON uh.UserUID = isnull(pol.sellingagentcode,pol.servicingagentcode)	AND isnull(pol.createdate,pol.PROP_DATE) BETWEEN uh.EffectiveStartDate AND uh.EffectiveEndDate 				
WHERE ph.RDRType is null and ph.ProductCategoryCode in (1,4)					
	GROUP BY pol.POL_NUM,				
CASE WHEN pol.comp_code LIKE '%Owl' THEN 'Owl'					
	 WHEN (uh.ADUID = '4021409' OR uh.ADUID = '4005013') AND pol.COMP_CODE NOT LIKE '%Owl' THEN 'Owl Panel'				
	 WHEN uh.BusinessUID = '2016789' OR uh.ADUID = '4019902' THEN 'Owl AR'				
	 ELSE 'Openwork'END,				
				year(isnull(createdate,pol.PROP_DATE))	
					
--------------------					
					
Select					
count(distinct case when st.Brand = 'Owl' then  pol.POL_NUM end) as NumberOfOwlPolicies,					
count(distinct case when st.Brand = 'Owl Panel' AND ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfOwlPanelPolicies,					
count(distinct case when st.Brand = 'Owl AR' AND ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfOwlARPolicies,					
count(distinct case when st.Brand = 'Openwork' and ph.ProductCategoryCode = 4 then  pol.POL_NUM end) as NumberOfProtectionPolicies,					
count(distinct case when ph.ProductCategoryCode = 1  then  pol.POL_NUM end) as NumberOfPreRDRWealthPolicies,					
year(isnull(createdate,pol.PROP_DATE))  as PolicyYear					
into #Policies					
From mstt_policies pol					
join mstt_producthierarchy ph on ph.productcode = pol.ProductCode					
JOIN #Staging st on pol.POL_NUM = st.POL_NUM					
Group by					
year(isnull(createdate,pol.PROP_DATE)) 					
					
					
Select year(createdatetime) as PaymentYear, 					
st.Year as PolicyYear,					
count(distinct case when st.Brand = 'Owl' then  st.POL_NUM end) as NumberOfCasesOwl,					
count(distinct case when st.Brand = 'Owl Panel' and ph.ProductCategoryCode = 4 then st.POL_NUM end) as NumberOfCasesOwlPanel,					
count(distinct case when st.Brand = 'Owl AR' and ph.ProductCategoryCode = 4 then st.POL_NUM end) as NumberOfCasesOwlAR,					
count(distinct case when st.Brand = 'Openwork' and ph.ProductCategoryCode = 4 then st.POL_NUM end) as NumberOfCasesOW,					
count(distinct case when ph.ProductCategoryCode = 1 and pp.CommissionType in (18,15,4) then st.POL_NUM end) as NumberOfCasesWealthRenewal,					
count(distinct case when ph.ProductCategoryCode = 1 and pp.CommissionType in (19,16,10) then st.POL_NUM end) as NumberOfCasesWealthTrail,					
sum( case when st.Brand = 'Owl' then  amount end) as RenewalAmountOwl,					
sum( case when st.Brand = 'Owl Panel' and ph.ProductCategoryCode = 4 then  Amount end) as RenewalAmountOwlPanel,					
sum( case when st.Brand = 'Owl AR' and ph.ProductCategoryCode = 4 then  Amount end) as RenewalAmountOwlAR,					
sum( case when st.Brand = 'Openwork' and ph.ProductCategoryCode = 4 then  Amount end) as RenewalAmountOW,					
sum( case when ph.ProductCategoryCode = 1 and pp.CommissionType in (18,15,4) then  Amount end) as RenewalAmountWealth,					
sum( case when ph.ProductCategoryCode = 1 and pp.CommissionType in (19,16,10) then  Amount end) as TrailAmount,					
poli.NumberOfPreRDRWealthPolicies,					
poli.NumberOfProtectionPolicies,					
poli.NumberOfOwlPolicies,					
poli.NumberOfOwlPanelPolicies,					
poli.NumberOfOwlARPolicies					
from mstt_paymentspending pp					
join #Staging st on st.POL_NUM = pp.PolicyID					
join mstt_producthierarchy ph on ph.productcode = pp.TranProduct					
join #Policies poli on poli.PolicyYear = st.Year					
					
where 					
ph.RDRType is null and ph.ProductCategoryCode in (1,4)					
--and pol.CONT_NUM = '899506J'					
and pp.CommissionType in (18,15,4,19,16,10)					
and year(createdatetime) >= @Year					
--and year(createdatetime) < 2019					
group by year(createdatetime), st.Year ,					
poli.NumberOfPreRDRWealthPolicies,					
poli.NumberOfProtectionPolicies,					
poli.NumberOfOwlPolicies,					
poli.NumberOfOwlARPolicies,					
poli.NumberOfOwlPanelPolicies


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



