			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_192_Owl_UnlicencedSales]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_192_Owl_UnlicencedSales] 
Author	: J Homer
Date	: 28/10/2025

Description:	This procedure reports on unlicenced sales within Owl Financial.  Typically there may only be
				1 per month on average.  The requirement stems from the fact that all the
				licences on Swift have been allowed to lapse as of 31/03/2011 which has
				introduced the need to report from Insight data.

				Note that Insight only receives data from OBP when the OBP Opportunity 
				Completed indicator has been checked.  There is the potential for an 
				integrity gap here as the adviser may or or may not check this indicator
				as it doesn't affect payment to them.

				The dependencies on when this report can run are as follows:
				1) After proc "pr_etl_mi_insight_BasicPolicyHistory" has run

				The report parameters are as follows:
				1) Report Start Date - This is the case creation date from which cases will be included for reporting
				2) Report End Date - This is the latest case creation date of cases to be included for reporting 

					

PREVOUS (LOGI) AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
06/05/2016	A Groves	SR424336. Remove the time element from the submission dates as this is causing
						submissions on the day that the licence expires to be considered an unlicenced 
						sale.
10/06/2016	A Groves	CH12709 New product type 59 introduced. Removed product type hardcoding.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_192_Owl_UnlicencedSales]

			@ReportStartDateDtTm	datetime,
			@ReportEndDateDtTm		datetime

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@LicenceCheckStartDate	datetime
			

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Owl Unlicensed Sales'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


/****************************************************************************

	Don't check cases before the oldest Owl licence was created because they
	will all appear to be unlicenced sales and it creates a large volume
	of data that makes the report slow																															

****************************************************************************/


--select	@LicenceCheckStartDate	= '2014-11-01'	-- Date when Metlife Sales Force became Owl Financial

select	@LicenceCheckStartDate = MIN(ul.ULIC_ValidFrom)
from	logi.f_Insight_OwlProductTypeToLicenceCode('2014-11-01') config
		inner join sa_insight_Licence l on l.LIC_Code = config.LicenceCode
		inner join sa_insight_UserLicence ul on l.LIC_ID = ul.ULIC_LicenceID
where	l.LIC_Code not in ('LIC1','LIC3')	-- Exclude these because these are Openwork licences and therefore old


/****************************************************************************

	There is a long standing issue whereby rows on the SalesCase and 
	BasicPolicy tables are duplicated. This is probably due to the adviser 
	pressing the submit multiple times before OWS disables the submit.  
	Therefore dedupe the cases.
																		
****************************************************************************/


select	sc.CASE_CaseReference, bp.BPOL_BackOfficeID, bp.BPOL_ProductType, min(sc.CASE_CreatedDate) as MinCASE_CreatedDate
into	#EarliestCase
from	sa_insight_SalesCase sc
		inner join sa_insight_BasicPolicy bp on bp.BPOL_ParentID = sc.CASE_ID 
		inner join sa_insight_UserDetails ud on ud.USR_ID = sc.CASE_AdviserID	--AG 10/06/2016
		inner join owv_AdviserBrand ab on ab.UserUID = ud.USR_ExternalID		--AG 10/06/2016
where	ab.Brand = 'Owl'														--AG 10/06/2016
--and		bp.BPOL_ProductType in (56,57)			-- 56=ACCIDENT PROTECTION; 57=ICOB Owl	AG 10/06/2016
and		isnumeric(bp.BPOL_BackOfficeID) = 1		-- Must have a proper case ref
and		sc.CASE_SubmitDate between @ReportStartDateDtTm and @ReportEndDateDtTm
--and		sc.CASE_SubmitDate between '2014-06-01' and '2015-06-29'
group	by sc.CASE_CaseReference, bp.BPOL_BackOfficeID, bp.BPOL_ProductType 


/****************************************************************************

	Select the earliest BPOL row for duplicating BPOL rows to ensure this
	is used for deriving the Submission Date.
																		
****************************************************************************/


select	BPDeduped.BPOL_ParentID, 
		BPDeduped.BPOL_BackOfficeID, 
		BPDeduped.EarliestBPOLCreatedDate, 
		bp.BPOL_ProductType
into	#EarliestBPOL
from	#EarliestCase ec
		inner join sa_insight_SalesCase sc 
					on sc.Case_CaseReference = ec.Case_CaseReference
					and sc.CASE_CreatedDate = ec.MinCASE_CreatedDate
		inner join sa_insight_BasicPolicy bp 
					on bp.BPOL_ParentID = sc.CASE_ID
					and bp.BPOL_BackOfficeID = ec.BPOL_BackOfficeID
					and bp.BPOL_ProductType = ec.BPOL_ProductType
		inner join (
					select	BPOL_ParentID, BPOL_BackOfficeID, BPOL_ProductType, min(BPOL_CreatedDate) as EarliestBPOLCreatedDate
					from	sa_insight_SalesCase sc
							inner join sa_insight_BasicPolicy bp on bp.BPOL_ParentID = sc.CASE_ID
							inner join sa_insight_UserDetails ud on ud.USR_ID = sc.CASE_AdviserID	--AG 10/06/2016
							inner join owv_AdviserBrand ab on ab.UserUID = ud.USR_ExternalID		--AG 10/06/2016
					where	ab.Brand = 'Owl'														--AG 10/06/2016
					and		isnumeric(BPOL_BackOfficeID) = 1	-- Must have a proper case ref
					--and		BPOL_ProductType in (56,57)			-- 56=ACCIDENT PROTECTION; 57=ICOB Owl	AG 10/06/2016
					and		sc.CASE_SubmitDate between @ReportStartDateDtTm and @ReportEndDateDtTm
					--and		sc.CASE_SubmitDate between '2014-06-01' and '2015-06-29'
					group	by BPOL_ParentID, BPOL_BackOfficeID, BPOL_ProductType
					) BPDeduped
								on	bp.BPOL_ParentID = BPDeduped.BPOL_ParentID
								and bp.BPOL_BackOfficeID = BPDeduped.BPOL_BackOfficeID 
								and bp.BPOL_ProductType = BPDeduped.BPOL_ProductType 
								and bp.BPOL_CreatedDate = BPDeduped.EarliestBPOLCreatedDate


/****************************************************************************

	Select the most recent and penultimate BPOL rows to check if ProductType 
	has changed.																
																		
****************************************************************************/


-- Get latest BPOL row in the reporting period

select	Hist.BPOL_ParentID, Hist.BPOL_BackOfficeID, Hist.BPOL_ProductType, Hist.BPOL_ID, max(Hist.UniqueId) as LatestUniqueID
into	#CurrentBPOL
from	mi_insight_BasicPolicyHistory Hist
		inner join sa_insight_SalesCase sc on sc.CASE_ID = Hist.BPOL_ParentID	--AG 10/06/2016 
		inner join sa_insight_UserDetails ud on ud.USR_ID = sc.CASE_AdviserID	--AG 10/06/2016
		inner join owv_AdviserBrand ab on ab.UserUID = ud.USR_ExternalID		--AG 10/06/2016
where	ab.Brand = 'Owl'														--AG 10/06/2016
and		Action <> 'DEL'
and		dateadd(dd,0,datediff(dd,0,Hist.BPOL_UpdatedDate)) between @ReportStartDateDtTm and @ReportEndDateDtTm
--and		dateadd(dd,0,datediff(dd,0,Hist.BPOL_UpdatedDate)) between '2014-06-01' and '2015-06-29'
and		isnumeric(Hist.BPOL_BackOfficeID) = 1	-- Must have a proper case ref
and		Hist.BPOL_BackOfficeID <> '0'			-- Unwanted DUPLICATE setting
--and		Hist.BPOL_ProductType in (56,57)		-- 57=ICOB Owl; 56=ACCIDENT PROTECTION	AG 10/06/2016
group	by Hist.BPOL_ParentID, Hist.BPOL_BackOfficeID, Hist.BPOL_ProductType, Hist.BPOL_ID


-- Get penultimate BPOL row (if there is one) for the reporting period

select	Hist.BPOL_ParentID, Hist.BPOL_BackOfficeID, Hist.BPOL_ProductType, Hist.BPOL_ID, max(Hist.UniqueId) as PenultimateUniqueID
into	#PreviousBPOL
from	#CurrentBPOL Curr
		inner join mi_insight_BasicPolicyHistory Hist 
					on  Hist.BPOL_ParentID = Curr.BPOL_ParentID 
					and Hist.BPOL_BackOfficeID = Curr.BPOL_BackOfficeID
					and Hist.BPOL_ProductType = Curr.BPOL_ProductType
					and Hist.BPOL_ID = Curr.BPOL_ID
		inner join sa_insight_SalesCase sc on sc.CASE_ID = Hist.BPOL_ParentID	--AG 10/06/2016 
		inner join sa_insight_UserDetails ud on ud.USR_ID = sc.CASE_AdviserID	--AG 10/06/2016
		inner join owv_AdviserBrand ab on ab.UserUID = ud.USR_ExternalID		--AG 10/06/2016
where	ab.Brand = 'Owl'														--AG 10/06/2016
and		Hist.UniqueId < Curr.LatestUniqueId
and		Hist.Action <> 'DEL'
--and		Hist.BPOL_ProductType in (56,57)		-- 57=ICOB Owl; 56=ACCIDENT PROTECTION	AG 10/06/2016
group	by Hist.BPOL_ParentID, Hist.BPOL_BackOfficeID, Hist.BPOL_ProductType, Hist.BPOL_ID


/****************************************************************************
	Select cases in scope for checking																															
****************************************************************************/


-- Select the case creation or basic policy creation date whichever is latest and within reporting period
-- Note that a case could have multiple policies so take the highest date spanning all the case's policies
select	ins_sc.CASE_ID,
		max(case when Earliest_bp.BPOL_ParentID is null then 'N' else 'Y' end) as LinkedPolicyYN,
		max(case when ins_bp.BPOL_CreatedDate > ins_sc.CASE_CreatedDate then ins_bp.BPOL_CreatedDate else ins_sc.CASE_CreatedDate end) as CaseReportingDate,
		convert(varchar(50),'Within Reporting Period') as ScopeReason
into	#CasesInScope
from	sa_insight_SalesCase ins_sc
		left join #EarliestBPOL Earliest_bp on Earliest_bp.BPOL_ParentID = ins_sc.CASE_ID 
		left join sa_insight_BasicPolicy ins_bp 
					on  ins_bp.BPOL_ParentID = Earliest_bp.BPOL_ParentID 
					and ins_bp.BPOL_BackOfficeID = Earliest_bp.BPOL_BackOfficeID
					and ins_bp.BPOL_ProductType = Earliest_bp.BPOL_ProductType
					and ins_bp.BPOL_CreatedDate = Earliest_bp.EarliestBPOLCreatedDate
		left join sa_insight_SalesCase sc on sc.CASE_ID = ins_bp.BPOL_ParentID	--AG 10/06/2016 
		left join sa_insight_UserDetails ud on ud.USR_ID = sc.CASE_AdviserID	--AG 10/06/2016
		left join owv_AdviserBrand ab on ab.UserUID = ud.USR_ExternalID			--AG 10/06/2016
where	isnull(ab.Brand,'') = 'Owl'												--AG 10/06/2016
--and		isnull(ins_bp.BPOL_ProductType,0) in (56,57)	-- 57=ICOB Owl; 56=ACCIDENT PROTECTION	AG 10/06/2016
and		ins_sc.CASE_CaseReference <> '0'				-- Unwanted DUPLICATE setting (case opportunity reference)
and		isnull(ins_bp.BPOL_BackOfficeID,'') <> '0'		-- Unwanted DUPLICATE setting	
and		ins_sc.CASE_SubmitDate between @ReportStartDateDtTm and @ReportEndDateDtTm
--and		ins_sc.CASE_SubmitDate between '2014-06-01' and '2015-06-29'
group	by ins_sc.CASE_ID

union

-- Select the last updated date from the basic policy table where the update occurred in the reporting period and the product changed
select	ins_sc.CASE_ID,
		'Y' as LinkedPolicyYN,
		curr_hist.BPOL_UpdatedDate as CaseReportingDate,
		convert(varchar(50),'Product Change') as ScopeReason
from	sa_insight_SalesCase ins_sc
		inner join #CurrentBPOL Curr on Curr.BPOL_ParentID = ins_sc.CASE_ID
		inner join #PreviousBPOL Prev 
					on  Prev.BPOL_ParentID = Curr.BPOL_ParentID
					and Prev.BPOL_BackOfficeID = Curr.BPOL_BackOfficeID
					and Prev.BPOL_ProductType = Curr.BPOL_ProductType
					and Prev.BPOL_ID = Curr.BPOL_ID
		inner join mi_insight_BasicPolicyHistory curr_hist on curr_hist.UniqueId = Curr.LatestUniqueID 
		inner join mi_insight_BasicPolicyHistory prev_hist on prev_hist.UniqueId = Prev.PenultimateUniqueID 		
where	prev_hist.BPOL_ProductType <> curr_hist.BPOL_ProductType


/****************************************************************************

	Identify licence check date for each policy within each case in scope 
	for checking.	
																		
****************************************************************************/


select	ins_sc.CASE_ID,
		ins_sc.CASE_CaseReference,		
		Earliest_bp.BPOL_ProductType,	
		ins_sc.CASE_CreatedDate,		
		ins_sc.CASE_AdviserID,
		Earliest_bp.BPOL_BackOfficeID,
		ins_bp.BPOL_ID,					
		pol.POL_NUM,					
		CasesInScope.LinkedPolicyYN,	
		CasesInScope.CaseReportingDate,	
		(select	max(RegulationGroupCode)
		 from	logi.f_Insight_OwlProductTypeToLicenceCode(ins_sc.CASE_SubmitDate)
		 where	InsightProductTypeCode = Earliest_bp.BPOL_ProductType) as PrimaryRegulationGroupCode,
--		coalesce(s.DateSubmitted, pol.Prop_Date, ins_sc.CASE_CreatedDate) as LicenceCheckDate,																   AG 06/05/2016
		coalesce(dateadd(dd,0,datediff(dd,0,s.DateSubmitted)), pol.Prop_Date, dateadd(dd,0,datediff(dd,0,ins_sc.CASE_CreatedDate))) as LicenceCheckDate,	-- AG 06/05/2016
		case when s.DateSubmitted is not null then 'OWSSubDate'
			 when pol.Prop_Date is not null then 'SwiftPropDate'
			 else 'CaseCreateDate' 
		end as LicenceCheckDateSource,
		CasesInScope.ScopeReason
into	#PolicyLicenceCheckDate
from	#CasesInScope CasesInScope 
		inner join sa_insight_SalesCase ins_sc on ins_sc.CASE_ID = CasesInScope.CASE_ID
		left join #EarliestBPOL Earliest_bp on Earliest_bp.BPOL_ParentID = ins_sc.CASE_ID 
		left join sa_insight_BasicPolicy ins_bp 
					on  ins_bp.BPOL_ParentID = Earliest_bp.BPOL_ParentID 
					and ins_bp.BPOL_BackOfficeID = Earliest_bp.BPOL_BackOfficeID
					and ins_bp.BPOL_ProductType = Earliest_bp.BPOL_ProductType
					and ins_bp.BPOL_CreatedDate = Earliest_bp.EarliestBPOLCreatedDate
		left join sa_ows_Policies p on p.PolicyID = case when isnumeric(ins_bp.BPOL_BackOfficeID) = 1 then ins_bp.BPOL_BackOfficeID else 0 end			
		left join sa_ows_Sale s on s.SaleID = p.SaleID																									
		left join mstt_Policies pol on pol.PolicyRef = case when isnumeric(ins_bp.BPOL_BackOfficeID) = 1 then ins_bp.BPOL_BackOfficeID else 0 end		
--where	ins_sc.CASE_SubmitDate >= '2015-06-05'								
where	ins_sc.CASE_SubmitDate >= @LicenceCheckStartDate		


--select * from #PolicyLicenceCheckDate
/****************************************************************************

	Derive SellerLicencesInScope from CasesInScope and attach to them all the 
	"Granted" licences that they have ever had
																		
****************************************************************************/


-- Note that we need to use distinct otherwise we will duplicate the number
-- of licences held for the number of cases in scope - and we want the licence 
-- set only once.
select	distinct ins_sc.CASE_AdviserID, Lic.LIC_Code, UL.ULIC_ValidFrom, 
		-- If cancelled or suspended, take the older of Last Updated or Valid To
		case when UL.ULIC_UpdatedDate < UL.ULIC_ValidTo and UL.ULIC_Status in (3,4) then UL.ULIC_UpdatedDate else UL.ULIC_ValidTo end as ULIC_ValidTo	
into	#SellerLicencesInScope
from	#CasesInScope CasesInScope
		inner join sa_insight_SalesCase ins_sc on ins_sc.CASE_ID = CasesInScope.CASE_ID
		inner join sa_insight_UserLicence UL on UL.ULIC_UserID = ins_sc.CASE_AdviserID
		inner join sa_insight_Licence Lic on Lic.LIC_ID = UL.ULIC_LicenceID
where	UL.ULIC_Status in (2,3,4)		-- Licence 2="Granted";3="Cancelled";4="Suspended".	
/*
-- !!!!!!! TEMP TO EXCLUDE SUSPENDED ADVISERS !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
and		ins_sc.CASE_AdviserID not in 
			(select USR_ID 
			 from sa_insight_UserDetails
			 where USR_ExternalID in ('4005804','4005134','4005701','4005304','4005268','4005971',
			 '4005856','4005614','4005841','4005578','4006130','4005901','4005617','4005911'))
-- !!!!!!! TEMP TO EXCLUDE SUSPENDED ADVISERS !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
*/

/****************************************************************************

	Compare each BPOL for each CaseInScope (#PolicyLicenceCheckDate) to the 
	SellerLicencesInScope and log against each BPOL whether or not the seller 
	was licenced at the time of the sale.

	Deal with non-policy holding cases later
																		
****************************************************************************/
--select top 1 * from #PolicyLicenceCheckDate
--select top 1 * from #PolicyLicenceGroupChecks
--declare	@LicenceConfigAsOfDate	datetime set @LicenceConfigAsOfDate = getdate()


select	PolicyLicenceCheckDate.CASE_ID,
		ins_bp.BPOL_BackOfficeID,
		ins_bp.BPOL_ProductType,
		PolicyLicenceCheckDate.POL_NUM,
		PolicyLicenceCheckDate.CASE_AdviserID,
		PolicyLicenceCheckDate.LicenceCheckDate,
		PolicyLicenceCheckDate.LicenceCheckDateSource,
		ProdLics.RegulationGroupCode,
		ProdLics.CheckType,
		PolicyLicenceCheckDate.ScopeReason,
		sum(case when ProdLics.CheckType = 'G' and SellerLicencesInScope.LIC_Code = ProdLics.LicenceCode then 1 else 0 end) as GroupMatchedLicenceCount,
		sum(case when ProdLics.CheckType = 'G' and isnull(SellerLicencesInScope.LIC_Code,'') <> isnull(ProdLics.LicenceCode,'') then 1 else 0 end) as GroupUnMatchedLicenceCount,
		sum(case when ProdLics.CheckType = 'M' and SellerLicencesInScope.LIC_Code = ProdLics.LicenceCode then 1 else 0 end) as MandMatchedLicenceCount,
		sum(case when ProdLics.CheckType = 'M' and isnull(SellerLicencesInScope.LIC_Code,'') <> isnull(ProdLics.LicenceCode,'') then 1 else 0 end) as MandUnMatchedLicenceCount
into	#PolicyLicenceGroupChecks
from	#PolicyLicenceCheckDate PolicyLicenceCheckDate
		inner join sa_insight_BasicPolicy ins_bp 
					on ins_bp.BPOL_ParentID = PolicyLicenceCheckDate.CASE_ID
					and ins_bp.BPOL_BackOfficeID = PolicyLicenceCheckDate.BPOL_BackOfficeID
					and ins_bp.BPOL_ProductType = PolicyLicenceCheckDate.BPOL_ProductType
		cross apply logi.f_Insight_OwlProductTypeToLicenceCode(PolicyLicenceCheckDate.LicenceCheckDate) ProdLics 
		left join #SellerLicencesInScope SellerLicencesInScope 
					on SellerLicencesInScope.CASE_AdviserID = PolicyLicenceCheckDate.CASE_AdviserID
					and SellerLicencesInScope.LIC_Code = ProdLics.LicenceCode
					and PolicyLicenceCheckDate.LicenceCheckDate between SellerLicencesInScope.ULIC_ValidFrom and SellerLicencesInScope.ULIC_ValidTo
where	ProdLics.InsightProductTypeCode = ins_bp.BPOL_ProductType
and		PolicyLicenceCheckDate.LicenceCheckDate between ProdLics.EffectiveStartDate and ProdLics.EffectiveEndDate
group	by	PolicyLicenceCheckDate.CASE_ID,
			ins_bp.BPOL_BackOfficeID,
			ins_bp.BPOL_ProductType,
			PolicyLicenceCheckDate.POL_NUM,
			PolicyLicenceCheckDate.CASE_AdviserID,
			PolicyLicenceCheckDate.LicenceCheckDate,
			PolicyLicenceCheckDate.LicenceCheckDateSource,
			ProdLics.RegulationGroupCode,
			ProdLics.CheckType,
			PolicyLicenceCheckDate.ScopeReason
--order	by	PolicyLicenceCheckDate.CASE_ID,
--			ins_bp.BPOL_BackOfficeID,
--			ins_bp.BPOL_ProductType,
--			PolicyLicenceCheckDate.POL_NUM,
--			PolicyLicenceCheckDate.CASE_AdviserID,
--			PolicyLicenceCheckDate.LicenceCheckDate,
--			PolicyLicenceCheckDate.LicenceCheckDateSource,
--			ProdLics.RegulationGroupCode,
--			ProdLics.CheckType,
--			PolicyLicenceCheckDate.ScopeReason


/****************************************************************************

	From the above selection we know that there were missing mandatory
	licences but we don't know which they are because the group by
	stops us identifying them.  The query below allows us to join to
	the above temp table to identify the missing licences.
																		
****************************************************************************/


select	PLGC.CASE_ID,
		PLGC.BPOL_BackOfficeID,
		PLGC.BPOL_ProductType,
		PLGC.POL_NUM,
		PLGC.LicenceCheckDate,
		PLGC.LicenceCheckDateSource,
		ProdLics.RegulationGroupCode,
		ProdLics.CheckType,
		PLGC.ScopeReason,
		isnull(ProdLics.LicenceCode,'') as MissingLicence
into	#MissingMandatoryLics
from	#PolicyLicenceGroupChecks PLGC
		cross apply logi.f_Insight_OwlProductTypeToLicenceCode(PLGC.LicenceCheckDate) ProdLics 
		-- Must be left join as we want to know the unmatched licence codes
		left join #SellerLicencesInScope SellerLicencesInScope 
					on SellerLicencesInScope.CASE_AdviserID = PLGC.CASE_AdviserID
					and SellerLicencesInScope.LIC_Code = ProdLics.LicenceCode
					and PLGC.LicenceCheckDate between SellerLicencesInScope.ULIC_ValidFrom and SellerLicencesInScope.ULIC_ValidTo
where	ProdLics.CheckType = 'M'
and		ProdLics.InsightProductTypeCode = PLGC.BPOL_ProductType
and		ProdLics.RegulationGroupCode = PLGC.RegulationGroupCode
and		isnull(ProdLics.LicenceCode,'') <> isnull(SellerLicencesInScope.LIC_Code,'') 
and		PLGC.MandUnMatchedLicenceCount > 0
and		PLGC.LicenceCheckDate between ProdLics.EffectiveStartDate and ProdLics.EffectiveEndDate


/****************************************************************************

	Table #MissingMandatoryLics contains one row per missing licence per
	case, per product, per regulation group. However, irrespective of the 
	number of missing licences, we want only one row on thre report for the 
	case. The code below pivots this table using a recursive CTE to comma 
	separate the list of missing licence codes. Note that the indexes on 
	#Temp1 as otherwise performance is terrible.
																		
****************************************************************************/


select BPOL_BackOfficeID, BPOL_ProductType, RegulationGroupCode, MissingLicence, rn=ROW_NUMBER() over (PARTITION by BPOL_BackOfficeID, BPOL_ProductType, RegulationGroupCode order by MissingLicence)
into #Temp1
from #MissingMandatoryLics

create index idx1 on #Temp1(BPOL_BackOfficeID, BPOL_ProductType, RegulationGroupCode, rn)

;with cte2(BPOL_BackOfficeID, BPOL_ProductType, RegulationGroupCode, MissingLicencesConcatenated, rn)
as
(
select BPOL_BackOfficeID, BPOL_ProductType, RegulationGroupCode, convert(varchar(max),MissingLicence), 1 
from #Temp1 
where rn=1

union all

select	cte2.BPOL_BackOfficeID, cte2.BPOL_ProductType, cte2.RegulationGroupCode, convert(varchar(max),cte2.MissingLicencesConcatenated + ', ' + #Temp1.MissingLicence), cte2.rn+1
from	cte2
		inner join #Temp1 
					on #Temp1.BPOL_BackOfficeID = cte2.BPOL_BackOfficeID 
					and #Temp1.BPOL_ProductType = cte2.BPOL_ProductType
					and #Temp1.RegulationGroupCode = cte2.RegulationGroupCode
					and #Temp1.rn=cte2.rn+1
)
select	MML.CASE_ID,
		MML.BPOL_BackOfficeID,
		MML.BPOL_ProductType,
		MML.POL_NUM,
		MML.LicenceCheckDate,
		MML.LicenceCheckDateSource,
		MML.RegulationGroupCode,
		MML.CheckType,
		MML.ScopeReason,		
		MAX(cte2.MissingLicencesConcatenated) as MissingLicences
into	#MissingMandatoryLics2
from	#MissingMandatoryLics MML
		inner join cte2 
				on cte2.BPOL_BackOfficeID = MML.BPOL_BackOfficeID
				and cte2.BPOL_ProductType = MML.BPOL_ProductType
				and cte2.RegulationGroupCode = MML.RegulationGroupCode
group	by	MML.CASE_ID,
			MML.BPOL_BackOfficeID,
			MML.BPOL_ProductType,
			MML.POL_NUM,
			MML.LicenceCheckDate,
			MML.LicenceCheckDateSource,
			MML.RegulationGroupCode,
			MML.CheckType,
			MML.ScopeReason
--order by 1


/****************************************************************************

	Get the earliest appointed date but get the re-appointeds first because
	we don't want to include their original appointment date.

****************************************************************************/


select	uph.UPS_UserID, uph.UPS_EmploymentStatus, min(uph.UPS_CreatedDate) as MinUPS_CreatedDate
into	#SellerBecameActive
from	sa_insight_UserPositionHistory uph
where	uph.UPS_EmploymentStatus in (8)		-- Re-appointed
and		uph.UPS_JobTitle in (4,42,5,32,33)	-- Sellers
group	by uph.UPS_UserID, uph.UPS_EmploymentStatus

insert into #SellerBecameActive
	select	uph.UPS_UserID, uph.UPS_EmploymentStatus, min(uph.UPS_CreatedDate)
	from	sa_insight_UserPositionHistory uph
			left join #SellerBecameActive UPBA on UPBA.UPS_UserID = uph.UPS_UserID
	where	uph.UPS_EmploymentStatus in (1)		-- Open
	and		UPBA.UPS_UserID is null				-- Only pull in this person if we don't already have them
	and		uph.UPS_JobTitle in (4,42,5,32,33)	-- Sellers
	group	by uph.UPS_UserID, uph.UPS_EmploymentStatus	


/****************************************************************************

	Create Output Table

****************************************************************************/


create table #Results
(
	OpportunityRef				varchar(20),
	CaseRef						varchar(40),
	ProductType					Varchar(30),
	SwiftPolicyNumber			varchar(25),
	LicenceCheckDate			varchar(10),
	ReportReason				varchar(100),
	RegulationGroupCode			varchar(20),
	MissingLicences				varchar(500),
	AdviserUID					nvarchar(20),
	AdviserName					nvarchar(255),
	AdviserEmploymentStatus		nvarchar(50),
	BQMName						nvarchar(255)
)


/****************************************************************************

	Report

****************************************************************************/


insert into #Results
(
	OpportunityRef,
	CaseRef,
	ProductType,
	SwiftPolicyNumber,
	LicenceCheckDate,
	ReportReason,
	RegulationGroupCode,
	MissingLicences,
	AdviserUID,
	AdviserName,
	AdviserEmploymentStatus,
	BQMName
)
--Report cases with missing mandatory licences
select	SC.CASE_CaseReference as OpportunityRef,
		MML.BPOL_BackOfficeID as CaseRef,
		convert(varchar(20),MML.BPOL_ProductType) + ' - ' + PT.PROD_ShortName as ProductType,
		isnull(polmai.CONT_NUM,'<Unknown>') as SwiftPolicyNumber,
		convert(varchar(10),MML.LicenceCheckDate,103) as LicenceCheckDate,
		'Missing Mandatory Licence(s)' as ReportReason,
		MML.RegulationGroupCode,
		MML.MissingLicences,
		coalesce(UD.USR_ExternalId,Sellers.UserUID,'<Unknown>') as AdviserUID,	
		coalesce(UD.USR_Name,Sellers.UserName,'<Unknown>') as AdviserName,	
		isnull(Sellers.UserEmploymentStatus,'<Unknown>') as AdviserEmploymentStatus,
		isnull(Sellers.BQMName,'<Unknown>') as BQMName
from	#MissingMandatoryLics2 MML
		inner join sa_insight_SalesCase SC on SC.CASE_ID = MML.CASE_ID
		inner join sa_insight_UserDetails UD on UD.USR_ID = SC.CASE_AdviserId		
		left join mi_insight_UserHierarchy Sellers on Sellers.UserGUID = SC.CASE_AdviserID
		left join sa_insight_staff staff on staff.STAF_UserID = SC.CASE_AdviserID
		left join sa_insight_CodeDescription CD on CD.Code_CodeType = 530 and CD.Code_Code = staff.STAF_CustomerFunction
		left join sa_swift_S_POLMAI polmai on polmai.POL_NUM = MML.POL_NUM
		left join sa_insight_ProductType PT on PT.PROD_Code = MML.BPOL_ProductType
		left join sa_insight_CodeDescription CD2 on CD2.Code_CodeType = 54 and CD2.Code_Code = coalesce(Sellers.UserJobTitleCodeSeller, Sellers.UserJobTitleCodePartner)
where	isnull(Sellers.UserJobTitleCodeNASP,0) <> 3	-- Don't report on non-advising sellers

union

-- Report cases where no group licences were held
select	SC.CASE_CaseReference as OpportunityRef,
		PLGC.BPOL_BackOfficeID as CaseRef,
		convert(varchar(20),PLGC.BPOL_ProductType) + ' - ' + PT.PROD_ShortName as ProductType,
		isnull(polmai.CONT_NUM,'<Unknown>') as SwiftPolicyNumber,
		convert(varchar(10),PLGC.LicenceCheckDate,103) as LicenceCheckDate,
		'Missing Group Licence' as ReportReason,
		PLGC.RegulationGroupCode,
		'One Of: ' + logi.f_Insight_OwlLicGrpToLicCodesConcatenated(PLGC.RegulationGroupCode) as MissingLicences,
		coalesce(UD.USR_ExternalId,Sellers.UserUID,'<Unknown>') as AdviserUID,
		coalesce(UD.USR_Name,Sellers.UserName,'<Unknown>') as AdviserName,
		isnull(Sellers.UserEmploymentStatus,'<Unknown>') as AdviserEmploymentStatus,
		isnull(Sellers.BQMName,'<Unknown>') as BQMName
from	#PolicyLicenceGroupChecks PLGC
		inner join sa_insight_SalesCase SC on SC.CASE_ID = PLGC.CASE_ID
		inner join sa_insight_UserDetails UD on UD.USR_ID = SC.CASE_AdviserId
		left join mi_insight_UserHierarchy Sellers on Sellers.UserGUID = SC.CASE_AdviserID
		left join sa_insight_staff staff on staff.STAF_UserID = SC.CASE_AdviserID
		left join sa_insight_CodeDescription CD on CD.Code_CodeType = 530 and CD.Code_Code = staff.STAF_CustomerFunction
		left join dbo.f_Insight_ListPanelHistoryOfAllSellers() SellerPanels 
					on  SellerPanels.InsightUserGUID = SC.CASE_AdviserID
					and dateadd(dd,0,datediff(dd,0,PLGC.LicenceCheckDate)) between SellerPanels.EffFrom and isnull(SellerPanels.EffTo,'9999-12-31')
		left join dbo.sa_swift_S_POLMAI polmai on polmai.POL_NUM = PLGC.POL_NUM
		left join sa_insight_ProductType PT on PT.PROD_Code = PLGC.BPOL_ProductType
		left join sa_insight_CodeDescription CD2 on CD2.Code_CodeType = 54 and CD2.Code_Code = coalesce(Sellers.UserJobTitleCodeSeller, Sellers.UserJobTitleCodePartner)
where	isnull(Sellers.UserJobTitleCodeNASP,0) <> 3	-- Don't report on non-advising sellers
and		PLGC.CheckType = 'G' 
and		PLGC.GroupMatchedLicenceCount = 0

union

-- a) Report cases with no linked policies
-- b) Report if seller's employment status not open or re-appointed on the date of sale.
select	SC.CASE_CaseReference as OpportunityRef,
		isnull(PLCD.BPOL_BackOfficeID, case when PLCD.LinkedPolicyYN = 'N' then '<None>' else '<Unknown>' end) as CaseRef,
		convert(varchar(20),PLCD.BPOL_ProductType) + ' - ' + PT.PROD_ShortName as ProductType,
		isnull(polmai.CONT_NUM,case when PLCD.LinkedPolicyYN = 'N' then '<None>' else '<Unknown>' end) as SwiftPolicyNumber,
		convert(varchar(10),PLCD.LicenceCheckDate,103) as LicenceCheckDate,
		case when PLCD.LinkedPolicyYN = 'N' then 'Case Has No Linked Policies'
			 when PLCD.LicenceCheckDate < SBA.MinUPS_CreatedDate then 'Seller Not Open or Re-Appointed on Licence Check Date'	
		end as ReportReason,
		'<None>' as RegulationGroupCode,
		'<None>' as MissingLicences,
		coalesce(UD.USR_ExternalId,Sellers.UserUID,'<Unknown>') as AdviserUID,
		coalesce(UD.USR_Name,Sellers.UserName,'<Unknown>') as AdviserName,
		isnull(Sellers.UserEmploymentStatus,'<Unknown>') as AdviserEmploymentStatus,
		isnull(Sellers.BQMName,'<Unknown>') as BQMName
from	#PolicyLicenceCheckDate PLCD
		inner join sa_insight_SalesCase SC on SC.CASE_ID = PLCD.CASE_ID
		inner join sa_insight_UserDetails UD on UD.USR_ID = SC.CASE_AdviserId
		left join mi_insight_UserHierarchy Sellers on Sellers.UserGUID = SC.CASE_AdviserID
		left join owv_AdviserBrand ab on ab.UserUID = Sellers.UserUID
		left join sa_insight_staff staff on staff.STAF_UserID = SC.CASE_AdviserID
		left join sa_insight_CodeDescription CD on CD.Code_CodeType = 530 and CD.Code_Code = staff.STAF_CustomerFunction
		left join sa_swift_S_POLMAI polmai on polmai.POL_NUM = PLCD.POL_NUM				-- If trapping Employment Status then there may be a policy
		left join sa_insight_ProductType PT on PT.PROD_Code = PLCD.BPOL_ProductType
		left join #SellerBecameActive SBA on SBA.UPS_UserID = ud.USR_ID
		left join sa_insight_CodeDescription CD2 on CD2.Code_CodeType = 54 and CD2.Code_Code = coalesce(Sellers.UserJobTitleCodeSeller, Sellers.UserJobTitleCodePartner)
where	(PLCD.LinkedPolicyYN = 'N'						-- No linked policies or...
or		PLCD.LicenceCheckDate < SBA.MinUPS_CreatedDate)	-- Not Open or Re-Appointed on the licence check date	
and		isnull(Sellers.UserJobTitleCodeNASP,0) <> 3		-- Don't report on non-advising sellers
and		ab.Brand = 'Owl'								-- Include Owl advisers	only


/****************************************************************************

	Select the data for Logi

****************************************************************************/


select 	
	AdviserUID,
	AdviserName,
	AdviserEmploymentStatus,
	OpportunityRef,
	CaseRef,
	ProductType,
	SwiftPolicyNumber,
	LicenceCheckDate,
	ReportReason,
	RegulationGroupCode,
	MissingLicences,
	BQMName
from #Results
order by 1,2,3,4,5,6


/****************************************************************************

	Drop temp tables

****************************************************************************/


drop table #EarliestBPOL
drop table #CurrentBPOL
drop table #PreviousBPOL
drop table #CasesInScope
drop table #SellerLicencesInScope
drop table #PolicyLicenceCheckDate
drop table #PolicyLicenceGroupChecks
drop table #MissingMandatoryLics
drop table #Results
drop table #SellerBecameActive
drop table #Temp1


