GO
/**********************************************************************************************
Name	: [BI].[pr_193_OwlOwnLifeCases] 
Author	: E Watts
Date	: 30/10/2025

		Insert report description here.

		Purpose	: This report is used by Payment Services. The owner in Sarah's absence is Debbie 
			Burchell.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_193_OwlOwnLifeCases]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int




/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


--Insert SQL Script here

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SELECT pol.ID,
		pol.PolicyID,
		pol.AgentCode,
		ag.DESCN,
		pol.CommCompanyCode as Provider,
		polm.CONT_NUM as 'PolicyNumber',
		shp.Description,
		polm.PolicyRef as 'CaseID',
		polm.CLIENT_NUM,
		agt.AGENT_CODE,
		agt.AGENT_PERC,
		cln.FIRSTNAMES,
		cln.NAME,
		pol.CreateDateTime,
		pol.PaymentMethod,
		agts.Firm
into #PolicyTable
FROM	dbo.sa_swift_PolicyTransactions pol
		join dbo.sa_swift_S_POLMAI polm on pol.PolicyID = polm.POL_NUM
		join dbo.sa_swift_S_AGTCOM agt on agt.TransactionID = pol.ID
		join dbo.sa_swift_S_AGENTS ag on ag.CODE = pol.AgentCode
		join dbo.sa_swift_S_CLIENT_1 cln on cln.CLIENT_NUM = polm.CLIENT_NUM
		join dbo.sa_swift_S_AGENTS agts on agts.CODE = agt.AGENT_CODE
		join dbo.sa_swift_CodeCommissionShape shp on shp.ID = pol.CodeCommissionShapeID
where	pol.CommCompanyCode like '%OWL'
and		agt.AGENT_CODE != '10002'
and		Pol.ID = (select max(pol1.ID) 
					from dbo.sa_swift_PolicyTransactions pol1
					where pol1.PolicyID = Pol.PolicyID)
and agt.CommissionType not in ( 4, 10)
and shp.Description like '016%'
and shp.Description like '%Non Indemnity%'


select	pol1.AgentCode as AdviserCode,
		pol1.DESCN as AdviserName,
		pol1.CLIENT_NUM as ClientNumber,
		pol1.FIRSTNAMES as ClientFirstNames,
		pol1.NAME as ClientLastName,
		pol1.CaseID,
		pol1.Provider,
		pol1.Description as CommShapeDescn,
		pol1.Agent_Code	as Adviser1Code,
		pol1.AGENT_PERC as Adviser1SplitPct,
		pol2.Agent_Code as Adviser2Code,
		pol2.AGENT_PERC as Adviser2SplitPct,
		pol3.Agent_Code as Adviser3Code,
		pol3.AGENT_PERC as Adviser3SplitPct,
		pol4.Agent_Code as Adviser4Code,
		pol4.AGENT_PERC as Adviser4SplitPct,
		isnull((select top 1 convert(varchar(20),'Matched')
		from   dbo.sa_swift_S_PACC pacc
		join   dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = pacc.ID
		where  pacc.TransactionID = pol1.id),'Not Matched') as MatchedUnmatched
from	#PolicyTable pol1
		LEFT join #PolicyTable pol2 
					on pol1.policyID = pol2.PolicyID
					and   isnull(pol2.Agent_Code,-1) = ISNULL((select max(pol2a.Agent_Code)
											  from   #PolicyTable pol2a
															   where  pol2.PolicyID = pol2a.PolicyID
															   and    pol2a.Agent_Code < pol1.Agent_Code
															   ),-1)
		left join   #PolicyTable pol3 
					on pol1.policyID = pol3.PolicyID
					and   ISNULL(pol3.Agent_Code,-1) = ISNULL((select max(pol3a.Agent_Code)
											  from   #PolicyTable pol3a
															   where  pol3.PolicyID = pol3a.PolicyID
															   and    pol3a.Agent_Code < pol2.Agent_Code
															   ),-1)
		left join   #PolicyTable pol4 
					on pol1.policyID = pol4.PolicyID
					and   ISNULL(pol4.Agent_Code,-1) = ISNULL((select max(pol4a.Agent_Code)
											  from   #PolicyTable pol4a
															   where  pol4.PolicyID = pol4a.PolicyID
															   and    pol4a.Agent_Code < pol3.Agent_Code
															   ) ,-1) 
where	pol1.Agent_Code = (select  max(pol1a.Agent_Code)
							from   #PolicyTable pol1a
							where  pol1.PolicyID = pol1a.PolicyID)
ORDER	BY pol1.AgentCode, pol1.CaseID;

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



