/**********************************************************************************************
Name	: [BI].[pr_194_TandC_COBSAdvisersWithNoStmtOfProfStanding]
Author	: E Watts
Date	: 30/10/2025

		Insert report description here.

		Purpose	: This report lists COBS advisers with no Statement of Professional Standing (SPS) 
			and is used by Karen Appleby in the Training and Competence Team.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_194_TandC_COBSAdvisersWithNoStmtOfProfStanding]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int




/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


--Insert SQL Script here

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select	uh.UserName as 'UserName', 
		uh.UserUID as 'UserUID' ,
		cd.code_description as 'ContractStatus',
		cd1.code_description as 'EmploymentStatus',
		cd2.code_description as 'BusinessArea',
		case isnull(uc_competencylevel,'') 
			when '1' then 'Stage 1' 
			when '2' then 'Interim Competency' 
			when '3' then 'Fully Competent' 
			when '4' then 'Suspended'  
			else 'Unknown' 
		end as 'COBCompetency',
		isnull(uH.BusinessUID,'') as 'EnterpriseUID', 
		isnull(uh.businesstradingname,isnull(uh.BusinessCompanyName,'')) as 'BusinessName' ,
		isnull(uh.aqmname,'') as 'AQM' ,
		isnull(uh.bqmname,'') as 'BQM'
from	sa_insight_UserDetails ud with (nolock)
		inner join sa_insight_Staff s with (nolock) on s.staf_userid = ud.usr_id
		inner join mi_insight_UserHierarchy UH ON UH.UserGUID = s.staf_userid
		inner join sa_insight_codedescription cd with (nolock) on cd.code_code = s.staf_contractstatus
		inner join sa_insight_codedescription cd1 with (nolock) on cd1.code_code = s.staf_employmentstatus
		left outer join sa_insight_UserCompetency uc with (nolock) on ud.usr_id = uc.uc_ownerid 
		and uc_status = 0						-- only including Active Status competencies
		and uc_businessarea in (3,6,7)			-- only includes COB competencies
		inner join sa_insight_codedescription cd2 with (nolock) on cd2.code_code = uc.uc_businessarea
where	cd.code_codetype = 527
and		cd1.code_codetype = 125
and		cd2.code_codetype = 534
and		staf_employmentstatus in ( 1, 8)	-- open or reappointed
and		staf_contractstatus = 1				-- under contract
and		uc_competencylevel is not null		-- ie has a COB competency 
--and usr_type not in ('27','6','20')
and		usr_type in ('201','3','5','32','25')
and		uh.UserJobTitleCodeSeller is not null --and UserJobTitleCodeSupervisor is null
and		uh.UserUID <> '4000024'
and		not exists (select 1 from sa_insight_StatementOfProfessionalStanding sps2 where sps2.sps_userid = s.staf_userid and SPS_Status = '2')
order by 1,2


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



