/**********************************************************************************************
Name	: [BI].[pr_195_OwlHeadcount] 
Author	: J Homer
Date	: 30/10/2025

Create a daily Owl Headcount Table for use in Power BI
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
12/03/2026	J Homer		Amended code for Status to match the Excel based Owl List
						Mirrored logic from spreadsheet
02/04/2026	J Homer		Added final row count to process logging

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_195_OwlHeadcount]


with recompile

AS 

set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseLog				varchar(50),
			@PhaseError				varchar(50),
			@Process				varchar(100),
			@Message				varchar(100),
			@RowCount				int,
			@Client					varchar(50),
			@Module					varchar(50),
			@DateLastUpdated		datetime
			

/****************************************************************************

		Set initial parameters																
																		
****************************************************************************/

	set @PhaseStart			= 'START'
	set @PhaseEnd   		= 'END'
	set @PhaseLog			= 'LOG'
	set @PhaseError			= 'ERROR'
	set @Process			= object_name(@@procid)
	set @Client				= 'Openwork'
	set @Module				= 'MI Team Owl Headcount'
	set @DateLastUpdated	= getdate()

	
/****************************************************************************

		Log start
																		
****************************************************************************/

	exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

IF OBJECT_ID('tempdb..#ASM')			IS NOT NULL DROP TABLE #ASM
IF OBJECT_ID('tempdb..#ESM')			IS NOT NULL DROP TABLE #ESM
IF OBJECT_ID('tempdb..#OwlHC')			IS NOT NULL DROP TABLE #OwlHC
IF OBJECT_ID('tempdb..#RowNum')			IS NOT NULL DROP TABLE #RowNum
IF OBJECT_ID('tempdb..#PreCon')			IS NOT NULL DROP TABLE #PreCon
IF OBJECT_ID('tempdb..#ReApps')			IS NOT NULL DROP TABLE #ReApps
IF OBJECT_ID('tempdb..#Panel')			IS NOT NULL DROP TABLE #Panel
IF OBJECT_ID('tempdb..#PanelMaxDate')	IS NOT NULL DROP TABLE #PanelMaxDate

--Create Latest Panel and Band temp table --
SELECT EnterpriseUID, MAX(up.DateProcessed) as MaxDate
INTO #PanelMaxDate
FROM bi.OwlEvoSwiftUpliftRates as up
 	group by EnterpriseUID
 
SELECT 
uh.UserUID
,up.Panel
,up.Band
Into #Panel
FROM bi.OwlEvoSwiftUpliftRates as up
  	INNER JOIN mi_insight_UserHierarchy as uh on up.EnterpriseUID = uh.businessuid
	INNER JOIN #PanelMaxDate as m on up.EnterpriseUID = m.EnterpriseUID 
								AND up.DateProcessed = m.MaxDate
	GROUP BY  uh.UserUID, up.Panel, up.Band

-- Create ASM and ESM temp tables --

SELECT DISTINCT 
UserUID
INTO #ASM 
   FROM [mi_insight_UserHierarchyAllUsers]
	WHERE 
	1=1 
		AND ADUID = '4021409'
		AND UserJobTitleCodeSalesMgr = '54'
		AND EffectiveEndDate = '9999-12-31'
		AND UserContractStatusCode = 1 -- OPEN
		AND (UserEmploymentStatusCode = 1 -- Under Contact
				OR UserEmploymentStatusCode = 8) -- Re-Appointed

SELECT DISTINCT 
OwlASMUID2 as UserUID
INTO #ESM  
 
  FROM [mi_insight_UserHierarchyAllUsers]
  	WHERE 
	1=1 
		AND ADUID = '4021409'
		AND EffectiveEndDate = '9999-12-31'
		AND UserContractStatusCode = 1 -- OPEN
		AND (UserEmploymentStatusCode = 1 -- Under Contact
			OR UserEmploymentStatusCode = 8) -- Re-Appointed


-- Owl headcount basis --

SELECT    DISTINCT
UID							= CASE	WHEN AgHier.AgentCode = '4005899' THEN '4303744'  
									WHEN AgHier.AgentCode = '4006371' THEN '4006317'
									WHEN AgHier.AgentCode = '4007583' THEN '4007584'
									WHEN AgHier.AgentCode = '1012004' THEN '4007110'
									WHEN AgHier.AgentCode = '4005961' THEN '4005968'
									WHEN AgHier.AgentCode = '4005958' THEN '4005228'
							  ELSE AgHier.AgentCode END,
AgHier.AgentStartDate,
AgHier.AgentLeftDate,
ROW_NUMBER()OVER(PARTITION BY CASE	WHEN AgHier.AgentCode = '4005899' THEN '4303744'  
									WHEN AgHier.AgentCode = '4006371' THEN '4006317'
									WHEN AgHier.AgentCode = '4007583' THEN '4007584'
									WHEN AgHier.AgentCode = '1012004' THEN '4007110'
									WHEN AgHier.AgentCode = '4005961' THEN '4005968'
									WHEN AgHier.AgentCode = '4005958' THEN '4005228'
							  ELSE AgHier.AgentCode END ORDER BY aghier.agentstartdate asc) AS [Sort]
Into #RowNum
from dbo.cscv_AgentsHierarchy as AgHier	
 
select
UserUID,
MAX(EffectiveEndDate) EndDate
into #PreCon
from
mi_insight_UserHierarchyAllUsers
where
UserContractStatus = 'Pre-Contract'
and EffectiveEndDate <> '9999-12-31'

GROUP BY
UserUID
 
select
uh.UserUID,
uh.UserName,
uh.UserEmploymentStatus,
uh.UserContractStatus,
(uh.EffectiveStartDate) StartDate
into #ReApps
from
mi_insight_UserHierarchyAllUsers uh JOIN
#PreCon pc on pc.UserUID = uh.UserUID
where
uh.UserContractStatus = 'Under Contract'
and uh.EffectiveStartDate = DATEADD(day,1,Enddate)


SELECT    DISTINCT
UID							= CASE	WHEN AgHier.AgentCode = '4005899' THEN '4303744'  
									WHEN AgHier.AgentCode = '4006371' THEN '4006317'
									WHEN AgHier.AgentCode = '4007583' THEN '4007584'
									WHEN AgHier.AgentCode = '1012004' THEN '4007110'
									WHEN AgHier.AgentCode = '4005961' THEN '4005968'
									WHEN AgHier.AgentCode = '4005958' THEN '4005228'
							  ELSE AgHier.AgentCode END
,[Name]						= LTRIM(RTRIM(AgHier.AgentDesc))
,DateOfBirth = BIRTHDATE
,Role						= CASE  WHEN ((RTRIM(AgHier.ASDName)) in('Pat Mckenna','Owl Sales Director') AND AgHier.AgentTypeDescription = 'Principal' ) THEN 'Adviser'
									WHEN AgHier.AgentTypeDescription = 'Seller' THEN 'Adviser'
							  ELSE AgHier.AgentTypeDescription END
,[SellerType]				= CASE WHEN uh.UserJobTitleCodeSeller IS NOT NULL THEN
										CASE uh.UserJobTitleCodeSeller WHEN 61 THEN 'Senior Protection Adviser'
																	WHEN 62 THEN 'Mortgage Adviser'
																	WHEN 63 THEN 'New Protection Adviser'
										ELSE 'Protection Adviser' END
							  ELSE NULL END
,AgHier.AgentCategoryDescription as Category
,Selling					= CASE WHEN (RIGHT(Agents.SupervisorTypeCode, 2) = 'NA' AND Agents.GivesAdvice = 'Y')
									OR  AgHier.AgentCode = '1005202' THEN 'N'
							  ELSE Agents.GivesAdvice END
,StartDate = CASE WHEN ReApps.StartDate is not null THEN ReApps.StartDate ELSE AgHier.AgentStartDate  END
--,StarDateReApps = ReApps.StartDate
--,StartDate =		 AgHier.AgentStartDate
,Suspension = CASE WHEN  Agents.Salutation is not null THEN 'Y' ELSE null END
,NoticeGiven = CASE WHEN  Agents.DeclarationofAssociationEffectiveDate is not null THEN 'Y' ELSE null END
,EndDate =  AgHier.AgentLeftDate
,Status = CASE WHEN Agents.DeclarationofAssociationEffectiveDate is not null 
					AND Agents.Salutation is not null  
					AND (CASE WHEN (RIGHT(Agents.SupervisorTypeCode, 2) = 'NA' AND Agents.GivesAdvice = 'Y')
								OR  AgHier.AgentCode = '1005202' THEN 'N'
							  ELSE Agents.GivesAdvice END) = 'Y' AND ((uh.UserContractStatus = 'Under Contract' AND uh.UserJobTitleCodeSeller IS NOT NULL) OR (AgHier.CompetentStatusdescription NOT IN ('Left', 'NPW', 'Deceased', 'Pre-appointed','Re-Appointed') AND uh.UserJobTitleCodeSeller IS NOT NULL))
					THEN 'Suspended and Under Notice'
			   WHEN Agents.DeclarationofAssociationEffectiveDate is null 
					AND Agents.Salutation is not null  
					AND (CASE WHEN (RIGHT(Agents.SupervisorTypeCode, 2) = 'NA' AND Agents.GivesAdvice = 'Y')
								OR  AgHier.AgentCode = '1005202' THEN 'N'
							  ELSE Agents.GivesAdvice END) = 'Y' AND ((uh.UserContractStatus = 'Under Contract' AND uh.UserJobTitleCodeSeller IS NOT NULL) OR (AgHier.CompetentStatusdescription NOT IN ('Left', 'NPW', 'Deceased', 'Pre-appointed','Re-Appointed') AND uh.UserJobTitleCodeSeller IS NOT NULL))
					THEN 'Suspended'
			   WHEN Agents.DeclarationofAssociationEffectiveDate is not null 
					AND Agents.Salutation is null  
					AND (CASE WHEN (RIGHT(Agents.SupervisorTypeCode, 2) = 'NA' AND Agents.GivesAdvice = 'Y')
								OR  AgHier.AgentCode = '1005202' THEN 'N'
							  ELSE Agents.GivesAdvice END) = 'Y' AND ((uh.UserContractStatus = 'Under Contract' AND uh.UserJobTitleCodeSeller IS NOT NULL) OR (AgHier.CompetentStatusdescription NOT IN ('Left', 'NPW', 'Deceased', 'Pre-appointed','Re-Appointed') AND uh.UserJobTitleCodeSeller IS NOT NULL))
					THEN 'Under Notice'
			   WHEN ISNULL(cd.Code_Description,UH.UserEmploymentStatus) = 'Vetting' THEN 'Pre-Appointed'
			   WHEN ISNULL(cd.Code_Description,UH.UserEmploymentStatus) = 'Deceased' or AgHier.CompetentStatusDescription = 'Deceased'  THEN 'Left'
			   WHEN AgHier.AgentCode = '1002505' THEN 'Left' 
			   WHEN AgHier.AgentCode = '1001364' THEN 'Left' 
			   WHEN (Agents.EMAIL LIKE '%Deceased%' AND AgHier.AgentType = 43) THEN 'Left'
			   WHEN AgHier.CompetentStatusdescription = 'N/A' AND AgHier.agentstartdate IS NOT NULL THEN 'Active' 
			   --WHEN ISNULL(cd.Code_Description,UH.UserEmploymentStatus) = 'Under Contract' or ISNULL(cd.Code_Description,UH.UserEmploymentStatus) = 'Re-Appointed'  or ISNULL(cd.Code_Description,UH.UserEmploymentStatus) = 'Open' THEN 'Active'
			   WHEN UH.UserEmploymentStatus is null THEN AgHier.CompetentStatusdescription 
			   WHEN cd.Code_Description = 'Pre-Contract' THEN 'Pre-appointed'
			   WHEN cd.Code_Description = 'Under Contract' or (uh.UserContractStatus = 'Under Contract' AND (uh.UserJobTitleCodePA IS NULL and uh.UserJobTitleCodeSeller IS NOT NULL)) 
														   or (uh.UserContractStatus = 'Under Contract' AND (uh.UserJobTitleCodePA IS NULL and uh.UserJobTitleCodePartner IS NOT NULL))THEN 'Active'
			   ELSE ISNULL(cd.Code_Description,AgHier.CompetentStatusdescription) END
			   --ELSE AgHier.CompetentStatusdescription END
			   ,ReasonForLeaving

	,uh.BQMName AS 'T&CSupervisor'
	,UH.OwlASMUID1
	,REPLACE(REPLACE(UH.OwlASMName1,'Owl',''),'OWL','')  as OwlASMName1
	,UH.OwlASMUID2
	,REPLACE(REPLACE(UH.OwlASMName2,'Owl',''),'OWL','')  as OwlASMName2
	, UH.OwlASMUID3
	,REPLACE(REPLACE(UH.OwlASMName3,'Owl',''),'OWL','')  as OwlASMName3
	,UH.OwlASMUID4
	,REPLACE(REPLACE(UH.OwlASMName4,'Owl',''),'OWL','')  as OwlASMName4
	,UH.OwlASMUID5
	,REPLACE(REPLACE(UH.OwlASMName5,'Owl',''),'OWL','')  as OwlASMName5
	,UH.OwlASMUID6
	,REPLACE(REPLACE(UH.OwlASMName6,'Owl',''),'OWL','')  as OwlASMName6
	,UH.OwlASMUID7
	,REPLACE(REPLACE(UH.OwlASMName7,'Owl',''),'OWL','')  as OwlASMName7
	,UH.OwlASMUID8
	,REPLACE(REPLACE(UH.OwlASMName8,'Owl',''),'OWL','')  as OwlASMName8
	,UH.OwlASMUID9
	,REPLACE(REPLACE(UH.OwlASMName9,'Owl',''),'OWL','')  as OwlASMName9

,PanelMarker = PT.Code_Description
,STAF.STAF_RecruitedByName
,StafUH.UserName
, Clients.Address1
, Clients.Address2
, Clients.Address3
, Clients.Address4
, Clients.Address5
, Clients.Postcode
, Agents.TELEPHONE AS Work_Telephone
, Clients.TEL_Mobile AS Mobile_Telephone
, CASE WHEN (RTRIM(Agents.EMAIL) IS NULL OR RTRIM(Agents.EMAIL) = null) THEN RTRIM(Clients.EMAIL) ELSE RTRIM(Agents.EMAIL) END AS Email
,[UserEmploymentStatus] =  ISNULL(cd.Code_Description,UH.UserEmploymentStatus)
, Agents.PortalLogon
, FirmCode					= AgHier.FirmCode
, Sort						= rn.sort
,#Panel.Panel
,#Panel.Band
INTO #OwlHC
FROM				dbo.mstt_Agents						 as Agents
	INNER JOIN		#RowNum								 as rn			on rn.UID = Agents.Code
	INNER JOIN		dbo.cscv_AgentsHierarchy			 as AgHier		on Agents.CODE = AgHier.AgentCode
	LEFT JOIN		#ReApps								 as ReApps		on ReApps.UserUID = AgHier.AgentCode
	INNER JOIN		(SELECT     CODE, MIN(ValidFromDate) as FirstDate
					 FROM          dbo.mstt_AgentsHistory
					 GROUP BY CODE
					 ) AS A												on A.CODE = AgHier.AgentCode
	LEFT OUTER JOIN dbo.mstt_Clients					 as Clients		on Agents.Code = Clients.AgentCode
	LEFT JOIN  [dbo].[mi_insight_UserHierarchyAllUsers]  as uh			on a.Code =  uh.UserUID
																		AND(ADName in('Pat Mckenna','Owl Sales Director') or UserJobTitleCodeBQM = 55 or UserJobTitleCodeSupervisor = 56)
																		AND uh.EffectiveEndDate > GETDATE()
																		AND uh.LatestRowInd >0	
	LEFT JOIN	sa_insight_userposition					 as up			on up.UPS_Userid = uh.UserGUID
																			AND ups_dateto IS NULL
																			AND ups_JobTitle IN (52,61,62,63,64)	
	LEFT JOIN	sa_insight_CodeDescription				 as cd			on cd.code_codetype = 527 AND cd.code_code = up.UPS_ContractStatus
	LEFT JOIN ( SELECT Code_Code, Code_Description
	   FROM sa_insight_CodeDescription
	   WHERE Code_CodeType = '53')  as PT	 on PT.Code_Code = UP.UPS_Section AND UP.UPS_JobTitle in ('52','61','62','63')--OWL Adviser / Owl Senior Protection Adviser / Owl Senior Protection and Mortgage Adviser /Owl Protection Adviser																
	LEFT JOIN	sa_insight_UserDetails		as USR	 on UP.UPS_UserID = USR.USR_ID 		
	LEFT JOIN	sa_insight_Staff			as STAF	 on  STAF.STAF_UserID = USR.USR_ID
	LEFT JOIN [dbo].[mi_insight_UserHierarchyAllUsers]   as StafUH			on staf.STAF_RecruitedByName =  StafUH.UserUID
																		AND StafUH.EffectiveEndDate > GETDATE()
																		AND StafUH.LatestRowInd >0	
	LEFT JOIN #Panel on #Panel.UserUID = AgHier.AgentCode
	
WHERE  (NOT (AgHier.AgentCode IN ('Jones', 'Michael','M1 3LD', 'Kurian','Tshuma', 'Rodzik','William', '1011671','4005317',' 401601'))) AND (RTRIM(AgHier.ASDName) in('Pat Mckenna','Owl Sales Director'))
		AND (AgHier.AgentTypeDescription <> 'Franchise')
		AND LTRIM(RTRIM(AgHier.AgentDesc)) NOT LIKE 'Marek Durachta OA'
		AND AgHier.CompetentStatusdescription not in ('Cancelled')
		AND ISNUMERIC (AgHier.AgentCode) = 1
		AND Sort = 1 
		AND (PT.Code_Description <> '099 - Please set Panel' or PT.Code_Description is null)


	
		--and AgHier.AgentCode in ('4031118')

		order by UID

-- Add in ASM and ESM roles, remove 'Owl' from ASM names --

Select 
#OwlHC.* 
,CASE WHEN #ASM.UserUID is null THEN #OwlHC.OwlASMUID1 ELSE  #ASM.UserUID END as AssuranceView
,CASE WHEN #ESM.UserUID = #OwlHC.UID AND #ASM.UserUID = #OwlHC.UID THEN 'ESM'
	  WHEN #ASM.UserUID = #OwlHC.UID THEN 'ASM' 
	  ELSE  #OwlHC.Role END as 'Role ASM'
,CASE WHEN #OwlHC.Status = 'Left' THEN 'Left' 
	  WHEN #OwlHC.StartDate is null THEN 'New'
	  WHEN #OwlHC.StartDate >= DATEADD(year,-1,GETDATE()) THEN 'New'
	  ELSE 'Experienced' END AS 'New/Experienced'
,CASE WHEN #OwlHC.EndDate is not null THEN DATEDIFF(month,#OwlHC.StartDate, #OwlHC.EndDate) 
	  ELSE DATEDIFF(month,#OwlHC.StartDate,GETDATE()) END AS 'Active Months'

INTO #OwlTable

FROM #OwlHC

LEFT JOIN #ASM on #ASM.UserUID = #OwlHC.UID
LEFT JOIN #ESM on #ESM.UserUID = #OwlHC.UID

/*  WRITE TO TABLE */
-- Empty existing table

delete from bi.OwlHeadcount

-- Write new data to table
insert into bi.OwlHeadcount
Select DISTINCT * 
from #OwlTable 


/****************************************************************************

	End Of Report
																	
****************************************************************************/

/****************************************************************************

		Processing end
																		
****************************************************************************/
	set @RowCount = @@ROWCOUNT
	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



