/**********************************************************************************************
Name	: [BI].[pr_196_TandC_COBSAdvisersWithDueStmtOfProfStanding] 
Author	: L Brigginshaw
Date	: 30/10/2024

Purpose	: This report lists COBS advisers and when their Statement of Professional Standing 
			(SPS) is due. This report is used by Karen Appleby in the Training and Competence 
			Team.

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_196_TandC_COBSAdvisersWithDueStmtOfProfStanding]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


select	STAF_ControlledFunctionStartDate as 'CFStartDate',
		dateadd(mm,30,STAF_ControlledFunctionStartDate) as 'CFStartDatePlus30Months',
		case 
			when dateadd(mm,30,STAF_ControlledFunctionStartDate) < getdate() then 'Past 30 months'
			when dateadd(mm,28,STAF_ControlledFunctionStartDate) < getdate() then 'Coming up within 2 months'
			else 'Future case'
		end as 'Description',
		uh.UserName as 'UserName', 
		uh.UserUID as 'UserUID' ,
		isnull(uH.BusinessUID,'') as 'EnterpriseUID', 
		isnull(uh.businesstradingname,isnull(uh.BusinessCompanyName,'')) as 'BusinessName' ,
		uh.aqmname as 'AQM' ,
		uh.bqmname as 'BQM'
from	sa_insight_Staff s
		inner join mi_insight_UserHierarchy UH ON UH.UserGUID = s.staf_userid
		left outer join sa_insight_UserCompetency uc with (nolock) on s.staf_userid = uc.uc_ownerid 
		and uc_status = 0					-- only including Active Status competencies
		and uc_businessarea in (3,6,7)		-- only includes COB competencies
where	STAF_ControlledFunctionStartDate is not null
and		staf_customerfunction = '1'
and		uc_competencylevel is not null		-- ie has a COB competency 
and		not exists (select 1 from sa_insight_StatementOfProfessionalStanding sps2 where sps2.sps_userid = s.staf_userid and SPS_Status = '2')
order by 4


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



