/**********************************************************************************************
Name	: [BI].[pr_197_TandC_SupervisorDiscrepancies] 
Author	: L Brigginshaw
Date	: 30/10/2024

Purpose	: This report lists advisers with different supervisors between Swift and Insight. 
		  It is used by Karen Appleby in the Training and Competence Team

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_197_TandC_SupervisorDiscrepancies]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SELECT 
i.useruid AS [Adviser UID],
              i.username AS [Adviser Name],
              isnull(i.supervisoruid,i.bqmuid) AS [Insight Supervisor UID],    -- SC 15.03.17
              isnull(i.supervisorname,i.bqmname) AS [Insight Supervisor Name],  -- SC 15.03.17
              ah.detailagentcode AS [SWIFT Supervisor UID],
              ag.[DESCN] AS [Swift Supervisor Name]
FROM mi_insight_UserHierarchy i 
INNER JOIN sa_swift_AgentHierarchyHistory ah ON ah.agentcode = i.useruid
INNER JOIN mstt_Agents a ON a.code = ah.agentcode
INNER JOIN mstt_Agents ag ON ah.detailagentcode = ag.CODE
WHERE participanttype IN (12)
AND DefaultValue = 1
AND a.CompetentStatus IN ('1', '5')
AND ah.enddate IS NULL
AND ah.detailagentcode <> isnull(i.supervisoruid,i.bqmuid)  -- SC 15.03.17
AND i.userjobtitlecodeseller = 4
AND OwlASMName1 IS NULL
order by username


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



