SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_198_JMDAdviserAgencyCode] 
Author	: E Watts
Date	: 31/10/2025

		Insert report description here.
			Report for Linsey Davies (Just Mortgages Direct) to show adviser details with
			their L&G Agency Number

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
18/06/2026	J Homer		Added a temp table to rank CodeAgencyNumbers IDs for L&G
						based on the last modified date by Adviser. This allows us to identify
						the latest Agency Code entry and removes duplicates from the results

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_198_JMDAdviserAgencyCode]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'JMDAdviserAgencyCode'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

/****************************************************************************

There are multiple rows per adviser, per provider/company.  This code takes
the ID column from the table sa_swift_CodeAgencyNumbers and ranks it based
on the last modified date, by agant code.  This table is then used in the 
main query so that results are limited to only the last modified record.

*****************************************************************************/

select 
				ROW_NUMBER () OVER(PARTITION BY cna.AgentCode ORDER BY can.ID DESC) AS Rank,
				can.ID
INTO #AgencyCodeRank				
from 
				sa_swift_CodeAgencyNumbers can  left join
				sa_swift_CodeAgencyNumberAgents cna on cna.AgencyNumberID = can.id

where 
				can.CompanyCode = 'L&G'
/****************************************************************************

JMD adviser list with L&G Agency Code

*****************************************************************************/

select 
				a.code as 'UID',
				a.descn as 'AdviserName', 
				lower(s2.Field1Value) as 'PtlCode', 
				can.AgencyNo as 'LandGAgencyNo.', 
				case CompetentStatus
						when 1 then 'Active'
						when 2 then 'Left'
						when 5 then 'Pre Appt'
						when 6 then 'NPW'
						else 'Unknown'
				end  as 'EmploymentStatus'
from 
				sa_swift_S_AGENTS a 
				left join sa_swift_CodeAgencyNumberAgents cna on a.code = cna.AgentCode
				inner join #AgencyCodeRank acr on acr.id = cna.AgencyNumberID and acr.Rank =1
				left  join sa_swift_CodeAgencyNumbers can on can.id = acr.id
				inner join (select SingleSignOnUserId, Field1Value from sa_ISL_SingleSignOnApplicationProfile where SingleSignOnApplicationId = 3) s1 on s1.Field1Value = a.code
				inner join sa_ISL_SingleSignOnApplicationProfile s2 on s1.SingleSignOnUserId = s2.singlesignonuserid
where 
				a.firm = '2005309'
				and can.CompanyCode = 'L&G'
				and s2.SingleSignOnApplicationId = 1
Group By
				a.code,
				a.descn, 
				lower(s2.Field1Value), 
				can.AgencyNo, 
				case CompetentStatus
						when 1 then 'Active'
						when 2 then 'Left'
						when 5 then 'Pre Appt'
						when 6 then 'NPW'
						else 'Unknown'
				end
order by 
				case CompetentStatus
						when 1 then 'Active'
						when 2 then 'Left'
						when 5 then 'Pre Appt'
						when 6 then 'NPW'
						else 'Unknown'
				end asc,
				a.DESCN asc


/****************************************************************************

	End Of Report
																	
****************************************************************************/

drop table #AgencyCodeRank


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



