/****** Object:  StoredProcedure [BI].[pr_199_JMD_ContraCases]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_199_JMD_ContraCases]
Author	: Luke Brigginshaw
Date	: 04/11/2025

		 This report is used for Just Mortgages Direct Limited. The recipients are:
                  1) JMD Limited

              The report name is "JMD Contra Cases" and is found on the "JMD MI" 
              menu. This report displays any JMD policy that has been paid and clawed back
              and deleted via the contra script.
              
              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_logi_JMD_ContraCases] 'ptl91371', 'Logi', JMD
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_199_JMD_ContraCases]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@JMDBusinessUID				 varchar(7)

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)

set @JMDBusinessUID = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'BusinessUID' and cde.Description = 'JMD')


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


select distinct
AgencyNo,
can.CompanyCode,
case when can.CompanyCode = 'PruProtect' then 'Unknown' else agt.CODE end as CODE,
case when can.CompanyCode = 'PruProtect' then 'Unknown' else agt.DESCN end as DESCN
into #JMDAgencyCode
from sa_swift_CodeAgencyNumbers can 
join sa_swift_CodeAgencyNumberAgents cna on can.id = cna.AgencyNumberID
join mstt_Agents agt on agt.code = cna.AgentCode
where agt.Firm = @JMDBusinessUID
and can.CompanyCode in ('L&G','Aviva','Metlife','LV','Zurich New','PruProtect')


select distinct 
edc.PolicyNumber, 
--edc.FullName,
case pcu.comp_code
when 'Aviva' then edc.Surname+' '+edc.initials 
else edc.fullname
end as Fullname,
edc.PremiumAmount, 
edc.IFAReference,
edc.AmountReceived as AmountReceived,
isnull(agt.COde,jmd.CODE) as CODE, 
isnull(agt.DESCN,jmd.DESCN) as DESCN,
min(edc.CommissionReceivedDate) as OriginalDate,
jmd.CompanyCode
into #Original
from sa_swift_EDIFACTCommissionStatementHeader edh
join sa_swift_EDIFACTCommissionStatementContents edc on edh.ID = edc.StatementHeaderID
join sa_swift_S_PACC pcu on pcu.ID = edc.Pacc_ID
join sa_swift_S_STMTCT stm on stm.STATEMENT = pcu.STATEMENT
join sa_swift_S_PACCSU pcs on pcs.INIT_ID = pcu.ID
join sa_swift_S_PACC pac on pac.ID = pcs.SUSP_ID
join #JMDAgencyCode jmd on jmd.AgencyNo = edc.IFAReference
left join mstt_Policies pol on pol.CONT_NUM = edc.PolicyNumber
left join mstt_PolicyTransactions pt on pt.PolicyID = pol.POL_NUM
left join mstt_Agents agt on agt.CODE = pt.AgentCode
where pac.NOTES like '%CR1003%' 
and AmountReceived > 0
and pcu.comp_code in  ('L&G','Aviva','Metlife','LV','Zurich New','PruProtect')
and PolicyNumber not like '%adj' and FullName not like '%MG/%'
Group by edc.PolicyNumber, 
pcu.comp_code,
edc.surname,
edc.initials,
edc.FullName,
edc.PremiumAmount, 
edc.IFAReference,
isnull(agt.COde,jmd.CODE), 
isnull(agt.DESCN,jmd.DESCN),
jmd.CompanyCode,
edc.AmountReceived

select distinct 
edc.PolicyNumber, 
--edc.FullName,
case pcu.comp_code
when 'Aviva' then edc.Surname+' '+edc.initials 
else edc.fullname
end as Fullname,
edc.PremiumAmount, 
edc.IFAReference,
edc.AmountReceived as AmountReceived,
max(edc.CommissionReceivedDate) as ClawbackDate
into #Clawback
from sa_swift_EDIFACTCommissionStatementHeader edh
join sa_swift_EDIFACTCommissionStatementContents edc on edh.ID = edc.StatementHeaderID
join sa_swift_S_PACC pcu on pcu.ID = edc.Pacc_ID
join sa_swift_S_STMTCT stm on stm.STATEMENT = pcu.STATEMENT
join sa_swift_S_PACCSU pcs on pcs.INIT_ID = pcu.ID
join sa_swift_S_PACC pac on pac.ID = pcs.SUSP_ID
join #JMDAgencyCode jmd on jmd.AgencyNo = edc.IFAReference
where pac.NOTES like '%CR1003%' 
and AmountReceived < 0
and PolicyNumber not like '%adj' and FullName not like '%MG/%'
Group by edc.PolicyNumber, 
edc.FullName,
pcu.comp_code,
edc.surname,
edc.initials,
edc.PremiumAmount, 
edc.IFAReference,
edc.AmountReceived


Select distinct
org.PolicyNumber,
org.FullName,
org.PremiumAmount,
org.CODE,
org.DESCN,
agt.firm,
org.OriginalDate,
round(case when org.CompanyCode = 'Zurich NEW' then org.AmountReceived * 0.825 else org.AmountReceived*0.865 end,2) as OriginalCommissionAmount,
clw.ClawbackDate,
round(case when org.CompanyCode = 'Zurich NEW' then clw.AmountReceived * 0.825 else clw.AmountReceived*0.865 end,2) as ClawbackCommissionAmount
from #Original org
join #Clawback clw on clw.PolicyNumber = org.PolicyNumber and org.AmountReceived = clw.AmountReceived*-1
left join mstt_agents agt on agt.code = org.code
where firm = @JMDBusinessUID --added 4.10.19
order by PolicyNumber


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



