			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_201_Finstat10NewNoUID]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_201_Finstat10NewNoUID] 
Author	: J Homer
Date	: 04/11/2025

On the 1st of the month there is an automated run of the Finstat Reports, which support the Financial
Reporting Team in their monthly reporting.

Add in Business UID based on which Firm the Adviser was with at the FinancialPeriodFromDate in the 
dbo.owt_Finance_S_PACC table.  Use the correct UID to assign the right Panel (Owl, Owl AR or Openwork)

Exclude UID from Results output
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_201_Finstat10NewNoUID]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Finstat10NewNoUID'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

Declare @FinancialPeriodFromDate date
Set @FinancialPeriodFromDate = DATEADD(MONTH, DATEDIFF(MONTH, -1, GETDATE())-1, -1) --Last Day of previous month

DROP TABLE IF EXISTS #Receipts
DROP TABLE IF EXISTS #ProductAmounts
DROP TABLE IF EXISTS #Products
DROP TABLE IF EXISTS #ProductAmountSplits
DROP TABLE IF EXISTS #ProductAmountSummary
DROP TABLE IF EXISTS #CommissionTypes
DROP TABLE IF EXISTS #FinstatTen
DROP TABLE IF EXISTS #ProductAmountSummary
DROP TABLE IF EXISTS #BusinessCodes

----START OF NEW CODE

SELECT		
			fipa.Id,
			fipa.PaccId,
			fipa.AgentCode,
			uh.ADUID,
			uh.BusinessUID
INTO #BusinessCodes
FROM		
			dbo.owt_Finance_S_PACC fipa 
			LEFT JOIN mi_insight_userhierarchyallusers uh on uh.UserUID = fipa.AgentCode and fipa.FinancialPeriodFromDate BETWEEN uh.EffectiveStartDate AND uh.EffectiveEndDate
		
---- END OF NEW CODE


select	convert(int,Codes.Code) as CommissionTypeCode,
			codes.Description as CommissionTypeDesc
	into	#CommissionTypes
	from	dbo.msit_MIWarehouseCodesAndDescriptions Codes
	where	Codes.ColumnName = 'CommissionType'

--	create clustered index idx_tmp on #CommissionTypes(CommissionTypeCode)
	
	select	isnull(fipa.ProviderCode,'NullProviderCode') ProviderCode,
			isnull(fipa.ProductSubGroupName,'NullProductSubGroupName') ProductSubGroupName,
			isnull(fipa.ProductBasisCode,'NullProductBasisCode') ProductBasisCode,
			isnull(fipa.ProductBasisDescr,'NullProductBasisDescr') ProductBasisDescr,
			isnull(fipa.ProductCode,'NullProductCode') ProductCode,
			fipa.PayType,
			fipa.RecAmt,
			fipa.PaccId,
			case when isnull(bc.ADUID,'9999') in ('4005013', '4021409') then 'Owl'
				 when (isnull(bc.BusinessUID, '9999') = '2016789' or ISNULL(bc.ADUID,'9999') = '4019902') then 'Owl AR' 
				 else 'Openwork' 
			end as Panel
			--,ISNULL(bc.BusinessUID,'9999') BusinessUID
	into	#Receipts
	from	dbo.owt_Finance_S_PACC fipa 
	LEFT JOIN #BusinessCodes bc ON bc.ID = fipa.ID AND bc.PaccId = fipa.PaccId
	--left join	mi_insight_userhierarchyallusers uh on uh.UserUID = fipa.AgentCode and uh.LatestRowInd = 1
	where	@FinancialPeriodFromDate between fipa.FinancialPeriodFromDate and fipa.FinancialPeriodToDate
	and		fipa.PayType not in (2,5,15,16)

	/****************************************************************************
	
		Insert rows into temp table 2

	****************************************************************************/

	select	--() over (order by fipa.ProductCode, fipa.PayType, fipa.BusinessUID) as ProductBasisKey,
			ROW_NUMBER() over (order by fipa.ProductCode, fipa.PayType) as ProductBasisKey,
			fipa.ProviderCode,
			fipa.ProductSubGroupName,
			fipa.ProductBasisCode,
			fipa.ProductBasisDescr,
			fipa.ProductCode,
			fipa.PayType,
			sum(fipa.RecAmt) as RecAmt,
			fipa.Panel
			--,fipa.BusinessUID
	into	#Products
	from	#Receipts fipa 
	group	by	fipa.ProviderCode,
				fipa.ProductSubGroupName,
				fipa.ProductBasisCode,
				fipa.ProductBasisDescr,
				fipa.ProductCode,
				fipa.PayType,
				fipa.Panel
				--,fipa.BusinessUID

	--create index idx_tmp_Products
	--				on #Products(	ProviderCode,
	--								ProductSubGroupName,
	--								ProductBasisCode,
	--								ProductBasisDescr,
	--								ProductCode,
	--								PayType)

	--exec msp_ProcessLog @PhaseLog, 'Temp Table 2 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 3

	****************************************************************************/

	select	rec.PayType,
			pr.ProductBasisKey,
			pr.RecAmt,
			agmf.AGENT_CODE as Agmf_AGENT_CODE,
			agmf.AMOUNT as Agmf_AMOUNT,
			agmf.PACC_ID as Agmf_PACC_ID,
			rec.RecAmt as fipa_RecAmt,
			agmp.AMOUNT as Agmp_AMOUNT,
			rec.Panel
			--rec.BusinessUID
	into	#ProductAmounts
	from	#Receipts rec 
			inner join #Products pr 
							on  pr.ProviderCode       = rec.ProviderCode
							and pr.ProductSubGroupName= rec.ProductSubGroupName
							and pr.ProductBasisCode   = rec.ProductBasisCode
							and pr.ProductBasisDescr  = rec.ProductBasisDescr
							and pr.ProductCode        = rec.ProductCode
							and pr.PayType            = rec.PayType
							and pr.Panel			  = rec.Panel
							--and pr.BusinessUID		  = rec.BusinessUID
			left join dbo.sa_swift_S_AGMFIL agmf on agmf.PACC_ID = rec.PaccId
			left join dbo.sa_swift_S_AGMPAY agmp on agmp.AGMID   = agmf.ID

--	exec msp_ProcessLog @PhaseLog, 'Temp Table 3 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 4

	****************************************************************************/

	select	pr.ProductBasisKey,
			pr.RecAmt,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then 0
                        when '10002' then 0
                        when '10004' then 0
                        when '10005' then 0
                        when '1006124' then 0
                        when '1006886' then 0
                        when '1011542' then 0
                        when '1011587' then 0
                        when '1011623' then 0
                        when '1011629' then 0
                        when '1011630' then 0
                        when '1011631' then 0
                        when '1011632' then 0
                        when '1011633' then 0
                        when '1011634' then 0
                        when '1011635' then 0
                        else pr.Agmf_AMOUNT 
			end as AgentAmountDue,
			case pr.Agmf_AGENT_CODE 
						when '1011543' then pr.Agmf_AMOUNT
                        when '10002' then pr.Agmf_AMOUNT
                        when '10004' then pr.Agmf_AMOUNT
                        when '10005' then pr.Agmf_AMOUNT
                        when '1006124' then pr.Agmf_AMOUNT
                        when '1006886' then pr.Agmf_AMOUNT
                        when '1011542' then pr.Agmf_AMOUNT
                        when '1011587' then pr.Agmf_AMOUNT
                        when '1011623' then pr.Agmf_AMOUNT
                        when '1011629' then pr.Agmf_AMOUNT
                        when '1011630' then pr.Agmf_AMOUNT
                        when '1011631' then pr.Agmf_AMOUNT
                        when '1011632' then pr.Agmf_AMOUNT
                        when '1011633' then pr.Agmf_AMOUNT
                        when '1011634' then pr.Agmf_AMOUNT
                        when '1011635' then pr.Agmf_AMOUNT
                        else 0 
			end as OpenWorkAmountDue,
			case ISNULL(pr.Agmf_PACC_ID,0) 
						when 0 then case pr.PayType 
										when 5 then 0
										when 6 then pr.fipa_RecAmt 
										else pr.fipa_RecAmt 
									end 
								else 0 
			end as NoAgmAmt,
			pr.Panel
			--,pr.BusinessUID
	into	#ProductAmountSplits
	from	#ProductAmounts pr

--	exec msp_ProcessLog @PhaseLog, 'Temp Table 4 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into temp table 5

	****************************************************************************/

	select	pr.ProductBasisKey,
			max(pr.RecAmt) as RecAmt,
			sum(AgentAmountDue) as AgentAmountDue,
			sum(OpenWorkAmountDue) as OpenWorkAmountDue,
			sum(NoAgmAmt) as NoAgmAmt,
			pr.Panel
			--,pr.BusinessUID
	into	#ProductAmountSummary
	from	#ProductAmountSplits pr
	group	by	pr.ProductBasisKey, pr.panel--, pr.BusinessUID

--	exec msp_ProcessLog @PhaseLog, 'Temp Table 5 Created.', null, @Module, @Client

	/****************************************************************************
	
		Insert rows into the staging table

	****************************************************************************/


	select	@FinancialPeriodFromDate as FinancialPeriodFromDate,	-- First day of previous month
	--		@FinancialPeriodToDate as FinancialPeriodToDate,
			0 as LatestRowInd,	-- Must be zero - will be toggled later
			p.ProviderCode,
			prpr.ProductProviderName,
			p.ProductSubGroupName,
			p.ProductBasisCode,
			p.ProductBasisDescr,
			p.ProductCode,
			p.PayType,
			ct.CommissionTypeDesc as CommDescription,
			pr.RecAmt,
			pr.AgentAmountDue,
			pr.OpenWorkAmountDue,
			pr.NoAgmAmt , 
			pr.Panel
			--,pr.BusinessUID
	--		@DateLastUpdated as DateInserted,
	--		@DateLastUpdated as DateLastUpdated
			into #FinstatTen
	from	#ProductAmountSummary pr
			inner join #Products p on p.ProductBasisKey = pr.ProductBasisKey
			left join #CommissionTypes ct on ct.CommissionTypeCode = p.PayType
			left join dbo.mstt_ProductProviders prpr on prpr.ProductProviderCode = p.ProviderCode



	Select 
--datename(month,@Month) + ' ' + convert(varchar(4),datepart(year,@Month)) as FinancialPeriod,
cme.ProviderCode,
ProductProviderName,
ProductSubGroupName,
ProductBasisCode,
ProductBasisDescr,
ProductCode,
PayType,
CommDescription,
RecAmt,
AgentAmountDue,
OpenWorkAmountDue,
NoAgmAmt,
cm.Margin1,
NoAgmAmt*(1-cm.Margin1) as AGMLessMargin,
Case when CommDescription = 'Initial Commission' or CommDescription = 'Adjustment IC' then ProductBasisDescr
      when CommDescription = 'Renewal' or CommDescription = 'Adjustment RC' then 'Renewal'
      when CommDescription = 'Trail Fee' or CommDescription = 'Adjustment Trail' then 'Trail'
      else '0'
      End as CommDesc,
Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end as ProductType,
isnull(Case when 
(Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end) = 'MORTGAGE'
Then 'MORTGAGE' ELSE
isnull(ProductProviderName,'NULL') + ' ' +
(Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end)+' '+
(Case when CommDescription = 'Initial Commission' or CommDescription = 'Adjustment IC' then ProductBasisDescr
      when CommDescription = 'Renewal' or CommDescription = 'Adjustment RC' then 'Renewal'
      when CommDescription = 'Trail Fee' or CommDescription = 'Adjustment Trail' then 'Trail'
      End) End,'NULL NON-CORE 0') as Descr,
	  cme.panel
	  --,.BusinessUID
from #FinstatTen cme
left join logi.Finance_ProdSubGroupInp psgi  on cme.ProductSubGroupName = psgi.productsubgroup
left join logi.Finance_ConfigMargins cm on cm.ProviderCode = cme.ProviderCode and '31-Dec-2015' between cm.EffectiveStartDate and cm.EffectiveEndDate
-- 
WHERE Panel in ('Owl AR','OWl') and ProductCode not like '%Owl'
--where @Month between FinancialPeriodFromDate and FinancialPeriodToDate

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_202_ExpiredLicences]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
