/**********************************************************************************************
Name	: [BI].[pr_202_ExpiredLicences]
Author	: Luke Brigginshaw
Date	: 07/11/2025

Purpose	: This report is used by Karen Appleby in the Training & Competence Team.

		  The security groups associated with is report are:
		  1) GLS_Logi_OpenworkPortalAudience - for the user to get the "Logi" link on the portal.
		  2) GLS_Logi_TrainingAndCompetence - to give visibility of the report on the Logi Main Menu.
		  3) GLS_Logi_AppManTeam - to give the visibility of the report to the App Man Team for support.

		  Execute as follows:
		  exec [logi].[pr_logi_ExpiredLicences] 'LIC1', 'ptl91543', 'NativeExcel'

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
22.11.19	S Inglis	Addition of column to state if user is PA or Head Office and ability to
						filter on all licences added
29.11.19	S Inglis	Addition of filter for User Type
07.11.25    L Brigginshaw  Move over to new BI. stored proceedure

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_202_ExpiredLicences]

@LicenceCode nvarchar(50) = 'View All',
@UserType	varchar(20) = 'View All'

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int
			--@LicenceCode	nvarchar(50) = 'View All',
			--@UserType		varchar(20) = 'View All' -- Added 29.11.19 SI

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)
--set @StoredProcParams	= '@LicenceCode = ' + CONVERT(varchar(50),@LicenceCode) 


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

select	USR.USR_Name as Name, 
		USR.USR_Login as UID, 
		ULIC.ULIC_ValidTo as [LicenceValidTo], 
		MI.SupervisorName as Supervisor, 
		MI.BQMName as BQM,
		case when mi.userjobtitlecodeHO is not null then 'Head Office' --added 22.11.19 SI
			 when mi.userjobtitlecodePA is not null then 'PA'
			 else 'Not HO or PA' end as JobTitle,
		l.LIC_description
from	sa_insight_UserLicence as ULIC
		join sa_insight_Licence L on L.LIC_ID = ULIC.ULIC_LicenceID
		join sa_insight_UserDetails as USR on ULIC.ULIC_UserID = USR.USR_ID
		join sa_insight_Staff as STAF on USR.USR_ID = STAF.STAF_UserID
		join mi_insight_UserHierarchy as MI on USR.USR_Login = MI.UserUID
where	
(L.LIC_Code = @LicenceCode or @LicenceCode = 'View All') --updated 22.11.19 SI
and STAF.STAF_ContractStatus = '1'
and (		case when mi.userjobtitlecodeHO is not null then 'Head Office' --added 29.11.19 SI
			 when mi.userjobtitlecodePA is not null then 'PA'
			 else 'Not HO or PA' end = @UserType or @UserType = 'View All')
and		ULIC.ULIC_Status = '2'
and		ULIC.ULIC_ValidTo <= GETDATE()
order by USR.USR_Name

/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



/****************************************************************************

			E N D															

****************************************************************************/
GO
/****** Object:  StoredProcedure [BI].[pr_203_AllLicences]    Script Date: 7/3/2026 3:34:43 PM ******/
