/**********************************************************************************************
Name	: [BI].[pr_203_AllLicences] 
Author	: J Homer
Date	: 11/11/2025

This is a general purpose utility for fetching all the Insight licence codes.
			
Note:  This is a general purpose utility used by potentially many reports.
	   If this proc is NOT doing exactly what you need, then please create 
	   a new proc because amending this proc may break many other reports.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_203_AllLicences]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'All Licences'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
/****************************************************************************
		DROP TABLES
****************************************************************************/

DROP TABLE IF EXISTS  #Licence1, #Licence2

/****************************************************************************
		CREATE TEMP TABLES
*****************************************************************************/
SELECT
			'View All' DisplayLicence, 
			'View All' LIC_Code,
			0		   Row_Num
INTO 
			#Licence1



SELECT
				LIC_Code + ' - ' + LIC_Description as DisplayLicence, 
				LIC_Code as LicenceCode,
				ROW_NUMBER() OVER (ORDER BY CASE 
													WHEN PATINDEX('%[0-9][0-9][0-9][0-9]%',LIC_Code) > 0 THEN LIC_Code
													WHEN PATINDEX('%[0-9][0-9][0-9]%',LIC_Code) > 0 THEN LEFT(LIC_Code,3) + '0' + SUBSTRING(LIC_Code,4,50)
													WHEN PATINDEX('%[0-9][0-9]%',LIC_Code) > 0 THEN LEFT(LIC_Code,3) + '00' + SUBSTRING(LIC_Code,4,50)
													WHEN PATINDEX('%[0-9]%',LIC_Code) > 0 THEN LEFT(LIC_Code,3) + '000' + SUBSTRING(LIC_Code,4,50)
											 END) Row_Num
INTO
				#Licence2
FROM	
				sa_insight_Licence
WHERE	
				PATINDEX('%OBSOLETE%',LIC_Description) = 0
ORDER BY 
				Row_Num
/****************************************************************************
		GENERATE FINAL LIST
*****************************************************************************/

SELECT
				*
FROM
				#Licence1

UNION ALL

SELECT
				*
FROM 
				#Licence2
ORDER BY 
				Row_Num Asc


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



