/**********************************************************************************************
Name	: [BI].[pr_204_JobTitles] 
Author	: J Homer
Date	: 12/11/2025

		Create a list of Job Titles for use with the Expired Licences Power BI
		paginated report.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_204_JobTitles]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Job Titles'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT
				'View All' JobTitle,
				0 Row_Num
UNION ALL

SELECT	
				CASE WHEN mi.userjobtitlecodeHO is not null THEN 'Head Office' --added 22.11.19 SI
					 WHEN mi.userjobtitlecodePA is not null THEN 'PA'
					 ELSE 'Not HO or PA' 
				END AS JobTitle,
				CASE WHEN mi.userjobtitlecodeHO is not null THEN 1 --added 22.11.19 SI
					 WHEN mi.userjobtitlecodePA is not null THEN 2
					 ELSE 3 
				END AS Row_Num
FROM			
				sa_insight_UserDetails AS USR 
				join sa_insight_Staff AS STAF ON USR.USR_ID = STAF.STAF_UserID
				join mi_insight_UserHierarchy AS MI ON USR.USR_Login = MI.UserUID
WHERE	
				STAF.STAF_ContractStatus = '1'
GROUP BY
				CASE WHEN mi.userjobtitlecodeHO is not null THEN 'Head Office' --added 22.11.19 SI
					 WHEN mi.userjobtitlecodePA is not null THEN 'PA'
					 ELSE 'Not HO or PA' 
				END,
				CASE WHEN mi.userjobtitlecodeHO is not null THEN 1 --added 22.11.19 SI
					 WHEN mi.userjobtitlecodePA is not null THEN 2
					 ELSE 3 
				END 
ORDER BY
				Row_Num


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



