/**********************************************************************************************
Name	: StoredProcedure [BI].[pr_210_AgentChange] 
Author	: ALuke Brigginshaw
Date	: 28/11/2025

		SQL to pull back any active ongoing fee's for adviser/firms selected in thte dro podown. 
		This will produce a list that Provider Agency Management uses to transfer clients from one adviser to another
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_210_AgentChange] 

@FirmUID nvarchar(50) = 'View All', 
@FirmName nvarchar(50) = 'View All'


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/




DECLARE @StartDate varchar(30), @EndDate varchar(30)
DECLARE @PaymentMonth date;
SET @StartDate = CONVERT(DATETIME, DATEADD(yy,-4,DATEADD(yy,DATEDIFF(yy,0,GETDATE()),0)), 102)
set @EndDate = Getdate()


IF OBJECT_ID('tempdb..#CCD') IS NOT NULL
DROP TABLE #CCD

select 

CaseID,
cc.ExtPolicyNumber,
MAX(cc.DueDate) as Maxdate

into #CCD 

from MSIT_commissionstatement cc


group by CaseID, ExtPolicyNumber


select distinct
cc.AgentCode [Adviser UID],
cc.SellerName [Adviser Name],
cc.BusinessCode [Firm UID],
cc.FranchiseName [Firm Name],
cc.CaseID,
cc.ProviderCode [Provider],
ph.productgroupname [Product Type],
FORMAT(MAX(ccD.Maxdate), 'dd/MM/yyy') [Payment Date],
cc.ExtPolicyNumber [Provider Policy Ref],
cc.ClientForenames [First Name],
cc.ClientSurname [Last Name],
cl.POSTCODE [Post Code],
format(cl.Birthdate, 'dd/MM/yyy') [Date Of Birth]



from MSIT_commissionstatement cc
left join #CCD CCD on CCD.ExtPolicyNumber = CC.ExtPolicyNumber
left join mstt_paymentspending pp on pp.TransactionID = Cc.TransactionID
left join mstt_ProductHierarchy PH on ph.ProductCode = pp.tranproduct
left join msit_S_CLIENT CL on cl.Client_num = cc.ClientID

where
(cc.BusinessCode = @FirmUID or @FirmUID = 'View All')
and ccD.Maxdate  >= @StartDate
and ccD.Maxdate <= @EndDate


group by 
cc.AgentCode,
cc.SellerName,
cc.BusinessCode,
cc.FranchiseName,
cc.CaseID,
cc.ProviderCode,
cc.ExtPolicyNumber,
cc.ClientForenames,
cc.ClientSurname,
cc.TransactionID,
ph.productgroupname,
cl.POSTCODE,
cl.Birthdate

order by CaseID asc





/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



