SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_211_BSCRebateCheck] 
Author	: J Homer
Date	: 05/12/2025

A Report that will be run on demand to assist Contract Servcices ith queries from Firms
about teh Wealth Retention Rebate (BSC Rebate).  The scan brings back data from the Open Access
table and does all ncessary calculations to allow the team to populate a template that they
send to the Firm.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
23/12/2025	J Homer		Amend join to Issued Business Case by Case table to limit to
						Recurring Income only
***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_211_BSCRebateCheck]

@CaseID Int	,
@OAMonth VARCHAR(255),
@FirmUID VARCHAR(255)					= 'View All',
@SellerUID VARCHAR(255)					= 'View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int


--Change the @Reportname param here to the name of your report
set	@ReportName			= 'BSC Rebate Check'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


/****************************************************************
SELECT MAX MONTH DATE FROM OPENWORK ADVISER LISTING TABLE AND 
THE END DATE RELATED TO THAT MONTH. THESE ARE THEN USED WHEN
DETERMINING THE PERIOD USED AS OPENACCESS IS BASED ON PAYMENT
DATES AND NOT REGULAR CALENDAR MONTHS
*****************************************************************/

DECLARE 
					@Date AS DATE,
					@Date2 AS DATE,
					@StartDate AS DATE,
					@EndDate AS DATE


SET					@Date = (SELECT MAX(oa.Month)
							 FROM msit_openworkadviserlisting oa)
SET					@Date2 = (SELECT CONVERT(DATE,cp.PeriodEndDate,103) [End Date]
							 FROM msit_Commissionstatementperiods cp LEFT JOIN
																	 (SELECT MAX(oa.Month) Month
																	  FROM msit_openworkadviserlisting oa) oa ON oa.Month = cp.Month
																	  WHERE cp.Month = oa.month);

--Create Agent Uplift Rate table with start and end date

SELECT 
					ROW_NUMBER() OVER(partition by au.agentcode, au.productcode order by au.dateinforce) as RowNum,
					au.AgentCode,
					au.DateInForce,
					au.ProductCode,
					au.UpliftRate,
					au.Status,
					au.PolicyType
INTO 
					#AgentUpliftTable
FROM 
					sa_swift_AgentUplifts au
					join mstt_ProductHierarchy ph on ph.ProductCode = au.ProductCode and ph.ProductCategoryCode = 1
WHERE 
					status = 0

	
SELECT
					aut.RowNum,
					aut.AgentCode,
					aut.DateInForce,
					aut.UpliftRate,
					aut.ProductCode,
					isnull(dateadd(day,-1,aut2.dateinforce),'31-Dec-3099')  as EndDate,
					aut2.RowNum as NewRow
INTO 
					#FranchiseUpliftRate
FROM 
					#AgentUpliftTable aut
					left join #AgentUpliftTable aut2 on aut2.AgentCode = aut.AgentCode 
																		 and aut2.ProductCode = aut.ProductCode
																		 and aut2.RowNum = aut.RowNum +1

/*****************************************************************
CREATE DATE TABLE OF OPEN ACCESS PERIODS FOR PREVIOUS R12 MONTHS
*****************************************************************/
SELECT
					cp.monthname [OA Month Name]
					,cp.Year [OA Year]
					,CONVERT(DATE,cp.PeriodStartDate,103) [Start Date]
					,CONVERT(DATE,cp.PeriodEndDate,103) [End Date]
					,CONVERT(DATE,cp.Month,103) [Month]
INTO	
					#CommissionPeriods
FROM
					msit_Commissionstatementperiods cp 
WHERE 
					cp.Month >= DATEADD(MONTH, CASE WHEN GETDATE() <= @Date2 THEN -12 ELSE -11 END, @Date) 
					AND cp.Month <= DATEADD(Month, CASE WHEN GETDATE() <= @Date2 THEN -1 ELSE -0 END, @Date)


SET					@StartDate = (SELECT MIN(cps.[Month]) from #CommissionPeriods cps)
SET					@EndDate = (SELECT Max(cps.[Month]) from #CommissionPeriods cps)

SELECT 
					cp.[OA Month Name],
					cp.[Start Date],
					cp.[End Date],
					oa.BusinessCode,
					oa.BusinessName,
					oa.SellerCode,
					oa.SellerSurname,
					oa.SellerForename,
					oa.Provider,
					CAST(oa.PaymentDate AS date) PaymentDate,
					oa.Client,
					oa.Policy,
					oa.CaseId,
					oa.ProdType,
					CAST(oa.StartDate AS date) StartDate,
					oa.Frequency,
					oa.Premium,
					oa.CommRate,
					oa.InitialPeriod,
					oa.TotDue_Base,
					Round(oa.Accrued_Base,2) Accrued_Base,
					oa.StillToAccr_Base,
					oa.ITAdvanced_Base,
					oa.EnhancementRate,
					oa.TotDue_Enhd,
					Round(oa.Accrued_Enhd,2) Accrued_Enhd,
					oa.StillToAccr_Enhd,
					oa.ITAdvanced_Enhd,
					Round(oa.TotalPayment,2) TotalPayment,
					oa.PayBasis,
					oa.Sacrifice,
					oa.AgentSplit,
					oa.FeeType,
					oa.APE,
					oa.ELITE_Points,
					oa.Remarks,
					oa.source
				   ,ROUND(oa.TotalPayment,2) TotalPayment2
				   ,fur.UpliftRate
				   ,100-ABS(fur.UpliftRate-120) AdviserRetentionRate
				   ,ABS(fur.UpliftRate-120) OWRetentionRate
				   ,SUM(cbc.DistributionAllowance) OGSFEE
				   ,agmf.AGENT_PERC BSCRetentionRate
				   ,ROUND((0.12/agmf.AGENT_PERC)*100, 2) OngoingFeeRate
				   ,ROUND((100-ABS(fur.UpliftRate-120))-(((0.12/((0.12/agmf.AGENT_PERC)*100))*((100-ABS(fur.UpliftRate-120))/100))*100),2) TrueAdviserRate
				   ,ROUND(ABS(fur.UpliftRate-120)-(((0.12/((0.12/agmf.AGENT_PERC)*100))*((ABS(fur.UpliftRate-120))/100))*100),2) TrueOWRate
				   ,ROUND((SUM(cbc.DistributionAllowance)*((0.12/((0.12/agmf.AGENT_PERC)*100)))),2) BSC_Charged
				   --,FORMAT(SUM(cbc.DistributionAllowance)*Round((0.12/((0.12/agmf.AGENT_PERC)*100)),4)*((100-ABS(fur.UpliftRate-120))/100),'N2') BSC_Rebate
				   ,Round(pp.amount-(pp.AMOUNT*(ABS(fur.UpliftRate-120)/100)),2) BSC_Rebate
				   ,CAST(pt.ProposalDate AS date) ProposalDate
				   ,ISNULL(ah.AgentOscarCode,'n/a') AgentOscarCode
FROM
					msit_openworkadviserlisting oa LEFT OUTER JOIN
					#CommissionPeriods cp ON cp.Month = oa.Month LEFT JOIN
					mstt_PolicyTransactions pt ON pt.ID = oa.TransactionID LEFT JOIN
					#FranchiseUpliftRate fur ON pt.ProposalDate BETWEEN fur.DateinForce AND fur.EndDate 
																						AND fur.AgentCode = oa.BusinessCode 
																						AND fur.ProductCode = oa.ProdType LEFT JOIN
					BI.IssuedBusinessCBC cbc ON ISNULL(CAST(cbc.CaseID AS varchar), cbc.ProviderRef) = ISNULL(Cast(oa.CaseId AS varchar), oa.Policy) AND cbc.CreateDateTime = oa.CreateDate AND cbc.ProductGroupName2 = 'Recurring Income' LEFT JOIN
					mstt_PaymentsPending pp ON ISNULL(CAST(pp.CaseID AS varchar), pp.ProviderRef) = ISNULL(Cast(oa.CaseId AS varchar), oa.Policy) AND pp.AGENT_CODE = '1011587' 
																																				  AND CAST(pp.CreateDateTime AS date) = CAST(oa.CreateDate AS date)  LEFT JOIN
					msit_S_AGMFIL agmf ON agmf.PACC_ID = pp.PACC_ID and agmf.AGENT_CODE = '1011587' LEFT JOIN
					cscv_agentsHierarchy ah ON ah.AgentCode = oa.BusinessCode
WHERE 
					oa.FeeType = 'Ongoing'
					and (cbc.DistributionAllowance)*Round((0.12/((0.12/agmf.AGENT_PERC)*100)),4) IS NOT NULL
					and oa.Month = @OAMonth
					and oa.CaseId = @CaseID
					and (oa.BusinessCode = @FirmUID OR @FirmUID = 'View All')
					and (oa.SellerCode = @SellerUID OR @SellerUID = 'View All')
		
GROUP BY
					cp.[OA Month Name],
					cp.[Start Date],
					cp.[End Date],
					oa.BusinessCode,
					oa.BusinessName,
					oa.SellerCode,
					oa.SellerSurname,
					oa.SellerForename,
					oa.Provider,
					CAST(oa.PaymentDate AS date),
					oa.Client,
					oa.Policy,
					oa.CaseId,
					oa.ProdType,
					CAST(oa.StartDate AS date),
					oa.Frequency,
					oa.Premium,
					oa.CommRate,
					oa.InitialPeriod,
					oa.TotDue_Base,
					oa.Accrued_Base,
					oa.StillToAccr_Base,
					oa.ITAdvanced_Base,
					oa.EnhancementRate,
					oa.TotDue_Enhd,
					oa.Accrued_Enhd,
					oa.StillToAccr_Enhd,
					oa.ITAdvanced_Enhd,
					oa.TotalPayment,
					oa.PayBasis,
					oa.Sacrifice,
					oa.AgentSplit,
					oa.FeeType,
					oa.APE,
					oa.ELITE_Points,
					oa.Remarks,
					oa.source
				   ,fur.UpliftRate
				   ,100-ABS(fur.UpliftRate-120)
				   ,ABS(fur.UpliftRate-120)
				   ,agmf.AGENT_PERC
				   ,pp.amount
				   ,CAST(pt.ProposalDate AS date)
				   ,ISNULL(ah.AgentOscarCode,'n/a')
	   
	 
	   

DROP TABLE			#CommissionPeriods
DROP TABLE			#FranchiseUpliftRate
DROP TABLE			#AgentUpliftTable


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



