/**********************************************************************************************
Name	: [BI].[pr_211_BSCRebateCheckDates] 
Author	: J Homer
Date	: 05/12/2025

A Report that will be run on demand to assist Contract Servcices ith queries from Firms
about teh Wealth Retention Rebate (BSC Rebate).  The scan brings back data from the Open Access
table and does all ncessary calculations to allow the team to populate a template that they
send to the Firm.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_211_BSCRebateCheckDates]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int


--Change the @Reportname param here to the name of your report
set	@ReportName			= 'BSC Rebate Check Dates'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


/****************************************************************
SELECT MAX MONTH DATE FROM OPENWORK ADVISER LISTING TABLE AND 
THE END DATE RELATED TO THAT MONTH. THESE ARE THEN USED WHEN
DETERMINING THE R12 PERIOD AS OPENACCESS IS BASED ON PAYMENT
DATES AND NOT REGULAR CALENDAR MONTHS
*****************************************************************/

DECLARE @Date AS DATE,
		@Date2 AS DATE

SET @Date = (SELECT MAX(oa.Month)
			  FROM msit_openworkadviserlisting oa)
SET @Date2 = (SELECT CONVERT(DATE,cp.PeriodEndDate,103) [End Date]
			  FROM msit_Commissionstatementperiods cp LEFT JOIN
				  (SELECT MAX(oa.Month) Month
				   FROM msit_openworkadviserlisting oa) oa ON oa.Month = cp.Month
				   WHERE cp.Month = oa.month);
--Create Agent Uplift Rate table with start and end date


/*****************************************************************
CREATE DATE TABLE OF OPEN ACCESS PERIODS FOR PREVIOUS R12 MONTHS
*****************************************************************/

SELECT
		cp.monthname [OA Month Name]
		,cp.Year [OA Year]
		,CONVERT(DATE,cp.PeriodStartDate,103) [Start Date]
		,CONVERT(DATE,cp.PeriodEndDate,103) [End Date]
		,CONVERT(DATE,cp.Month,103) [Month]
--INTO	
--		#CommissionPeriods
FROM
		msit_Commissionstatementperiods cp 
WHERE 
		cp.Month >= DATEADD(MONTH, CASE WHEN GETDATE() <= @Date2 THEN -12 ELSE -11 END, @Date) AND cp.Month <= DATEADD(Month, CASE WHEN GETDATE() <= @Date2 THEN -1 ELSE -0 END, @Date)


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



