CREATE PROCEDURE [BI].[pr_212_Finstat10Param]

@BusinessUID VARCHAR(255) = 'View All',
@Panel VARCHAR(255) = 'View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
