Finstat 9 Full with parameter value to allow Finance to filter on Business UID if required.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_217_Finstat9FullUIDs]

--@Panel VARCHAR(255) = 'View All'

WITH RECOMPILE

AS 

SET NOCOUNT ON

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ErrMsg						nvarchar(4000),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@DateLastUpdated			datetime
			
/****************************************************************************

		Set initial parameters																
																		
****************************************************************************/

	set @DateLastUpdated			= getdate()
	
/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT
					'View All' BusinessUID,
					'View All' BusinessName,
					0 Row_Num

UNION ALL

SELECT
					CAST(F9.BusinessUID AS VARCHAR(255)) BusinessUID,
					RTRIM(ISNULL(ah.AgentDesc, 'Unknown')) + ' - ' + CAST(F9.BusinessUID AS VARCHAR(255)) BusinessName,
					ROW_NUMBER() OVER (ORDER BY ISNULL(ah.AgentDesc, 'Unknown') + ' - ' + CAST(F9.BusinessUID AS VARCHAR(255)))
FROM
					bi.Finstat9_Full F9 LEFT JOIN
					cscv_AgentsHierarchy ah ON ah.AgentCode = CAST(F9.BusinessUID AS VARCHAR(255))
--WHERE				(CAST(f9.Panel AS VARCHAR(255))  = @Panel or @Panel = 'View All')

GROUP BY 
					F9.BusinessUID,
					ah.AgentDesc

/****************************************************************************

	End Of Report
																	
****************************************************************************/
/****************************************************************************

		Processing end
																		
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

