/**********************************************************************************************
Name	: [BI].[pr_218_Finstat9FullParam] 
Author	: E Brown
Date	: 04/02/2026

Finstat 9 Full with parameter value to allow Finance to filter on Business UID if required.
			

AMENDMENT HISTORY
=================
Date		Author		Description


***********************************************************************************************/
Create PROCEDURE [BI].[pr_218_Finstat9FullParam]

@BusinessUID VARCHAR(255) = 'View All',
@Panel VARCHAR(255) = 'View All'

WITH RECOMPILE

AS 

SET NOCOUNT ON

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ErrMsg						nvarchar(4000),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@DateLastUpdated			datetime
			
/****************************************************************************

		Set initial parameters																
																		
****************************************************************************/

	set @DateLastUpdated			= getdate()
	
/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SELECT 
					f9.ProviderCode,
					f9.ProductProviderName,
					f9.ProductSubGroupName,
					f9.ProductBasisCode,
					f9.ProductBasisDescr,
					f9.ProductCode,
					f9.PayType,
					f9.CommDescription,
					SUM(f9.RecAmt) RecAmt,
					SUM(f9.AgentAmountDue) AgentAmountDue,
					SUM(f9.OpenworkAmountDue) OpenworkAmountDue,
					SUM(f9.NoAgmAmt) NoAgmAmt,
					f9.Prov,
					f9.ClawbackType,
					f9.Panel

FROM 
					bi.Finstat9_Full f9
WHERE	
					(CAST(f9.BusinessUID AS VARCHAR(255))  = @BusinessUID or @BusinessUID = 'View All')
					and (CAST(f9.Panel AS VARCHAR(255))  = @Panel or @Panel = 'View All')
GROUP BY
					f9.ProviderCode,
					f9.ProductProviderName,
					f9.ProductSubGroupName,
					f9.ProductBasisCode,
					f9.ProductBasisDescr,
					f9.ProductCode,
					f9.PayType,
					f9.CommDescription,
					f9.Prov,
					f9.ClawbackType,
					f9.Panel

/****************************************************************************

	End Of Report
																	
****************************************************************************/
/****************************************************************************

		Processing end
																		
****************************************************************************/

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH

