/**********************************************************************************************
Name	: [BI].[pr_220_Finstat10FullParam] 
Author	: E Brown
Date	: 04/02/2026

Finstat 10 Fullwith parameter value to allow Finance to filter on Business UID if required.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
Create PROCEDURE [BI].[pr_220_Finstat10FullParam]

@BusinessUID VARCHAR(255) = 'View All',
@Panel VARCHAR(255) = 'View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ErrMsg						nvarchar(4000),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@DateLastUpdated			datetime
			
/****************************************************************************

		Set initial parameters																
																		
****************************************************************************/

	set @DateLastUpdated			= getdate()
	
/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SELECT 
					f10.ProviderCode,
					f10.ProductProviderName,
					f10.ProductSubGroupName,
					f10.ProductBasisCode,
					f10.ProductBasisDescr,
					f10.ProductCode,
					f10.PayType,
					f10.CommDescription,
					SUM(f10.RecAmt) RecAmt,
					SUM(f10.AgentAmountDue) AgentAmountDue,
					SUM(f10.OpenworkAmountDue) OpenworkAmountDue,
					SUM(f10.NoAgmAmt) NoAgmAmt,
					SUM(f10.Margin1) Margin,
					SUM(f10.AGMLessMargin) AGMLessMargin,
					f10.CommDesc,
					f10.ProductType,
					f10.Descr,
					f10.Panel
					--(CAST(f10.BusinessUID AS VARCHAR(255))) BusinessUID
FROM 
					bi.Finstat10Full f10
WHERE	
					(CAST(f10.BusinessUID AS VARCHAR(255))  = @BusinessUID or @BusinessUID = 'View All')
					AND (CAST(f10.Panel AS VARCHAR(255))  = @Panel or @Panel = 'View All')
GROUP BY
					f10.ProviderCode,
					f10.ProductProviderName,
					f10.ProductSubGroupName,
					f10.ProductBasisCode,
					f10.ProductBasisDescr,
					f10.ProductCode,
					f10.PayType,
					f10.CommDescription,
					f10.CommDesc,
					f10.ProductType,
					f10.Descr,
					f10.Panel


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



