/**********************************************************************************************
Name	: [BI].[pr_221_FINANCE_Weekly_AgentView]
Author	: Luke Brigginshaw
Date	: 09/02/2024

		Agents View Weekly Download of Finance
			

AMENDMENT HISTORY
=================
Date		Author		Description
14.04.26	Edd Brown	Add is numeric clause to AgentCode column

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_221_FINANCE_Weekly_AgentView]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SELECT     REPLACE(REPLACE(REPLACE(cscv_AgentsHierarchy.AgentCode, CHAR(9),''),CHAR(10),''),CHAR(13),'') AS AgentCode,
		   CASE WHEN (COALESCE(LTRIM(RTRIM(cscv_AgentsHierarchy.ASDName)),'') in ('Pat McKenna','Owl Sales Director') AND cscv_AgentsHierarchy.AgentTypeDescription = 'Principal') THEN 'Adviser' when cscv_AgentsHierarchy.AgentTypeDescription = 'Seller' then 'Adviser' else cscv_AgentsHierarchy.AgentTypeDescription end AS AgentTypeDescription, 
		   LTRIM(RTRIM(cscv_AgentsHierarchy.AgentDesc)) AS AgentDesc, 
		   cscv_AgentsHierarchy.FirmFranchiseType, 
           cscv_AgentsHierarchy.AgentCategoryDescription, 
		   COALESCE(CASE WHEN (LEFT(mstt_Agents_3.AgentCategoryDescription, 4) = 'NASP' AND 
                      dbo.cscv_AgentsHierarchy.AgentCategoryDescription = 'Administrator') 
					  THEN 'NASP Seller' ELSE mstt_Agents_3.AgentCategoryDescription END,'') AS Agent_Cat, 
		   COALESCE(cscv_AgentsHierarchy.OscarAgentId, '') AS OscarAgentId, 
		   COALESCE(cscv_AgentsHierarchy.AgentOscarCode, '') AS AgentOscarCode, 	
		   CASE When COALESCE(LTRIM(RTRIM(cscv_AgentsHierarchy.ASDName)),'') in ('Pat McKenna','Owl Sales Director') then 
				(case when UH.UserEmploymentStatuscode not in (2,5,6) --Ignoring Left,NPW,Deceased
					and (UH.UserContractStatuscode not in (2,3,4) AND cscv_AgentsHierarchy.AgentStartDate IS NOT NULL) -- Ignoring Out of Contract,Pre-contract,Vetting and ensuring that they have a start date on Swift
					and UH.UserJobTitleCodeSeller in (52,61,62,63) then 'Active' end)
		  			when cscv_AgentsHierarchy.AgentCode = '1002505' THEN 'Left' 
					WHEN cscv_AgentsHierarchy.AgentCode = '1001364' THEN 'Left' 
					WHEN (mstt_Agents.EMAIL LIKE '%Deceased%' AND cscv_AgentsHierarchy.AgentType = 43) 
				THEN 'Left' ELSE cscv_AgentsHierarchy.CompetentStatusdescription END AS CompetentStatusdescription,
			CASE WHEN (RIGHT(dbo.mstt_Agents.SupervisorTypeCode, 2) = 'NA' AND dbo.mstt_Agents.GivesAdvice = 'Y') OR dbo.cscv_AgentsHierarchy.AgentCode = '1005202' 
				THEN 'N' ELSE dbo.mstt_Agents.GivesAdvice END AS Gives_Advice,
			cscv_AgentsHierarchy.AgentStartDate, 
			cscv_AgentsHierarchy.AgentLeftDate AS AgentLeftDat, 
			COALESCE(RTRIM(cscv_AgentsHierarchy.FirmDescn),'') AS FirmDescn,
			COALESCE(cscv_AgentsHierarchy.FirmTypeDescription, '') AS FirmTypeDescription, 
			COALESCE(cscv_AgentsHierarchy.FirmCode, '') AS FirmCode, 
			COALESCE(cscv_AgentsHierarchy.FirmOscarAgentId,'') AS FirmOscarAgentId, 
			COALESCE(cscv_AgentsHierarchy.FirmOscarCode,'') AS FirmOscarCode,
			cscv_AgentsHierarchy.FranchiseType, 
			COALESCE(RTRIM(cscv_AgentsHierarchy.RSMName),'') AS RSMName, 
			COALESCE(RTRIM(cscv_AgentsHierarchy.ASDName),'') AS ASDName, 
			COALESCE(CASE WHEN (REPLACE(REPLACE(REPLACE(mstt_Agents.EMAIL,CHAR(9),''),CHAR(10),''),CHAR(13),'') IS NULL OR REPLACE(REPLACE(REPLACE(mstt_Agents.EMAIL,CHAR(9),''),CHAR(10),''),CHAR(13),'') = '') 
				THEN REPLACE(REPLACE(REPLACE(mstt_Agents.EMAIL,CHAR(9),''),CHAR(10),''),CHAR(13),'') ELSE REPLACE(REPLACE(REPLACE(mstt_Agents.EMAIL,CHAR(9),''),CHAR(10),''),CHAR(13),'') END,'') AS Email,
		    COALESCE(mstt_Agents.ReasonForLeaving,'') AS ReasonForLeaving, 
			A.FirstDate, 
			COALESCE(CASE WHEN mstt_Agents.LicenceNumber = 'Excluded' 
				THEN '' ELSE mstt_Agents.LicenceNumber END,'') AS LicenceNumber, 
			COALESCE(CONVERT(varchar, mstt_Clients.BIRTHDATE, 103),'') AS DOB, 
			REPLACE(REPLACE(REPLACE(COALESCE(dbo.mstt_Agents.TELEPHONE,''), CHAR(9),''),CHAR(10),''),CHAR(13),'') AS Telephone, 
			Case when dbo.mstt_Agents.Salutation in ('Ocademy','Ocademy MCOB','Academy') then 'Academy' else ' ' End as Academy,
			--Case when (dbo.mstt_Agents.Salutation <> 'Ocademy' OR dbo.mstt_Agents.Salutation IS NULL) 
			--	then '' else dbo.mstt_Agents.Salutation end as Ocademy
			
			-- Gender Info
			--dbo.mstt_Agents.Title,
			--case when dbo.mstt_Agents.Title = 'Mr' Then 'M' when (dbo.mstt_Agents.Title = 'Mrs' or dbo.mstt_Agents.Title =  'Miss' or dbo.mstt_Agents.Title =  'Ms') then 'F' else 'NULL' END as 'Gender',
			REPLACE(REPLACE(REPLACE(dbo.mstt_Clients.Gender, CHAR(9),''),CHAR(10),''),CHAR(13),'') AS Gender
			                       
FROM         dbo.mstt_Agents INNER JOIN
                      dbo.cscv_AgentsHierarchy ON mstt_Agents.CODE = cscv_AgentsHierarchy.AgentCode INNER JOIN
                          (SELECT     CODE, MIN(ValidFromDate) AS FirstDate
                            FROM          dbo.mstt_AgentsHistory
                            GROUP BY CODE) AS A ON A.CODE = cscv_AgentsHierarchy.AgentCode LEFT OUTER JOIN
                      dbo.mstt_Agents AS mstt_Agents_3 ON mstt_Agents.Firm = mstt_Agents_3.CODE LEFT OUTER JOIN
                      dbo.mstt_Clients ON cscv_AgentsHierarchy.AgentCode = mstt_Clients.AgentCode LEFT OUTER JOIN -- use clients to get gender field.
                      dbo.mstt_Agents AS mstt_Agents_2 ON mstt_Agents.SpanSupervisorCode = mstt_Agents_2.CODE LEFT OUTER JOIN
                      dbo.mstt_Agents AS mstt_Agents_1 ON mstt_Agents.SaleSupervisorCode = mstt_Agents_1.CODE LEFT JOIN
					  mi_insight_UserHierarchyALLUSERS UH on UH.UserUID = dbo.cscv_AgentsHierarchy.AgentCode and UH.LatestRowInd = 1

Where cscv_AgentsHierarchy.AgentCode <> '2106332'
and ISNUMERIC(LEFT(REPLACE(REPLACE(REPLACE(cscv_AgentsHierarchy.AgentCode, CHAR(9),''),CHAR(10),''),CHAR(13),''),1)) = 1 -- EB ADDED 14.04.2026 -- umeric Adviser Codes Only


--WHERE     (NOT (cscv_AgentsHierarchy.AgentCode IN ('Jones', 'Michael','M1 3LD', 'Kurian','Tshuma', 'Rodzik','William','112 Roy'))) --AND (COALESCE(RTRIM(cscv_AgentsHierarchy.ASDName),'') <> 'Pat Mckenna')


				


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



