/**********************************************************************************************
Name	: [BI].[pr_222_FINANCE_Weekly_DailyIssuedOwl] 
Author	: Luke Brigginshaw
Date	: 09/02/2024

		Daily Issued Scan OWL v3.2.5 (Adj FIX) Download of Finance
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
02/04/2026	J Homer		Added row count to process logging

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_222_FINANCE_Weekly_DailyIssuedOwl] 

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@Process				varchar(100),
			@Client					varchar(50),
			@Module					varchar(50),
			@RowCount				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'pr_222_FINANCE_Weekly_DailyIssuedOwl'
set @StoredProcName		= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'Weekly Finance'

/****************************************************************************

	Start Process Log																
																		
****************************************************************************/


exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client



/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


SET NOCOUNT ON 
SET DATEFIRST 1;

declare @StartDate varchar(30),@EndDate varchar(30), @s3custsdate varchar(30), @s3custedate varchar(30)
declare @scan1 int, @scan3 int;
declare @s3YTD int, @s3Quart int, @s3Month int, @s3CumMonth int, @s3R12 int, @chkscan int, @prodm int, @goals int, @s3all int, @productivity int,@GI int, @daily int, @claw int, @LG int
declare @s3QuartP int, @s3PYTD int, @irec1 int, @irec2 int, @s3cust int, @s3year int
declare @adv int, @prod int, @WtoI1 int, @WtoI2 int, @MScard int
declare @adv2 int, @prod2 int, @BP1 int, @BP2 int, @inc1 int, @inc2 int
declare @APE int, @Margin int, @DA int, @Newpolicies int, @Premium int, @prom int, @OW_1 int
declare @sadv varchar(max), @odate date

--Table1%OWL Issued Protection%

------------------------------------------------------------------------------------------------
/**********************************************************************************************

There are multiple scans in this file which can be selected from the below parameters;

Scan1; the standard issued production scan with product and adviser breakdown by day for APE/Cases/DA/Margin. It uses the dates in the @startdate and @enddate parameters below.

Scan3; A scan running the data for useful periods; YTD, QUARTERLY, MONTHLY, CUMULATIVE Monthly with product and adviser breakdown.

CheckScan; A scan highlighting any dodgy cases - any entries in this table is potentially a dodgy case; run a case by case to get the details.

Scans for specific owl reports; Sets the parameters for specific scans used on the various owl BAU reports. The required scasn is referenced in the report procedures and replaces the output of scan3.
								Only 1 report specific scan can be run at a time. 
------------------------------------------------------------------------------------------------

To choose what scans you want running set the below variables to 1 or 0; 1 to include, 0 to ignore. If any report specific reports are selected these will overwrite the scan3 results.

***********************************************************************************************/

---------------------------------------------------------------------------------------------------------------------------------------------------
---------------------------------------------------------------------------------------------------------------------------------------------------
-- INCLUDE GI?
SET @GI = 1        -- Include GI = 1, Exclude GI = 0
---------------
-- INCLUDE L&G?
SET @LG = 1        -- Include L&G = 1, Exclude L&G = 0
---------------

---dates for daily scans

-----------------------------------------------------------------------------------------------------------------
set @StartDate =  DATEADD(Month,-MONTH(GETDATE())-12, DATEADD(DAY, 1, EOMONTH(GETDATE()))) -- Start of Previous Year
set @EndDate = DATEADD(day,datediff(day,0,GETDATE()),0) --CONVERT(DATETIME, '2017-06-01 00:00:00',102) 
-----------------------------------------------------------------------------------------------------------------
set @sadv =  '' -- Return results for selected adviser UIDs (set as '' for all advisers); comma sperated advisers eg '4005158,4004759,1011258'
-----------------------------------------------------------------------------------------------------------------

set @scan1 = 1 -- Standard issued  day by day scan (for daily production)

		set @adv = 1			-- Breakdown by selling adviser
		set @prod = 1			-- Breakdown by product

--------------------------------------------------------------------------

set @scan3 = 0 		-- Useful periods 
		set @s3YTD =  0		-- YTD
		set @s3PYTD = 0		-- Previous YTD
		set @s3Quart = 0    -- Current Year Quarterly
		set @s3QuartP = 0	-- Previous Year Quarterly 	
		set @s3Month = 0	-- Monthly (for previous 12 months)
		set @s3CumMonth = 0 -- Cumulative Monthly from adviser start date (for owl recruitment report)
		set @s3R12 = 0		-- Rolling 12 month (365 day) period 
		set @s3all = 0		-- All production
		set @s3year = 0		-- Yearly for the last 5 years

		set @s3cust = 0		-- Any dates (dates used below) Column headers will be called "Custom_".. 

				set @s3custsdate = CONVERT(DATETIME, '2018-08-13 00:00:00',102) -- Custom Start date (Inclusive)
				set @s3custedate = DATEADD(day,datediff(day,0,GETDATE()),0) -- Custom End date	 (Inclusive)

---------------
		--Metrics
		set @APE = 1
		set @Margin = 0
		set @DA = 0
		set @Newpolicies = 1
		set @Premium = 0

		set @adv2 = 1    -- Breakdown by selling adviser
		set @prod2 = 1   -- Breakdown by product


		
--------------------------------------------------------------------------
		set @chkscan = 0 -- Checkscan (used in all owl reports)
--------------------------------------------------------------------------
-- Scans for specific owl reports

		set @MScard = 0 -- Monthly quality scorecard (issued)
		set @irec1 = 0 	--Owl Recruitment Report Scan1 (issued)
		set @irec2 = 0	--Owl Recruitment Report Scan2 (issued)
		set @prodm = 0  --Owl Product Mix Report 
		set @goals = 0  --Owl Goals Report
		set @WtoI1 = 0  --Owl WtoI Scan1 (issued)
		set @WtoI2 = 0	--Owl WtoI Scan2 (issued) (ARCHIVED JB 15/01/19)
		set @productivity = 0	--Owl Productivity Report (Issued)
		set @daily = 0	--Owl Daily Production Report (Issued)
		set @claw = 0	--Owl Monthly Clawback Report (Issued)
		set @inc1 = 0	-- Weekly Recognition (Issued)
		set @inc2 = 0	-- Other Incentives  (Issued)


			if @inc2 = 1 
				BEGIN
					set @s3custsdate = CONVERT(DATETIME, '2018-09-24 00:00:00',102)
				END
------------------ 
-- Scans for BP reports (Paul L)

		set @BP1 = 0
		set @BP2 = 0 -- Adviser APE by year (Updated wednesday)

-- Scans for OW

		set @OW_1 = 0 -- scan for xTD production going back a few years by hierarchy (Luke)
---------------------------------------------------------------------------------------------------------------------------------------------------
---------------------------------------------------------------------------------------------------------------------------------------------------
---------------------------------------------------------------------------------------------------------------------------------------------------


If @inc1 = 1
BEGIN
	set @scan1 = 0	set @scan3 = 1 set @chkscan = 0
	set @adv = 0	set @prod = 0	
	set @GI = 1 	set @LG = 1  
	set @adv2 = 1	set @prod2 = 0
	set @APE = 1	set @Margin = 0	set @DA = 0	set @Newpolicies = 1	set @Premium = 0
	set @s3YTD =  1	set @s3PYTD = 0	set @s3Quart = 0	set @s3QuartP = 0	set @s3Month = 0	set @s3CumMonth = 0	set @s3R12 = 1	set @s3all = 0	set @s3cust = 1	set @s3year = 0

	set @odate = getdate()-5


	set @s3custsdate =  case when @odate < convert(date,'01/05/'+ convert(varchar,year(@odate)),103) then DATEADD(yy, DATEDIFF(yy, 0, @odate), 0)
						when @odate < convert(date,'01/09/'+ convert(varchar,year(@odate)),103) then convert(date,'01/05/'+ convert(varchar,year(@odate)),103)	
						else convert(date,'01/09/'+ convert(varchar,year(@odate)),103) end
	set @StartDate =  DATEADD(yy, DATEDIFF(yy, 0, @odate), 0)						
END


If @inc2 = 1
BEGIN
	set @scan1 = 0	set @scan3 = 1 set @chkscan = 0
	set @adv = 0	set @prod = 0	
	set @GI = 1 	set @LG = 1  
	set @adv2 = 1	set @prod2 = 0
	set @APE = 1	set @Margin = 0	set @DA = 0	set @Newpolicies = 1	set @Premium = 0
	set @s3YTD =  0	set @s3PYTD = 0	set @s3Quart = 0	set @s3QuartP = 0	set @s3Month = 0	set @s3CumMonth = 0	set @s3R12 = 1	set @s3all = 0	set @s3cust = 1	set @s3year = 0
	set @StartDate = @s3custsdate
END



If @claw = 1
BEGIN
	set @scan1 = 0	set @scan3 = 1 set @chkscan = 0
	set @adv = 0	set @prod = 0	
	set @GI = 0 	set @LG = 0  
	set @adv2 = 1	set @prod2 = 0
	set @APE = 1	set @Margin = 0	set @DA = 0	set @Newpolicies = 1	set @Premium = 1
	set @s3YTD =  0	set @s3PYTD = 0	set @s3Quart = 0	set @s3QuartP = 0	set @s3Month = 0	set @s3CumMonth = 0	set @s3R12 = 1	set @s3all = 1	set @s3cust = 0	set @s3year = 0
END

If @daily = 1
BEGIN
	set @scan1 = 1	set @scan3 = 0 set @chkscan = 0
	set @adv = 0	set @prod = 1	
	set @GI = 1 	set @LG = 1  
	set @adv2 = 0	set @prod2 = 0
	set @APE = 0	set @Margin = 0	set @DA = 0	set @Newpolicies = 0	set @Premium = 0
	set @s3YTD =  0	set @s3PYTD = 0	set @s3Quart = 0	set @s3QuartP = 0	set @s3Month = 0	set @s3CumMonth = 0	set @s3R12 = 0	set @s3all = 0	set @s3cust = 0	set @s3year = 0
END


If @productivity = 1
BEGIN
	set @scan1 = 0	set @scan3 = 1 set @chkscan = 0
	set @adv2 = 1	set @prod2 = 0
	set @GI = 0 	set @LG = 1  
	set @APE = 1	set @Margin = 0	set @DA = 0	set @Newpolicies = 1	set @Premium = 1
	set @s3YTD =  0	set @s3PYTD = 0	set @s3Quart = 0	set @s3QuartP = 0	set @s3Month = 0	set @s3CumMonth = 0	set @s3R12 = 1	set @s3all = 0	set @s3cust = 0	set @s3year = 0
END


If @BP1 = 1
BEGIN
	set @scan1 = 0 set @scan3 = 1 set @chkscan = 0
	set @adv2 = 1	set @prod2 = 1
