IF OBJECT_ID('tempdb..#e') IS NOT NULL DROP TABLE #e
IF OBJECT_ID('tempdb..#h') IS NOT NULL DROP TABLE #h
IF OBJECT_ID('tempdb..#prom') IS NOT NULL DROP TABLE #prom
