--create temporary table for user inputs
---------------------------------------
	  DECLARE @var TABLE(UID varchar(100)) 	
      DECLARE @x XML 

	  IF LEN(@sadv) <> 0
	  --SET ANSI_WARNINGS ON
	  BEGIN 
      SELECT @x = CAST('<A>'+ REPLACE(@sadv,',','</A><A>')+ '</A>' AS XML)     
	  INSERT INTO @var            
	  SELECT t.value('.', 'int') AS inVal  
	  FROM @x.nodes('/A') AS x(t) 
	  
	  SET ANSI_WARNINGS OFF 	
	  END

----- Manager Promotion Dates
select distinct ud.Usr_login
	   ,UPS_Jobtitle
	   ,max(UPS_Createddate) PromotionDate
	   ,ups_userid	
	  into #prom
from  sa_insight_UserDetails ud left join sa_insight_UserPositionHistory uph on uph.ups_userid = ud.Usr_id
	  left join mi_insight_UserHierarchy uh on uh.useruid = ud.Usr_login
where UPS_Jobtitle = 54 --and ud.Usr_login not like '4008363'
and UserJobTitleCodeSalesMgr = 54	
group by 
ud.Usr_login,UPS_Jobtitle,ups_userid	


select commissionmonth,policyreference
into #p
from owt_OwlDirectPayments
where source like 'L&G'
and (Transactiontype like 'Endorse%' or Transactiontype like 'New%Business')
group by commissionmonth,policyreference
having 
sum(case when sign(grosspremium)<>sign(openworkcommissionamt) then grosspremium*-1 else grosspremium end) =0



