select
'Issued' Type,
oal.sellercode,
'Advised',
'GI',case when oal.remarks like  '%Renewal%' then 'GI-REN' else 'GI-NB' end,
'GIPAYMENTSHIELD',
'GI OWL',
 convert(date,dateadd(m,1,oal.paymentdate)) Date, --offset for reporting
 day(convert(date,dateadd(m,1,oal.paymentdate))),
 Month(convert(date,dateadd(m,1,oal.paymentdate))),
 year(convert(date,dateadd(m,1,oal.paymentdate))),
 sum(oal.premium) Premium,
 sum(oal.APE) as APE,
 sum(Case when (oal.remarks like '%New Business%' and oal.CommRate >12) or oal.remarks like '%Renewal%'  then 1 else 0 end) as NewPolicies,
 sum(oal.APE) as DA, -----  GI DA = APE
 sum(oal.APE - oal.TotalPayment)  as Margin,
 ah.agentstartdate,
 svar.UID,
 oal.paymentdate,
 pr.Promotiondate
 
from msit_OpenworkAdviserListing oal
     inner join owt_PaymentshieldCommissionPayments pcp on pcp.ID = oal.SourceID and oal.Source = 'Payshield'
	 left join cscv_AgentsHierarchy ah on ah.Agentcode = oal.sellercode
	 left join @var svar on svar.uid = oal.sellercode
	 left join #prom pr on pr.Usr_login = oal.sellercode

where oal.Source = 'Payshield'
and oal.MONTH > '2015-01-01'
and oal.Provider in ('Payment Shield Owl ASM','Payment Shield Owl')
and oal.remarks not like 'CANCELLATION' 
and @GI = 1
and ((svar.uid IS NULL and len(@sadv) = 0)
or (svar.uid IS NOT NULL and len(@sadv) > 0))

group by
oal.sellercode,
case when oal.remarks like  '%Renewal%' then 'GI-REN' else 'GI-NB' end,
 convert(date,dateadd(m,1,oal.paymentdate)),
 day(convert(date,dateadd(m,1,oal.paymentdate))),
 Month(convert(date,dateadd(m,1,oal.paymentdate))),
 year(convert(date,dateadd(m,1,oal.paymentdate))),
 ah.agentstartdate,
 svar.UID,
 oal.paymentdate,
 pr.Promotiondate


--------------------------------------------------------------------------GI End


------adding hierarchy and duplicate APE (for incentives)
BEGIN

select h.Type,h.PriAdviser,h.Adminmethod,h.ProductGroupName,h.daily_category,h.productsubgroup,h.productsubtype,h.Date,h.Day,h.Month,h.Year,h.Premium,h.Newpolicies,h.DA,h.Margin,h.startdate,h.temp_uid,h.writdate,h.promotiondate

--Double APE for incentives (not weekly recognition) period 05/11/18 and 09/12/18 inclusive (JB 02/11/18)
,case when date between convert(datetime,'2018-11-05') and convert(datetime,'2018-12-09') and @inc2 = 1 then h.APE*2 else h.APE end APE

,hier.owlasmuid1 asm1
,hier.owlasmuid2 asm2
,hier.owlasmuid3 asm3
,hier.owlasmuid4 asm4
,hier.owlasmuid5 asm5
,hier.owlasmuid6 asm6
,case when h.promotiondate is null or h.writdate <= convert(date, h.promotiondate) then 'Adviser' 
	  when h.writdate > convert(date, h.promotiondate) then 'Manager'
	  end PriStatus
,case when date between convert(datetime,'2018-11-05') and convert(datetime,'2018-12-09') and  @inc2 = 1 then '0-2' else  '0' end dupe --(0-2 = double APE flag)
into #i
from #h h left join
mi_insight_UserHierarchyAllUsers hier on convert(varchar,hier.UserUID) = h.Priadviser
				 and convert(date,h.writdate) >= hier.effectivestartdate and convert(date,h.writdate) <= hier.effectiveenddate

union all

-- duplicate ape for new managers in incentive period
----
select h.Type,h.PriAdviser,h.Adminmethod,h.ProductGroupName,h.daily_category,h.productsubgroup,h.productsubtype,h.Date,h.Day,h.Month,h.Year,h.Premium,h.Newpolicies,h.DA,h.Margin,h.startdate,h.temp_uid,h.writdate,h.promotiondate

--Double APE for incentives (not weekly recognition) period 05/11/18 and 09/12/18 inclusive (JB 02/11/18)
,case when date between convert(datetime,'2018-11-05') and convert(datetime,'2018-12-09') and @inc2 = 1 then h.APE*2 else h.APE end APE
 
,hier.owlasmuid1 asm1
,hier.owlasmuid2 asm2
,hier.owlasmuid3 asm3
,hier.owlasmuid4 asm4
,hier.owlasmuid5 asm5
,hier.owlasmuid6 asm6

,case when h.promotiondate is null or h.writdate <= convert(date, h.promotiondate) then 'Manager' 
	  when h.writdate > convert(date, h.promotiondate) then 'Adviser'
	  end PriStatus

,case when date between convert(datetime,'2018-11-05') and convert(datetime,'2018-12-09') and  @inc2 = 1 then '1-2' else '1' end dupe --(1-2 = double APE flag)

from #h h left join
mi_insight_UserHierarchyAllUsers hier on convert(varchar,hier.UserUID) = h.Priadviser
				 and convert(date,h.writdate) >= hier.effectivestartdate and convert(date,h.writdate) <= hier.effectiveenddate

where  h.promotiondate >= DATEADD(yy, DATEDIFF(yy, 0, @startdate)-2, 0)
	  and (@inc2 = 1 or @inc1 = 1)	


----
-----Final summary table with full hierarchy

select Type
,cast(case when Priadviser = '4007583' then '4007584' when Priadviser= '1012011' then '1012002' else Priadviser end as int) PriAdviser
,Adminmethod,Productgroupname,Productsubgroup,productsubtype,daily_category
,Date,Day,Month,Year
,Premium,APE,Newpolicies,DA,Margin,Startdate,Temp_uid	   	
,dupe,
-- Reporting hierarchy
case when  asm1 is null and asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
	 when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm2
	 when  asm4 is null and asm5 is null and asm6 is null then asm3
	 when  asm5 is null and asm6 is null then asm4
	 when  asm6 is null then asm5
end L0,

case when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
	 when  asm2 is null and asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm4 is null and asm5 is null and asm6 is null then asm2
	 when  asm5 is null and asm6 is null then asm3
	 when  asm6 is null then asm4
end L1,

case when  asm3 is null and asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
	 when  asm3 is null and asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm5 is null and asm6 is null then asm2
	 when  asm6 is null then asm3
end L2,

case when  asm4 is null and asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
     when  asm4 is null and asm5 is null and asm6 is null then asm1
	 when  asm5 is null and asm6 is null then asm1
	 when  asm6 is null then asm2
end L3,

case when  asm5 is null and asm6 is null and Pristatus <> 'Adviser' then Priadviser
	 when  asm5 is null and asm6 is null then asm1
	 when  asm6 is null then asm1
end L4
into #g

from #i 

END

-------------------------------------------------------------------------- Hierarchy end
------------------------------------------------------ Scan Manager 
--Scan1 
 ----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
IF @scan1 = 1

BEGIN

DECLARE @CMD AS VARCHAR(MAX)
DECLARE @COL AS VARCHAR(MAX)

SET @CMD = 'SELECT '
DECLARE COLUMN_CURSOR CURSOR FOR
SELECT COLUMN_NAME 



FROM tempdb.INFORMATION_SCHEMA.[COLUMNS] 
WHERE TABLE_NAME like '%#g%'
	   and column_name not like '%tdate%'
	   and column_name not like '%promo%'
	   and column_name not like '%temp_uid%'	
	   and (column_name not like '%priad%' or @adv <> 0)
	   and (column_name not like '%product%' or @prod <> 0)
	   and (column_name not like '%dupe%' or (@inc1 <> 0 and @inc2 <> 0))
	   and ((column_name not like '%dupe%' and column_name not like 'L%' and column_name not like 'productsubt%')  or @daily = 0)
	   and (column_name not like '%priad%' or @adv <> 0)


OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0
BEGIN 
	 IF @COL IN ('Premium','APE','NewPolicies','DA','Margin')
		SET @CMD = @CMD + 'Sum('+ @COL + ') ' + @COL+ ','
	 ELSE IF @COL IN ('Date')
		SET @CMD = @CMD + 'CONVERT(varchar(10),' + @COL + ',103) Date,' 
	 ELSE
		SET @CMD = @CMD + @COL + ','
	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL
END

BEGIN
	 SET	@CMD = left(@CMD,len(@CMD)-1)
	 SET    @CMD = @CMD + ' INTO ##Table '
	 SET	@CMD = @CMD + ' FROM #g '
	 SET	@CMD = @CMD + ' WHERE #g.Date >=  CONVERT(DATETIME,''' + @startdate +  ''',103) and #g.Date <=  CONVERT(DATETIME,''' + @enddate +  ''',103)' + ' GROUP BY '

END
CLOSE COLUMN_CURSOR

OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0
BEGIN
	 IF @COL IN ('Date')
		SET @CMD = @CMD + 'CONVERT(varchar(10),' + @COL + ',103),' 
	 ELSE IF @COL NOT IN ('Premium','APE','NewPolicies','DA','Margin')
		SET @CMD = @CMD + @COL + ','

	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL
END

SET	@CMD = left(@CMD,len(@cmd)-1)
SET @CMD = @CMD + ' ORDER BY [YEAR] desc, [MONTH] desc, [DAY] desc'
CLOSE COLUMN_CURSOR
DEALLOCATE COLUMN_CURSOR
EXEC (@CMD)

END
--------------------------------------------------------------------------------------------------------------------
---- Scan3

If @scan3 = 1
BEGIN
SET @CMD = 'SELECT '
DECLARE COLUMN_CURSOR CURSOR FOR
SELECT COLUMN_NAME FROM tempdb.INFORMATION_SCHEMA.[COLUMNS] 
WHERE TABLE_NAME like '%#g%'
	   and column_name not like '%date%' and column_name not like '%temp%' and column_name not like '%admin%'
       and column_name not like '%Day%' and column_name not like '%Month%' and column_name not like '%Year%'
	   and column_name not like '%Daily_%'
	   and (column_name not like '%priad%' or @adv2 <> 0)
	   and (column_name not like '%product%' or @prod2 <> 0)
	   and (column_name not like '%APE%' or @APE <> 0)
	   and (column_name not like '%policies%' or @Newpolicies <> 0)
	   and (column_name not like 'DA' or @DA <> 0)
	   and (column_name not like '%Margin%' or @Margin <> 0)
	   and (column_name not like 'Premium%' or @Premium <> 0)
	   and (column_name not like '%dupe%' or @inc1 <> 0 or @inc2 <> 0)
	   and (column_name not like 'L%' or ((@prodm <> 1 and @irec1 <>1 and @irec2<>1 and @claw<>1) or @OW_1 <>0))
	   and (column_name not like 'productsubg%' or (@prodm <> 1 or @WtoI1 <>1))
		

IF @BP2 = 1 -- additional columns for BP2
	BEGIN
		SET	@CMD = @CMD + 'uh.agentdesc, uh.competentstatusdescription, ' 
	END	 

OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0

BEGIN 

	 IF @COL IN ('Premium','APE','NewPolicies','DA','Margin')
		--YTD
		BEGIN 
		BEGIN	 IF @s3YTD = 1
					BEGIN
					SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0)) then #g.' + @COL + ' else 0 end) YTD_' + @COL + ','
					END
		END	

		--Previous YTD
		BEGIN	 IF @s3PYTD = 1
					BEGIN
					SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0)) and #g.date <convert(datetime,DATEADD(yy,-1, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) PrevYTD_' + @COL + ','
					END

				 	
					-- Additional YTD for OW_1

					IF @OW_1 = 1
						BEGIN
						SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-0, 0)) and #g.date <convert(datetime,DATEADD(yy,-0, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) ''' + convert(varchar,year(DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-0, 0)))+ 'YTD_' + @COL + ''','
						SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0)) and #g.date <convert(datetime,DATEADD(yy,-1, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) ''' + convert(varchar,year(DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0)))+ 'YTD_' + @COL + ''','
						SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-2, 0)) and #g.date <convert(datetime,DATEADD(yy,-2, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) ''' + convert(varchar,year(DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-2, 0)))+ 'YTD_' + @COL + ''','
						SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-3, 0)) and #g.date <convert(datetime,DATEADD(yy,-3, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) ''' + convert(varchar,year(DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-3, 0)))+ 'YTD_' + @COL + ''','
						SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-4, 0)) and #g.date <convert(datetime,DATEADD(yy,-4, convert(date,GETDATE())))  then #g.' + @COL + ' else 0 end) ''' + convert(varchar,year(DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-4, 0)))+ 'YTD_' + @COL + ''','

						END

		END	

		-- R12 Month
		BEGIN	IF @s3R12 = 1
					BEGIN
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(dd, DATEDIFF(dd, 0, GETDATE())-365, 0) then #g.' + @COl + ' else 0 end) as R12Month' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(dd, DATEDIFF(dd, 0, GETDATE())-183, 0) then #g.' + @COl + ' else 0 end) as R6Month' + @COL + ','
					END
		END	


		-- Yearly (Previous 5 Years)
		BEGIN	IF @s3Year = 1
					BEGIN  
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-7 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-7)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-6 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-6)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-5 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-5)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-4 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-4)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-3 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-3)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-2 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-2)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-1 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-1)  + '_' + @COL + '''' + ','
					SET @CMD = @CMD + 'sum(case when #g.year = year(getdate())-0 then #g.' + @COL + ' else 0 end) as ' + '''' + convert(varchar,year(getdate())-0)  + '_' + @COL + '''' + ','
					END
		END

		-- Current Year Quarterly
		BEGIN	IF @s3Quart = 1
					BEGIN  
					SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0)) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+3, 0) then #g.' + @COL + ' else 0 end) as Q1_' + @COL +','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+3,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+6, 0) then #g.' + @COL + ' else 0 end) as Q2_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+6,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+9, 0) then #g.' + @COL + ' else 0 end) as Q3_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+9,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0))+12, 0) then #g.' + @COL + ' else 0 end) as Q4_' + @COL +','
					END
		END
		
		-- Previous Year Quarterly
		BEGIN	IF @s3QuartP = 1
					BEGIN  
					SET @CMD = @CMD + 'sum(case when #g.date >=convert(datetime,DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0)) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+3, 0) then #g.' + @COL + ' else 0 end) as PrevQ1_' + @COL +','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+3,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+6, 0) then #g.' + @COL + ' else 0 end) as PrevQ2_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+6,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+9, 0) then #g.' + @COL + ' else 0 end) as PrevQ3_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+9,0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0))+12, 0) then #g.' + @COL + ' else 0 end) as PrevQ4_' + @COL +','
					END
		END 
		
		-- Custom Dates
		BEGIN	IF @s3cust = 1
					BEGIN  
					SET @CMD = @CMD + 'sum(case when #g.date >=''' + @s3custsdate + ''' and #g.date <=''' + @s3custedate + ''' then #g.' + @COL + ' else 0 end) as Custom_' + @COL +','
					END
		END

		
				-- All Production
		BEGIN	IF @s3all = 1
					BEGIN  
					SET @CMD = @CMD + 'sum(#g.' + @COL + ') as All_' + @COL +','
					END
		END   

				-- Monthly
		BEGIN 
				IF @s3Month = 1
					BEGIN
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())+1, 0)	then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0),107),2)  + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-1, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0)	then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-1, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-1, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-2, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-1, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-2, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-2, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-3, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-2, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-3, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-3, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-4, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-3, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-4, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-4, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-5, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-4, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-5, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-5, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-6, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-5, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-6, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-6, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-7, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-6, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-7, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-7, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-8, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-7, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-8, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-8, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-9, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-8, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-9, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-9, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-10, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-9, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-10, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-10, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-11, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-10, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-11, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-11, 0),107),2) + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-12, 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-11, 0) then #g.' + @COL + ' else 0 end) as ' + left(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-12, 0),107),3) + right(convert(varchar,DATEADD(mm, DATEDIFF(mm, 0, GETDATE())-12, 0),107),2) + @COL + ','
					END
		END

	
				BEGIN 
				IF @s3CumMonth = 1
					BEGIN
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*1, #g.startdate)+1 then #g.' + @COl + ' else 0 end) as Mn1_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*2, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn2_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*3, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn3_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*4, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn4_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*5, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn5_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*6, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn6_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*7, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn7_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*8, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn8_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*9, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn9_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*10, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn10_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*11, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn11_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*12, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn12_' + @COL + ','
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(dd, 28*13, #g.startdate)+1 then #g.' + @COl + ' else 0 end)  as Mn13_' + @COL + ','
					END
		END

		-- Additional periods for recruitment report - Total production, first 6 months from adviser start date
		
		BEGIN 
				IF @irec1 = 1
				-- Total Production 
					BEGIN
					SET @CMD = @CMD + 'sum(#g.' + @COl + ') as Total_Iss' + @COL + ','

				-- First 6 months from adviser start date
					SET @CMD = @CMD + 'sum(case when #g.date < DATEADD(mm, 6, #g.startdate)+1 then #g.' + @COl + ' else 0 end) as First6Mnth' + @COL + ','
					END

		END

				-- Additional periods for WtoI2 scan (Current MTD, Current Week TD (Monday onwards)

		BEGIN 
				IF @WtoI2 = 1
					BEGIN
					-- Current MTD
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(mm, DATEDIFF(mm, 0, GETDATE()), 0) and #g.date < DATEADD(mm, DATEDIFF(mm, 0, GETDATE())+1, 0)	then #g.' + @COL + ' else 0 end) as Curr_MTD' + @COL + ','
					
					-- Current Week TD (Monday onwards)
					SET @CMD = @CMD + 'sum(case when #g.date >= DATEADD(dd, DATEDIFF(dd, 0, dateadd(day,-datepart(weekday,getdate())+1,getdate())), 0) then #g.' + @COL + ' else 0 end) as Curr_WeekTD'  + @COL + ','
					
					END
		END
		END

	 ELSE IF @COL IN ('%Date%')
		BEGIN
		SET @CMD = @CMD + 'CONVERT(varchar(10),#g.' + @COL + ',103) Date,'
		END
	 ELSE
		BEGIN
		SET @CMD = @CMD + '#g.' + @COL + ','
		END
	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL	 
END
BEGIN
	 SET	@CMD = left(@CMD,len(@CMD)-1)

	 IF @BP2 <> 1
		BEGIN
			SET	@CMD = @CMD + ' FROM #g GROUP BY '
		END
	 ELSE
	 BEGIN
		SET	@CMD = @CMD + ' FROM #g left join cscv_AgentsHierarchy uh on convert(varchar,uh.agentcode) = convert(varchar,#g.Priadviser) and convert(varchar,uh.asdcode) in(''4005013'', ''4021409'') Group by uh.agentdesc, uh.competentstatusdescription, ' 
	 END
END

CLOSE COLUMN_CURSOR

OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0
BEGIN
	 IF @COL IN ('%Date%')
		SET @CMD = @CMD + 'CONVERT(varchar(10),#g.' + @COL + ',103),' 
	 ELSE IF @COL NOT IN ('Premium','APE','NewPolicies','DA','Margin')
		SET @CMD = @CMD + '#g.' + @COL + ','

	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL
END

SET	@CMD = left(@CMD,len(@cmd)-1)
CLOSE COLUMN_CURSOR
DEALLOCATE COLUMN_CURSOR

---- run final table

EXEC (@CMD)
END

------Checkscan
if @chkscan = 1
	BEGIN
	select #g.priadviser, #g.productsubgroup, convert(date,#g.date) as date, sum(case when #g.newpolicies = 0 then 0 when #g.newpolicies<0.1 then 0 else #g.margin/#g.newpolicies end) as 'marg/case' 
	from #g		
	where #g.date > DATEADD(dd, DATEDIFF(dd, 0, GETDATE())-5, 0)
	group by 

	#g.priadviser, #g.productsubgroup, convert(date,#g.date)

	having sum(case when #g.newpolicies = 0 then 0 when #g.newpolicies<0.1 then 0 else #g.margin/#g.newpolicies end) >= 5000
	END



If len(@sadv) = 0 BEGIN SET ANSI_WARNINGS ON; END

IF OBJECT_ID('tempdb..#b') IS NOT NULL DROP TABLE #b
IF OBJECT_ID('tempdb..#g') IS NOT NULL DROP TABLE #g
IF OBJECT_ID('tempdb..#i') IS NOT NULL DROP TABLE #i
IF OBJECT_ID('tempdb..#e') IS NOT NULL DROP TABLE #e
IF OBJECT_ID('tempdb..#h') IS NOT NULL DROP TABLE #h
IF OBJECT_ID('tempdb..#prom') IS NOT NULL DROP TABLE #prom
IF OBJECT_ID('tempdb..#p') IS NOT NULL DROP TABLE #p


/*  WRITE TO TABLE */

-- Empty existing table
 
delete from [BI].[FINANCE_Weekly_DailyIssuedOwl]
 
-- Write new data to table

insert into [BI].[FINANCE_Weekly_DailyIssuedOwl]

Select  * 

from ##Table

/****************************************************************************

	End Process Log																
																		
****************************************************************************/


	set @RowCount = @@rowcount
	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount	


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



