/**********************************************************************************************
Name	: [BI].[pr_223_FINANCE_Weekly_DailyWrittenOwl] 
Author	: Luke Brigginshaw
Date	: 09/02/2026

		Daily Written Scan OWL v3.2.5 for finance weekly download
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
02/04/2026	J Homer		Added row count to process logging

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_223_FINANCE_Weekly_DailyWrittenOwl]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@Process				varchar(100),
			@Client					varchar(50),
			@Module					varchar(50),
			@RowCount				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'pr_223_FINANCE_Weekly_DailyWrittenOwl'
set @StoredProcName		= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'Weekly Finance'

/****************************************************************************

	Start Process Log																
																		
****************************************************************************/


exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


/******************************************************************* WEEKLY WRITTEN *******************************************************************
1a) Date variables
1b) Other variables
2a) Warnings, delete temp tables AND datefirst format
2b) create temporary table for user inputs
3a) CREATE #PMargin: Panel Margin Adjustments
3b) CREATE #PROD: Product Code
3c) CREATE #PROM --- Manager Promotion Dates
4)  CREATE #OWL: UNION QUERY
		4a) Part 1 of UNION :STANDARD OWL WRITTEN SCAN
		4b) Part 2 of UNION : OWS L&G ASU PRODUCT
5)  CREATE #HIER: UNION QUERY
		5a) Part 1 of UNION: Hierarchy 
		5b) Part 2 of UNION: Duplicate APE for new managers in incentive period
6)  CREATE #WritDataWtoI: THE FINAL TABLE
		6a) CREATE# WritDataWtoI
		6b) Add the values into the #WritDataWtoI
--FINAL TIDY UP	
*************************************************************************************************************************************************************************/
SET NOCOUNT ON; SET DATEFIRST 1; SET ANSI_WARNINGS OFF;
--1a)Date Variables
DECLARE @RunDate datetime, @ExclDate varchar(30), @StartDate varchar(30),@EndDate varchar(30), @StartDate2 varchar(30), @EndDate2 varchar(30)
	SET @RunDate =  (DATEADD(day,datediff(day,0,GETDATE()),0))		-- Sets scan rundate for aggregated periods (Data will run up to this date - useful for year END reports)
	SET @ExclDate =  CONVERT(DATETIME, '2020-01-01 00:00:00',102)	-- Exclude incorrect mortgage CASEs up to 01-01-2020
	SET @StartDate = DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-2, 0)  --WtoI
	SET @EndDate = (DATEADD(day,datediff(day,0,GETDATE()),0)) 
	SET @StartDate2  = CONVERT( DATETIME, DATEADD(Month,-MONTH(GETDATE())-12, DATEADD(DAY, 1, EOMONTH(GETDATE())))) 
	SET @EndDate2 = @RunDate 
	
--1b) Other Variables ----------------------------------------------------------------------------------------------------------------------------------
DECLARE @sadv varchar(max), @hier int ,@daily2 int ,@inc1 int, @inc2 int
	SET @sadv =  '' -- Return results for SELECTed adviser UIDs (set as '' for all advisers); comma sperated advisers eg '4005158,4004759,1011258'
	SET @hier = 0	
	SET @daily2 = 0 --Owl Daily Production Report for written table2. Excludes L&GASU, all CASEs by current panel advisers (written)
---------------------------------------------------------------------------------------------------------------------------------------------------
If len(@sadv) = 0 BEGIN SET ANSI_WARNINGS OFF; END

--2a) Warnings, delete temp tables AND datefirst format ------------------------------------------------------------------------------------------------------------
	IF OBJECT_ID('tempdb..#PROD')		IS NOT NULL DROP TABLE #PROD
	IF OBJECT_ID('tempdb..#WW')			IS NOT NULL DROP TABLE #WW
	IF OBJECT_ID('tempdb..#OWL')		IS NOT NULL DROP TABLE #OWL
	IF OBJECT_ID('tempdb..#HIER')		IS NOT NULL DROP TABLE #HIER
	IF OBJECT_ID('tempdb..#PROM')		IS NOT NULL DROP TABLE #PROM
	IF OBJECT_ID('tempdb..#PMargin')	IS NOT NULL DROP TABLE #PMargin
	IF OBJECT_ID('tempdb..#Table')	IS NOT NULL DROP TABLE #Table

	SET DATEFIRST 1;

--2b)create temporary table for user inputs-----------------------------------------------------------------------------------------------------------------------
	DECLARE @var TABLE(UID varchar(100)) 	
	DECLARE @x XML 

	SET ANSI_WARNINGS ON
	IF LEN(@sadv) <> 0
		  BEGIN 
			  SELECT @x = CAST('<A>'+ REPLACE(@sadv,',','</A><A>')+ '</A>' AS XML)     
INSERT INTO @var            
			  SELECT t.value('.', 'int') AS inVal  
			  FROM @x.nodes('/A') AS x(t) 	

			  SET ANSI_WARNINGS OFF
		  END
--3a) CREATE #PMargin: Panel Margin Adjustments -----------------------------------------------------------------------------------------------------------------
	SELECT
		comm.TransactionID
		,[AdditionalPayaway] = FixedAmount * (  (cr.UpfrontASM+cr.UpfrontESM+cr.UpfrontIntro+cr.DeferredASM+cr.DeferredESM+cr.DeferredIntro)  /100) 
INTO #PMargin
	FROM dbo.mstt_Commissions					as comm
	JOIN mstt_transagentsplithierarchyhistory	as tashh	on tashh.TransactionID = comm.TransactionID AND tashh.AgentCode = comm.AGENT_CODE AND comm.CommissionType = tashh.CommissionType
	JOIN (  SELECT DISTINCT [EnterpriseUID],Panel 
			FROM [prod_zurich_openwork_datawarehouse].[BI].[OwlEvoSwiftUpliftRates]
		 )										as ol		on ol.EnterpriseUID = tashh.FranchiseAgentCode
	JOIN  OwlEvolution.ConfigRates				as cr		on cr.Panel = ol.Panel AND cr.UpliftRate = franchiseupliftpercent AND cr.ProductOrganization != 'Accruals'
	WHERE comm.Commissiontype = 1 AND poltrantranstype in (39) AND comm.ProductProviderCode NOT LIKE '%Owl'

--3b) CREATE #PROD: Product Code (was #c) ----------------------------------------------------------------------------------------------------------------------
	SELECT
			  [TransactionID]		= MIN(TransactionID)
			, po.PolicyRef
			, po.CONT_NUM
			, co.ProductCode
INTO #PROD
	FROM				dbo.mstt_Commissions				as co 
		INNER JOIN		dbo.mstt_PolicyTransactions			as pt  on pt.ID = co.TransactionID 
		INNER JOIN		dbo.mstt_Policies					as po  on po.POL_NUM = co.PolicyID 
		LEFT OUTER JOIN dbo.mstt_ProductHierarchy			as ph  on ph.ProductCode = co.ProductCode 
		LEFT OUTER JOIN dbo.mstt_ProductProviders			as pp  on pp.ProductProviderCode = po.COMP_CODE 
		LEFT OUTER JOIN dbo.msit_CodeReportingProductCode	as wr  on wr.Code = ph.ReportingProductCode 
		LEFT OUTER JOIN dbo.msit_CodeCommissionShape		as ccs on ccs.id = pt.CodeCommissionShapeID 
		LEFT OUTER JOIN mstt_agents							as ag  on pt.agentcode = ag.code
	WHERE
		co.agent_code NOT IN ('10002','1011542','10004')
		AND co.CommissionType = 1
		AND co.PolTranTransType = 39
		AND (ph.ProductGroupName <> 'GI' OR ph.ProductGroupName IS NULL)
		AND (LEFT(ccs.[Description],3) <> 'IMP' OR ccs.[Description] IS NULL)
		AND (LEFT(ccs.[Description],2) <> 'UA' OR ccs.[Description] IS NULL)
		AND po.PolicyRef NOT LIKE '800%' -- ignoring split multi-protect CASEs
	GROUP BY po.policyref, po.cont_num, co.productcode
--3c) CREATE #PROM --- Manager Promotion Dates  ----------------------------------------------------------------------------------------------------
	SELECT DISTINCT 
			  ud.Usr_login
			, UPS_Jobtitle
			, [PromotionDate] = MAX(UPS_Createddate) 
			, UPS_UserID	
INTO #PROM
	FROM			sa_insight_UserDetails			as ud 
		LEFT JOIN	sa_insight_UserPositionHistory	as uph on uph.UPS_UserID = ud.Usr_id
		LEFT JOIN	mi_insight_UserHierarchy		as uh on uh.UserUID = ud.Usr_login
	WHERE		UPS_Jobtitle = 54 AND UserJobTitleCodeSalesMgr = 54	
	GROUP BY	ud.USR_Login,UPS_Jobtitle,UPS_UserID	
	HAVING MAX(UPS_CreatedDate) < @RunDate

--4) CREATE #OWL: (was #h)  --------------------------------------------------------------------------------------------------------------------------
/*	Type	PriAdviser	AdminMethod	ProductGroupName	ProductSubGroup	productsubtype	Date		Day	Month	Year	Premium	APE		NewPolicies	DA		Margin	StartDate				Temp_UID	daily_category	PromotionDate			personID	policyID	ProductGroupName2
	Written	4005118		Advised		Protection			LPP OWL			LPZURICH OWL	2015-03-06	6	3		2015	99.48	99.48	1			263.6	88.03	2014-11-01 00:00:00.000	NULL		LP OWL			016-12-01 13:33:15.410	238781		550189655	Level Protection Plan*/


SET ANSI_WARNINGS OFF;
--4a) Part 1 of UNION:STANDARD OWL WRITTEN SCAN
		SELECT 
				 [Type]				= 'Written'
				, wr.PriAdviser
				, wr.AdminMethod
				,[ProductGroupName] =  wr.ProductGroupName 
				,[ProductSubGroup]	= CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END 
				, wr.productsubtype
				,[Date]				= wr.WrittenDate 
				,[Day]				= DAY(wr.WrittenDate) 
				,[Month]			= MONTH(wr.WrittenDate) 
				,[Year]				= YEAR(wr.WrittenDate) 
				,[Premium]			= SUM(CASE WHEN wr.frequency = 'Single' THEN wr.APE * 10 ELSE wr.APE END)
				,[APE]				= SUM(wr.APE) 
				,[NewPolicies]		= SUM(wr.NBCASEs) 
				,[DA]				= SUM(wr.DistributionAllowance) 
				,[Margin]			= SUM(wr.Margin)  
				, wr.StartDate
				, wr.Temp_UID
				, wr.daily_category
				, #PROM.PromotionDate
				, wr.personID
				, wr.policyID
				, wr.ProductGroupName2
INTO #OWL
		FROM	(SELECT  
					 [Adviser]				= CAST(co.AGENT_CODE as int)
					,[PriAdviser]			= CAST(pt.AGENTCODE as int)
					,[ProductSubType]		= CASE	WHEN ph.ProductProviderCode LIKE 'METLIFE%' AND ph.ProductSubGroupName LIKE 'Term %' THEN 'A&HMETLIFE' 
											  ELSE
													  CASE	WHEN ph.ProductSubGroupName LIKE 'Income %' THEN 'IP'
															WHEN ph.ProductSubGroupName LIKE 'Term %' OR ph.ProductSubGroupName LIKE 'Whole o%' THEN 'LP'
															ELSE ph.ProductSubGroupName END 
											+ ph.ReportingProductProviderCode END
					,[Daily_Category]		= CASE	WHEN ph.ProductProviderCode LIKE 'METLIFE%' AND ph.ProductSubGroupName LIKE 'Term %' THEN 'A&H '
													WHEN ph.ProductSubGroupName LIKE 'Income %' THEN 'IP '
													WHEN ph.ProductSubGroupName LIKE 'Term %'  THEN 'LP '
													WHEN ph.ProductSubGroupName LIKE 'Whole o%' THEN 'WOL '
											ELSE ph.ProductSubGroupName END  
											+ CASE WHEN ph.ProductProviderCode LIKE '%OWL%' THEN 'OWL' ELSE 'PANEL' END		  
					,[WrittenDate]			= CAST(MIN(ISNULL(s.DateSubmitted,pt.WrittenDate)) as date) 
					,[APE]					= ROUND((CASE WHEN (ph.ProductGroupName = 'Mortgage' AND ccs.Description IS NULL) 
														 THEN ((pt.MortgageAmount * (co.Agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) 
					,[DistributionAllowance]= ROUND(MIN(CASE WHEN (ph.ProductGroupName = 'Protection' AND ccs.Description IS NULL) THEN co.Turnover * 2.2 
															 WHEN (ph.ProductGroupName = 'Mortgage' AND ccs.Description IS NULL) THEN ((pt.MortgageAmount * (co.Agent_Perc/100)) * 0.0045) 
															 ELSE co.DistributionAllowance END),2) 
					,[Margin]				= ROUND(MIN(CASE WHEN (ph.ProductGroupName = 'Protection' AND ccs.Description IS NULL) THEN ((co.Turnover * 2.2) *0.3) 
															 WHEN (ph.ProductGroupName = 'Mortgage' AND ccs.Description IS NULL) 
															 THEN (((pt.MortgageAmount * (co.agent_perc/100)) * 0.0045) * 0.1) 
															 ELSE (co.SalesMargin) END),2)
											 - ISNULL(SUM(pm.additionalpayaway),0)	
					,[NBCASEs]				= MAX(CASE WHEN co.TransactionID = #PROD.TransactionID THEN (co.Agent_Perc/100) ELSE 0 END) 
					,[AllCASEs]				= MAX((co.agent_perc/100))
					,[Frequency]			= MIN(pt.FrequencyDescription) 
					,[AdminMethodDescription] = MIN(co.AdminMethodDescription) 
					,[ProductCode]			= MIN(co.ProductCode) 
					,[ProductSubGroupName]	= MIN(ph.ProductSubGroupName) 
					,[ProductGroupName]		= MIN(ph.ProductGroupName)
					,[ProductGroupName2]	= MIN(pmv.DisplayName) 	
					,[AdminMethod]			= MIN(CASE WHEN ((ph.ProductGroupName <> 'Mortgage' AND co.AdminMethod NOT IN ('A','G'))) THEN 'Non Advised' ELSE 'Advised' END) 
					,[StartDate]			= ah.agentStartDate 
					, Temp_UID				= svar.UID 
					, s.personID
					, p.policyID
--STILL SubQ of 4a)
FROM            dbo.mstt_Commissions			as co  
					INNER JOIN  dbo.mstt_PolicyTransactions			as pt   on pt.ID = co.TransactionID 
					INNER JOIN  dbo.mstt_Policies					as po   on po.POL_NUM = co.PolicyID 
					LEFT JOIN   dbo.mstt_ProductHierarchy			as ph   on ph.ProductCode = co.ProductCode 
					LEFT JOIN   dbo.mstt_ProductProviders			as pp   on pp.ProductProviderCode = po.COMP_CODE 
					LEFT JOIN   dbo.msit_CodeCommissionShape		as ccs  on ccs.ID = pt.CodeCommissionShapeID 
					LEFT JOIN   #PROD								as #PROD    on #PROD.TransactionID = co.TransactionID 
					LEFT JOIN   cscv_AgentsHierarchy				as ah   on ah.agentcode = pt.AgentCode 
					LEFT JOIN   sa_ows_Policies						as p    on p.PolicyID = po.PolicyRef 
					LEFT JOIN   sa_ows_Sale							as s    on s.SaleID = p.SaleID 
					LEFT JOIN   @var								as svar on svar.UID = pt.AGENTCODE 
					LEFT JOIN   mi_insight_UserHierarchyAllUsers	as uh2 on uh2.UserUID = pt.AgentCode AND pt.WrittenDate BETWEEN uh2.EffectiveStartDate AND uh2.EffectiveEndDate 
					LEFT JOIN   #PMargin							as pm   on pm.TransactionID = pt.id
						-- Excluding panel advisers (@Daily2)
					LEFT JOIN (	SELECT UserUID 
								FROM mi_insight_userhierarchyallusers WHERE effectiveenddate >GETDATE() AND userjobtitlecodeseller = '61'
								)									as pan		on pan.UserUID = pt.AGENTCODE AND @daily2 <>0
					LEFT JOIN staticdata.sa_ows_ProductMergeView	as pmv on pmv.internalproductid = p.internalproductid
				WHERE	co.AGENT_CODE not in ('10002','1011542','10004')
					AND co.CommissionType = 1
					AND co.PolTranTransType = 39
					AND (co.AdminMethodDescription <> 'Indexation' OR co.AdminMethodDescription IS NULL)
					AND (LEFT(ccs.[Description],3) <> 'IMP' OR ccs.[Description] IS NULL)
					AND (LEFT(ccs.[Description],2) <> 'UA' OR ccs.[Description] IS NULL)
					AND ((RTRIM(uh2.ADName) in( 'Pat Mckenna','Owl Sales Director') OR RTRIM(ah.ASDName) in( 'Pat Mckenna','Owl Sales Director')) OR co.AGENT_CODE in ('1011623','1011629','1011630','1011631','1011632','1011633','1011634','1011635'))---OWL POT ACCOUNT NOT COUNTED
					AND (po.PolicyRef not in ('500020430','500020431') OR po.PolicyRef IS NULL)
					AND ISNULL(s.DateSubmitted,pt.WrittenDate) >= CONVERT(datetime, @StartDate2,103)
					AND ISNULL(s.DateSubmitted,pt.WrittenDate) <= CONVERT(datetime, @Enddate2,103)
					AND ((svar.UID IS NULL AND LEN(@sadv) = 0) OR (svar.UID IS NOT NULL AND LEN(@sadv) > 0))
					AND ((@daily2 <>0 AND pan.userUID IS NULL) OR @daily2=0)
				GROUP BY
					 CAST(co.AGENT_CODE as int)
					,CAST(pt.AGENTCODE as int)
					,ROUND((CASE WHEN (ph.ProductGroupName = 'Mortgage' AND ccs.Description IS NULL) THEN ((pt.MortgageAmount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2)
					,po.PolicyRef
					,po.CONT_NUM
					,ah.AgentStartDate
					,svar.[UID]
					,CASE WHEN ph.ProductProviderCode LIKE 'METLIFE%' AND ph.ProductSubGroupName LIKE 'Term %' THEN 'A&HMETLIFE' ELSE
							 CASE WHEN ph.ProductSubGroupName LIKE 'Income %' THEN 'IP'
								  WHEN ph.ProductSubGroupName LIKE 'Term %' OR ph.ProductSubGroupName LIKE 'Whole o%' THEN 'LP'
								  ELSE ph.ProductSubGroupName END + ph.ReportingProductProviderCode
					END
					,CASE WHEN ph.ProductProviderCode LIKE 'METLIFE%' AND ph.ProductSubGroupName LIKE 'Term %' THEN 'A&H '
						  WHEN ph.ProductSubGroupName LIKE 'Income %' THEN 'IP '
						  WHEN ph.ProductSubGroupName LIKE 'Term %'  THEN 'LP '
						  WHEN ph.ProductSubGroupName LIKE 'Whole o%' THEN 'WOL '
						  ELSE ph.ProductSubGroupName END  +
					 CASE WHEN ph.ProductProviderCode LIKE '%OWL%' THEN 'OWL' ELSE 'PANEL' END		  
					, s.personID
					, p.policyID
				HAVING -- (Excluding non-owl CASEs before panel)
					NOT (MIN(co.ProductCode) NOT LIKE '%owl%' AND MIN(ISNULL(s.DateSubmitted,pt.WrittenDate)) <= '2018-12-01')
		) wr
--End of SubQ for 4a)
		LEFT JOIN	 #PROM as #PROM  on #PROM.Usr_login = wr.PriAdviser 
		WHERE		 wr.WrittenDate >=  @StartDate2 
			AND		 wr.WrittenDate <= @EndDate2
			AND NOT (wr.WrittenDate <= @ExclDate AND wr.ProductGroupName = 'Mortgage') -- excluding incorrect mortgage CASEs for OWL advisers (RB 04/09/2019)
		GROUP BY	wr.WrittenDate, DAY(wr.WrittenDate), MONTH(wr.WrittenDate), year(wr.WrittenDate), wr.PriAdviser, wr.ProductGroupName
					,CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END, wr.AdminMethod, wr.StartDate
					,wr.Temp_UID, #PROM.PromotionDate ,wr.productsubtype ,wr.daily_category,wr.personID,wr.policyID,wr.ProductGroupName2 --end of Part 1 of Owl Scan
--End 4a) #CREATE #OWL: Part1 OWL STANDARD SCAN
UNION ALL
--4b) Start Part 2 of UNION : OWS L&G ASU PRODUCT Added 20/03/17
		SELECT 
					 [Type]				= 'Written'
					,[PriAdviser]		=  sale.AdviserUID 
					,[AdminMethod]		='Advised' 
					,[ProductGroupName] ='Protection' 
					,[ProductSubGroup]	= 'L&GASU OWL'  
					,[Productsubtype]	='LPL&G' 
					,[Date]				= CAST(pol.ApplicationDate as date) 
					,[Day]				= DAY(pol.ApplicationDate) 
					,[Month]			= MONTH(pol.ApplicationDate) 
					,[Year]				= Year(pol.ApplicationDate) 
					,[Premium]			= SUM(pps.PremiumAmount*12)
					,[APE]				= SUM(pps.PremiumAmount*12)
					,[NewPolicies]		= SUM(1) 
					,[DA]				= SUM(pps.PremiumAmount*12*0.35) 
					,[Margin]			= SUM(pps.PremiumAmount*12*0.10) 
					,[StartDate]		= ah.agentStartDate 
					, svar.[UID]
					,[Daily_category] = 'LP OWL' 
					, #PROM.PromotionDate
					,sale.personID
					,pol.policyID
					,'L&GASU OWL' as ProductGroupName2
		FROM			sa_ows_Policies							as pol 
			JOIN		policy.sa_ows_ProtectionProductSummary	as pps		on pps.PolicyID = pol.PolicyID
			JOIN		sa_ows_sale								as sale		on sale.SaleID = pol.SaleID
			JOIN		mi_insight_UserHierarchy				as uh		on uh.UserUID = sale.AdviserUID
			JOIN		cscv_AgentsHierarchy					as ah		on agentcode = sale.adviserUID
			LEFT JOIN	@var									as svar		on svar.UID = sale.AdviserUID
			LEFT JOIN	#PROM									as #PROM	on #PROM.Usr_login = sale.adviserUID 
		WHERE	
				InternalProductID = 10000063
			AND SaleStatusID = 2 AND pol.Status = 2
			AND sale.adviserUID <> '4006226' -- Excluding the test UID
			AND pol.ApplicationDate >=	CONVERT(date, @StartDate2,103)
			AND pol.ApplicationDate <= CONVERT(date, @enddate2,103)
			AND ((svar.UID IS NULL AND LEN(@sadv) = 0)  OR (svar.UID IS NOT NULL AND LEN(@sadv) > 0))
			AND @daily2 <>1
		GROUP BY pol.ApplicationDate, DAY(pol.ApplicationDate), MONTH(pol.ApplicationDate), Year(pol.ApplicationDate), sale.AdviserUID
				,ah.agentStartDate , svar.UID, #PROM.PromotionDate,sale.personID,pol.policyID
--End 4b) #CREATE #OWL: Part2 OWS L&G ASU PRODUCT
--END OF 4) CREATE #OWL UNION QUERY---------------------------------------------------------------------------------------------------------------------------------------------

--5) CREATE #HIER: Adding ASMs and Duplicate APE (for incentives)---------------------------------------------------------------------------------------------------------------
/*  Type	PriAdviser	AdminMethod	ProductGroupName	ProductSubGroup		productsubtype	Date		Day	Month	Year	Premium		APE			NewPolicies	DA		Margin	StartDate	Temp_UID	daily_category	PromotionDate	ASM1	ASM2	ASM3	ASM4	ASM5	ASM6	PriStatus	dupe
    Written	4005165		Advised		Protection			A&H OWL				A&HMETLIFE		21/04/2016	21	4		2016	1452.02		1452.02		8			3194.49	631.96	00:00.0		NULL		A&H OWL			39:52.3			4005051	1011625	NULL	NULL	NULL	NULL	Adviser		0*/	

--BEGIN
--5a) Part1: Hierarchy 
			SELECT 
				#OWL.* 
				,[ASM1]			= hier.OwlASMUID1 
				,[ASM2]			= hier.OwlASMUID2 
				,[ASM3]			= hier.OwlASMUID3 
				,[ASM4]			= hier.OwlASMUID4 
				,[ASM5]			= hier.OwlASMUID5 
				,[ASM6]			= hier.OwlASMUID6 
				,[ASM7]			= hier.OwlASMUID7
				,[ASM8]			= hier.OwlASMUID8 
				,[ASM9]			= hier.OwlASMUID9 
				,[ASM10]		= hier.OwlASMUID10
				,[PriStatus]	= CASE  WHEN #OWL.PromotionDate IS NULL OR #OWL.date <= CONVERT(date, #OWL.PromotionDate) THEN 'Adviser' 
										WHEN #OWL.date > CONVERT(date, #OWL.PromotionDate) THEN 'Manager'  END 
				,[dupe]			= 0 
		INTO #HIER
			FROM		#OWL  
			LEFT JOIN	mi_insight_UserHierarchyAllUsers hier on CONVERT(varchar,hier.UserUID) = CONVERT(varchar,#OWL.Priadviser)
																 AND ((CONVERT(date,#OWL.date) >= hier.effectiveStartDate AND CONVERT(date,#OWL.date) <= hier.effectiveenddate AND @hier <>1) 
				 														 OR (effectiveenddate > GETDATE() AND @hier =1)
																	 )
	UNION ALL
--5b)Part2: duplicate APE for new managers in incentive period
			SELECT 
				#OWL.* 
				,[ASM1]			= hier.OwlASMUID1 
				,[ASM2]			= hier.OwlASMUID2 
				,[ASM3]			= hier.OwlASMUID3 
				,[ASM4]			= hier.OwlASMUID4 
				,[ASM5]			= hier.OwlASMUID5 
				,[ASM6]			= hier.OwlASMUID6 
				,[ASM7]			= hier.OwlASMUID7
				,[ASM8]			= hier.OwlASMUID8 
				,[ASM9]			= hier.OwlASMUID9 
				,[ASM10]		= hier.OwlASMUID10
				,[PriStatus]	= CASE  WHEN #OWL.PromotionDate IS NULL OR #OWL.date <= CONVERT(date, #OWL.PromotionDate) THEN 'Manager' 
										WHEN #OWL.date > CONVERT(date, #OWL.PromotionDate) THEN 'Adviser'	  END 
				,[dupe]			= 1 
			
			FROM		#OWL  
			LEFT JOIN	mi_insight_UserHierarchyAllUsers hier on CONVERT(varchar,hier.UserUID) = CONVERT(varchar,#OWL.Priadviser)
																	AND ((CONVERT(date,#OWL.date) >= hier.effectiveStartDate AND CONVERT(date,#OWL.date) <= hier.effectiveenddate AND @hier <>1) 
																			OR	(effectiveenddate > GETDATE() AND @hier =1)
																		)
			WHERE  #OWL.PromotionDate between @StartDate AND @enddate
				  AND (@inc2 = 1 OR @inc1 = 1)	
--END --THE END OF THE BEGIN STATEMENT OF 5) CREATE #HIER----------------------------------------------------------------------------------------------------------------------------------------------------

--6) CREATE #WW: THE FINAL TABLE ---------------------------------------------------------------------------------------------------------------------------------
--6a) CREATE #WW
/*	Type	PersonID	PolicyID	PriAdviser	Experience	AdminMethod	ProductGroupName	Productsubgroup	Productsubtype	Daily_Category	Date	Day	Month	Year	Premium		APE	Newpolicies	DA		Margin	StartDate				Temp_UID	dupe	L0		L1		L2		L3		L4		ProductGroupName2
	Written	389922		550346979	4005589		Experienced	Advised		Protection			A&H OWL			A&HMETLIFE		A&H OWL		2015-10-29	29	10		2015	108			108		1		237.61	47.01	2014-11-01 00:00:00.000	NULL		0		NULL	NULL	NULL	NULL	NULL	MultiProtect*/

			SELECT 
				  [Type]
				 , PersonID
				 , PolicyID
				,[PriAdviser]		= CAST(CASE WHEN Priadviser = '4007583' THEN '4007584' ELSE Priadviser END as int) 
				,[Experience]		= CASE WHEN Date <=dateadd(m,12,StartDate) AND year(StartDate)<>2014 THEN 'New' ELSE 'Experienced' END 
				, AdminMethod
				, ProductGroupName
				, Productsubgroup
				, Productsubtype
				, Daily_Category
				,[Date]
				,[Day]
				,[Month]
				,[Year]
				,Premium
				,APE
				,Newpolicies
				,DA
				,Margin
				,StartDate
				,Temp_UID	   	
				,dupe
				,L9					= CASE	WHEN  ASM1  IS NULL AND ASM2  IS NULL AND ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM2  IS NULL AND ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2
											WHEN  ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM3
											WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM4
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM5 
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM6											
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM7											
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM8											
											WHEN  ASM10 IS NULL THEN ASM9 END
				,L8					= CASE  WHEN  ASM2  IS NULL AND ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM2  IS NULL AND ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2
											WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM3
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM4 
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM5 
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM6 
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM7 
											WHEN  ASM10 IS NULL THEN ASM8 END 
				,L7					= CASE  WHEN  ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM3  IS NULL AND ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM3 
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM4
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM5
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM6
											WHEN  ASM10 IS NULL THEN ASM7 END 
				,L6					= CASE  WHEN  ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM4  IS NULL AND ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2 
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM3 
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM4 
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM5 
											WHEN  ASM10 IS NULL THEN ASM6 END
				,L5					= CASE  WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM5  IS NULL AND ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1 
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2 
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM3 
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM4 
											WHEN  ASM10 IS NULL THEN ASM5 END
				,L4					= CASE  WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM6  IS NULL AND ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1 
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM2 
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM3 
											WHEN  ASM10 IS NULL THEN ASM4 END
				,L3					= CASE  WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM7  IS NULL AND ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1 
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM2 
											WHEN  ASM10 IS NULL THEN ASM3 END
				,L2					= CASE  WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM8  IS NULL AND ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM1 
											WHEN  ASM10 IS NULL THEN ASM2 END
				,L1					= CASE  WHEN  ASM9  IS NULL AND ASM10 IS NULL AND Pristatus <> 'Adviser' THEN Priadviser
											WHEN  ASM9  IS NULL AND ASM10 IS NULL THEN ASM1
											WHEN  ASM10 IS NULL THEN ASM1 END
				,ProductGroupName2

		INTO #WW
			FROM #HIER

----6b) Add the values into the #WW
			SELECT 
			 [Type],
			 PriAdviser,
			 AdminMethod,
			 ProductGroupName,
			 ProductSubGroup,
			 ProductSubType,
			 Daily_Category,
			 Date,
			 Day,
			 Month,
			 Year,
			 SUM(Premium) as 'Premium',
			 SUM(APE) as 'APE',
			 SUM(NewPolicies) as 'NewPolicies',
			 SUM(DA) as 'DA',
			 SUM(Margin) as 'Margin',
			 dupe = SUM(dupe),
			 L1,	
			 L2,
			 L3,
			 L4

			 Into #table
			 
			FROM #WW
			GROUP BY
			[Type],
			 PriAdviser,
			 AdminMethod,
			 ProductGroupName,
			 ProductSubGroup,
			 ProductSubType,
			 Daily_Category,
			 Date,
			 Day,
			 Month,
			 Year,
			 dupe,
			 L1,	
			 L2,
			 L3,
			 L4


		
If len(@sadv) = 0 BEGIN SET ANSI_WARNINGS ON; END

IF OBJECT_ID('tempdb..#PROD')		IS NOT NULL DROP TABLE #PROD
IF OBJECT_ID('tempdb..#DailyProd')	IS NOT NULL DROP TABLE #DailyProd
IF OBJECT_ID('tempdb..#OWL')		IS NOT NULL DROP TABLE #OWL
IF OBJECT_ID('tempdb..#i')			IS NOT NULL DROP TABLE #i
IF OBJECT_ID('tempdb..#prom')		IS NOT NULL DROP TABLE #prom


delete from [BI].[FINANCE_Weekly_DailyWrittenOwl]
 
