then (case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ','OE') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) end)END))END as "APE",

(case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ','OE') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end) as 'DA',

-- COMM INITIAL
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then cs.inissued
-- COMM SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ','OE') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- COMM TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end as NBI,

-- GROSS MARGIN INITIAL
(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
-- GROSS MARGIN TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
-- GROSS MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) when (ph.ProductGroupName = 'Mortgage' AND ag.commissiontype = 2) then (round((cs.inissued/ag.amount),0) *ag.derivedmarginamount) else 0 end) as 'Margin',
----------
--(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NB Cases",
--CASE WHEN b.policyref = 0 then 0 else ((case when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end))END as "NB Cases",
(case when ag.commissiontypedesc like '%claw%' then 0 
	  when b.transactionid is null then 0 
	  when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 
	  when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 
	  when em.TargetAccountId IS NOT NULL then 0
	  when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 
	  when cs.ape = 0 then 0 
	  when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 
	  else 0 
 end) as "NBCases",
--coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection') then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases",
--CASE WHEN b.policyref = 0 then 0 else (coalesce(case when (ag.caseid is NULL AND ph.productgroupname = 'Protection') then 0 when cs.ape <= 0 then -ag.derivedagentsplit/100 else ag.derivedagentsplit/100 end,0))END as "Cases",
coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when ((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection') then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases",

case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency', 
ag.caseid, 
ag.providerref
, coalesce(co.businessreason,co2.businessreason,'NB') as "business reason", 
coalesce(co.adminmethoddescription,co2.adminmethoddescription) as adminmethod, 
isnull(co.productcode,ag.tranproduct) as "ProductCode", 
isnull(co.productprovidercode,ag.comp_code) as "Comp_code", 
rp.reportingproductname as reportingproductname, 
ph.productsubgroupname as productsubgroupname, 

case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' or  ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end as ProductGroupName,
ccs.calculationcode, 
case when cs.paybasisdesc in ('Accr') then 'Accrual' else 'Indemnity' end as paybasisdesc, 
cs.oastatus,

case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end as ProductGroupName2,

case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when (left(isnull(co.productcode,ag.tranproduct),2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Recurring Income'

--Protection
when (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'Protection' then (case when isnull(co.productprovidercode,ag.comp_code) in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when isnull(co.productprovidercode,ag.comp_code) = 'Scot Eq' then 'Aegon' when isnull(co.productprovidercode,ag.comp_code) = 'Axa' then 'Friends Life' else isnull(co.productprovidercode,ag.comp_code) end) 
-- Pensions
when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OW') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productcode,ag.tranproduct) = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'IFDL'
when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'ZIP'
when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'Annuities' else ph.productgroupname end) = 'Pensions') then 'MetLife'
when (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'Pensions' then isnull(co.productprovidercode,ag.comp_code)

-- Annuities
when (isnull(co.productprovidercode,ag.comp_code) = 'PTSP') then 'Partnership' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'MGMA'
when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'COB Off-Platform') then 'Pru Ann'
when (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'COB Off-Platform' then isnull(co.productprovidercode,ag.comp_code)

-- Investments
when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
when (isnull(co.productprovidercode,ag.comp_code) = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'Annuities' else ph.productgroupname end) = 'Investment') then 'Aegon'
when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
when (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) = 'Investment' then isnull(co.productprovidercode,ag.comp_code)

when ph.productgroupname = 'Mortgage' then 
(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
else (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' else ph.productgroupname end) end as "ProductSubGroup",

case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Advised' when 
	((ph.productgroupname <> 'Mortgage' and coalesce(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich Leg' or isnull(co.productcode,ag.tranproduct) = 'ZGUA' or isnull(co.productprovidercode,ag.comp_code) = 'Close' or isnull(co.productprovidercode,ag.comp_code) = 'MSQ') then 'Non Advised' else 'Advised' end as "Advicemethod",
(replace(ccs.description,'do not use - ','')) as description
--client details
,cl.client_num
,cl.Firstnames
,cl.name

into #f

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id AND oa.Source = 'Openwork 2006' LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.FranchiseAgentCode = ah.agentcode LEFT OUTER JOIN
mstt_expectation ex ON ex.id = cs.expectationid LEFT OUTER JOIN
(select max(cashreceiveddate) as cashreceiveddate, amount_rec, transactionid from mstt_expectation group by transactionid, amount_rec) ex2 ON ex2.transactionid = ag.transactionid and ag.amount = ex2.amount_rec LEFT OUTER JOIN
(select max(cashreceiveddate) as cashreceiveddate, transactionid from mstt_expectation group by transactionid) ex3 ON ex3.transactionid = ag.transactionid LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
--JOIN #d d on (d.caseID = ag.caseid) --AND (c.TransID = ag.TransactionID)
JOIN #d d ON (d.caseID = case when ag.caseid IS NULL then convert(VARCHAR,replace(ag.providerref,'-','')) else convert(VARCHAR, ag.caseID) end)
--- client details
left join mstt_Policies po ON pt.policyid = po.pol_num 
left join mstt_Clients cl ON cl.Client_Num = po.Client_Num
LEFT OUTER JOIN #c c on (c.PolicyNumber = ag.providerref) AND (c.TransID = ag.TransactionID)
LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = ag.providerref


where 
ag.createdatetime >= @StartDate
and ag.createdatetime <= @EndDate
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and (ag.commissiontype in ('1','4','10','17','18','19','2') OR (ph.productgroupname = 'Mortgage' AND ag.commissiontype = 2))
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (cs.oastatus = 'valid' or cs.oastatus is null)
and (rtrim(ah.ASDName) not in ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
-----------------------EXCLUDE ALL GROUP PENSION BUSINESS-----------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
--------------------------------------------------------------------------------
and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0

and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 
-------------------------SELECT PRODUCT GROUP(S)--------------------------------------------------------
--AND case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'Annuity' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end in ('Protection')
--------------------------------------------------------------------------------------------------------
and d.caseID = Case when ag.caseid IS NULL then convert(VARCHAR,replace(ag.providerref,'-','')) else convert(VARCHAR, ag.caseID) end
and case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end NOT IN ('4006738', '4006770')



UNION ALL

-------Mortgage Broker Fee

Select Distinct 
'',
'Issued' as "Type", 
MBF.AdviserUID, 

MBF.FirmUID, 
'Mortgage Broker Fee' as commissiontypedesc, 
MBF.ApplicationDate as createdatetime, 
MBF.PaymentMatchedDate as cashreceiveddate, 
Day(MBF.PaymentMatchedDate) as "Day", 
Month(MBF.PaymentMatchedDate) as "Month", 
Year(MBF.PaymentMatchedDate) as "Year",
(MBF.AdviceFeeAmount*(MBF.AgentSplit/100)) as Premium, 
(MBF.APE) as "APE", 
(MBF.APE) as "DA", 
(MBF.AdviceFeeAmount+MBF.DeductionAmount) as "NBI",
(MBF.DeductionAmount*-1) as "Margin",
(MBF.AgentSplit)/100 as "New Policies",
'' as cases, 
'Single' as Frequency, 
convert(varchar, MBF.PolicyID) as caseid, 
MBF.MortgageNumber as providerref, 
'NB' as "business Reason", 
'' as adminmethod,
ag.tranproduct as ProductCode, 
ag.comp_code as Comp_code, 
rp.reportingproductname as reportingproductname, 
ph.productsubgroupname as productsubgroupname,
'Mortgage Broker Fee' as productgroupname,
'' as calculationcode,
'' as paybasisdesc,
'' as oastatus,
'Mortgage Broker Fee' as productgroupname2,
case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' 
	  when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' 
	  when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' 
	  when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society'  
	  when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' 
	  when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)'
	  when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' 
	  when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' 
	  when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end
	  as "ProductSubGroupName", 
'Advised' as "AdminMethod",
'Mortgage Broker Fee' as description
--client details
,cl.client_num
,cl.Firstnames
,cl.name
FROM dbo.owt_MortgageBrokerFees MBF left outer join
     mstt_paymentspending ag ON ag.transactionid = MBF.transactionid AND ag.AGENT_CODE = 10002  LEFT OUTER JOIN
	 mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
	 msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode JOIN 
	 #d d on (d.caseID = convert(varchar, MBF.PolicyID))
	 --- client details
	left join mstt_Policies po ON MBF.policyid = po.pol_num 
	left join mstt_Clients cl ON cl.Client_Num = po.Client_Num

where
(MBF.PaymentMatchedDate) >= @StartDate
and (MBF.PaymentMatchedDate) <= @EndDate
and MBF.AdviceFeeCharged = 'Yes'

------------------------------------------------------------------------------------
------------------------------------------------------------------------------------
-- Final Table

--select 
--sum (case when (f.cases) = 0 then 0 else 1 end) as counttest,
--LEFT(f.providerref,len(f.providerref)-1) as providerrefshort
--into #e

--from #f f left join mstt_agents ah on ah.code= f.agent_code

--where LEFT(d.providerref,len(d.providerref)-1) ='BPL013D0'

--group by 
--LEFT(f.providerref,len(f.providerref)-1)

select 
f.priadviser,
'Issued' "Type",
f.agent_code,

rtrim(ah.descn) agent_name,
f.firm,
f.commissiontypedesc,
convert(varchar, f.createdatetime,103) createdatetime,
convert(varchar, f.Cashreceiveddate,103) cashreceiveddate,
f.day,
f.month,
f.year,
sum(f.premium) premium,
sum(f.APE) APE,
sum(f.DA) DA,
sum(f.NBI) NBI,
sum(f.Margin) Margin,
sum(f.[NBCases]) AS NBCases,
--case when sum(f.cases) <> sum (f.[NB Cases]) then sum(f.cases)/count(f.caseid) else sum(f.cases) end as Cases,
f.Frequency,
(f.caseid),
f.Firstnames,
f.name,
f.providerref,
f.[business reason],
f.adminmethod,
f.productcode,
f.comp_code,
f.reportingproductname,
f.productsubgroupname,
f.productgroupname,
f.calculationcode,
f.paybasisdesc,
f.oastatus,
f.productsubgroup,
f.advicemethod,
f.description

into #g
from #f f left join mstt_agents ah on ah.code= f.agent_code

group by 
f.agent_code,
f.priadviser,
ah.descn,
f.firm,
f.commissiontypedesc,
convert(varchar, f.createdatetime,103),convert(varchar, f.Cashreceiveddate,103),
f.day,f.month,f.year,
f.Frequency,
f.caseid,
f.Firstnames,
f.name,
f.providerref,
f.[business reason],
f.adminmethod,
f.productcode,
f.comp_code,
f.reportingproductname,
f.productsubgroupname,
f.productgroupname,
f.calculationcode,
f.paybasisdesc,
f.oastatus,
f.productsubgroup,
f.advicemethod,
f.description
--(f.premium),
--(f.APE),
--(f.DA),
--(f.NBI) ,
--(f.Margin),




select

--case when g.nbcases > 0.5 then g.DA else g.margin end New_Margin,
--case when g.nbcases > 0.5 then 0 else g.NBI end New_NBI, 
case when g.Firm in ('2004728') AND g.agent_code not in ('4006738','4006770') then g.DA else g.margin end New_Margin,
case when g.Firm in ('2004728') AND g.agent_code not in ('4006738','4006770') then 0 else g.NBI end New_NBI, 

g.*

INTO #table

from #g g


Order by [year] desc, [month] desc, [day] desc


/*  WRITE TO TABLE */

-- Empty existing table
 
delete from BI.FINANCE_Weekly_IssuedProductionCBC
 
-- Write new data to table

insert into BI.FINANCE_Weekly_IssuedProductionCBC

Select  * 

from #table
 

