=================
Date		Author		Description
----		------		-----------
10/03/2026	J Homer		Added in Process Logging for bi.pr_ProcessLog
02/04/2026	J Homer		Added row count to process logging
02/07/2026  E Brown		Exclude Openwork Corporate/Partnership Services

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_225_FINANCE_Weekly_WrittenMortgageScorecard]  

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@Process				varchar(100),
			@Client					varchar(50),
			@Module					varchar(50),
			@RowCount				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'pr_225_FINANCE_Weekly_WrittenMortgageScorecard'
set @StoredProcName		= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'Weekly Finance'

/****************************************************************************

	Start Process Log																
																		
****************************************************************************/


exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SET NOCOUNT ON

----------------------QUERY NAME - DATA WAREHOUSE-----------------------------------------------------------------------
-- This scan is used by Marcus Cossey for the Mortgage Scorecard

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c

IF OBJECT_ID('tempdb..#table') IS NOT NULL
DROP TABLE #table

SET DATEFIRST 1;

select

min(transactionid) as transactionid
, po.PolicyRef
, po.cont_num
--, co.productcode
,ph.productgroupname
,COMP_CODE
,co.poltrantranstype
 --case when po.policyref IS NULL then convert(VARCHAR,replace(po.cont_num,'-','')) else convert(VARCHAR, po.policyref) end AS caseid
into #TransTable

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
AND (ah.FirmCode NOT IN ('10003', '2004728') OR ah.FirmCode IS NULL) -- Exclude Openwork Corporate/Partnership Services
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

group by po.PolicyRef, po.cont_num, ph.productgroupname,COMP_CODE,co.poltrantranstype

union all

select
min(transactionid) as transactionid
, '' t1
, '' t2
--,'' t3
,ph.productgroupname,
COMP_CODE,
co.poltrantranstype

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
AND (ah.FirmCode NOT IN ('10003', '2004728') OR ah.FirmCode IS NULL) -- Exclude Openwork Corporate/Partnership Services
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,ph.productgroupname,COMP_CODE,co.poltrantranstype

select transactionid,policyref,cont_num
into #c
from #TransTable
where (left(cont_num,2) <> 'ZR' or cont_num is null)

union all
select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
from #TransTable
where left(cont_num,2) = 'ZR'
group by  policyref, cont_num

drop table #TransTable



--MONTH & YEAR
SELECT 'Written' as "Type", 
case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT'or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end as 'ProductGroupName',
CONVERT(varchar(10),wr.writtendate,103) as Date,
day(wr.writtendate) as "Day", 
--case when (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) = 'Protection' then (case when wr.provider in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when wr.provider = 'Scot Eq' then 'Aegon' when wr.provider = 'Axa' then 'Friends Life' else wr.provider end) 
case when wr.productgroupname = 'Protection' then (case when wr.provider in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when wr.provider = 'Scot Eq' then 'Aegon' when wr.provider = 'Axa' then 'Friends Life' else wr.provider end) 

-- Platform
when ((left(wr.productcode,2) in ('OW') AND left(wr.productsubgroupname,3) <> 'FEE') or wr.productcode = 'OFHBSIPP'or wr.provider = 'Pru PLT' or wr.provider = 'IFDL') then 'IFDL'
when ((left(wr.productcode,2) in ('OZ') AND left(wr.productsubgroupname,3) <> 'FEE') or wr.provider = 'Zurich PLT') then 'ZIP'

-- Annuities
when (wr.provider = 'PTSP') then 'Partnership' when wr.provider = 'MGMA' then 'MGMA'
when (wr.provider = 'PRU' and (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) = 'Annuities') then 'Pru Ann'
when (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) = 'Annuities' then wr.provider

-- Off Platform
when wr.provider = 'MetLife' then 'MetLife'
when wr.provider = 'PRU' then 'Pru'
when wr.provider = 'Octopus' then 'Octopus'
when (wr.productgroupname = 'Investment' and wr.productsubgroupname like '%Guaranteed Account%') then 'Structured'
when (left(wr.productsubgroupname,3)) = 'FEE' then 'Other Fee'
when wr.productgroupname in ('Pensions','Investment') then 'Other Comm'

-- Mortgages
when wr.productgroupname = 'Mortgage' then 
(case when wr.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when wr.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when wr.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when wr.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when wr.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when wr.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society'  when wr.reportingproductname like '%Northern Rock%' then 'Virgin Money' when wr.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when wr.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when wr.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when wr.reportingproductname like '%Godiva%' then 'Coventry' when wr.reportingproductname like '%Principality%' then 'Principality' when wr.reportingproductname like '%lloyds TSB%' then 'TSB' when wr.reportingproductname like '%Precise%' then 'Precise' when wr.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' when wr.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(wr.reportingproductname,' Mortgages',''),' (TBMC)','') end)
else (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) end as "ProductSubGroup",
sum(wr.ape) as APE, 
sum(wr.NBcases) as NewPolicies,
sum(case when wr.frequency = 'Single' then wr.ape * 10 else wr.ape end) as Premium, 
wr.adminmethod,
sum(wr.distributionallowance) as DA, 
month(wr.writtendate) as "Month", 
year(wr.writtendate) as "Year",
sum(wr.margin) as Margin,
case when wr.MortgageCategory = 'BTL' then wr.MortgageCategory when wr.MortgageCategory = 'CBTL' then 'BTL' when wr.MortgageType IN ('First Time Purchase', 'Second or Subsequent Purchase', 'Purchase', 'First Time Buyer', 'Unencumbered Property') Then 'New' When  wr.productgroupname Not IN('Mortgage') Then '' when wr.MortgageType = 'Product transfer' then 'Product transfer' else 'Remo' end AS 'MortgageType', --Updated with Product Transfer as separate type SI 18/02/19
wr.MortgageCategory,
SUM(wr.MortgageAmount) as 'Loan Amount' 

INTO #Table

from

(SELECT
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) END as APE,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,

--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
--when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2)End as distributionallowance, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance,

--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
--when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2)End as NBI, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI,

--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
--when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2)End as Margin, 
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin,

min(po.PolicyRef) minpolref,
co.agent_perc tst2,
--CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End)END as "NBCases", 
--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End as "NBCases", 
CASE WHEN (min(c.policyref) = 0 and min(po.CONT_NUM) is null) then 0 --min(c.policyref) = 0 then 0 
	else (Case when ((min(po.PolicyRef) is null OR min(c.PolicyRef) =0) AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else 
	max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) 
	then (co.agent_perc/100) else 0 end)End)End as "NBCases",

--CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') OR (((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')) then 0 else max((co.agent_perc/100))End)END as "AllCases", 
Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') OR (((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')) then 0 else max((co.agent_perc/100))End as "AllCases", 
min(pt.FrequencyDescription) as frequency, min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD
,invtrans.ValueName as MortgageType
,invtrans2.ValueName as MortgageCategory
,pt.MortgageAmount
,min(ah.ASDCode) as ASDCode


FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

--------------------------------------------- return mortgage type ---------------------------------------------------------------------------------------------------
left join vw_ows_MortgageProductSummary mps on mps.PolicyID = po.policyref
left join policy.sa_ows_MortgageRecommendedSolution mrs on mrs.PolicyID = mps.PolicyID
left join policyonelink.sa_ows_MortgageProductSummary olmps on olmps.PolicyId = mps.PolicyID
left join policy.sa_ows_MortgageProductSummary pmps on pmps.PolicyID = mps.PolicyID
left join StaticData.sa_ows_InputValues invTrans on invtrans.InputID = case when olmps.PolicyId is null then mrs.TransactionTypeID else olmps.TransactionTypeId end
left join StaticData.sa_ows_InputValues invTrans2 on invtrans2.InputID = mps.mortgagecategoryID

--------------------------------------------- IFDL to Zurich Transfer -------------------------------------------------------------------------------------------------
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and po.COMP_CODE NOT LIKE '%Owl%'
and (rtrim(ah.ASDName) not in('Pat Mckenna','Owl Sales Director') or ah.ASDName is Null)
AND (ah.FirmCode NOT IN ('10003', '2004728') OR ah.FirmCode IS NULL) -- Exclude Openwork Corporate/Partnership Services


----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), 
ph.productgroupname,ph.productgroupname,co.agent_code,co.agent_perc,invtrans.ValueName,invtrans2.ValueName, PT.MortgageAmount)wr

where
(wr.writtendate) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 1, 0)
and (wr.writtendate) <= (dateadd(day,datediff(day,0,GETDATE()),0))

and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
and wr.productgroupname = 'Mortgage'
AND (ISNULL(wr.Firm,'111') <> '2016789') 
--AND wr.ASDCode <> '4019902'

group by
CONVERT(varchar(10),wr.writtendate,103), day(wr.writtendate), month(wr.writtendate), year(wr.writtendate),

--Protection
case when wr.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end,
case when wr.productgroupname = 'Protection' then (case when wr.provider in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when wr.provider = 'Scot Eq' then 'Aegon' when wr.provider = 'Axa' then 'Friends Life' else wr.provider end) 

-- Platform
when ((left(wr.productcode,2) in ('OW') AND left(wr.productsubgroupname,3) <> 'FEE') or wr.productcode = 'OFHBSIPP' or wr.provider = 'Pru PLT' or wr.provider = 'IFDL' ) then 'IFDL'
when ((left(wr.productcode,2) in ('OZ') AND left(wr.productsubgroupname,3) <> 'FEE') or wr.provider = 'Zurich PLT') then 'ZIP'

-- Annuities
when (wr.provider = 'PTSP') then 'Partnership' when wr.provider = 'MGMA' then 'MGMA'
when (wr.provider = 'PRU' and (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) = 'Annuities') then 'Pru Ann'
when (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) = 'Annuities' then wr.provider

-- Off Platform
when wr.provider = 'MetLife' then 'MetLife'
when wr.provider = 'PRU' then 'Pru'
when wr.provider = 'Octopus' then 'Octopus'
when (wr.productgroupname = 'Investment' and wr.productsubgroupname like '%Guaranteed Account%') then 'Structured'
when (left(wr.productsubgroupname,3)) = 'FEE' then 'Other Fee'
when wr.productgroupname in ('Pensions','Investment') then 'Other Comm'

-- Mortgages
when wr.productgroupname = 'Mortgage' then 
(case when wr.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when wr.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when wr.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when wr.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when wr.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when wr.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when wr.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society'  when wr.reportingproductname like '%Northern Rock%' then 'Virgin Money' when wr.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when wr.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when wr.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when wr.reportingproductname like '%Godiva%' then 'Coventry' when wr.reportingproductname like '%Principality%' then 'Principality' when wr.reportingproductname like '%lloyds TSB%' then 'TSB' when wr.reportingproductname like '%Precise%' then 'Precise' when wr.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when wr.reportingproductname = 'BOI' THEN 'Bank of Ireland' when wr.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(wr.reportingproductname,' Mortgages',''),' (TBMC)','') end)
else (case when wr.productsubgroupname like '%Annuity' then 'Annuities' else wr.productgroupname end) end,
wr.adminmethod,
case when wr.MortgageCategory = 'BTL' then wr.MortgageCategory when wr.MortgageCategory = 'CBTL' then 'BTL' when wr.MOrtgageType IN ('First Time Purchase', 'Second or Subsequent Purchase', 'Purchase', 'First Time Buyer', 'Unencumbered Property') Then 'New' When  wr.productgroupname Not IN('Mortgage') Then '' when wr.MortgageType = 'Product transfer' then 'Product transfer' else 'Remo' end, --Updated with Product Transfer as separate type SI 18/02/19
wr.MortgageCategory

--UNION ALL

------------MORTGAGE BROKER FEES ------------------------
--select
--'Written' as Type,
--'Mortgage Broker Fee' as ProductGroupName,
----'Mortgage' as ProductGroupName,
--CONVERT(varchar(10),sale.datesubmitted,103) as Date,
--day(sale.datesubmitted) as Day,
--mp.DisplayName,
--sum(mdaf.brokerfeeamount*AGENT_PERC/100) as APE,
--count(distinct mdaf.policyID) as Policies,
----0 as NewPolicies,
--' ' as Premium,
--'Advised' as AdminMethod,
--sum(mdaf.brokerfeeamount*AGENT_PERC/100) as DA,
--Month(sale.datesubmitted) as Month,
--Year(sale.datesubmitted) as Year,
--sum(CASE when ah.ASDName in ('First Affinity','GHL') then ((mdaf.brokerfeeamount*AGENT_PERC/100)*0.05) else (((mdaf.brokerfeeamount*AGENT_PERC/100) * (100 - (FranchiseUpliftPercent - (case when sale.businessUID = '2005309' then 22.79 else 20 end)))/100)) END) as Margin
--,'' as 'MortgageType'
--,'' as MortgageCategory
--,'' as 'Loan Amount'

--from sa_swift_S_POLMAI polm
--join sa_swift_PolicyTransactions potr on potr.PolicyID = polm.POL_NUM
--join sa_swift_S_AGTCOM agtc on agtc.TransactionID = potr.ID
--join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf on mdaf.PolicyId = polm.PolicyRef 
--join sa_ows_Sale sale on sale.SaleID = mdaf.saleid
--join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId
--join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
--left join cscv_AgentsHierarchy ah on ah.AgentCode = Sale.businessUID

--where 1=1 
--and potr.ID = (select min(potr1.ID)
--                        from sa_swift_S_POLMAI polm1
--                       join sa_swift_PolicyTransactions potr1 on potr1.PolicyID = polm1.POL_NUM
--                       where polm.PolicyRef = polm1.PolicyRef)
--and AGENT_CODE != '10002' and agtc.CommissionType = 1
--and mdaf.HasBrokerFeeCharged = 19
--and (sale.datesubmitted) >= DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 1, 0)
--and (sale.datesubmitted) <= (dateadd(day,datediff(day,0,GETDATE()),0))
----and sale.businessUID <> '2005309'
--Group by mp.DisplayName, day(datesubmitted), month(datesubmitted), year(datesubmitted), CONVERT(varchar(10),sale.datesubmitted,103)


--Order by [type], [year] desc, [month] desc, [day] desc


delete from [BI].[FINANCE_Weekly_WrittenMortgageScorecard]
 
-- Write new data to table
insert into [BI].[FINANCE_Weekly_WrittenMortgageScorecard]
Select  * 
from #Table

