/**********************************************************************************************
Name	: [BI].[pr_226_FINANCE_Weekly_WrittenProductionCBC]
Author	: Luke Brigginshaw
Date	: 09/02/2026

		Written Production Case by Case CS  (with Embark NBCase Fix) for finance weekly download
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------
10/03/2026	J Homer		Added in Process Logging for bi.pr_ProcessLog
02/04/2026	J Homer		Added row count to process logging

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_226_FINANCE_Weekly_WrittenProductionCBC]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@Process				varchar(100),
			@Client					varchar(50),
			@Module					varchar(50),
			@RowCount				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'pr_226_FINANCE_Weekly_WrittenProductionCBC'
set @StoredProcName		= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'Weekly Finance'

/****************************************************************************

	Start Process Log																
																		
****************************************************************************/

exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/

SET NOCOUNT ON; SET ANSI_WARNINGS OFF;

IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c
IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d
IF OBJECT_ID('tempdb..#h') IS NOT NULL
DROP TABLE #h


declare @StartDate datetime,@EndDate datetime;
set @StartDate = '01 January 2016'
set @EndDate = GETDATE() -- Enter Monday's date (or if last day of month, the current date)


select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #c

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) < '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

--and(po.comp_code <> 'L&G'  or (po.comp_code = 'L&G' and (left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null)))

group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
--and (po.comp_code = 'L&G' and po.policyref like '8000%')
and((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

Select

--wr2.CaseID
case when wr2.caseid IS NULL then convert(VARCHAR,replace(wr2.Policy,'-','')) else convert(VARCHAR, wr2.caseID) end AS caseid
into #d

from

(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
pt.AGENTCODE priadviser,
min(coalesce(co.franchiseagentcode,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
Case when min(po.PolicyRef) is null then 0 else round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) End as APE,
Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) End as DA, 

Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) END as NBI, 


Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) End as Margin, 
--Case when min(po.PolicyRef) is null then 0 else max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) end as "NBCases", 
--CASE WHEN min(c.policyref) = 0 then 0 else (Case when min(po.PolicyRef) is null then 0 else max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) end) END as NBCases,
CASE WHEN (min(c.policyref) = 0 and min(po.CONT_NUM) is null) then 0 
		when em.TargetAccountId IS NOT NULL then 0 else
		(Case when ((min(po.PolicyRef) is null OR min(c.PolicyRef) =0) AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else 
		max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)	
		End)
		End as "NBCases",

--Case when min(po.PolicyRef) is null then 0 else max((co.agent_perc/100)) end as "AllCases", 
CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' OR (((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) then 0 else max((co.agent_perc/100))END)END as "AllCases",

min(pt.FrequencyDescription) as frequency, 
min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, 
min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD, ah2.AgentDesc



FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode left join
			  cscv_AgentsHierarchy ah2 ON co.agent_code = ah2.agentcode
			  --left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
			  LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = po.CONT_NUM  --JOIN TO NEW EMBARKL MIGRATION TABLE
where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) not in ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ah2.AgentDesc, pt.AGENTCODE, co.agent_code, ph.productgroupname, em.TargetAccountId) wr2

 where
wr2.writtendate >= @StartDate
and wr2.writtendate < @EndDate	
and (wr2.caseid not in ('500020430','500020431') or wr2.caseid is null)
and (wr2.Firm in ('2004728','10003') AND wr2.Adviser not in ('4006738','4006770')) 


select
wr.priadviser,
'Written' AS Type,
wr.Adviser,
wr.AgentDesc,
wr.Firm,
--wr.transactionid,
CONVERT(DATE,wr.Writtendate,103) AS Writtendate, 
CONVERT(DATE,wr.issueddate,103) AS issuedate,
DAY(wr.Writtendate) AS Day,
Month(wr.Writtendate) as Month,
Year(wr.Writtendate) as Year,
wr.Premium, -- JH added 220426
wr.Ape,
wr.DA, 
wr.NBI, 
wr.Margin, 
--wr.NBcases,
--wr.NBCases2,
wr.NBCases,
--wr.Allcases, 
wr.frequency, 
wr.CaseID, 
wr.Firstnames,
wr.name,
wr.Policy, 
--wr.MortgageAmount,
wr.Businessreason,
wr.Adminmethoddescription, 
wr.Productcode, 
wr.Provider, 
wr.Reportingproductname, 
wr.Productsubgroupname, 
case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ','OE') AND wr.productcode NOT IN ('OWADHOC','OWADVICE')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT' OR wr.provider = '7IM1') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end as 'ProductGroupName',
wr.Calculationcode, 
wr.Originatingsource, 
wr.Adminmethod, 
wr.Description
--wr.ASD
into #h
from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
pt.AGENTCODE priadviser,
min(coalesce(co.franchiseagentcode,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
CASE WHEN MIN(pt.FrequencyDescription) = 'Monthly' THEN min((pt.Amount)* (co.Agent_Perc/100))*12 ELSE ISNULL(min((pt.Amount)* (co.Agent_Perc/100)), min((pt.mortgageamount) * (co.Agent_Perc/100))) END Premium, -- JH added 220426
Case when min(po.PolicyRef) is null then 0 else round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) End as APE,
Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) End as DA, 

Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) END as NBI, 


Case when min(po.PolicyRef) is null then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) End as Margin, 
--Case when min(po.PolicyRef) is null then 0 else max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) end as "NBCases", 
--CASE WHEN min(c.policyref) = 0 then 0 else (Case when min(po.PolicyRef) is null then 0 else max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) end) END as "NBCases",
CASE WHEN (min(c.policyref) = 0 and min(po.CONT_NUM) is null) then 0 
			when em.TargetAccountId IS NOT NULL then 0 else 
			(Case when ((min(po.PolicyRef) is null OR min(c.PolicyRef) =0) AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else 
			max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) 
			then (co.agent_perc/100) else 0 end)
			End)
			End as "NBCases",

--Case when min(po.PolicyRef) is null then 0 else max((co.agent_perc/100)) end as "AllCases", 
CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' OR (((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) then 0 else max((co.agent_perc/100))END)END as "AllCases",

min(pt.FrequencyDescription) as frequency, 
min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, 
min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD, ah2.AgentDesc
--client details
,cl.Firstnames
,cl.name


FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.mstt_Clients cl ON co.CLIENT_NUM = cl.CLIENT_NUM  LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode left join
			  cscv_AgentsHierarchy ah2 ON co.agent_code = ah2.agentcode
			  JOIN #d d ON (d.caseID = case when po.policyref IS NULL then convert(VARCHAR,replace(po.cont_num,'-','')) else convert(VARCHAR, po.PolicyRef) end)
			  --left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
			  LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = po.CONT_NUM  --JOIN TO NEW EMBARKL MIGRATION TABLE
where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) not in ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------
group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ah2.AgentDesc, cl.Firstnames,cl.name, pt.AGENTCODE, co.agent_code, em.TargetAccountId, ph.productgroupname, pt.Amount) wr

 where
wr.writtendate >= @StartDate
and wr.writtendate < @EndDate	
and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
--and wr.Firm in ('2004728') AND wr.Adviser not in ('4006738','4006770')
--and wr.ProductGroupName = 'Protection'


select

case when h.Firm in ('2004728') AND h.Adviser not in ('4006738','4006770') then h.DA 
     when h.Firm in ('10003') then h.DA
	 else h.margin 
end New_Margin,

case when h.Firm in ('2004728') AND h.Adviser not in ('4006738','4006770') then 0 
	 when h.Firm in ('10003') then 0
	 else h.NBI 
end New_NBI, 

h.*
INTO #Table
from #h h

/*  WRITE TO TABLE */

-- Empty existing table
 
delete from [BI].[FINANCE_Weekly_WrittenProductionCBC]
 
-- Write new data to table

insert into [BI].[FINANCE_Weekly_WrittenProductionCBC]

