	   WHEN inp.ValueName = 'Product transfer' AND inp2.ValueName = 'Residential' THEN 'PT'
	   WHEN inp.ValueName in ('First time purchase', 'Second or subsequent purchase', 'Unencumbered property') AND inp2.ValueName in ('BTL', 'CBTL') THEN 'BTLNEW'
