-----------------SELECT PRODUCT GROUP HERE ----------------------------------------------
--and case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off-Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' when ph.productgroupname = 'Other' then 'COB Off-Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end in ('COB Off-Platform')

