select h.adviser, h.firm,h.transactionid,h.Writtendate,h.issuedate,h.Premium,h.ape,h.distributionallowance,h.NBI,h.Margin, h.NBCases, h.AllCases,h.frequency,h.CaseID,h.Policy,h.MortgageAmount,h.businessreason,h.adminmethoddescription,h.productcode,h.Provider,h.reportingproductname,h.productsubgroupname,h.ProductGroupName,h.originatingsource,h.Adminmethod, h.calculationcode,h.description,h.ASD, inp.ValueName as MortgageCategory, inp2.ValueName as MortgageTransactionType, case when inp.ValueName = 'BTL' then inp.ValueName when inp.ValueName = 'CBTL' then 'BTL' when inp2.ValueName IN ('First Time Purchase', 'Second or Subsequent Purchase', 'Purchase', 'First Time Buyer', 'Unencumbered Property') Then 'New' When  productgroupname Not IN('Mortgage') Then '' when inp2.ValueName = 'Product transfer' then 'Product transfer' else 'Remo' end AS 'MortgageType', h.MeetingVenue, h.Source 

Into #table

from #h h
left join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = h.CaseID
left join StaticData.sa_ows_InputValues inp on inp.InputID = mps.MortgageCategoryId
left join StaticData.sa_ows_InputValues inp2 on inp2.InputID = mps.TransactionTypeId
where productgroupname in('mortgage') --Table2%OW Written Mortgage%
AND (Firm NOT IN ('10003', '2004728') OR Firm IS NULL) -- Exclude Openwork Corporate/Partnership Services

delete from [BI].[FINANCE_Weekly_WrittenCBCMaster(Mortgage)]
 
