DROP TABLE #Table

Declare @StartDate datetime,@EndDate datetime;
set @StartDate = DATEADD(yy, DATEDIFF(yy, 0, GETDATE())-1, 0) 
set @EndDate = GETDATE() -- Enter Monday's date (or if last day of month, the current date)


select

--@StartDate
min(transactionid) as transactionid
, po.PolicyRef
, po.cont_num
--, co.productcode
,ph.productgroupname
,COMP_CODE
,co.poltrantranstype
 --case when po.policyref IS NULL then convert(VARCHAR,replace(po.cont_num,'-','')) else convert(VARCHAR, po.policyref) end AS caseid
into #TransTable

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) < '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

group by po.PolicyRef, po.cont_num, ph.productgroupname,COMP_CODE,co.poltrantranstype

union all

select
min(transactionid) as transactionid
, '' t1
, '' t2
--,'' t3
,ph.productgroupname,
COMP_CODE,
co.poltrantranstype

FROM          dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end,ph.productgroupname,COMP_CODE,co.poltrantranstype

select transactionid,policyref,cont_num
into #c
from #TransTable
where (left(cont_num,2) NOT IN ('ZR','EM') or cont_num is null)

union all
select case when left(cont_num,2) IN ('ZR','EM') then min(transactionid) end transactionid, policyref, cont_num
from #TransTable
where left(cont_num,2) IN ('ZR','EM')
group by  policyref, cont_num

drop table #TransTable

select
wr.Adviser,
wr.Firm,
wr.transactionid,
CONVERT(DATE,wr.Writtendate,103) AS Writtendate, CONVERT(DATE,wr.issueddate,103) AS issuedate,
case when wr.frequency = 'Single' then wr.ape * 10 else wr.ape end as Premium, 
wr.Ape,
wr.Distributionallowance, 
wr.NBI, wr.Margin, 
--wr.NBcases, 
wr.NBCases, 
wr.Allcases, 
wr.frequency, 
wr.CaseID, 
wr.Policy, 
wr.MortgageAmount,
wr.Businessreason,
wr.Adminmethoddescription, 
wr.Productcode, 
wr.Provider, 
wr.Reportingproductname, 
wr.Productsubgroupname, 
case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ','OE')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT' OR wr.provider = '7IM1') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end as 'ProductGroupName',
wr.Originatingsource, wr.Adminmethod, wr.Calculationcode, wr.Description, wr.ASD,wr.MeetingVenue
--wr.Client_Num, wr.REFER, wr.Title, wr.FIRSTNAME, wr.LastNAME, wr.DOB, datediff(year,wr.DOB,dateadd(month,2,getdate())) 'Age' 
--wr.GrossIncome
, CASE WHEN wr.Firm = '2016789' OR wr.ASDCode = '4019902' THEN 'Owl AR'
	   ELSE 'Core'
  END 'Source'
into #h
from


(SELECT  
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm,
min(co.transactionid) as transactionid, 
min(pt.writtendate) as writtendate, min(pt.issueddate) as issueddate,
datepart(week,(pt.writtendate)) as writtenweek, year(pt.writtendate) as writtenyear,
min((pt.mortgageamount) * (co.Agent_Perc/100)) as MortgageAmount,
round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as APE,
round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then co.turnover * 2.2 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.distributionallowance end),2) as distributionallowance, 

round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2) as NBI, 


round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2) as Margin, 
--max(case when co.transactionid = c.transactionid then (co.agent_perc/100) else 0 end) as "NBCases",

--CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End)End as "NBCases", 
--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End as "NBCases", 
CASE WHEN (min(c.policyref) = 0 and min(po.CONT_NUM) is null) then 0 --min(c.policyref) = 0 then 0 
		when em.TargetAccountId IS NOT NULL then 0 else 
		(Case when ((min(po.PolicyRef) is null OR min(c.PolicyRef) =0) AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else 
		max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) 
		then (co.agent_perc/100) else 0 end)End)End as "NBCases",

CASE WHEN min(c.policyref) = 0 then 0 else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' OR (((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) then 0 else max((co.agent_perc/100))END)END as "AllCases",

--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312' OR (((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection'))) then 0 else max((co.agent_perc/100))END as "AllCases",
min(pt.FrequencyDescription) as frequency, 
min(po.PolicyRef) AS CaseID, 
po.CONT_NUM AS Policy, min(co.BusinessReason) as businessreason,
min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",
min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD, inp.ValueName as MeetingVenue,
min(ah.ASDCode) as ASDCode

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #c c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
			  dbo.sa_ows_Policies P ON P.PolicyID = po.PolicyRef 
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num
			  left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = p.SaleID
			  left join StaticData.sa_ows_InputValues inp on inp.InputID = ffog.MeetingVenueID
			  LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = po.CONT_NUM  --JOIN TO NEW EMBARKL MIGRATION TABLE

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and (rtrim(ah.ASDName) not in('Pat Mckenna','Owl Sales Director') or ah.ASDName is Null)
--and ph.productgroupname = 'Mortgage'

Group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ph.productgroupname, co.AGENT_CODE,inp.ValueName, em.TargetAccountId

having min(pt.writtendate) >= @StartDate
	   and min(pt.writtendate) < @EndDate

) wr

where
--wr.writtendate >= @StartDate
--and wr.writtendate < @EndDate	
--and wr.adviser = '1003198'
--and wr.originatingsource = '5'
 (wr.caseid not in ('500020430','500020431') or wr.caseid is null)
--and case when wr.productsubgroupname like '%Annuity' then 'Annuities' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off-Platform' else wr.productgroupname end in ('Protection')
--and wr.Firm = '1005170'
--and wr.provider in ('L&G')
--and wr.policy = '0140406919'
--and wr.caseID in ('800003086','800003085', '551299911','551299523')
--AND (ISNULL(wr.Firm,'111') <> '2016789') 
--AND wr.ASDCode <> '4019902'

order by wr.writtendate desc

drop table #c


--------------Summ Asssured Table--------------------- 
select


PPS.PolicyID, 
SUM(PPBD.SumAssuredForDeath) as 'Sum_Assured_Death',
SUM(PPBD.SumAssuredForCI) as 'Sum_Assured_CI',
SUM(PPBD.IncomeProtectionBenefit) as 'Sum_Assured_IP'


Into #PRO	
		
From vw_ows_ProtectionProductSummary pps
	join vw_ows_ProtectionProductBenefitDetail ppbd on ppbd.ProtectionProductID = pps.ProtectionProductID

	Group By PPS.PolicyID





-------------------------------------------------------

select *  

Into #Table

from #h where productgroupname like '%platform%' -- Table3%OW Written Wealth%
AND (Firm NOT IN ('10003', '2004728') OR Firm IS NULL) -- Exclude Openwork Corporate/Partnership Services

 
delete from [BI].[FINANCE_Weekly_WrittenCBCMaster(Wealth)]
 
-- Write new data to table
insert into [BI].[FINANCE_Weekly_WrittenCBCMaster(Wealth)]
