/**********************************************************************************************
Name	: [BI].[pr_233_logi_TandT_NegativeSplits] 
Author	: J Homer
Date	: 06/05/2026

This report is used for Transfers and Terminations. The recipients are:
		1) T&T Team

The report name is "Negative Splits" and This report displays any transactions which have been
paid with a negative agent split

This code is from Stored Procedure [logi].[pr_logi_TandT_NegativeSplits] which was used by
the original Logi report.  This code replaces the opriginal Stored proc and is used by a
Power BI Paginated Report called "Negative Splits"
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_233_logi_TandT_NegativeSplits]

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'pr_233_logi_TandT_NegativeSplits'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/
Begin

Select
TransactionID
into #Transactions
from mstt_Commissions
where AGENT_PERC < 0


Select
pp.transactionid,
sum(pp.amount) as TotalDA,
max(pp.CreateDateTime) as LatestDate
into #payments
from mstt_PaymentsPending pp
join #Transactions tr on tr.TransactionID = pp.TransactionID
group by pp.TransactionID

Select 
pt.AgentCode, 
AGENT_CODE, 
AGENT_PERC, 
sum(pp.amount) as AmountPaid, 
pp.TransactionID, 
ProviderRef as PolicyNumber,
CaseID, 
pt.TransactionNumber, 
pay.LatestDate, 
pay.TotalDA 
from mstt_PaymentsPending pp
join mstt_PolicyTransactions pt on pt.ID = pp.TransactionID
join #Transactions tr on tr.TransactionID = pp. TransactionID
join #payments pay on pay.TransactionID = pp.TransactionID
Group by 
pt.AgentCode, AGENT_CODE, AGENT_PERC, pp.TransactionID, ProviderRef, CaseID, pt.TransactionNumber, pay.LatestDate, pay.TotalDA
order by LatestDate desc

End


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



