CREATE PROCEDURE [BI].[pr_234_JMDAdviserAllAgencyCode]

-- Insert declaration of report parameters here
-- e.g. Declare @Startdate

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


select distinct
a.code as 'UID',
a.descn as 'AdviserName', 
lower(s2.Field1Value) as 'PtlCode', 
can.AgencyNo as 'AgencyNo.', 
case CompetentStatus
	when 1 then 'Active'
	when 2 then 'Left'
	when 5 then 'Pre Appt'
	when 6 then 'NPW'
	else 'Unknown'
	end  as 'EmploymentStatus'
from sa_swift_S_AGENTS a 
	left join sa_swift_CodeAgencyNumberAgents cna on a.code = cna.AgentCode
	left  join sa_swift_CodeAgencyNumbers can on can.id = cna.AgencyNumberID
	inner join (select SingleSignOnUserId, Field1Value from sa_ISL_SingleSignOnApplicationProfile where SingleSignOnApplicationId = 3) s1 on s1.Field1Value = a.code
	inner join sa_ISL_SingleSignOnApplicationProfile s2 on s1.SingleSignOnUserId = s2.singlesignonuserid
where a.firm = '2005309'
	--and can.CompanyCode = 'L&G' -- removed to show all agency codes rather than just L&G
	and s2.SingleSignOnApplicationId = 1
order by a.DESCN


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

