SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_237_TandT_AgentChangeDefaultCommissionSplitOnly] 
Author	: J Homer
Date	: 13/05/2026

Purpose     : This report is used for Transfers and Terminations. The recipients are:
                  1) T&T Team

              The report name is "AgentChangeDefaultCommissionSplitOnly" and is found on the "T & T MI" 
              menu. This report displays any policy on Swift where an agent change has been
			  implemented and the case has not been updated a new Active line to redirect the commission
			  for the new adviser.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_237_TandT_AgentChangeDefaultCommissionSplitOnly]

@OldAdviserUID	  varchar (7)  = '  View All',
@NewAdviserUID	  varchar (7)  = '  View All',
@NewFirmUID		  varchar (7)  = '  View All'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'TandT_AgentChangeDefaultCommissionSplitOnly'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


Select
				PolicyID,
				CreateDateTime,
				CommissionTypeDesc,
				TransactionID
into 
				#LatestPayment
from 
				mstt_PaymentsPending pp
where 
				TranProduct in (Select 
										ProductCode 
								from 
										mstt_ProductHierarchy 
								where 
										RDRType is not null or ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
																			   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
																			   'HSIPP','INCOME','MGMA','PRUFUND')
								) 
				and pp.CreateDateTime = (Select 
													max(createdatetime) 
										 from 
													mstt_PaymentsPending pp2
										 where 
													pp2.CommissionType in (4,10) 
													and pp2.PolicyID = pp.PolicyID
										)

Select
				ROW_Number() over (Partition By TransactionID order by case when Agent_Code = '1011543' then '9999999'
																			when agent_code = '1011587' then '8888888'
																			else FranchiseAgentCode 
																		end
								   ) as Row_Num,
				TransactionID,
				PolicyID,
				AGENT_CODE,
				AGENT_PERC,
				FranchiseAgentCode
into 
				#Splits
from 
				mstt_Commissions cs
where
				CommissionType = 10
				and TransactionID = (Select 
												max(cs2.transactionid)
									 from 
												mstt_Commissions cs2
									 where 
												cs.PolicyID = cs2.PolicyID
												and cs2.PolTranTransType not in (39,117)
									)
				and ProductCode in (Select 
												ProductCode 
									from 
												mstt_ProductHierarchy 
									where 
												RDRType is not null 
												or ProductCode in ('ASP','FPP','INDPP','INDSTK','PPXFR','RTRCON','SECT32','EPP','GRPMP',
																   'GRPPP','GRPSTK','FPP-FAC','ZSIPP','PPP','SWGRPP','MLRP','MLIVPP','PRUTIP',
																   'HSIPP','INCOME','MGMA','PRUFUND')
									 ) 

Select distinct
				pol.CONT_NUM as PolicyNumber,
				pol.PolicyRef as CaseID,
				pol.COMP_CODE,
				pol.ProductCode,
				@NewAdviserUID as ToAdviser,
				@NewFirmUID as ToFirm,
				@OldAdviserUID as FromAdviser,
				convert(varchar(10),pol.CreateDate,103) as 'CreatedDate',
				case when lp.PolicyID is null then 'No Ongoing Payment Recd'
					 when ph.RDRType is not null and lp.CommissionTypeDesc = 'Trail Fee'  then 'Ongoing Fee'
					 else lp.CommissionTypeDesc 
				end as OngoingPaymentType,
				lp.CreateDateTime as LatestPaymentDate,
				pt.TransactionNumber,
				bsc.AGENT_CODE as BSC,
				bsc.AGENT_PERC as BSCPct,
				owm.AGENT_CODE as Margin,
				owm.AGENT_PERC as MarginPct,
				sp1.AGENT_CODE as Code1,
				sp1.AGENT_PERC as Code1Pct, 
				sp1.FranchiseAgentCode as Code1Firm,
				sp2.AGENT_CODE as Code2,
				sp2.AGENT_PERC as Code2Pct,
				sp2.FranchiseAgentCode as Code2Firm,
				sp3.AGENT_CODE as Code3,
				sp3.AGENT_PERC as Code3Pct,
				sp3.FranchiseAgentCode as Code3Firm,
				case when clt.CLIENT_OF = @NewAdviserUID and pt.TransType = 117 then 'Default Commisssion Split Only'
					 when pt.AgentCode = @OldAdviserUID and clt.client_of = @NewAdviserUID and @OldAdviserUID <> @NewAdviserUID then 'Policy Adviser Not Updated'
					 when @NewAdviserUID in (sp1.AGENT_CODE,sp2.AGENT_CODE,sp3.AGENT_CODE) and (bsc.AGENT_PERC < 0 or owm.AGENT_PERC < 0 or sp1.AGENT_PERC < 0 or sp2.AGENT_PERC < 0 or sp3.AGENT_PERC < 0) then 'Negative Splits'
					 when @NewAdviserUID in (sp1.AGENT_CODE,sp2.AGENT_CODE,sp3.AGENT_CODE) and round(isnull(bsc.AGENT_PERC,0)+isnull(owm.AGENT_PERC,0)+isnull(sp1.AGENT_PERC,0)+isnull(sp2.Agent_perc,0)+isnull(sp3.Agent_Perc,0),2) <> 100 then 'Splits Dont Add Up' 
					 else 'OK'
				end as Reason,
				case when lp.TransactionID = tid.TransactionID then 'Latest Payment New Slice' 
					 else 'Latest Payment Old Slice' 
				end as LatestPayment
from 
				#Splits tid
				left join #Splits bsc on bsc.TransactionID = tid.TransactionID and bsc.agent_code = '1011587'
				left join #Splits owm on owm.TransactionID = tid.TransactionID and owm.AGENT_CODE = '1011543'
				left join #Splits sp1 on sp1.TransactionID = tid.TransactionID and sp1.AGENT_CODE not in ('1011543','1011587') and sp1.Row_Num = 1
				left join #Splits sp2 on sp2.TransactionID = tid.TransactionID and sp2.AGENT_CODE not in ('1011543','1011587') and sp2.Row_Num = 2
				left join #Splits sp3 on sp3.TransactionID = tid.TransactionID and sp3.AGENT_CODE not in ('1011543','1011587') and sp3.Row_Num = 3
				left join mstt_PolicyTransactions pt on pt.ID = tid.TransactionID
				left join mstt_Policies pol on pol.POL_NUM = tid.PolicyID
				left join mstt_clients clt on clt.CLIENT_NUM = pol.CLIENT_NUM
				left join #LatestPayment lp on lp.PolicyID = tid.PolicyID
				left join mstt_ProductHierarchy ph on ph.ProductCode = pol.ProductCode
				left join sa_swift_TransAgentSplitHierarchyHistory tash on tash.TransactionID = pt.ID and (tash.AgentCode = clt.CLIENT_OF or tash.AgentCode = pt.AgentCode)
where 
				clt.CLIENT_OF = @NewAdviserUID or @NewAdviserUID = '  View All'
				or ((pt.AgentCode = @OldAdviserUID or @OldAdviserUID = '  View All') and (clt.client_of = @NewAdviserUID or @NewAdviserUID = '  View All') and @OldAdviserUID <> @NewAdviserUID) 
				or @NewAdviserUID in (sp1.AGENT_CODE,sp2.AGENT_CODE,sp3.AGENT_CODE) 

OPTION (OPTIMIZE FOR UNKNOWN);



/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



