/****** Object:  StoredProcedure [BI].[pr_238_IT_Clawback_Liability_Calcualtor]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/**********************************************************************************************
Name	: [BI].[pr_238_IT_Clawback_Liability_Calcualtor] 
Author	: Edd Brown
Date	: 15/05/2026

IT Liability Calcualtor with the ability to Provide Adviser Firm and Date Parameters
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_238_IT_Clawback_Liability_Calcualtor]

@BusinessUID VARCHAR(255) = 'View All',
@AdviserUID VARCHAR(255) = 'View All',
@RunDate DATE = '01-Jan-2000'

with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ErrMsg						nvarchar(4000),
			@ErrNum						int,
			@ErrSev						int,
			@ErrLine					int,
			@DateLastUpdated			datetime
			
/****************************************************************************

		Set initial parameters																
																		
****************************************************************************/
IF
@BusinessUID  = 'View All'
AND @AdviserUID  = 'View All'
AND @RunDate = '01-Jan-2000'

BEGIN
SELECT
null as sellercode, 
'Use Slicers To Limit Results' as SellerName,
null as SwiftStatus,
null as businesscode,
null as BusinessName, 
null as COMP_CODE,
null as productsubgroupname,
null as productgroup,
null as paybasisdesc,
null as Type,
null as Frequency,
null as start_date,
null as comminitialperiod,
null as term_y,
null as policy,
null as description,
null as APE, 
null as [NET DA],
null as [NET NBI],
null as totalpayment,
null as AgentSplit,
null as [Month In Force],
null as ProviderRate,
null as [Remaining Liability]

RETURN
END

DECLARE 
@ActualRunDateTime DATETIME = CAST(@RunDate as DATETIME)

-- Convert Default Value to GETDATE() if not date value provided
BEGIN IF 
@RunDate = '01-Jan-2000'
SET @ActualRunDateTime  = GETDATE() 
END


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


DROP TABLE IF EXISTS #d, #CB, #Final

--Idenitify Clawback Policies from remarks
select oa.policy
into #d
from 
msit_openworkadviserlisting oa LEFT OUTER JOIN
msit_commissionstatement cs ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_paymentspending ag ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = co.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON cs.ProductCode = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = cs.commshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode
where
oa.remarks IN( 'claw', 'CLAWBACK')
and (oa.feetype not in ('Ongoing','RC','TF','Trail') or oa.feetype is NULL)
and (oa.source <> 'OMS' or oa.source is NULL)
and oa.providercode not in ('GI', 'Payment shield', 'PYMTSHLD')
and (oa.source <> 'openwork 2005' or oa.source is NULL)
and po.START_DATE <= GETDATE()
 
 --Idenitify Owl Clawback Policies
Select
PolicyNumber
into #CB
from owoa_OwlHierarchyPayments ohp
where PaymentAmount < 0
 

select 
oa.sellercode, rtrim(oa.sellername) as "SellerName", oa.businesscode, 
rtrim(oa.businessname) as "BusinessName", 
ag.COMP_CODE,
ph.productsubgroupname, oa.productgroup, cs.paybasisdesc, case when oa.remarks = 'claw' then 'Clawback' else 'IC' end as 'Type', 
case when cs.frequencydesc = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency',
convert(datetime, po.start_date) as start_date,
pt.comminitialperiod, po.term_y, oa.policy,ccs.description,
sum(oa.ape) as "APE", 
sum((case when oa.feetype in ('RC','TF','Trail') then oa.totalpayment when oa.source = 'OMS' then oa.totdue_enhd/0.6 when (oa.source = 'openwork 2005'
and ph.productgroupname = 'Mortgage') then oa.ape when oa.providercode in ('GI', 'Payment shield', 'PYMTSHLD') then oa.ape when oa.source = 'openwork 2005' then oa.totdue_enhd/0.8163 
when ag.amount = 0 then 0 when oa.source ='openwork 2006' then cs.inissued + ((cs.inissued/ag.amount)*ag.derivedmarginamount) end)) as "NET DA",
sum((oa.totdue_enhd)) as "NET NBI",
sum((oa.totalpayment)) as "totalpayment",
oa.AgentSplit --added 24.5.18 SI
Into #Final
from 
msit_openworkadviserlisting oa LEFT OUTER JOIN
msit_commissionstatement cs ON oa.sourceid = cs.id LEFT OUTER JOIN
mstt_paymentspending ag ON cs.PendingPaymentID = ag.id INNER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = co.TransactionID LEFT OUTER JOIN
mstt_ProductHierarchy ph ON cs.ProductCode = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = cs.commshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode LEFT OUTER JOIN
#d d on d.policy = oa.policy
where (oa.month >= '1 February 2003') ---ALWAYS ONE MONTH AFTER ACTUAL PERIOD
and (oa.feetype not in ('Ongoing','RC','TF','Trail') or oa.feetype is NULL)
and (oa.source <> 'OMS' or oa.source is NULL)
and oa.providercode not in ('GI', 'Payment shield', 'PYMTSHLD')
and (oa.source <> 'openwork 2005' or oa.source is NULL)
and d.policy is NULL
and (oa.productgroup <> 'Mortgage' or oa.productgroup is NULL)
and (ph.productsubgroupname not like '%Annuity%' or ph.productsubgroupname is null)
and (oa.productgroup <> 'Structured' or oa.productgroup is null)
and (case when oa.productgroup in ('Pensions','Investment','Protection') and (case when cs.frequencydesc = 'Single' Then 'Single' ELSE 'Regular' END) = 'Regular' and cs.paybasisdesc = 'Accr' then 'COBRegular' else 'Other' end ) <> 'COBRegular'
and dateadd(month,comminitialperiod,start_date) > @ActualRunDateTime
and po.START_DATE <= GETDATE()
--Parameters
and (oa.businesscode = @BusinessUID or @BusinessUID = 'View All')
and (oa.sellercode   = @AdviserUID or @AdviserUID = 'View All')


group by oa.AgentSplit, oa.sellercode, oa.businesscode, rtrim(oa.sellername), rtrim(oa.businessname), ph.productsubgroupname, oa.productgroup, cs.paybasisdesc, case when oa.remarks = 'claw' then 'Clawback' else 'IC' end, case when cs.frequencydesc = 'Single' Then 'Single' ELSE 'Regular' END, po.start_date, oa.policy, pt.comminitialperiod, po.term_y, ccs.description, ag.COMP_CODE --added 24.5.18 SI

UNION -- Owl

Select 
RoleAdviserUID,
agt.DESCN,
ohp.RoleEnterpriseUID,
frm.DESCN,
ProviderCode,
ProductSubGroupName,
ProductGroupName,
ohp.PaymentBasis,
ohp.CommissionTypeDesc,
'Regular',
convert(datetime, ohp.ProposalDate) as start_date,
ohp.InitialPeriod,
'',
ohp.PolicyNumber,
'Owl Panel Hierarchy',
'',
'',
PaymentAmount,
PaymentAmount,
100
From owoa_OwlHierarchyPayments ohp
Join mstt_agents agt on agt.code = ohp.RoleAdviserUID
Join mstt_agents frm on frm.code = ohp.RoleEnterpriseUID
Join mstt_ProductHierarchy ph on ph.ProductCode = ohp.ProductCode
left join #CB cb on cb.PolicyNumber = ohp.PolicyNumber
where ohp.PaymentStage = 'Upfront'
and cb.PolicyNumber is null
and PaymentBasis = 'IT'
and dateadd(month,InitialPeriod,ProposalDate) > @ActualRunDateTime
and ProposalDate <= getdate()
--Paramteres
and (ohp.RoleEnterpriseUID = @BusinessUID or @BusinessUID = 'View All')
and (RoleAdviserUID   = @AdviserUID or @AdviserUID = 'View All')


 SELECT
f.sellercode, 
f.SellerName,
ISNULL(sh.SwiftStatus,'Left') as SwiftStatus,
f.businesscode,
f.BusinessName, 
f.COMP_CODE,
f.productsubgroupname,
f.productgroup,
f.paybasisdesc,
f.Type,
f.Frequency,
f.start_date,
f.comminitialperiod,
f.term_y,
f.policy,
f.description,
f.APE, 
f.[NET DA],
f.[NET NBI],
f.totalpayment,
f.AgentSplit,
CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0)) as [Month In Force],
CASE WHEN cr.ProviderRate is null then (f.CommInitialPeriod - CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0))) / CONVERT(Decimal, f.CommInitialPeriod)
								  else cr.ProviderRate/100 END as ProviderRate,
CASE WHEN cr.ProviderRate IS NULL THEN ROUND(((f.CommInitialPeriod - CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0))) / CONVERT(Decimal, f.CommInitialPeriod))* f.[NET NBI],2)
		ELSE ROUND((f.[NET NBI] * cr.ProviderRate)/100,2) END as [Remaining Liability]
FROM #Final as f

LEFT JOIN BI.SellingHeadCount as sh on sh.AdviserUID = f.sellercode
LEFT JOIN mi_ClawbackRates as cr on f.COMP_CODE = cr.ProviderCompCode
								AND f.CommInitialPeriod = cr.InitialPeriod
								AND CASE WHEN ISNULL(CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0)),-9999) = -9999 then null
								WHEN CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0)) = 0 then 1
								ELSE CONVERT(INT, ROUND((CONVERT(Decimal, @ActualRunDateTime - f.START_DATE) / 365*12),0)) END 							
								= CONVERT(INT, cr.ClawbackMonth)
								AND f.START_DATE Between cr.EffectiveFromDate AND cr.EffectiveToDate
WHERE 1=1 
and f.Type NOT LIKE 'Clawback%'


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



