/**********************************************************************************************
Name	: [BI].[pr_241_TandT_ClientListing] 
Author	: J Homer
Date	: 15/05/2026

		Insert report description here.
			

AMENDMENT HISTORY
=================
Date		Author		Description
----		------		-----------

***********************************************************************************************/
CREATE PROCEDURE [BI].[pr_241_TandT_ClientListing]

@BusinessUID	varchar(200) = 'View All',
@AdviserUID		varchar(200) = 'View All'


with recompile

AS 

set nocount on

/****************************************************************************

	Initialisation																
																		
****************************************************************************/
	
BEGIN TRY

declare
			@ReportName				varchar(200),
			@StoredProcName			varchar(200),
			@StoredProcParams		varchar(4000),
			@ErrMsg					nvarchar(4000),
			@LastAuditID			int,
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int

			--Change the @Reportname param here to the name of your report
set	@ReportName			= 'Example Report'
set @StoredProcName		= object_name(@@procid)


/****************************************************************************

	Select the data for the report																
																		
****************************************************************************/


--IF @BusinessUID != ''
--BEGIN
	CREATE TABLE #Agents
		(ID INT NOT NULL PRIMARY KEY CLUSTERED
		,CODE VARCHAR(7) NOT NULL
		,UserName VARCHAR(255) NULL
		,FirmName VARCHAR(255) NULL
		);

	INSERT #Agents 
				(ID
				,CODE
				,UserName
				,FirmName
				)
		SELECT	 a.ID
				,CASE WHEN a.CODE = '1005181' THEN '1003604' ELSE a.CODE END AS CODE
				,a.DESCN AS UserName
				,ISNULL(b.TradingName, b.DESCN) AS FirmName
		FROM		dbo.sa_swift_S_AGENTS a
		LEFT JOIN	dbo.sa_swift_S_AGENTS b ON b.CODE = a.Firm
		WHERE	a.Firm = @BusinessUID;

	CREATE TABLE #Person
		(PersonID INT NOT NULL PRIMARY KEY CLUSTERED
		,AdviserUID VARCHAR(7) NOT NULL
		);

	INSERT #Person
				(PersonID
				,AdviserUID
				)
		SELECT	 p.PersonID
				,CAST( RIGHT( N'0000000' + p.AdviserUID, 7 ) AS VARCHAR(7) )  AS AdviserUID
		FROM	dbo.sa_ows_Person p
		WHERE	p.AdviserUID = @AdviserUID or @AdviserUID = 'View All'
		UNION ALL
		SELECT	 p.PersonID
				,CAST( RIGHT( N'0000000' + p.AdviserUID, 7 ) AS VARCHAR(7) )  AS AdviserUID
		FROM	dbo.sa_ows_Person p
		WHERE	@AdviserUID IS NULL
		AND		EXISTS ( SELECT 1 FROM #Agents a WHERE a.CODE = CAST( RIGHT( N'0000000' + p.AdviserUID, 7 ) AS VARCHAR(7) ) );

	CREATE TABLE #PersonAudit
		(PersonAuditID BIGINT NOT NULL
		,PersonID INT NOT NULL
		,AdviserUID NVARCHAR(100) NOT NULL
		,BusinessUID NVARCHAR(100) NOT NULL
		,RowNum TINYINT NOT NULL
		,CONSTRAINT PK_Temp_PersonAudit PRIMARY KEY CLUSTERED ( PersonID, RowNum )
		);

	WITH PersonAudit AS
	(
		SELECT	 pa.PersonAuditID
				,pa.PersonID
				,pa.AdviserUID
				,pa.BusinessUID
				,ROW_NUMBER() OVER( PARTITION BY pa.PersonID ORDER BY PersonAuditID DESC ) AS RowNum
		FROM	dbo.sa_ows_PersonAudit pa
		WHERE	EXISTS ( SELECT 1 FROM #Person p WHERE p.PersonID = pa.PersonID )
	)
	INSERT #PersonAudit
				(PersonAuditID
				,PersonID
				,AdviserUID
				,BusinessUID
				,RowNum
				)
		SELECT	 PersonAuditID
				,PersonID
				,AdviserUID
				,BusinessUID
				,CAST( RowNum AS TINYINT )
		FROM	PersonAudit
		WHERE	RowNum < 3
		ORDER BY PersonID
				,RowNum
				;

	SELECT	 pers.BusinessUid
			,a.FirmName
			,pers.AdviserUID
			,a.UserName
			,pa1.PersonAuditID
			,pers.PersonID
			,pers.FirstName
			,pers.LastName
			,pers.DateOfBirth
			,pers.Address1 --added 3/5/17
			,pers.Address2 --added 3/5/17 
			,pers.Address3 --added 3/5/17
			,pers.Address4 --added 3/5/17
			,pers.Address5 --added 3/5/17
			,pers.PostCode
			,pers.TelephoneHome --added 3/2/17 SI
			,pers.TelephoneMobile --added 3/2/17 SI
			,pers.EmailAddress --added 3/2/17 SI
			,sele.Name
			,CASE sele.BscApplies WHEN 1 THEN 'Yes' ELSE 'No' END AS BSCApplies
			,CASE WHEN PrevAgNoBSC.PersonID IS NOT NULL THEN 'Yes' ELSE 'No' END AS PreviousAgreementNoBSC
			,pa2.BusinessUID AS PreviousBusinsess
			,ISNULL(miuh1.BusinessTradingName,miuh1.BusinessCompanyName) AS PreviousFirmName
			,pa2.AdviserUID AS PreviousAdviser
			,miuh1.UserName PreviousAdviserName
	FROM		#Agents a
	INNER JOIN	#Person p ON p.AdviserUID = a.CODE
	INNER JOIN	dbo.sa_ows_Person pers ON pers.PersonID = p.PersonID
	LEFT JOIN	dbo.sa_ows_ClientServiceLevel csle ON csle.PersonID = Pers.PersonID
	LEFT JOIN	Proposition.sa_ows_ServiceLevel sele ON sele.ServiceLevelId = csle.ServiceLevelId
	LEFT JOIN	#PersonAudit pa1 ON pa1.PersonID = p.PersonID AND pa1.RowNum = 1
	LEFT JOIN	#PersonAudit pa2 ON pa2.PersonID = p.PersonID AND pa2.RowNum = 2
	LEFT JOIN	dbo.mi_insight_UserHierarchy miuh1 ON miuh1.UserUID = pa2.AdviserUID
	LEFT JOIN	(
					SELECT DISTINCT csla.PersonID
					FROM   prod_zurich_openwork_datawarehouse.dbo.sa_ows_ClientServiceLevelAudit csla   
					JOIN   prod_zurich_openwork_datawarehouse.Proposition.sa_ows_ServiceLevel sl ON sl.ServiceLevelId = csla.ServiceLevelId AND sl.BscApplies = 0
				) PrevAgNoBSC ON PrevAgNoBSC.PersonID = p.PersonID
	ORDER BY a.UserName
			,pers.LastName
			,pers.FirstName
			;
--END


/****************************************************************************

	End Of Report
																	
****************************************************************************/


END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) 
	
END CATCH



