/****** Object:  StoredProcedure [BI].[pr_IssuedBusinessCaseByCase]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/************************************************************************************************
  	 Program:  	pr_IssuedBusinessCaseByCase
  	 					
	  Author:	John Homer - SQL (17/09/2021)
				A Groves - Stored procedure 

Date created:	20/09/2021
													
 Description:   This stored proc implements the "Issued Business Case by Case" scan to populate table
				[BI].[IssuedBusinessCBC].

				It is called as follows:

				declare @StartDate datetime = convert(datetime,'01/01/2006', 103)
				declare @EndDate datetime = DATEADD(day,datediff(day,0,GETDATE()),0)
				declare @IncrementalLoad varchar(1) = 'Y'
				exec BI.pr_IssuedBusinessCaseByCase @StartDate, @EndDate, @IncrementalLoad
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
24/11/2021	A Groves	SP63/US62644. The automation job at the current time takes between 3
						and 3.5 hours to run for Written, Written CBC, Issued and Issued
						CBC (CBC = case by case). This amendment is to make the proc run quicker. 
						The changes include:
						1) Removal of all CTEs and use of temp tables instead with some indexed.
						2) Relocated the emptying of the destination table from the start to the
							end of the proc. This stops the blocking of table expanding in SSMS.
						3) Logging added between each SQL statement so we can identify the
							poor performers.
25/11/2021	A Groves	Removed TRANSACTION handling to boost performance.
10/12/2021	A Groves	SP64/US66034. Further work on this proc to speed it up. This has been 
						achieved by:
						1) Using the same incremental update driver table that is
						used in the batch to update OpenAccess: owt_TransformationMovements.
						2) In addition, a new primary key has been added to the destination
						table called "PendingPaymentID". An important subtlety to note is that
						the incremental table (#AGMFILCHANGES) may contain DELETEs but we
						don't know which ones they are. So, as in the proc "mstp_PaymentsPending",
						we have to delete existing rows and re-insert them to ensure the deleted
						rows drop out.
						3) New proc parameter "@IncrementalLoad" added. It is set as follows:
							Y - The proc will update incrementally. This is the default.
							N - The proc will update on a full load  basis
22/12/2021	S Campbell	Add 3 columns to identify:
							- Single Tie and Panel  
							- 2 and 4 year business type
							- Indemnity and non-indemnity
28/03/2022	J Homer		Corrected the code to count NB Cases as it was incorrectly referencing 
						Transaction IDs to determine if a case should count instead of the 
						PolicyRef.
09/12/2022	J Homer		Amend ProductGroupName definition to include 7IM (7IM1 code) as 
						COB Platform
13/02/2023	J Homer		Amend Productgroupname2 definition for Legacy Business to correctly
						identify business rarther than classify all as Legacy off Platform
28/02/2023	J Homer		Update code for Multi Benefit cases so that cases now leading 8001 do not count as 
						New Business Cases
01/07/2023	J Homer		Update NBI Calculation to include GHL & First Affinity Override and to
						match calc in Issued Business Scan
02/07/2023	J Homer		Amend NBI and other areas of code to properly include 7IM cases		
16/08/2023	J Homer		Amend NBI and other areas of code to include new Embark (Scottish Widows Product
						Code prefix of OE.  Products are: 
							OEGIAS Scottish Widows General Investment Account
							OEISA Scottish Widows Individual Savings Account
							OEPENACC Scottish Widows Personal Pension
							OEBONDOF Utmost Bond (Scottish Widows)
14/11/2023	C Mellors	The changes at the start of June have caused the performance of this SP to be inconsistent.
						Several times a week, the SP never completes and is killed by the following night's DWH batch.
						Not only does this porevent the data from being generated, but it casuses undue stress on the DWH
						and negatively impacts everyone else using it.
						This change moves the incremental/full filter to the #AGMFILCHANGES table, reducing effort on the
						following query. This was where the SP was getting stuck.
12/02/2024	J Homer		Amend Legacy Business ProductGroupName and ProductGroupName2 descriptions
03/06/2024  J Homer		CHANGE TO NBCASES TO FIX THE ISSUE WITH SCOTTISH WIDOWS CASES, POST PLATFORM MIGRATION,  
						BEING INCORRECTLY CLASSIFIED AS NEW BUSINESS WHEN WE RECEIVE AN INCREASE TO AN OLD ZR POLICY NUMBER 
						UNDER THE NEW SCOTTISH WIDOWS EM POLICY NUMBER
27/01/2025	J Homer		Update Zero Fee Business code to use the Transaction Date from the Commission Table where the 
						CreateDateTime in the Policy Transaction table is NULL
02/04/2026	J Homer		Added Row Count to final Process Log Entry
************************************************************************************************/
CREATE PROCEDURE [BI].[pr_IssuedBusinessCaseByCase]
	@StartDate datetime,
	@EndDate datetime,
	@IncrementalLoad varchar(1) = 'Y'
AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.
SET DATEFIRST 1 
SET DATEFORMAT DMY

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@Message					varchar(100),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@Client						varchar(50),
		@Module						varchar(50),
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'MI Team Issued Business CBC'
set @DateLastUpdated	= getdate()

/****************************************************************************

	Log start 
																		
****************************************************************************/

exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

set @Message = '@IncrementalLoad = ' + @IncrementalLoad
exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	--BEGIN TRANSACTION

	/****************************************************************************

		Populate temp table

	****************************************************************************/
	
	create table #TransTable
	(
		transactionid	int,
		policyref		int,
		cont_num		varchar(25),
		productcode		varchar(8)
	)

	insert into #TransTable
	(
		transactionid,
		policyref,
		cont_num,
		productcode		
	)
	select	min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
	from	dbo.mstt_Commissions co INNER JOIN
			dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
			dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
	where co.poltrantranstype <> 39
	and co.agent_code not in ('10002','1011542','10004')	
	and co.commissiontype = 1
	and((left(ltrim(po.policyref),4) < '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
	and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
	group by po.policyref, po.cont_num, co.productcode

	set @RowCount = @@ROWCOUNT

	set @Message = '#TransTable Population 1'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	insert into #TransTable
	(
		transactionid,
		policyref,
		cont_num,
		productcode		
	)
	select	min(co.transactionid) as transactionid, '', '','L&G' provider
	from	dbo.mstt_Commissions co INNER JOIN
			dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
			dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
			#TransTable tt on tt.transactionid = co.TransactionID
	where
	tt.transactionid is null
	and co.agent_code not in ('10002','1011542','10004')
	and co.commissiontype = 1
	and co.poltrantranstype = 39
	--and co.businessreason in ('NB','NI')
	and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
	and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
	and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
	and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
	and((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
	and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
	group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

	set @RowCount = @@ROWCOUNT

	set @Message = '#TransTable Population 2'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	/****************************************************************************

		Populate #TransTable2

	****************************************************************************/

	select	transactionid,
			policyref,
			cont_num 
	into	#TransTable2 
	from	#TransTable 
	where	left(cont_num,2) NOT IN ('ZR','EM') 
	or		cont_num is null
	
	union all
	
	select	case when left(cont_num,2) IN ('ZR','EM') then min(transactionid) end transactionid, 
			policyref, 
			cont_num
	from	#TransTable 
	where	left(cont_num,2) IN ('ZR','EM')
	group	by  policyref, cont_num

	set @RowCount = @@ROWCOUNT

	set @Message = '#TransTable2 Population'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	drop table #TransTable

	/****************************************************************************

		Create #TransTable2 index

	****************************************************************************/

	create index IX_TransTable2_TransactionID on #TransTable2(transactionid)

	set @Message = '#TransTable2 Index Created'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client

	/****************************************************************************

		CORRECT APE LV

	****************************************************************************/

	Select distinct 
	edic.PolicyNumber, 
	edic.PremiumAmount, 
	edic.AmountReceived,  
	edic.CommissionType, 
	edih.LifeOfficeCode, 
	edih.DateReceived,
	potr.Amount, 
	potr.CommInitialPeriod, 
	potr.Amount/potr.CommInitialPeriod as CorrectPremium,
	(potr.Amount/potr.CommInitialPeriod)*12 as CorrectAPE,
	potr.Amount*12 as IncorrectAPE,
	pp.AGENT_CODE,
	pp.AGENT_PERC,
	pp.BACSDate,
	pp.FranchiseAgentCode,
	agt.DESCN,
	pp.TransactionID AS TransID
	into #LVTable
	from sa_swift_EDIFACTCommissionStatementContents edic
	join sa_swift_EDIFACTCommissionStatementHeader edih on edih.ID = edic.StatementHeaderID
	join sa_swift_S_PACC pacc on pacc.ID = edic.Pacc_ID
	join sa_swift_PolicyTransactions potr on potr.ID = pacc.TransactionID
	join mstt_PaymentsPending pp on pp.PACC_ID = pacc.ID
	join sa_swift_S_AGENTS agt on agt.code = pp.FranchiseAgentCode
	where edih.LifeOfficeCode = '24225G' and edih.DateReceived <= '10-Apr-2017' --dateadd(year,-1,getdate())
	and pp.BACSDate > '11-Jan-2016' 
	and edic.CommissionType = 'Y'
	and edic.PremiumAmount = potr.Amount
	and pp.AGENT_CODE != '10002'
	--order by Amount desc
	
	set @RowCount = @@ROWCOUNT

	set @Message = '#LVTable Population'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	/****************************************************************************

		Create #LVTable index

	****************************************************************************/

	create index IX_LVTable_PolicyNumber_TransID on #LVTable(PolicyNumber,TransID)

	set @Message = '#LVTable Index Created'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client

	/****************************************************************************

		Create a temp table for all the cases in scope

	****************************************************************************/

	CREATE TABLE #IssuedCBC
	(
		[PendingPaymentID] [int] NULL,
		[ZeroFeeID] [int] NULL,
		[LegacyID] [int] NULL,
		[BusinessType] [varchar](6) NOT NULL,
		[caseid] [int] NULL,
		[agent_code] [varchar](7) NULL,
		[Firm] [varchar](7) NULL,
		[commissiontypedesc] [varchar](255) NULL,
		[createdatetime] [date] NULL,
		[cashreceiveddate] [datetime] NULL,
		[IssDay] [int] NULL,
		[IssMonth] [int] NULL,
		[IssYear] [int] NULL,
		[Premium] [float] NULL,
		[APE] [float] NULL,
		[DA] [float] NULL,
		[NBI] [float] NULL,
		[Margin] [float] NULL,
		[NBCases] [float] NULL,
		[Cases] [float] NULL,
		[Frequency] [varchar](7) NOT NULL,
		[providerref] [varchar](25) NULL,
