	/****************************************************************************

		Identify the incremental updates
		NB: PendingPaymentID added to fix an issue with the wrong data type on msit_commissionstatement

	****************************************************************************/

	CREATE TABLE #AGMFILChanges 
		(ID INT NOT NULL CONSTRAINT PK_AGMFILChanges PRIMARY KEY CLUSTERED
		,PendingPaymentID VARCHAR(10) NOT NULL
		)
	CREATE INDEX IX_AGMFILChanges_PendingPaymentID ON #AGMFILChanges (PendingPaymentID)

	IF @IncrementalLoad = 'Y'
	BEGIN
		INSERT	#AGMFILChanges
		SELECT	DISTINCT 
				 ag.ID
				,CAST(ag.ID AS VARCHAR(10)) AS PendingPaymentID
		FROM	dbo.mstt_paymentspending ag
		JOIN	dbo.owt_TransformationMovements tm	 ON tm.PKID = ag.ID
													AND tm.DriverTableName = 'sa_swift_S_AGMFIL'
													AND tm.PendingPayments = 'Y' 
		WHERE	ag.CreateDateTime >= @StartDate
		AND		ag.CreateDateTime <= @EndDate
		AND		ag.AGENT_CODE <> '10002' 
		AND		ag.AGENT_CODE <> '1011623'
		AND		ag.AMOUNT <> 0
		AND		ISNULL(ag.Manager2Code,'1111') <> '1011671' -- EXCLUDES OWL ADVISERS
	END
	ELSE
	BEGIN
		INSERT	#AGMFILChanges
		SELECT	 ag.ID
				,CAST(ag.ID AS VARCHAR(10)) AS PendingPaymentID
		FROM	dbo.mstt_paymentspending ag
		WHERE	ag.CreateDateTime >= @StartDate
		AND		ag.CreateDateTime <= @EndDate
		AND		ag.AGENT_CODE <> '10002' 
		AND		ag.AGENT_CODE <> '1011623'
		AND		ag.AMOUNT <> 0
		AND		ISNULL(ag.Manager2Code,'1111') <> '1011671' -- EXCLUDES OWL ADVISERS
	END
 
	set @RowCount = @@ROWCOUNT

	set @Message = '#AGMFILCHANGES Population'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	/****************************************************************************

		Select issued Swift

	****************************************************************************/

	insert into #IssuedCBC
	(
		PendingPaymentID,
		ZeroFeeID,
		LegacyID,
		BusinessType,
		caseid,
		agent_code,
		Firm,
		commissiontypedesc,
		createdatetime,
		cashreceiveddate,
		IssDay,
		IssMonth,
		IssYear,
		Premium,
		APE,
		DA,
		NBI,
		Margin,
		NBCases,
		Cases,
		Frequency,
		providerref,
		BusinessReason,
		adminmethod,
		ProductCode,
		Comp_code,
		reportingproductname,
		productsubgroupname,
		ProductGroupName,
		calculationcode,
		paybasisdesc,
		oastatus,
		ProductGroupName2,
		ProductSubGroup,
		Advicemethod,
		CCSDescription,
		PanelType,
		InitialPeriod,
		IndemnityType
	)
	select
	ag.ID as PaymentPendingID,
	null as ZeroFeeID,
	null as LegacyID,
	'Issued' as "BusinessType",
	ag.caseid,
	case when ag.agent_code in ('1011543','1011587') then co3.agent_code when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end as agent_code,

	Case 
	when ag.agent_code in ('1011543','1011587') then 

	(case 

	when co3.firm = '1000941' then '1007791' when co3.firm = '1000976' then '2001655' when co3.firm = '1001619' then '2001460' when co3.firm = '1001747' then '1006123' when co3.firm = '1001860' then '2000914' when co3.firm = '1001931' then '2001142' when co3.firm = '1002683' then '2001252' when co3.firm = '1002866' then '2001140' when co3.firm = '1002958' then '1002961' when co3.firm = '1003038' then '2001543' when co3.firm = '1003450' then '2001454' when co3.firm = '1004284' then '1000392' when co3.firm = '1005445' then '2001002' when co3.firm = '1010723' then '1001338' when co3.firm = '1000746' then '1011544' when co3.firm = '1002578' then '2001476' when co3.firm = '1002580' then '1011548' when co3.firm = '2000508' then '1004215'
	when co3.firm = '1001374' then '2001538' when co3.firm = '1000981' then '2000425' when co3.firm = '2000522' then '2001536' when co3.firm = '1009210' then '2001543' when co3.firm = '1001167' then '2001540' when co3.firm = '1001789' then '2001395' when co3.firm = '1002076' then '2001475' when co3.firm = '1001058' then '2001549' when co3.firm = '1011487' then '2001497' when co3.firm = '1000821' then '1011541' when co3.firm = '1000692' then '2001575' when co3.firm = '1007638' then '2001578' when co3.firm = '1001804' then '2001582' when co3.firm = '1000794' then '2001580' when co3.firm = '1001492' then '2001584' when co3.firm = '1011448' then '2001585' when co3.firm = '1011540' then '1001897' when co3.firm = '1002178' then '2001613'
	when co3.firm = '1000967' then '2001653' when co3.firm = '2001040' then '2001655' when co3.firm = '1001891' then '2001714' when co3.firm = '1002112' then '2001807' when co3.firm = '1000867' then '1011604' when co3.firm = '1011608' then '1010815' when co3.firm = '1001049' then '2001995' when co3.firm = '1000724' then '1004141' when co3.firm = '1001346' then '1009425' when co3.firm = '1000678' then '2004388' when co3.firm = '1000704' then '1003010' when co3.firm = '1008026' then '1001546' when co3.firm = '1002702' then '2001504' when co3.firm = '2000988' then '1001249' when co3.firm = '2001397' then '2004449' when co3.firm = '1000995' then '2004732'
	when co3.firm = '1002174' then '2006794' when co3.firm = '1009620' then '2010099' when co3.firm = '1007327' then '2011344' when co3.Firm = '1002338' then '1002949'

	else co3.firm end)

	when (case when((cs.oastatus <> 'valid' or cs.oastatus is NULL) and (ag.agent_code <> '1011543' or ag.agent_code <> '1011587' or ag.agent_code is NULL)) then '1006886' else ag.agent_code end) = '1006886' then 'NULL' 

	when ag.firm = '1000941' then '1007791' when ag.firm = '1000976' then '2001655' when ag.firm = '1001619' then '2001460' when ag.firm = '1001747' then '1006123' when ag.firm = '1001860' then '2000914' when ag.firm = '1001931' then '2001142' when ag.firm = '1002683' then '2001252' when ag.firm = '1002866' then '2001140' when ag.firm = '1002958' then '1002961' when ag.firm = '1003038' then '2001543' when ag.firm = '1003450' then '2001454' when ag.firm = '1004284' then '1000392' when ag.firm = '1005445' then '2001002' when ag.firm = '1010723' then '1001338' when ag.firm = '1000746' then '1011544' when ag.firm = '1002578' then '2001476' when ag.firm = '1002580' then '1011548' when ag.firm = '2000508' then '1004215'
	when ag.firm = '1001374' then '2001538' when ag.firm = '1000981' then '2000425' when ag.firm = '2000522' then '2001536' when ag.firm = '1009210' then '2001543' when ag.firm = '1001167' then '2001540' when ag.firm = '1001789' then '2001395' when ag.firm = '1002076' then '2001475' when ag.firm = '1001058' then '2001549' when ag.firm = '1011487' then '2001497' when ag.firm = '1000821' then '1011541' when ag.firm = '1000692' then '2001575' when ag.firm = '1007638' then '2001578' when ag.firm = '1001804' then '2001582' when ag.firm = '1000794' then '2001580' when ag.firm = '1001492' then '2001584' when ag.firm = '1011448' then '2001585' when ag.firm = '1011540' then '1001897' when ag.firm = '1002178' then '2001613'
	when ag.firm = '1000967' then '2001653' when ag.firm = '2001040' then '2001655' when ag.firm = '1001891' then '2001714' when ag.firm = '1002112' then '2001807' when ag.firm = '1000867' then '1011604' when ag.firm = '1011608' then '1010815' when ag.firm = '1001049' then '2001995' when ag.firm = '1000724' then '1004141' when ag.firm = '1001346' then '1009425' when ag.firm = '1000678' then '2004388' when ag.firm = '1000704' then '1003010' when ag.firm = '1008026' then '1001546' when ag.firm = '1002702' then '2001504' when ag.firm = '2000988' then '1001249' when ag.firm = '2001397' then '2004449' when ag.firm = '1000995' then '2004732'
	when ag.firm = '1002174' then '2006794' when ag.firm = '1009620' then '2010099' when ag.firm = '1007327' then '2011344' when ag.firm = '1002338' then '1002949'

	else ag.firm End AS "Firm", ag.commissiontypedesc,
	CONVERT(DATE,ag.createdatetime,103) as createdatetime, coalesce(ex.cashreceiveddate,ex2.cashreceiveddate,ex3.cashreceiveddate) as cashreceiveddate,

	day(ag.createdatetime) as "IssDay", month(ag.createdatetime) as "IssMonth", year(ag.createdatetime) as "IssYear",

	-- PREMIUM FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM
	(Case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 else
	(Case when (case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' end) = 'Single' then ((case when  (ag.commissiontype = 2 AND ph.productgroupname = 'Mortgage') then (coalesce(cs.ape,co2.turnover,0)) when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) *10) else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end)
	end) end) as "Premium",

	-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
	Case when (c.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then c.CorrectAPE else
	((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
	-- ENSURE MORTGAGES APE IS THE SAME AS DA
	(case when 
	ph.productgroupname = 'mortgage'
	then (case when (
	ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
	-- GROSS DA SERVICING
	when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ','OE') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- GROSS DA TRAIL
	when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
	-- GROSS DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
	else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) END))End as "APE", 

	case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount+ag.derivedmarginamount) ElSE

		(Case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
	-- GROSS DA SERVICING
	when (cs.oastatus = 'valid' and (left(ag.tranproduct,2) in ('OW','OF','OZ', 'OE') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- GROSS DA TRAIL
	when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
	-- GROSS DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then 
		(ag.amount + isnull(derivedmarginamount,0)) else 0 END)END as 'DA',

	-- COMM INITIAL
	--case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then cs.inissued
	---- COMM SERVICING
	--when (cs.oastatus = 'valid' and left(ag.tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
	---- COMM TRAIL
	--when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
	--else 0 end as NBI,

	CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
		      WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
		      WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
		      when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
		      when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount)
			  when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName <> 'Mortgage') then (cs.INIssued)
-- NET COMM SERVICING
			  when (cs.oastatus = 'valid' and (left(ag.tranproduct,2) in ('OW','OF','OZ', 'OE') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- NET COMM TRAIL
			  when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
			  else 0 
		  end as NBI,

	-- GROSS MARGIN INITIAL
	CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
		when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
		WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
		when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) 
	
	
		when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.productgroupname = 'Mortgage') then 
		(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
			 when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
			 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
			 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) ELSE (ag.derivedmarginamount) END)
	
		when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)
	-- GROSS MARGIN TRAIL
	when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ((ag.amount / (8.0/10)) - ag.amount) 
	-- GROSS MARGIN POT ACCOUNT/SERVICING
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end as 'Margin',

	--(case when ag.commissiontypedesc like '%claw%' then 0 when b.PolicyRef is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NBCases",
	(case when ag.commissiontypedesc like '%claw%' then 0 
		  when b.transactionid is null then 0 
		  when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 
		  when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 
		  when em.TargetAccountId IS NOT NULL then 0  -- ADDED LINE TO SET NBCASES AS 0 WHEN THE NEW EM POLICY NUMBER IS FOUND IN THE EMBARK MIGRATION TABLE
		  when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 
		  when cs.ape = 0 then 0 
		  when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 
		  else 0 
	 end) as "NBCases",
	
	coalesce(case when ag.commissiontypedesc like '%claw%' then 0 when ((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection') then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when cs.ape < 0 then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 else ag.derivedagentsplit/100 end,0) as "Cases",

	case when pt.frequencydescription = 'Single' Then 'Single' ELSE 'Regular' END AS 'Frequency', ag.providerref
	, coalesce(co.businessreason,co2.businessreason,'NB') as "BusinessReason", coalesce(co.adminmethoddescription,co2.adminmethoddescription) as adminmethod, isnull(co.productcode,ag.tranproduct) as "ProductCode", isnull(co.productprovidercode,ag.comp_code) as "Comp_code", rp.reportingproductname as reportingproductname, ph.productsubgroupname as productsubgroupname, 

	case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' 
															 when ((left(ag.tranproduct,2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' 
															 when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' 
															 when ph.productgroupname = 'Other' then 'COB Off Platform' 
															 else ph.productgroupname 
														 end) 
		 when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) then 'Servicing Fee' 
		 when ag.agent_code = '1011587' then 'BSC' 
		 when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' 
		 else 'Legacy Recurring' 
	end as ProductGroupName,
	
	ccs.calculationcode, case when cs.paybasisdesc in ('Accr') then 'Accrual' else 'Indemnity' end as paybasisdesc, cs.oastatus,

	case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' 
															 when ((left(ag.tranproduct,2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' 
															 when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' 
															 when ph.productgroupname = 'Other' then 'COB Off Platform' 
															 else ph.productgroupname 
														 end) 
		  when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) then 'Recurring Income' 
		  when ag.agent_code = '1011587' then 'Recurring Income' 
		  when ag.commissiontype in ('10','16','19') then 'Recurring Income' 
		  else 'Recurring Income' 
	 end as ProductGroupName2,

	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' 
																		when (left(isnull(co.productcode,ag.tranproduct),2) in ('OW','OZ','OE') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.COMP_CODE = '7IM1' then 'COB Platform' 
																		when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' 
																		else ph.productgroupname 
																	end) 
				    when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) then 'Recurring Income' 
					when ag.commissiontype in ('10','16','19') then 'Recurring Income'
					else 'Recurring Income' 
				end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Recurring Income'
	
	--Protection
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when isnull(co.productprovidercode,ag.comp_code) in ('Zurich New','Zurich Leg','Zurich PNL') then 'Zurich' when isnull(co.productprovidercode,ag.comp_code) = 'Scot Eq' then 'Aegon' when isnull(co.productprovidercode,ag.comp_code) = 'Axa' then 'Friends Life' else isnull(co.productprovidercode,ag.comp_code) end) 
	-- Pensions
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OW') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productcode,ag.tranproduct) = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'IFDL'
	when ((left(isnull(co.productcode,ag.tranproduct),2) in ('OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT') then 'ZIP'
	when (isnull(co.productprovidercode,ag.comp_code) = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'Annuities' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then isnull(co.productprovidercode,ag.comp_code)

	-- Annuities
	when (isnull(co.productprovidercode,ag.comp_code) = 'PTSP') then 'Partnership' when isnull(co.productprovidercode,ag.comp_code) = 'MGMA' then 'MGMA'
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru Ann'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform' then isnull(co.productprovidercode,ag.comp_code)

	-- Investments
	when (isnull(co.productprovidercode,ag.comp_code) = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (isnull(co.productprovidercode,ag.comp_code) = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'Annuities' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then isnull(co.productprovidercode,ag.comp_code)

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Santander%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Skipton (Buildstore)%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Principality%' then 'Principality' when rp.reportingproductname like '%lloyds TSB%' then 'TSB' when rp.reportingproductname like '%Precise%' then 'Precise' when rp.reportingproductname like '%Newcastle%' then 'Newcastle Building Society' when rp.reportingproductname = 'BOI' THEN 'Bank of Ireland' when rp.reportingproductname like '%Woolwich%' then 'Barclays' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
	else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end as "ProductSubGroup",

	case when (case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ((left(ag.tranproduct,2) in ('OW','OF','OZ','OE')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.commissiontype in ('10','16','19') then 'Trail Income' else 'Renewal Income' end) in ('Trail Income','Renewal Income','Servicing Fee') then 'Advised' when 
	((ph.productgroupname <> 'Mortgage' and coalesce(co.adminmethod,co2.adminmethod,'A') NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich Leg' or isnull(co.productcode,ag.tranproduct) = 'ZGUA' or isnull(co.productprovidercode,ag.comp_code) = 'Close' or isnull(co.productprovidercode,ag.comp_code) = 'MSQ') then 'Non Advised' else 'Advised' end as "Advicemethod",
	(replace(ccs.description,'do not use - ','')) as CCSDescription,
	case isnull(left(ccs.Description,3) ,'X')
	when '001' then 'Single Tie'
	when '002' then 'Single Tie'
	when '032' then 'Single Tie'
	when '005' then 'Panel'
	else  'N/A' end as 'PanelType',
	CONVERT(VARCHAR(4),pt.comminitialperiod/12) as 'Initial Period',
	case isnull(co.CommType ,'X')
	when 'F' then 'Non-Indemnity'
	when 'T' then 'Indemnity'
	else 'N/A' end as 'IndemnityType'
	from	#AGMFILCHANGES chg INNER JOIN
			mstt_paymentspending ag ON ag.ID = chg.ID LEFT OUTER JOIN
			msit_commissionstatement cs ON cs.PendingPaymentID = chg.PendingPaymentID LEFT OUTER JOIN
			msit_openworkadviserlisting oa ON oa.sourceid = cs.id AND oa.Source = 'Openwork 2006' LEFT OUTER JOIN
			mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
			mstt_Commissions co2 on co2.transactionid = ag.transactionid 
			and co2.agent_code = ag.agent_code 
			and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
			when ag.commissiontype in (4,15,18) then 4 
			when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
			mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
			mstt_Commissions co3 on co3.transactionid = ag.transactionid 
			and co3.agent_code = pt.agentcode
			and co3.commissiontype = ag.commissiontype 
			and co3.firm <> '1011543' LEFT OUTER JOIN
			mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
			msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
			cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
			mstt_expectation ex ON ex.id = cs.expectationid LEFT OUTER JOIN
			(select max(cashreceiveddate) as cashreceiveddate, amount_rec, transactionid from mstt_expectation group by transactionid, amount_rec) ex2 ON ex2.transactionid = ag.transactionid and ag.amount = ex2.amount_rec LEFT OUTER JOIN
			(select max(cashreceiveddate) as cashreceiveddate, transactionid from mstt_expectation group by transactionid) ex3 ON ex3.transactionid = ag.transactionid LEFT OUTER JOIN
			#TransTable2 b on b.transactionid = ag.transactionid LEFT OUTER JOIN 
			#LVTable c on (c.PolicyNumber = ag.providerref) AND (c.TransID = ag.TransactionID)
			left join mstt_Policies po ON pt.policyid = po.pol_num
			LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = ag.providerref  --JOIN TO NEW EMBARKL MIGRATION TABLE
	where	(co2.id not in ('17797514','17797515') or co2.id is NULL)
	and		(co3.id not in ('17797514','17797515') or co3.id is NULL)
	--ENSURE NO TRAIL WHERE OPENWORK DO NOT TAKE A MARGIN IS INCLUDED
	and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') 
										  and ag.tranproduct not like '%INCOME%' 
										  and ag.tranproduct not like '%PRUFUND%' 
										  and ag.tranproduct not like '%FIA%' 
										  and ag.tranproduct not like 'OW%' 
										  and ag.tranproduct not like 'OF%' 
										  and ag.tranproduct not like 'OZ%'
										   and ag.tranproduct not like 'OE%'
										  AND (ag.CommissionTypeDesc <>'Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) <> '7IM1'))  then 'NonTrail' 
				else 'Other' end) <> 'NonTrail' 

	---ENSURE NO ZERO DA TRANSACTIONS ARE INCLUDED AS UNNEEDED
	and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
	-- NET DA SERVICING
	when (cs.oastatus = 'valid' and (left(ag.tranproduct,2) in ('OW','OF','OZ','OE') OR (ag.CommissionTypeDesc ='Trail Fee' AND ISNULL(co.productprovidercode, ag.COMP_CODE) = '7IM1')) and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
	-- NET DA TRAIL
	when (cs.oastatus = 'valid' and ag.tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
	-- NET DA POT ACCOUNT
	when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
	----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
	and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
	-----------------------------------------------------------------------

	set @RowCount = @@ROWCOUNT

	set @Message = '#IssuedCBC Population 1'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	/****************************************************************************

		Select zero upfront APE

	****************************************************************************/

	insert into #IssuedCBC
	(
		PendingPaymentID,
		ZeroFeeID,
		LegacyID,
		BusinessType,
		caseid,
		agent_code,
		Firm,
		commissiontypedesc,
		createdatetime,
		cashreceiveddate,
		IssDay,
		IssMonth,
		IssYear,
		Premium,
		APE,
		DA,
		NBI,
		Margin,
		NBCases,
		Cases,
		Frequency,
		providerref,
		BusinessReason,
		adminmethod,
		ProductCode,
		Comp_code,
		reportingproductname,
		productsubgroupname,
		ProductGroupName,
		calculationcode,
		paybasisdesc,
		oastatus,
		ProductGroupName2,
		ProductSubGroup,
		Advicemethod,
		CCSDescription,
		PanelType,
		InitialPeriod,
		IndemnityType
	)
	select
	null as PaymentPendingID,
	co.ID as ZeroFeeID,
	null as LegacyID,
	'Issued' as "Type",
	po.policyref as CaseID,
	co.agent_code,

	case
	when co.firm = '1000941' then '1007791' when co.firm = '1000976' then '2001655' when co.firm = '1001619' then '2001460' when co.firm = '1001747' then '1006123' when co.firm = '1001860' then '2000914' when co.firm = '1001931' then '2001142' when co.firm = '1002683' then '2001252' when co.firm = '1002866' then '2001140' when co.firm = '1002958' then '1002961' when co.firm = '1003038' then '2001543' when co.firm = '1003450' then '2001454' when co.firm = '1004284' then '1000392' when co.firm = '1005445' then '2001002' when co.firm = '1010723' then '1001338' when co.firm = '1000746' then '1011544' when co.firm = '1002578' then '2001476' when co.firm = '1002580' then '1011548' when co.firm = '2000508' then '1004215'
	when co.firm = '1001374' then '2001538' when co.firm = '1000981' then '2000425' when co.firm = '2000522' then '2001536' when co.firm = '1009210' then '2001543' when co.firm = '1001167' then '2001540' when co.firm = '1001789' then '2001395' when co.firm = '1002076' then '2001475' when co.firm = '1001058' then '2001549' when co.firm = '1011487' then '2001497' when co.firm = '1000821' then '1011541' when co.firm = '1000692' then '2001575' when co.firm = '1007638' then '2001578' when co.firm = '1001804' then '2001582' when co.firm = '1000794' then '2001580' when co.firm = '1001492' then '2001584' when co.firm = '1011448' then '2001585' when co.firm = '1011540' then '1001897' when co.firm = '1002178' then '2001613'
	when co.firm = '1000967' then '2001653' when co.firm = '2001040' then '2001655' when co.firm = '1001891' then '2001714' when co.firm = '1002112' then '2001807' when co.firm = '1000867' then '1011604' when co.firm = '1011608' then '1010815' when co.firm = '1001049' then '2001995' when co.firm = '1000724' then '1004141' when co.firm = '1001346' then '1009425' when co.firm = '1000678' then '2004388' when co.firm = '1000704' then '1003010' when co.firm = '1008026' then '1001546' when co.firm = '1002702' then '2001504' when co.firm = '2000988' then '1001249' when co.firm = '2001397' then '2004449' when co.firm = '1000995' then '2004732'
	when co.firm = '1002174' then '2006794' when co.firm = '1009620' then '2010099' when co.firm = '1007327' then '2011344' when co.Firm = '1002338' then '1002949'

	else co.firm end as "Firm",
	commissiontypedesc = 'Zero Fee',
	CONVERT(DATE,ISNULL(pt.createdatetime, co.TransactionDate),103) as createdatetime,--CONVERT(DATE,pt.createdatetime,103) as createdatetime,
	ISNULL(pt.createdatetime, co.TransactionDate) createdatetime, --pt.createdatetime,

	day(ISNULL(pt.createdatetime, co.TransactionDate)) as "Day", month(ISNULL(pt.createdatetime, co.TransactionDate)) as "Month", year(ISNULL(pt.createdatetime, co.TransactionDate)) as "Year", --day(pt.createdatetime) as "Day", month(pt.createdatetime) as "Month", year(pt.createdatetime) as "Year",
	(case when pt.frequencydescription = 'Single' Then (co.ape * 10) ELSE (co.ape) end) as "Premium",
	(co.ape),
	DA = 0,
	NBI = 0,
	Margin = 0,
	(case when b.PolicyRef is null then 0 
		  when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 
		  when co.ape = 0 then 0 
		  when em.TargetAccountId IS NOT NULL then 0  -- ADDED LINE TO SET NBCASES AS 0 WHEN THE NEW EM POLICY NUMBER IS FOUND IN THE EMBARK MIGRATION TABLE
		  when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 
		  else 0 
	  end) as "NewPolicies",
	agent_perc/100 as Cases,
	pt.frequencydescription,
	po.cont_num as Provideref,
	co.businessreason,
	co.adminmethoddescription,
	co.productcode,
	co.productprovidercode as Comp_Code,
	rp.reportingproductname,
	ph.productsubgroupname,
	
	case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ','OE') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE'))  or ph.ProductProviderCode = '7IM1' or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end as 'ProductGroupName'
	
	, ccs.description,
	pt.commissiontypedesc,
	oastatus = 'NULL',
	
	case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ','OE') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or ph.ProductProviderCode = '7IM1' or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end as "Productgroupname",

	--Protection
	case when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Protection' then (case when po.comp_code in ('Zurich New','Zurich Leg') then 'Zurich' when po.comp_code = 'Scot Eq' then 'Aegon' when po.comp_code = 'Axa' then 'Friends Life' else po.comp_code end) 
	-- Pensions
	when ((left(co.productcode,2) in ('OW') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or co.productcode = 'OFHBSIPP' or po.comp_code = 'Pru PLT') then 'IFDL'
	when ((left(co.productcode,2) in ('OZ') AND ph.ProductCode NOT IN ('OWADHOC', 'OWADVICE')) or po.comp_code = 'Zurich PLT') then 'ZIP'
	when (po.comp_code = 'MetLife' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions') then 'MetLife'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Pensions' then po.comp_code

	-- Annuities
	when (po.comp_code = 'PTSP') then 'Partnership' when po.comp_code = 'MGMA' then 'MGMA'
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'COB Off Platform') then 'Pru'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Annuities' then po.comp_code

	-- Investments
	when (po.comp_code = 'PRU' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Pru'
	when (po.comp_code = 'Scot EqInt' and (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment') then 'Aegon'
	when (ph.productgroupname = 'Investment' and ph.productsubgroupname like '%Guaranteed Account%') then 'Structured'
	when (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) = 'Investment' then po.comp_code

	when ph.productgroupname = 'Mortgage' then 
	(case when rp.reportingproductname like '%Leeds & Holbeck Mortgages%' then 'Leeds Building Society' when rp.reportingproductname like '%Nationwide Mortgages%' then 'Nationwide Building Society' when rp.reportingproductname like '%Natwest Mortgages%' then 'Natwest' when rp.reportingproductname like '%Progressive Mortgages%' then 'Progressive Building Society' when rp.reportingproductname like '%Abbey Mortgages%' then 'Santander for Intermediaries' when rp.reportingproductname like '%Skipton Mortgages%' then 'Skipton Building Society' when rp.reportingproductname like '%Northern Rock%' then 'Virgin Money' when rp.reportingproductname like '%Platform%' then 'Platform (Co-op Bank)' when rp.reportingproductname like '%BM Solutions%' then 'BM Solutions (LBG)' when rp.reportingproductname like '%The Mortgage Works%' then 'The Mortgage Works (NBS)' when rp.reportingproductname like '%Godiva%' then 'Coventry' when rp.reportingproductname like '%Kensington%' then 'Investec' when rp.reportingproductname like '%Principality%' then 'Principality' else replace(replace(rp.reportingproductname,' Mortgages',''),' (TBMC)','') end)
	else (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' else ph.productgroupname end) end as "ProductSubGroup",

	(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod",
	(replace(ccs.description,'do not use - ','')) as description,
	case isnull(left(ccs.Description,3) ,'X')
	when '001' then 'Single Tie'
	when '002' then 'Single Tie'
	when '032' then 'Single Tie'
	when '005' then 'Panel'
	else  'N/A' end as 'PanelType',
	CONVERT(VARCHAR(4),pt.comminitialperiod/12) as 'Initial Period',
	case isnull(co.CommType ,'X')
	when 'F' then 'Non-Indemnity'
	when 'T' then 'Indemnity'
	else 'N/A' end as 'IndemnityType'
	from	mstt_Commissions co LEFT OUTER JOIN
			mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
			mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
			mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
			msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
			cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
			#TransTable2 b on b.transactionid = co.transactionid
			LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = po.CONT_NUM  --JOIN TO NEW EMBARKL MIGRATION TABLE
	where	co.agent_code <> '10002'
	and		ISNULL(pt.createdatetime, co.TransactionDate) >= @StartDate --pt.createdatetime >= @StartDate
	and		ISNULL(pt.createdatetime, co.TransactionDate) <= @EndDate --pt.createdatetime <= @EndDate
	and		co.commissiontype = 1
	and		ph.rdrtype is not null
	and		pt.comminitialamount <= 0 and pt.amount > 0
	and		co.poltrantranstype = 17
	and		(rtrim(ah.ASDName) not in ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
	----------------------------EXCLUDE ALL GROUP PENSION BUSINESS--------------------------------
	and		(case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
	----------------------------------------------------------------------------------------------

	set @RowCount = @@ROWCOUNT

	set @Message = '#IssuedCBC Population 2'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	/****************************************************************************

		Select legacy

	****************************************************************************/

	insert into #IssuedCBC
	(
		PendingPaymentID,
		ZeroFeeID,
		LegacyID,
		BusinessType,
		caseid,
		agent_code,
		Firm,
		commissiontypedesc,
		createdatetime,
		cashreceiveddate,
		IssDay,
		IssMonth,
		IssYear,
		Premium,
		APE,
		DA,
		NBI,
		Margin,
		NBCases,
		Cases,
		Frequency,
		providerref,
		BusinessReason,
		adminmethod,
		ProductCode,
		Comp_code,
		reportingproductname,
		productsubgroupname,
		ProductGroupName,
		calculationcode,
		paybasisdesc,
		oastatus,
		ProductGroupName2,
		ProductSubGroup,
		Advicemethod,
		CCSDescription,
		PanelType,
		InitialPeriod,
		IndemnityType
	)
	select 
	null as PaymentPendingID,
	null as ZeroFeeID,
	fnsfl.ID as LegacyID,
	'Issued' as "Type",
	oa.caseID,
	oa.sellercode as "agent_code",
	Case
	when oa.businesscode = '1000941' then '1007791' when oa.businesscode = '1000976' then '2001040' when oa.businesscode = '1001619' then '2001460' when oa.businesscode = '1001747' then '1006123' when oa.businesscode = '1001860' then '2000914' when oa.businesscode = '1001931' then '2001142' when oa.businesscode = '1002683' then '2001252' when oa.businesscode = '1002866' then '2001140' when oa.businesscode = '1002958' then '1002961' when oa.businesscode = '1003038' then '2001543' when oa.businesscode = '1003450' then '2001454' when oa.businesscode = '1004284' then '1000392' when oa.businesscode = '1005445' then '2001002' when oa.businesscode = '1010723' then '1001338' when oa.businesscode = '1000746' then '1011544' when oa.businesscode = '1002578' then '2001476' when oa.businesscode = '1002580' then '1011548' when oa.businesscode = '2000508' then '1004215'
	when oa.businesscode = '1001374' then '2001538' when oa.businesscode = '1000981' then '2000425' when oa.businesscode = '2000522' then '2001536' when oa.businesscode = '1009210' then '2001543' when oa.businesscode = '1001167' then '2001540' when oa.businesscode = '1001789' then '2001395' when oa.businesscode = '1002076' then '2001475' when oa.businesscode = '1001058' then '2001549' when oa.businesscode = '1011487' then '2001497' when oa.businesscode = '1000821' then '1011541' when oa.businesscode = '1000692' then '2001575' when oa.businesscode = '1007638' then '2001578' when oa.businesscode = '1001804' then '2001582' when oa.businesscode = '1000794' then '2001580' when oa.businesscode = '1001492' then '2001584' when oa.businesscode = '1011448' then '2001585' when oa.businesscode = '1011540' then '1001897' when oa.businesscode = '1002178' then '2001613'
	when oa.businesscode = '1000967' then '2001653' when oa.businesscode = '2001040' then '2001655' when oa.businesscode = '1001891' then '2001714' when oa.businesscode = '1002112' then '2001807' when oa.businesscode = '1000867' then '1011604' when oa.businesscode = '1011608' then '1010815' when oa.businesscode = '1001049' then '2001995' when oa.businesscode = '1000724' then '1004141' when oa.businesscode = '1001346' then '1009425' when oa.businesscode = '1000678' then '2004388' when oa.businesscode = '1000704' then '1003010' when oa.businesscode = '1008026' then '1001546' when oa.businesscode = '1002702' then '2001504' when oa.businesscode = '2000988' then '1001249' when oa.businesscode = '2001397' then '2004449' when oa.businesscode = '1000995' then '2004732' when oa.BusinessCode = '2001518' then '2006569' when oa.BusinessCode = '2005389' then '2006353'
	when oa.businesscode = '1002174' then '2006794' when oa.businesscode = '1009620' then '2010099' when oa.businesscode = '1007327' then '2011344' when oa.businesscode = '1002338' then '1002949'

	Else oa.businesscode End as "Firm Code",
	'Legacy' as commissiontypedec,
	CONVERT(DATETIME, oa.month,102) as Date, 
	CONVERT(varchar(10),oa.month,103) as Date2,
	'1' as "Day", 
	month(oa.month) as "Month",
	year(oa.month) as "Year",
	(oa.ape) as "Premium",
	(oa.ape) as "APE",

	(case when ph.productgroupname = 'Mortgage' then oa.ape else oa.totdue_enhd/0.8163 end) as "DA",
	(case when ph.productgroupname = 'Mortgage' then oa.ape else oa.totdue_enhd/0.8163 end) - (case when ph.productgroupname = 'Mortgage' then oa.ape - oa.totdue_enhd else ((oa.totdue_enhd/0.8163) - oa.totdue_enhd) end) AS NBI,
	(case when ph.productgroupname = 'Mortgage' then oa.ape - oa.totdue_enhd else ((oa.totdue_enhd/0.8163) - oa.totdue_enhd) end) as "Margin",
	0 as 'NB Cases',
	0 as Cases,
	CASE WHEN oa.frequency = 'S' THEn 'Single' ELSE 'Regular' END,
	OA.Policy as 'providerref',
	'Legacy' AS 'business reason',
	'Legacy' as 'adminmethod',
	ph.productcode,
	ph.ProductProviderCode,
	rp.reportingproductname,

	'Legacy ' + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' else (case when isNull(ph.productgroupname,'Protection') = 'Protection' then 'Zurich' else isNull(ph.productgroupname,'Protection') end) end as productsubgroupname,

	'Legacy ' + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' else (case when isNull(ph.productgroupname,'Protection') = 'Protection' then 'Zurich' else isNull(ph.productgroupname,'Protection') end) end as productgroupname,
	oa.source,
	' ' as paybasisdesc,
	NULL as oastatus,
	case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end as 'ProductGroupName2',
	'Legacy' as 'ProductSubGroup',
	'Non Advised' as "AdminMethod",
	' ' as 'description',
	' ' as 'PanelType',
	' ' as 'InitialPeriod',
	' ' as 'IndemnityType'
	from	msit_openworkadviserlisting oa left outer join 
			msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oa.sourceID left outer join
			mstt_producthierarchy ph on 'NBI_'+ fnsfl.productCode = ph.productCode left outer join
			cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode left outer join
			cscv_AgentsHierarchy ah1 ON oa.sellercode = ah1.agentcode LEFT OUTER JOIN
			msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode
	where	oa.month >= @StartDate
	and		oa.month <= @EndDate
	and		oa.feetype <> 'RC'
	and		oa.feetype <> 'Trail'
	and		oa.feetype <> 'TF'
	and		oa.source = 'openwork 2005'
	and		oa.providercode <> 'GI'
	and		((ape + totdue_enhd) <> 0)
	and		(fnsfl.id <> '27617494' or fnsfl.id is NULL)
	and		(rtrim(ah.ASDName) not in ('Pat Mckenna', 'Owl Sales Director') or oa.sellercode <> '1011623' or ah.ASDName is Null)
	----------------------------EXCLUDE ALL GROUP PENSION BUSINESS--------------------------------
	and		(case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(oa.month) <2016) then 1 else 0 end) = 1
	----------------------------------------------------------------------------------------------
	--Order by [BusinessType], [IssYear] desc, [IssMonth] desc, [IssDay] desc

	set @RowCount = @@ROWCOUNT

	set @Message = '#IssuedCBC Population 3'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount

	drop table #TransTable2

	/****************************************************************************

		If it's an incremental load:
			1) Delete ONLY the Swift issued incremental data
			2) Delete ALL the zero upfront APE data
		Otherwise it's a full load:
			1) Truncate the Issued Business Case By Case table
			2) Remove indexes (for performance)
																		
	****************************************************************************/

	if @IncrementalLoad = 'Y'
	begin
		delete from BI.IssuedBusinessCBC
		where PendingPaymentID in (select ID From #AGMFILChanges)  
		or ZeroFeeID is not null
		set @RowCount = @@ROWCOUNT
		set @Message = 'Destination table - rows deleted'
		exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount
	end
	else
	begin
		truncate table BI.IssuedBusinessCBC
		if indexproperty(object_id('BI.IssuedBusinessCBC'),'IX_IssuedBusinessCBC_PendingPaymentID','IndexID') is not null
			DROP INDEX BI.IssuedBusinessCBC.IX_IssuedBusinessCBC_PendingPaymentID
		if indexproperty(object_id('IssuedBusinessCBC'),'IX_IssuedBusinessCBC_ZeroFeeID','IndexID') is not null
			DROP INDEX BI.IssuedBusinessCBC.IX_IssuedBusinessCBC_ZeroFeeID
		if indexproperty(object_id('BI.IssuedBusinessCBC'),'IX_IssuedBusinessCBC_LegacyID','IndexID') is not null
			DROP INDEX BI.IssuedBusinessCBC.IX_IssuedBusinessCBC_LegacyID
		set @Message = 'Destination table - truncated and indexes dropped'
		exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client
	end

	/****************************************************************************

		Populate the Issued Business Case By Case Table with the Swift issued.
																		
	****************************************************************************/	
		
	insert into BI.IssuedBusinessCBC
	(	PendingPaymentID,
		ZeroFeeID,
		LegacyID,
		BusinessType,
		CaseID,
		AdviserUID,
		FirmUID,
		CommissionTypeDesc,
		CreateDateTime,
		CashReceivedDate,
		CreateDay,
		CreateMonth,
		CreateYear,
		Premium,
		APE,
		DistributionAllowance,
		NBI,
		Margin,
		NBCases,
		Cases,
		Frequency,
		ProviderRef,
		BusinessReason,
		AdminMethod,
		ProductCode,
		CompanyCode,
		ReportingProductName,
		ProductSubGroupName,
		ProductGroupName,
		CalculationCode,
		PayBasisDesc,
		OAStatus,
		ProductGroupName2,
		ProductSubGroup,
		AdviceMethod,
		CommShapeDescription,
		PanelType,
		InitialPeriod,
		IndemnityType,
		DateInserted,
		DateLastUpdated
	)
	SELECT	tmp.PendingPaymentID,
			tmp.ZeroFeeID,
			tmp.LegacyID,
			tmp.BusinessType,
			tmp.caseid,
			tmp.agent_code,
			tmp.Firm,
			tmp.commissiontypedesc,
			tmp.createdatetime,
			tmp.cashreceiveddate,
			tmp.IssDay,
			tmp.IssMonth,
			tmp.IssYear,
			tmp.Premium,
			tmp.APE,
			tmp.DA,
			tmp.NBI,
			tmp.Margin,
			tmp.NBCases,
			tmp.Cases,
			tmp.Frequency,
			tmp.providerref,
			tmp.BusinessReason,
			tmp.adminmethod,
			tmp.ProductCode,
			tmp.Comp_code,
			tmp.reportingproductname,
			tmp.productsubgroupname,
			tmp.ProductGroupName,
			tmp.calculationcode,
			tmp.paybasisdesc,
			tmp.oastatus,
			tmp.ProductGroupName2,
			tmp.ProductSubGroup,
			tmp.Advicemethod,
			tmp.CCSDescription,
			tmp.PanelType,
			tmp.InitialPeriod,
			tmp.IndemnityType,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	FROM	#IssuedCBC tmp
			left join BI.IssuedBusinessCBC legacy on legacy.LegacyID = tmp.LegacyID
	where	tmp.PendingPaymentID is not null	--Any temp table Swift issued (these will have been deleted if they alreday existed)
	or		tmp.ZeroFeeID is not null			--Any temp table zero fee data (these will have all been deleted unconditionally)			
	or		legacy.LegacyID is null				--Any legacy data not already on the destination table
	
	set @RowCount = @@ROWCOUNT

	set @Message = 'IssuedBusinessCBC Population'
	exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client, @RowCount	

	/****************************************************************************

		Add indexes back on if needed
																		
	****************************************************************************/

	if @IncrementalLoad = 'N'
	begin
		if indexproperty(object_id('BI.IssuedBusinessCBC'),'IX_IssuedBusinessCBC_PendingPaymentID','IndexID') is null
			CREATE  INDEX IX_IssuedBusinessCBC_PendingPaymentID ON BI.IssuedBusinessCBC(PendingPaymentID)
		if indexproperty(object_id('BI.IssuedBusinessCBC'),'IX_IssuedBusinessCBC_ZeroFeeID','IndexID') is null
			CREATE  INDEX IX_IssuedBusinessCBC_ZeroFeeID ON BI.IssuedBusinessCBC(ZeroFeeID)
		if indexproperty(object_id('BI.IssuedBusinessCBC'),'IX_IssuedBusinessCBC_LegacyID','IndexID') is null
			CREATE  INDEX IX_IssuedBusinessCBC_LegacyID ON BI.IssuedBusinessCBC(LegacyID)
		set @Message = 'Destination table - indexes created'
		exec BI.pr_ProcessLog @PhaseLog, @Message, @Module, @Client
	end

	/****************************************************************************

		Processing end
																		
	****************************************************************************/
	set @RowCount = @@ROWCOUNT
	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	--COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	--IF @@TRANCOUNT <> 0
	--	ROLLBACK TRANSACTION
		
	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	exec BI.pr_ProcessLog @PhaseError, @Process, @Module, @Client, null, @ErrMsg

	RAISERROR(@ErrMsg, @ErrSev, 1)

END CATCH

/****************************************************************************

			E N D															

*****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[pr_logi_finance_PotCodeDownload]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [BI].[pr_logi_finance_PotCodeDownload]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
		@Month				date


AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_logi_finance_PotCodeDownload]
Author      : S Inglis
Date  : 19/10/2016

Purpose     : This report is used for CR460 - Automating Finstats. The recipients are:
                  1) Finance Team

              The report name is "Pot Code Download" and is found on the "Finance MI" 
              menu. This report displays: 
              - The full Finstat 11 - Pot Codes for downloading and manipulating in browser



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_logi_finance_PotCodeDownload] 'ptl91371', 'Logi', '01-Jul-2016'

AMENDMENT HISTORY
=================
Date        Author		Description
----        ------		-----------
02-09-19	S Inglis	Added pot code 1012045 to list of columns
22/12/2022	A Groves	Added new pot code '1012561' (Defined Benefit Transfer Fee).
***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);


print 'setting parameters';
set @ReportName               = 'Pot Code Download';
set @StoredProcName           = object_name(@@procid);

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
 --                                                                 @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/


Begin


select
datename(month,@Month) + ' ' + convert(varchar(4),datepart(year,@Month)) as FinancialPeriod,
ProviderCode,
ProductProviderName,
ProductSubGroupName,
ProductBasisCode,
ProductBasisDescr,
ProductCode,
PayType,
CommDescription,
RecAmt,
OpenWorkAmountDue1011543,
OpenWorkAmountDue10002,
OpenWorkAmountDue10004,
OpenWorkAmountDue10005,
OpenWorkAmountDue1006124,
OpenWorkAmountDue1006886,
OpenWorkAmountDue1011542,
OpenWorkAmountDue1011587,
OpenWorkAmountDue1011623,
OpenWorkAmountDue1011629,
OpenWorkAmountDue1011630,
OpenWorkAmountDue1011631,
OpenWorkAmountDue1011632,
OpenWorkAmountDue1011633,
OpenWorkAmountDue1011634,
OpenWorkAmountDue1011635,
OpenWorkAmountDue1012045,
OpenWorkAmountDue1012561
from BI.owt_Finance_PotCodes where @Month between FinancialPeriodFromDate and FinancialPeriodToDate


print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [BI].[pr_logi_finance_ProviderCommMargExcClawSusDownload]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [BI].[pr_logi_finance_ProviderCommMargExcClawSusDownload]
		@PtlCode			varchar(255),
	    @ReportFormat		varchar(200),
		@Month				date


AS 


set nocount on

/**********************************************************************************************
Name  : [logi].[pr_logi_finance_ProviderCommMargExcClawSusDownload]
Author      : S Inglis
Date  : 14/10/2016

Purpose     : This report is used for CR460 - Automating Finstats. The recipients are:
                  1) Finance Team

              The report name is "Provider Comm Marg Exc Claw Sus Download" and is found on the "Finance MI" 
              menu. This report displays: 
              - The full Finstat 10 - Provider Comm Marg Exc Claw Sus for downloading and manipulating in browser



              The security groups associated with is report are:
              1) 
              2)  

              Execute as follows:
              exec [logi].[pr_logi_finance_ProviderCommMargExcClawSusDownload] 'ptl91371', 'Logi', '01-Jul-2016'

AMENDMENT HISTORY
=================
Date        Author            Description
----        ------            -----------

***********************************************************************************************/


/****************************************************************************

      Initialisation                                                                                              
                                                                                                            
****************************************************************************/


BEGIN TRY


print 'In the try';
declare           @ErrorMessage                  varchar(500),
                  @ReportName                    varchar(200),
                  @StoredProcName                varchar(200),
                  @StoredProcParams				 varchar(4000),
                  @ErrMsg                        nvarchar(4000),
                  @LastAuditID                   int,
                  @ErrNum                        int,
                  @ErrSev                        int,
                  @ErrLine                       int,
				  @StartDate					 datetime,
				  @EndDate						 datetime; 
DECLARE			  @return_value					 int;
DECLARE			  @lc_UserUid					 varchar(7);
DECLARE			  @lc_UserName					 varchar(50);


print 'setting parameters';
set @ReportName               = 'Provider Comm Marg Exc Claw Sus Download';
set @StoredProcName           = object_name(@@procid);

--exec [logi].[pr_logi_ReportAuditInsert] @PtlCode, @ReportName, @ReportFormat, @StoredProcName, 
 --                                                                 @StoredProcParams, @LastAuditID output

/****************************************************************************

      Select the data for the report                                                                                                
                                                                                                            
****************************************************************************/


Begin


Select 
datename(month,@Month) + ' ' + convert(varchar(4),datepart(year,@Month)) as FinancialPeriod,
cme.ProviderCode,
ProductProviderName,
ProductSubGroupName,
ProductBasisCode,
ProductBasisDescr,
ProductCode,
PayType,
CommDescription,
RecAmt,
AgentAmountDue,
OpenWorkAmountDue,
NoAgmAmt,
cm.Margin1,
NoAgmAmt*(1-cm.Margin1) as AGMLessMargin,
Case when CommDescription = 'Initial Commission' or CommDescription = 'Adjustment IC' then ProductBasisDescr
      when CommDescription = 'Renewal' or CommDescription = 'Adjustment RC' then 'Renewal'
      when CommDescription = 'Trail Fee' or CommDescription = 'Adjustment Trail' then 'Trail'
      else '0'
      End as CommDesc,
Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end as ProductType,
isnull(Case when 
(Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end) = 'MORTGAGE'
Then 'MORTGAGE' ELSE
isnull(ProductProviderName,'NULL') + ' ' +
(Case when cme.ProviderCode in ('COVENTRY','WOOLWICH') then 'MORTGAGE' else (case when ProductSubGroupName is Null then 'NON-CORE' else psgi.ProductType end) end)+' '+
(Case when CommDescription = 'Initial Commission' or CommDescription = 'Adjustment IC' then ProductBasisDescr
      when CommDescription = 'Renewal' or CommDescription = 'Adjustment RC' then 'Renewal'
      when CommDescription = 'Trail Fee' or CommDescription = 'Adjustment Trail' then 'Trail'
      End) End,'NULL NON-CORE 0') as Descr
from BI.owt_Finance_ProviderCommMargExcClawSus cme
left join logi.Finance_ProdSubGroupInp psgi  on cme.ProductSubGroupName = psgi.productsubgroup
left join logi.Finance_ConfigMargins cm on cm.ProviderCode = cme.ProviderCode and '31-Dec-2015' between cm.EffectiveStartDate and cm.EffectiveEndDate
where @Month between FinancialPeriodFromDate and FinancialPeriodToDate


print 'Leaving try';

End

/*Else

Begin
Print 'Access Denied'
End   */
END TRY

BEGIN CATCH 
      print 'In the catch';
      select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE();
      set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10)) ;
      
END CATCH


/****************************************************************************

                  E N D                                                                                     

****************************************************************************/


--exec [logi].[pr_logi_ReportAuditUpdate] @LastAuditID, @ErrMsg     
GO
/****** Object:  StoredProcedure [BI].[pr_mi_ent_JustMortgages_Cases]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	pr_mi_ent_JustMortgages_Cases
  	 					
	  Author:	Sarah Inglis - SQL (10/03/2016)
				A Groves - Stored procedure 

Date created:	14/03/2016
													
 Description:   As part of the onboarding of Just Mortgages (Project India) there is a 
				requirement to provide them with an automated MI data feed. The data is 
				obtained from the Data Warehouse and presented as a .csv file
				
				It is called as follows:

				exec pr_mi_ent_JustMortgages_Cases
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
16/03/2016	A Groves	Added in @JMDBusinessUID for compatibility between UAT and PROD.
18/03/2016	A Groves	V3 SQL from Sarah Inglis applied. This fixes bugs and introduces
						a new column at the end called ClientNI.
18/03/2016	A Groves	V5 SQL from Sarah Inglis applied. SQL re-written to fix duplicates.
						Column ClientNI removed as this was already in the results set.
18/03/2016	A Groves	Added: SET ANSI_WARNINGS OFF.
						This stops the control flow in SSIS from failing with the following error:
						Warning: Null value is eliminated by an aggregate or other SET operation.
07/04/2016	A Groves	SR428683. V7 SQL change by Sarah Inglis: 
						Addition of a filter on the policy type to only include ones that are still live.
21/04/2016	A Groves	SR431160. New fields introduced by OWS Release of 24/04/2016.
						SQL Supplied by Sarah Inglis.
03/05/2016	S Inglis	SR432749. As part of the M1 OWS release there has been a correction of code 
						which means that the mortgage address no longer pulls through to the MI. 
						Addition of a join to a different property table is needed to ensure that 
						no matter where the AddressID is stored it is pulled through to the MI.
05/06/2019	A Groves	SR530881/CH25322. At JMD's request, column NewBuildID has been appended 
						to the data file.
29/09/2020	A Groves	CR830/SR594786. Appended commission type indicator and whether adviser
						is self-employed. Note: when clients are reassigned, this creates a 117 
						transaction on Swift which defaults to accruals. So 117s must be excluded. 
06/11/2020	A Groves	CR847/SR603969. Just Mortgages are due to introduce a referral process and 
						allow advisers to split commission. To facilitate that, JMD have asked 
						for the initial and renewal splits for one adviser to be included in this 
						MI file.
09/11/2020 S Tourlidas  The JMD file couldn't be generated because of an illegal character in the IncomeSource
12/10/2021 S Tourlidas  Adding data from ABS
13/09/2022 S Tourlidas  Adding data from Concert 
11/10/2022 S Tourlidas  Adding FirmBranchReference, FirmReferenceNumber and an identifier flag [CH] 
************************************************************************************************/
CREATE PROCEDURE [BI].[pr_mi_ent_JustMortgages_Cases]
		
AS

SET ANSI_WARNINGS OFF	--AG 18/03/2016. 
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@Client						varchar(50),
		@Module						varchar(50),
		@JMDBusinessUID				varchar(7)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'OutboundMI-JM'

set @JMDBusinessUID = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	
			where cde.ColumnName = 'BusinessUID' and cde.Description = 'JMD')

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Select advisers and combine competency codes for later checking

	****************************************************************************/
	
	drop table if exists ##JM
					 
;With CTE_GrossIncome as (
	Select Distinct
	PersonID
	,case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID
	,sum(case when invIF.ValueName = 'Annually' then (GrossIncome/12)
			  when invIF.ValueName = 'Quarterly' then (GrossIncome/3)
			  when invIF.ValueName = 'Half-Yearly' then (GrossIncome/6)
			  else GrossIncome end) as MonthlyGrossIncome
	--,invIF.ValueName
	--,cdid.*
	from sa_ows_ClientDetailIncomeDetail cdid
	join staticdata.sa_ows_InputValues invIF on invIF.InputID = cdid.IncomeFrequencyID
	--where PersonID = 17890
	Group by PersonID, case when PersonTypeID = 1 then 1 else 2 end 
	--order by PersonID
	),

	--EmployerDetails
	CTE_Employer as (
	select
	cdid.PersonID,
	cdid.PersonTypeID,
	invEmpSt.ValueName,
	occ.JobTitle,
	LEFT(replace(cdid.IncomeSource COLLATE Latin1_General_BIN,N'􀆟','') ,50) as IncomeSource, -- Changed because of illegal characters and size of the source
	grin.MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	left join StaticData.sa_ows_InputValues invEmpSt on invEmpSt.InputID = cdid.EmploymentStatusID
	left join StaticData.sa_ows_OwlOccupations occ on occ.OrigoCode = OccupationOrigoCode
	left join CTE_GrossIncome grin on grin.PersonID = cdid.PersonID and grin.PersonTypeID = cdid.PersonTypeID
	where cdid.ClientDetailIncomeDetailID = (select min(clientdetailincomedetailID)
											 from sa_ows_ClientDetailIncomeDetail cdid1
											 where cdid1.PersonID = cdid.PersonID
											 and   cdid1.PersonTypeID = cdid.PersonTypeID)
	),
	--IncomeDetails
	CTE_NetIncomeDetails as (
	select
	saleID,
	case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID,
	sum(totalNetMonthlyIncome) TotalNetIncome
	from sa_ows_FactFindIncome
	Group by SaleID, case when PersonTypeID = 1 then 1 else 2 end
	),
	--MortgageDetails--
	CTE_MortgageDetails as (
	select
	mps.PolicyId,
	case when obr.PurchasePrice is null then obr.PropertyValuation else obr.PurchasePrice end as PropertyValue,
	mps.LoanToValueRatio,
	mps.TotalMortgageAmount,
	invMortCatID.ValueName as MortgageCategory,
	invTranType.ValueName as TransactionType,
	invMortType.ValueName as MortgageType,
	invIntRate.ValueName as InterestRateType,
	invIRP.ValueName as InitialRatePeriod,
	mdf.MortgageApplicationDate,
	mdf.ArrangementFeeAmount,
	mdf.BrokerFeeAmount,
	mdf.MortgageExchangeDate,
	mdf.MortgageCompletionDate,
	mdf.MortgageAbortedDate,
	qr.AnswerText as ProcFee,
	mps.MortgageTermYears,
	addr.AddressLine1,
	addr.AddressLine2,
	addr.AddressLine3,
	addr.AddressLine4,
	addr.AddressLine5,
	addr.Postcode,
	case when invIRP.ValueName = '2 Years' then dateadd(year,2,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '3 Years' then dateadd(year,3,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '4 Years' then dateadd(year,4,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '5 Years' then dateadd(year,5,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '10 Years' then dateadd(year,10,mdf.MortgageApplicationDate)
		 else '01-Jan-1800' end as EndDate,
	case when isnull(pep.NewBuildID,20) = 19 then 'Yes' else 'No' end as NewBuild		--AG 05/06/2019			
	from PolicyOneLink.sa_ows_MortgageProductSummary mps
	join sa_ows_Policies pol on pol.PolicyID = mps.PolicyId
	--join sa_ows_Sale sale on sale.SaleID = pol.SaleID
	join Objectives.sa_ows_ObjectivesBorrowingRequirements obr on obr.SaleID = pol.SaleID
						and obr.ObjectivesBorrowingRequirementsId = (select max(obr1.ObjectivesBorrowingRequirementsId)
																	 from objectives.sa_ows_ObjectivesBorrowingRequirements obr1
																	 where obr.SaleID = obr1.SaleID)
	left join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdf on mdf.PolicyId = mps.PolicyId
	left join StaticData.sa_ows_InputValues invMortCatID on invMortCatID.InputID = mps.MortgageCategoryId
	left join StaticData.sa_ows_InputValues invTranType on invTranType.InputID = mps.TransactionTypeId
	left join StaticData.sa_ows_InputValues invMortType on invMortType.InputID = mps.MortgageTypeId
	left join StaticData.sa_ows_InputValues invIntRate on invIntRate.InputID = mps.InterestRateTypeId
	left join StaticData.sa_ows_InputValues invIRP on invIRP.InputID = mps.InitialRatePeriodId
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = mps.PolicyID and QuestionID = 2110
	left join sa_ows_ClientDetailPropertiesExistingProperties ffpep on ffpep.ExistingPropertyID = mps.RelatedPropertyID
	left join sa_ows_FactFindPropertiesExistingProperties pep on pep.ExistingPropertyID = mps.RelatedPropertyId							--S Inglis 03/05/2016
	left join sa_ows_addresses addr on addr.AddressID = case when ffpep.AddressID is null then pep.AddressID else ffpep.AddressID end),	--S Inglis 03/05/2016

	--Protection Details--
	CTE_ProtectionDetails as (
	select 
	pps.PolicyId,
	pps.ApplicationDated
	,pps.ProtectionOnRiskDate
	,pps.ProtectionAbortedDate
	,convert(varchar,ppbd.ProductTermYears) + ' Years' + ' ' + convert(varchar,ppbd.ProductTermMonths) + ' Months' as LifeCoverTerm
	,pps.PremiumAmount as TotalRegularPremium
	,case when PremiumFrequencyID = 10100 then (pps.PremiumAmount * 12)
			when PremiumFrequencyID = 10101 then (pps.PremiumAmount * 4)
			when PremiumFrequencyID = 10102 then (pps.PremiumAmount * 2)				
			else pps.PremiumAmount end as AnnualisedPremium
	,invPF.ValueName as CurrentRegularPremiumFrequency
	,invPF.ValueName as 'Current Regular Premium (Self) Frequency' 
	,case when ppbd.SumAssuredForDeath IS null then ppbd.SumAssuredForCriticalIllness else ppbd.SumAssuredForDeath end as LifeCoverSumAssured
	,ppbd.LifeAssuredId
	from PolicyOneLink.sa_ows_ProtectionProductSummary pps
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = pps.PolicyId and qr.QuestionID = 2510
	left join StaticData.sa_ows_InputValues invPF on pps.PremiumFrequencyID = invPF.InputID
	left join PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd on ppbd.ProtectionProductSummaryId = pps.ProtectionProductSummaryId
																	and ppbd.ProtectionProductBenefitId = (select min(ppbd1.protectionProductBenefitID)
																										   from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																										   where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId) 
																	and ppbd.BenefitTypeID = (select top 1 ppbd1.BenefitTypeID
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																							  where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
																	and ppbd.LifeAssuredId = (select top 1 ppbd2.LifeAssuredId
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd2
																							  where ppbd2.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
	)

	--Basic Policy Details, Client Name, Address, DOB--
	select	
	pol.PolicyID as SequentialRef,
	pers.PersonID As Owner1ID,
	pers.PartnerPersonID As Owner2ID,
	sale.DateSubmitted As SubmittedDate,
	pd.ProtectionOnRiskDate as InForceDate,					--AG 21/04/2016
	pd.ProtectionAbortedDate as NTUDate,					--AG 21/04/2016
	sale.AdviserUID as SellingAdviserID,
	sale.AdviserUID as AgencyNumber,
	uh.UserName as SellingAdviserFullName,
	advadd.ADD_Line1 as SellingAdviserAddressLine1,
	advadd.ADD_Line2 as SellingAdviserAddressLine2,
	advadd.ADD_Line3 as SellingAdviserAddressLine3,
	advadd.ADD_Postcode as SellingAdviserPostcode,
	cd.CD_Telephone as SellingAdviserWorkTelephoneNumber,
	cd.CD_Mobile as SellingAdviserMobileNumber,
	cd.CD_email as SellingAdviserEmailAddress,
	staf.STAF_NINumber	as SellingAdviserNINumber,
	sale.SaleID as AdviceCaseSequentialReference,
	pers.DateCreated As Owner1CreationDate,
	case when md.PolicyId is not null 
	then
		(case when md.MortgageAbortedDate Is NOT null then 'Aborted' 
			 when md.MortgageCompletionDate IS NOT null then 'Completed' 
			 when md.MortgageExchangeDate IS NOT NULL then 'Exchanged' else Null End)
	else (case when pd.ProtectionAbortedDate IS NOT null then 'Aborted' 
				when pd.ProtectionOnRiskDate IS NOT null then 'On Risk' 
				else NULL end) end as PlanStatus,			--AG 21/04/2016
	cast(invP1T.ValueName as varchar(250)) As Owner1Title,
	pers.FirstName As Owner1FirstName,
	pers.LastName As Owner1LastName,
	pers.DateOfBirth As Owner1DateOfBirth,
	cast(invP1G.ValueName as varchar(250)) As Owner1Gender,
	pers.Address1 As Owner1AddressLine1,
	pers.Address2 As Owner1AddressLine2,
	pers.Address3 As Owner1AddressLine3,
	pers.Address4 As Owner1AddressLine4,
	pers.Address5 As Owner1AddressLine5,
	pers.PostCode As Owner1PostCode,
	pers.TelephoneHome As Owner1HomeTelephoneNumber,
	pers.TelephoneMobile As Owner1MobileNumber,
	pers.EmailAddress As Owner1EmailAddress,
	emp.JobTitle as Owner1Occupation,
	emp.IncomeSource as Owner1EmployerName,
	emp.ValueName as Owner1EmploymentStatus,
	emp.MonthlyGrossIncome as Owner1TotalGrossMonthlyIncome,
	nid.TotalNetIncome as Owner1TotalNetMonthlyIncome,
	pers.NINo as Owner1NINumber,
	invMS.ValueName as Owner1MaritalStatus,
	ffog.IntroducerDetails as Owner1DescriptionReference,	--AG 21/04/2016
	cast(invP2T.ValueName as varchar(250)) As Owner2Title,
	pers1.FirstName As Owner2FirstName,
	pers1.LastName As Owner2Surname,
	pers1.DateOfBirth As Owner2DateOfBirth,
	cast(invP2G.ValueName  as varchar(250)) As Owner2Gender,
	pers1.TelephoneHome As Owner2HomeTelephoneNumber,
	pers1.TelephoneMobile As Owner2MobileNumber,
	pers1.EmailAddress  As Owner2EmailAddress,
	emp2.JobTitle As Owner2Occupation,
	emp2.IncomeSource As Owner2EmployerName,
	emp2.MonthlyGrossIncome As Owner2TotalGrossMonthlyIncome,
	nid2.TotalNetIncome as Owner2TotalNetMonthlyIncome,
	cast(polm.cont_Num as varchar(25)) as PolicyNumber,
	CAST(REPLACE(ppr.DisplayName COLLATE Latin1_General_BIN, '–','-') as nvarchar(50)) as ProtectionProductName,
	cast(pd.LifeCoverTerm as varchar(74)) as LifeCoverTerm,
	pd.TotalRegularPremium,
	pd.AnnualisedPremium,
	cast(pd.CurrentRegularPremiumFrequency as varchar(250)) as CurrentRegularPremiumFrequency,
	cast(pd.[Current Regular Premium (Self) Frequency] as varchar(250)) as 'Current Regular Premium (Self) Frequency', 
	pd.LifeCoverSumAssured,
	case when md.PolicyId is not null then
	(case when md.MortgageAbortedDate Is NOT null then md.MortgageAbortedDate 
	when md.MortgageCompletionDate IS NOT null then md.MortgageCompletionDate 
	when md.MortgageExchangeDate IS NOT NULL then md.MortgageExchangeDate else convert(datetime,Null) End)
	else (case when pd.ProtectionAbortedDate IS NOT null then pd.ProtectionAbortedDate 
	when pd.ProtectionOnRiskDate IS NOT null 
		then pd.ProtectionOnRiskDate 
		else convert(datetime,Null) end) 
	end as PlanStatusDate,									--AG 21/04/2016
	sale.DateCreated as AdviceCaseCreatedOn,
	pol.ApplicationDate as PolicyStartDate,
	case when pp.DisplayName is null then mp.DisplayName else pp.DisplayName end as ProviderName,
	case when pd.LifeAssuredId = 10110 then pers.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10111 then pers1.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10112 then 'Joint Policy'
			when pd.LifeAssuredId = 10113 then 'Life of Another' end as LifeAssured1FullName,
	md.TransactionType as MortgageTransactionType,
	polm.cont_Num as MortgageRefNo,
	md.MortgageCategory as MortgageMortgageType,
	md.InterestRateType as MortgageRateType,
	md.MortgageType as MortgageRepaymentMethod,
	md.EndDate as MortgageFeatureExpires,
	md.MortgageTermYears,
	md.MortgageExchangeDate as MortgageExchangeDate,		--AG 21/04/2016
	md.MortgageCompletionDate as MortgageCompletionDate,	--AG 21/04/2016
	md.PropertyValue as MortgagePriceValuation,
	md.TotalMortgageAmount as MortgageLoanAmount,
	md.ArrangementFeeAmount as MortgageLenderFees,
	md.LoanToValueRatio as MortgageLTV,
	md.MortgageApplicationDate as MortgageApplicationSubmitted,
	md.ProcFee as ExpectedCommissionProcurement,
	md.BrokerFeeAmount,
	md.AddressLine1 as MortgageAddressLine1,
	md.AddressLine2 as MortgageAddressLine2,
	md.AddressLine3 as MortgageAddressLine3,
	md.AddressLine4 as MortgageAddressLine4,
	md.AddressLine5 as MortgageAddressLine5,
	md.Postcode as MortgagePostcode,
	md.NewBuild,									--AG 05/06/2019
	case											--AG 29/09/2020
		when pt.CommType = 'F' then 'Accr' 
		when pt.CommType = 'T' then 'IT' 
		when pt.CommType = 'L' then 'Level'
		else 'Unknown' 
	end as PayBasis,
	isnull(EmpType.Code_Description,'Unknown') as EmploymentType,	--AG 29/09/2020
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitAdv.AdviserUID 
	end as InitialAdviserUID,										--AG 06/11/2020
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitAdv.AdviserName
	end as InitialAdviserName,										--AG 06/11/2020
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitPct.AdviserPct
	end as InitialSplitPct,											--AG 06/11/2020
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'		--AG 06/11/2020
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitAdv.AdviserUID end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenAdv.AdviserUID end
	end as RenewalAdviserUID,
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'		--AG 06/11/2020							
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitAdv.AdviserName end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenAdv.AdviserName end
	end as RenewalAdviserName,			
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'		--AG 06/11/2020	
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitPct.AdviserPct end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenPct.AdviserPct end
	end as RenewalSplitPct
	,BranchNumber.FirmBranchReference as [FirmBranchReference]
	,CCMSNumber.FirmReferenceNumber as [FirmReferenceNumber]
	,case when sale.CrmMessageSourceId is not NULL then 'TRUE' else 'FALSE' END AS [CH]		
	from sa_ows_sale sale
	join sa_ows_Policies pol on pol.SaleID = sale.SaleID
	join sa_ows_Person pers on pers.PersonID = sale.PersonID
	join StaticData.sa_ows_InputValues invP1G on invP1G.InputID = pers.GenderID
	join StaticData.sa_ows_InputValues invP1T on invP1T.InputID = pers.TitleID
	--left join mi_insight_userhierarchy uh on uh.UserUID = sale.AdviserUID									  AG 29/09/2020
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = sale.AdviserUID and uh.LatestRowInd = 1	--AG 29/09/2020
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_ows_Person pers1 on pers.PartnerPersonID = pers1.PersonID
	left join StaticData.sa_ows_InputValues invP2G on invP2G.InputID = pers1.GenderID
	left join StaticData.sa_ows_InputValues invP2T on invP2T.InputID = pers1.TitleID
	left join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_ows_ProtectionProvider pp on pp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_OWS_ProtectionProduct ppr on ppr.InternalProductID = pol.InternalProductID
	left join sa_swift_S_POLMAI polm on polm.PolicyRef = pol.PolicyID
	left join (select PolicyID, max(ID) as MaxID from mstt_PolicyTransactions where TransType <> 117 group by PolicyID) LatestTxn on LatestTxn.PolicyID = polm.POL_NUM	--AG 29/09/2020
	left join mstt_PolicyTransactions pt on pt.ID = LatestTxn.MaxID	--AG 29/09/2020
	left join sa_ows_ClientDetailOverviewClientDetails cdocd on cdocd.PersonID = pers.personid and cdocd.PersonTypeID = 1
															 and cdocd.DateUpdated = (select max(cdocd1.DateUpdated)
																					  from sa_ows_ClientDetailOverviewClientDetails cdocd1
																					  where cdocd.PersonID = cdocd1.PersonID
																					  and cdocd1.PersonTypeID = 1)
	left join StaticData.sa_ows_InputValues invMS on invMS.inputid = cdocd.MaritalStatusID
	left join CTE_Employer emp on emp.PersonID = pers.PersonID and emp.PersonTypeID = 1
	left join CTE_Employer emp2 on emp2.PersonID = pers.PersonID and emp2.PersonTypeID = 2
	left join CTE_NetIncomeDetails nid on nid.SaleID = sale.SaleID and nid.PersonTypeID = 1
	left join CTE_NetIncomeDetails nid2 on nid2.SaleID = sale.SaleID and nid2.PersonTypeID = 2
	left join CTE_MortgageDetails md on md.PolicyId = pol.PolicyID
	left join CTE_ProtectionDetails pd on pd.PolicyId = pol.PolicyID
	left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = pol.SaleID
	--AG 06/11/2020 Start
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'InitialAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as InitAdv on InitAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'InitialPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as InitPct on InitPct.PolicyID = pol.PolicyID
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as RenAdv on RenAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'RenewalPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as RenPct on RenPct.PolicyID = pol.PolicyID
	left join (	select	distinct qrUID.PolicyID, qrUID.AnswerText as RenewalCommissionSameAsInitial
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalCommissionSameAsInitial'
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				) as RenSameInit on RenSameInit.PolicyID = pol.PolicyID
	left join (	select	distinct qrUID.PolicyID, qrUID.AnswerText as FirmReferenceNumber
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and (qbUID.ObjectModelProperty = 'NewcastleCCMSNumber'  or qbUID.QuestionID = 250)
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				) as CCMSNumber on CCMSNumber.PolicyID = pol.PolicyID
	left join ( select	distinct qrUID.PolicyID, qrUID.AnswerText as FirmBranchReference
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and (qbUID.ObjectModelProperty = 'NewcastleBranchNumber' or qbUID.QuestionID = 251)
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				   ) as BranchNumber on BranchNumber.PolicyID = pol.PolicyID
	--AG 06/11/2020 End
	where sale.DateSubmitted is not null
	and pol.Status in (0,1,2)
	and (md.PolicyId is not null or pd.PolicyId is not null)
	and sale.BusinessUid = @JMDBusinessUID


	UNION ALL

	Select	
	ps.SwiftCaseID,
	pers.PersonID,
	part.PersonID,
	cases.DateSubmitted,
	null,
	null,
	cases.AdviserID,
	null,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	cases.ABSCaseID,
	null,
	null,
	cast(pers.Title as varchar(250)) As Owner1Title,
	pers.FirstName,
	pers.LastName,
	convert(date,pers.DOB,103),
	cast(pers.Gender as varchar(250)) As Owner1Gender,
	pers.Address1,
	pers.Address2,
	null,
	null,
	null,
	pers.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	CAST(part.Title as varchar(250)) As Owner2Title ,
	part.FirstName,
	part.LastName,
	convert(date,part.DOB,103),
	CAST(part.Gender  as varchar(250)) As Owner2Gender,
	null As Owner2HomeTelephoneNumber,
	null As Owner2MobileNumber,
	null As Owner2EmailAddress,
	null As Owner2Occupation,
	null As Owner2EmployerName,
	null As Owner2TotalGrossMonthlyIncome,
	null as Owner2TotalNetMonthlyIncome,
	CAST(qr.AnswerText as varchar(25)) as PolicyNumber,
	CAST(REPLACE(prod.DisplayName COLLATE Latin1_General_BIN, '–','-') as nvarchar(50)) as ProtectionProductName,
	cast(qr1.AnswerText + ' Years' as varchar(74)) as LifeCoverTerm,
	qr7.AnswerText,
	case when qr2.AnswerText = 3 then convert(decimal(10,2),qr7.AnswerText)*12 else qr7.AnswerText end,
	CAST(ab.AnswerText as varchar(250)) as CurrentRegularPremiumFrequency,
	CAST(ab.AnswerText  as varchar(250)) as [Current Regular Premium (Self) Frequency],--Current Regular Premium (Self) Frequency
	null,
	null,
	cases.CreatedDate,
	ps.CommencementDate,
	prov.DisplayName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	case when qr8.AnswerText = 50 then 'IT' when qr8.AnswerText = 51 then 'Accr' end,
	EmpType.Code_Description,
	qr3.AnswerText,
	agt.Descn,
	qr4.AnswerText,
	qr5.AnswerText,
	agt2.DESCN,
	qr6.AnswerText
	,NULL AS [FirmBranchReference]
	,NULL AS [FirmReferenceNumber]
	,'FALSE' AS [CH]		
	from sa_abs_ABS_Person pers
	left join sa_abs_ABS_Person part on part.ABSCaseID = pers.ABSCaseID and part.PersonType = 'Partner'
	left join sa_abs_ABS_Cases cases on cases.ABSCaseID = pers.ABSCaseID
	left join sa_abs_ABS_ProductSales ps on ps.ABSCaseID = cases.ABSCaseID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = cases.AdviserID and cases.DateSubmitted between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_abs_ABS_UIQuestionnaireResponses qr on qr.SwiftCaseID = ps.SwiftCaseID and qr.QuestionID in (30,58,420)
	left join sa_abs_ABS_Products prod on prod.ABSProductID = ps.ProductID
	left join sa_abs_ABS_UIQuestionnaireResponses qr1 on qr1.SwiftCaseID = ps.SwiftCaseID and qr1.QuestionID in (421)
	left join sa_abs_ABS_UIQuestionnaireResponses qr7 on qr7.SwiftCaseID = ps.SwiftCaseID and qr7.QuestionID = 378
	left join sa_abs_ABS_UIQuestionnaireResponses qr2 on qr2.SwiftCaseID = ps.SwiftCaseID and qr2.QuestionID = 379
	left join sa_abs_ABS_UIAnswerBank ab on convert(varchar(250),ab.AnswerID) = qr2.AnswerText
	left join sa_abs_ABS_Providers prov on prov.ABSProviderID = ps.ProviderID
	left join sa_abs_ABS_UIQuestionnaireResponses qr3 on qr3.SwiftCaseID = ps.SwiftCaseID and qr3.QuestionID = 36
	left join sa_abs_ABS_UIQuestionnaireResponses qr4 on qr4.SwiftCaseID = ps.SwiftCaseID and qr4.QuestionID = 37
	left join mstt_agents agt on agt.CODE = qr3.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr5 on qr5.SwiftCaseID = ps.SwiftCaseID and qr5.QuestionID = 115
	left join sa_abs_ABS_UIQuestionnaireResponses qr6 on qr6.SwiftCaseID = ps.SwiftCaseID and qr6.QuestionID = 116
	left join mstt_agents agt2 on agt2.CODE = qr5.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr8 on qr8.SwiftCaseID = ps.SwiftCaseID and qr8.QuestionID = 423
	where pers.PersonType = 'Client'
	and uh.BusinessUID = @JMDBusinessUID
	

	set @RowCount = @@rowcount
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	set @ProcessMessage = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[pr_mi_TPG_Mortgage]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	pr_mi_TPG_Mortgage
  	 					
	  Author:	A Bryant - Stored procedure 

Date created:	17/11/2021
													
 Description:   
				
				It is called as follows:

				exec dbo.pr_mi_TPG_Mortgage
													
Amendment History								
-----------------								
											
Date		Who				Description				
----		---				-----------
01/02/2022	Arren Bryant	Added ABS sql to stored proc and SubmittedByUserName column
23/03/2022  Arren Bryant	Added splits and renewal splits
16/11/2022	A Groves		Sarah Collins, the TPG MI Manager, spotted two ABS cases were missing
							(500035216 and 500035056). The fix was to convert the DateSubmitted
							from datetime to date while joining to mi_insight_UserHierarchyAllUsers.
************************************************************************************************/
CREATE PROC [BI].[pr_mi_TPG_Mortgage]

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@Client						varchar(50),
		@Module						varchar(50)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'OutboundMI-TPG'


/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	Declare @TPGBusinessUID varchar(7)
	Set @TPGBusinessUID = '2000978'

	;With CTE_GrossIncome as (
	Select Distinct
	PersonID
	,case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID
	,sum(case when invIF.ValueName = 'Annually' then (GrossIncome/12)
			  when invIF.ValueName = 'Quarterly' then (GrossIncome/3)
			  when invIF.ValueName = 'Half-Yearly' then (GrossIncome/6)
			  else GrossIncome end) as MonthlyGrossIncome
	--,invIF.ValueName
	--,cdid.*
	from sa_ows_ClientDetailIncomeDetail cdid
	join staticdata.sa_ows_InputValues invIF on invIF.InputID = cdid.IncomeFrequencyID
	--where PersonID = 17890
	Group by PersonID, case when PersonTypeID = 1 then 1 else 2 end 
	--order by PersonID
	),

	--EmployerDetails
	CTE_Employer as (
	select
	cdid.PersonID,
	cdid.PersonTypeID,
	invEmpSt.ValueName,
	occ.JobTitle,
	LEFT(replace(cdid.IncomeSource COLLATE Latin1_General_BIN,N'􀆟','') ,50) as IncomeSource, -- Changed because of illegal characters and size of the source
	grin.MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	left join StaticData.sa_ows_InputValues invEmpSt on invEmpSt.InputID = cdid.EmploymentStatusID
	left join StaticData.sa_ows_OwlOccupations occ on occ.OrigoCode = OccupationOrigoCode
	left join CTE_GrossIncome grin on grin.PersonID = cdid.PersonID and grin.PersonTypeID = cdid.PersonTypeID
	where cdid.ClientDetailIncomeDetailID = (select min(clientdetailincomedetailID)
											 from sa_ows_ClientDetailIncomeDetail cdid1
											 where cdid1.PersonID = cdid.PersonID
											 and   cdid1.PersonTypeID = cdid.PersonTypeID)
	),
	--IncomeDetails
	CTE_NetIncomeDetails as (
	select
	saleID,
	case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID,
	sum(totalNetMonthlyIncome) TotalNetIncome
	from sa_ows_FactFindIncome
	Group by SaleID, case when PersonTypeID = 1 then 1 else 2 end
	),
	--MortgageDetails--
	CTE_MortgageDetails as (
	select
	mps.PolicyId,
	case when obr.PurchasePrice is null then obr.PropertyValuation else obr.PurchasePrice end as PropertyValue,
	mps.LoanToValueRatio,
	mps.TotalMortgageAmount,
	invMortCatID.ValueName as MortgageCategory,
	invTranType.ValueName as TransactionType,
	invMortType.ValueName as MortgageType,
	invIntRate.ValueName as InterestRateType,
	invIRP.ValueName as InitialRatePeriod,
	mdf.MortgageApplicationDate,
	mdf.ArrangementFeeAmount,
	mdf.BrokerFeeAmount,
	mdf.MortgageExchangeDate,
	mdf.MortgageCompletionDate,
	mdf.MortgageAbortedDate,
	qr.AnswerText as ProcFee,
	mps.MortgageTermYears,
	addr.AddressLine1,
	addr.AddressLine2,
	addr.AddressLine3,
	addr.AddressLine4,
	addr.AddressLine5,
	addr.Postcode,
	case when invIRP.ValueName = '2 Years' then dateadd(year,2,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '3 Years' then dateadd(year,3,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '4 Years' then dateadd(year,4,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '5 Years' then dateadd(year,5,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '10 Years' then dateadd(year,10,mdf.MortgageApplicationDate)
		 else '01-Jan-1800' end as EndDate,
	case when isnull(pep.NewBuildID,20) = 19 then 'Yes' else 'No' end as NewBuild		--AG 05/06/2019			
	from PolicyOneLink.sa_ows_MortgageProductSummary mps
	join sa_ows_Policies pol on pol.PolicyID = mps.PolicyId
	--join sa_ows_Sale sale on sale.SaleID = pol.SaleID
	join Objectives.sa_ows_ObjectivesBorrowingRequirements obr on obr.SaleID = pol.SaleID
						and obr.ObjectivesBorrowingRequirementsId = (select max(obr1.ObjectivesBorrowingRequirementsId)
																	 from objectives.sa_ows_ObjectivesBorrowingRequirements obr1
																	 where obr.SaleID = obr1.SaleID)
	left join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdf on mdf.PolicyId = mps.PolicyId
	left join StaticData.sa_ows_InputValues invMortCatID on invMortCatID.InputID = mps.MortgageCategoryId
	left join StaticData.sa_ows_InputValues invTranType on invTranType.InputID = mps.TransactionTypeId
	left join StaticData.sa_ows_InputValues invMortType on invMortType.InputID = mps.MortgageTypeId
	left join StaticData.sa_ows_InputValues invIntRate on invIntRate.InputID = mps.InterestRateTypeId
	left join StaticData.sa_ows_InputValues invIRP on invIRP.InputID = mps.InitialRatePeriodId
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = mps.PolicyID and QuestionID = 2110
	left join sa_ows_ClientDetailPropertiesExistingProperties ffpep on ffpep.ExistingPropertyID = mps.RelatedPropertyID
	left join sa_ows_FactFindPropertiesExistingProperties pep on pep.ExistingPropertyID = mps.RelatedPropertyId							--S Inglis 03/05/2016
	left join sa_ows_addresses addr on addr.AddressID = case when ffpep.AddressID is null then pep.AddressID else ffpep.AddressID end),	--S Inglis 03/05/2016

	--Protection Details--
	CTE_ProtectionDetails as (
	select 
	pps.PolicyId,
	pps.ApplicationDated
	,pps.ProtectionOnRiskDate
	,pps.ProtectionAbortedDate
	,convert(varchar,ppbd.ProductTermYears) + ' Years' + ' ' + convert(varchar,ppbd.ProductTermMonths) + ' Months' as LifeCoverTerm
	,pps.PremiumAmount as TotalRegularPremium
	,case when PremiumFrequencyID = 10100 then (pps.PremiumAmount * 12)
			when PremiumFrequencyID = 10101 then (pps.PremiumAmount * 4)
			when PremiumFrequencyID = 10102 then (pps.PremiumAmount * 2)				
			else pps.PremiumAmount end as AnnualisedPremium
	,invPF.ValueName as CurrentRegularPremiumFrequency
	,invPF.ValueName as 'Current Regular Premium (Self) Frequency'
	,case when ppbd.SumAssuredForDeath IS null then ppbd.SumAssuredForCriticalIllness else ppbd.SumAssuredForDeath end as LifeCoverSumAssured
	,ppbd.LifeAssuredId
	from PolicyOneLink.sa_ows_ProtectionProductSummary pps
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = pps.PolicyId and qr.QuestionID = 2510
	left join StaticData.sa_ows_InputValues invPF on pps.PremiumFrequencyID = invPF.InputID
	left join PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd on ppbd.ProtectionProductSummaryId = pps.ProtectionProductSummaryId
																	and ppbd.ProtectionProductBenefitId = (select min(ppbd1.protectionProductBenefitID)
																										   from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																										   where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId) 
																	and ppbd.BenefitTypeID = (select top 1 ppbd1.BenefitTypeID
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																							  where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
																	and ppbd.LifeAssuredId = (select top 1 ppbd2.LifeAssuredId
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd2
																							  where ppbd2.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
	)

	--Basic Policy Details, Client Name, Address, DOB--
	select
	pol.PolicyID as CaseID,
	pers.PersonID As Owner1ID,
	pers.PartnerPersonID As Owner2ID,
	sale.DateSubmitted As SubmittedDate,
	pd.ProtectionOnRiskDate as InForceDate,					
	pd.ProtectionAbortedDate as NTUDate,					
	sale.AdviserUID as SellingAdviserID,
	uh.UserName as SellingAdviserFullName,
	advadd.ADD_Line1 as SellingAdviserAddressLine1,
	advadd.ADD_Line2 as SellingAdviserAddressLine2,
	advadd.ADD_Line3 as SellingAdviserAddressLine3,
	advadd.ADD_Postcode as SellingAdviserPostcode,
	cd.CD_Telephone as SellingAdviserWorkTelephoneNumber,
	cd.CD_Mobile as SellingAdviserMobileNumber,
	cd.CD_email as SellingAdviserEmailAddress,
	staf.STAF_NINumber	as SellingAdviserNINumber,
	sale.SaleID as AdviceCaseSequentialReference,
	pers.DateCreated As Owner1CreationDate,
	invP1T.ValueName As Owner1Title,
	pers.FirstName As Owner1FirstName,
	pers.LastName As Owner1LastName,
	pers.DateOfBirth As Owner1DateOfBirth,
	invP1G.ValueName As Owner1Gender,
	pers.Address1 As Owner1AddressLine1,
	pers.Address2 As Owner1AddressLine2,
	pers.Address3 As Owner1AddressLine3,
	pers.Address4 As Owner1AddressLine4,
	pers.Address5 As Owner1AddressLine5,
	pers.PostCode As Owner1PostCode,
	pers.TelephoneHome As Owner1HomeTelephoneNumber,
	pers.TelephoneMobile As Owner1MobileNumber,
	pers.EmailAddress As Owner1EmailAddress,
	emp.JobTitle as Owner1Occupation,
	emp.IncomeSource as Owner1EmployerName,
	emp.ValueName as Owner1EmploymentStatus,
	emp.MonthlyGrossIncome as Owner1TotalGrossMonthlyIncome,
	nid.TotalNetIncome as Owner1TotalNetMonthlyIncome,
	pers.NINo as Owner1NINumber,
	invMS.ValueName as Owner1MaritalStatus,
	ffog.IntroducerDetails as Owner1DescriptionReference,	
	invP2T.ValueName As Owner2Title,
	pers1.FirstName As Owner2FirstName,
	pers1.LastName As Owner2Surname,
	pers1.DateOfBirth As Owner2DateOfBirth,
	invP2G.ValueName As Owner2Gender,
	pers1.TelephoneHome As Owner2HomeTelephoneNumber,
	pers1.TelephoneMobile As Owner2MobileNumber,
	pers1.EmailAddress  As Owner2EmailAddress,
	emp2.JobTitle As Owner2Occupation,
	emp2.IncomeSource As Owner2EmployerName,
	emp2.MonthlyGrossIncome As Owner2TotalGrossMonthlyIncome,
	nid2.TotalNetIncome as Owner2TotalNetMonthlyIncome,
	polm.cont_Num as PolicyNumber,
	ppr.DisplayName as ProtectionProductName,
	pd.LifeCoverTerm,
	pd.TotalRegularPremium,
	pd.AnnualisedPremium,
	pd.CurrentRegularPremiumFrequency,
	pd.[Current Regular Premium (Self) Frequency],
	pd.LifeCoverSumAssured,
	case when md.PolicyId is not null then
	(case when md.MortgageAbortedDate Is NOT null then md.MortgageAbortedDate 
	when md.MortgageCompletionDate IS NOT null then md.MortgageCompletionDate 
	when md.MortgageExchangeDate IS NOT NULL then md.MortgageExchangeDate else convert(datetime,Null) End)
	else (case when pd.ProtectionAbortedDate IS NOT null then pd.ProtectionAbortedDate 
	when pd.ProtectionOnRiskDate IS NOT null 
		then pd.ProtectionOnRiskDate 
		else convert(datetime,Null) end) 
	end as PlanStatusDate,									
	sale.DateCreated as AdviceCaseCreatedOn,
	pol.ApplicationDate as PolicyStartDate,
	case when pp.DisplayName is null then mp.DisplayName else pp.DisplayName end as ProviderName,
	case when pd.LifeAssuredId = 10110 then pers.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10111 then pers1.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10112 then 'Joint Policy'
			when pd.LifeAssuredId = 10113 then 'Life of Another' end as LifeAssured1FullName,
	md.TransactionType as MortgageTransactionType,
	polm.cont_Num as MortgageRefNo,
	md.MortgageCategory as MortgageMortgageType,
	md.InterestRateType as MortgageRateType,
	md.MortgageType as MortgageRepaymentMethod,
	md.EndDate as MortgageFeatureExpires,
	md.MortgageTermYears,
	md.MortgageExchangeDate as MortgageExchangeDate,		
	md.MortgageCompletionDate as MortgageCompletionDate,	
	md.PropertyValue as MortgagePriceValuation,
	md.TotalMortgageAmount as MortgageLoanAmount,
	md.ArrangementFeeAmount as MortgageLenderFees,
	md.LoanToValueRatio as MortgageLTV,
	md.MortgageApplicationDate as MortgageApplicationSubmitted,
	md.ProcFee as ExpectedCommissionProcurement,
	md.BrokerFeeAmount,
	md.AddressLine1 as MortgageAddressLine1,
	md.AddressLine2 as MortgageAddressLine2,
	md.AddressLine3 as MortgageAddressLine3,
	md.AddressLine4 as MortgageAddressLine4,
	md.AddressLine5 as MortgageAddressLine5,
	md.Postcode as MortgagePostcode,
	md.NewBuild,									--AG 05/06/2019
	case											--AG 29/09/2020
		when pt.CommType = 'F' then 'Accr' 
		when pt.CommType = 'T' then 'IT' 
		when pt.CommType = 'L' then 'Level'
		else 'Unknown' 
	end as PayBasis,
	isnull(EmpType.Code_Description,'Unknown') as EmploymentType,
	uh1.UserName as SubmittedByUserName,
	initCom.InitialCommission as 'Splitting Initial Commission',
	--Advisor1.Advisor1,
	InitSplit.SplitPercentage1 as 'Selling Adviser Initial Split',
	Advisor2.Advisor2 as 'Initial Split 1',
	InitSplit2.SplitPercentage2 as 'Initial Split 1 Percentage',
	Advisor3.Advisor3 as  'Initial Split 2',
	InitSplit3.SplitPercentage3 as 'Initial Split 2 Percentage',
	renewal.RenewalCommissionSplit as 'Splitting Renewal',
	
	RenewalPercentage1.RenewalPercentage1 as 'Selling Adviser Renewal Split',
	renewalAdvisor2.RenewalAdvisor2 as 'Renewal Split 1',
	RenewalPercentage2.RenewalPercentage2 as 'Renewal Split 1 Percentage',
	renewalAdvisor3.RenewalAdvisor3 as 'Renewal Split 2',
	RenewalPercentage3.RenewalPercentage3 as 'Renewal Split 2 Percentage'
	from sa_ows_sale sale
	join sa_ows_Policies pol on pol.SaleID = sale.SaleID
	join sa_ows_Person pers on pers.PersonID = sale.PersonID
	join StaticData.sa_ows_InputValues invP1G on invP1G.InputID = pers.GenderID
	join StaticData.sa_ows_InputValues invP1T on invP1T.InputID = pers.TitleID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = sale.AdviserUID and uh.LatestRowInd = 1	--AG 29/09/2020
	left join mi_insight_UserHierarchyAllUsers uh1 on sale.SubmittedBy = uh1.UserUID and uh1.LatestRowInd = 1
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_ows_Person pers1 on pers.PartnerPersonID = pers1.PersonID
	left join StaticData.sa_ows_InputValues invP2G on invP2G.InputID = pers1.GenderID
	left join StaticData.sa_ows_InputValues invP2T on invP2T.InputID = pers1.TitleID
	left join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_ows_ProtectionProvider pp on pp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_OWS_ProtectionProduct ppr on ppr.InternalProductID = pol.InternalProductID
	left join sa_swift_S_POLMAI polm on polm.PolicyRef = pol.PolicyID
	left join (select PolicyID, max(ID) as MaxID from mstt_PolicyTransactions where TransType <> 117 group by PolicyID) LatestTxn on LatestTxn.PolicyID = polm.POL_NUM	--AG 29/09/2020
	left join mstt_PolicyTransactions pt on pt.ID = LatestTxn.MaxID	--AG 29/09/2020
	left join sa_ows_ClientDetailOverviewClientDetails cdocd on cdocd.PersonID = pers.personid and cdocd.PersonTypeID = 1
															 and cdocd.DateUpdated = (select max(cdocd1.DateUpdated)
																					  from sa_ows_ClientDetailOverviewClientDetails cdocd1
																					  where cdocd.PersonID = cdocd1.PersonID
																					  and cdocd1.PersonTypeID = 1)
	left join StaticData.sa_ows_InputValues invMS on invMS.inputid = cdocd.MaritalStatusID
	left join CTE_Employer emp on emp.PersonID = pers.PersonID and emp.PersonTypeID = 1
	left join CTE_Employer emp2 on emp2.PersonID = pers.PersonID and emp2.PersonTypeID = 2
	left join CTE_NetIncomeDetails nid on nid.SaleID = sale.SaleID and nid.PersonTypeID = 1
	left join CTE_NetIncomeDetails nid2 on nid2.SaleID = sale.SaleID and nid2.PersonTypeID = 2
	left join CTE_MortgageDetails md on md.PolicyId = pol.PolicyID
	left join CTE_ProtectionDetails pd on pd.PolicyId = pol.PolicyID
	left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = pol.SaleID
	--AG 06/11/2020 Start
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'InitialAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as InitAdv on InitAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'InitialPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as InitPct on InitPct.PolicyID = pol.PolicyID
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as RenAdv on RenAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'RenewalPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as RenPct on RenPct.PolicyID = pol.PolicyID
	left join (	select	distinct qrUID.PolicyID, qrUID.AnswerText as RenewalCommissionSameAsInitial
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalCommissionSameAsInitial'
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				) as RenSameInit on RenSameInit.PolicyID = pol.PolicyID
	left join 
	(
		-- initial commision split
		select distinct r.PolicyID, case when r.AnswerText = '1' then 'yes' when r.AnswerText = '2' then 'no' else null end as InitialCommission--, *
		from StaticData.sa_ows_HDRUI_QuestionBank q
		left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
		where q.ObjectModelProperty in ('DrawdownInitialCommissionSplitApplies', 'InitialCommissionSplitApplies')
	) as initCom on initCom.PolicyID = pol.PolicyID
	left join
	(	
		select *
		from
		(
			--initial split percentage 1
			select distinct r.PolicyID, r.AnswerText as SplitPercentage1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 1

	) as InitSplit on InitSplit.PolicyID = pol.PolicyID

	left join
	(	
		select *
		from
		(
			--initial split percentage 2
			select distinct r.PolicyID, r.AnswerText as SplitPercentage2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 2

	) as InitSplit2 on InitSplit2.PolicyID = pol.PolicyID
	left join
	(	
		select *
		from
		(
			--initial split percentage 3
			select distinct r.PolicyID, r.AnswerText as SplitPercentage3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 3

	) as InitSplit3 on InitSplit3.PolicyID = pol.PolicyID
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 1
			select distinct r.PolicyID, r.AnswerText as Advisor1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where rownum = 1
	) as Advisor1 on Advisor1.PolicyID = pol.PolicyID
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 2
			select distinct r.PolicyID, r.AnswerText as Advisor2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where sub1.rownum = 2
	) as Advisor2 on Advisor2.PolicyID = pol.PolicyID
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 3
			select distinct r.PolicyID, r.AnswerText as Advisor3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where sub1.rownum = 3
	) as Advisor3 on Advisor3.PolicyID = pol.PolicyID
	left join
	(

		-- RenewalCommissionSplitApplies
		select distinct r.PolicyID, case when r.AnswerText = '1' then 'yes' when r.AnswerText = '2' then 'no' else null end as RenewalCommissionSplit
		from StaticData.sa_ows_HDRUI_QuestionBank q
		left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
		where q.ObjectModelProperty = 'RenewalCommissionSplitApplies'
		
	) as renewal on renewal.PolicyID = pol.PolicyID
	left join
	(
		--RenewalAgentID 1
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 1
	) as renewalAdvisor1 on renewalAdvisor1.PolicyID = pol.PolicyID
	left join
	(
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 2
	) as renewalAdvisor2 on renewalAdvisor2.PolicyID = pol.PolicyID
	left join
	(
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 3
	) as renewalAdvisor3 on renewalAdvisor3.PolicyID = pol.PolicyID
	left join
	(
		--RenewalPercentage 1
		select *
		from
		(
			-- RenewalPercentage 1
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 1
	) as RenewalPercentage1 on RenewalPercentage1.PolicyID = pol.PolicyID
	left join
	(
		--RenewalPercentage 2
		select *
		from
		(
			-- RenewalPercentage 2
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 2
	) as RenewalPercentage2 on RenewalPercentage2.PolicyID = pol.PolicyID
	left join
	(
		--RenewalPercentage 3
		select *
		from
		(
			-- RenewalPercentage 3
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 3
	) as RenewalPercentage3 on RenewalPercentage3.PolicyID = pol.PolicyID
	--AG 06/11/2020 End
	where sale.DateSubmitted is not null
	and pol.Status in (0,1,2)
	and (md.PolicyId is not null or pd.PolicyId is not null)
	and sale.BusinessUid = @TPGBusinessUID

		UNION ALL

	Select
	pol.PolicyRef,
	pol.CLIENT_NUM,
	pol.JOINT_NUM,
	pol.CreateDate,
	null,
	null,
	pol.SellingAgentCode,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	null,
	null,
	clt.Title,
	clt.FIRSTNAMES,
	clt.Name,
	clt.BIRTHDATE,
	clt.Gender,
	clt.Address1,
	clt.Address2,
	null,
	null,
	null,
	clt.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	jt.Title,
	jt.FIRSTNAMES,
	jt.Name,
	jt.BIRTHDATE,
	jt.Gender,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	pol.CONT_NUM,
	pol.ProductCodeDescription,
	convert(varchar(3),pol.TERM_Y) + ' Years '+ convert(varchar(3),pol.TERM_M) + ' Months',
	pt.Amount,
	pt.APE,
	pt.FrequencyDescription,
	pt.FrequencyDescription,
	null,
	null,
	pol.CreateDate,
	pol.START_DATE,
	pol.CompanyName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	pt.CommissionTypeDesc,
	EmpType.Code_Description,
	null as SubmittedByUserName,
	initCom.InitialCommission as 'Splitting Initial Commission',
	InitSplit.SplitPercentage1 as 'Selling Adviser Initial Split',
	Advisor2.Advisor2 as 'Initial Split 1',
	InitSplit2.SplitPercentage2 as'Initial Split 1 Percentage',
	Advisor3.Advisor3 as  'Initial Split 2',
	InitSplit3.SplitPercentage3 as 'Initial Split 2 Percentage',
	renewal.RenewalCommissionSplit as 'Splitting Renewal',
	RenewalPercentage1.RenewalPercentage1 as 'Selling Adviser Renewal Split',
	renewalAdvisor2.RenewalAdvisor2 as 'Renewal Split 1',
	RenewalPercentage2.RenewalPercentage2 as 'Renewal Split 1 Percentage',
	renewalAdvisor3.RenewalAdvisor3 as 'Renewal Split 2',
	RenewalPercentage3.RenewalPercentage3 as 'Renewal Split 2 Percentage'
	from mstt_Policies pol
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = pol.SellingAgentCode and pol.CreateDate between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join mstt_PolicyTransactions pt on pt.PolicyID = pol.POL_NUM and pt.TransactionNumber = 1
	left join mstt_Clients clt on clt.CLIENT_NUM = pol.CLIENT_NUM
	left join mstt_Clients jt on jt.CLIENT_NUM = pol.JOINT_NUM
		left join 
	(
		-- initial commision split
		select distinct r.PolicyID, case when r.AnswerText = '1' then 'yes' when r.AnswerText = '2' then 'no' else null end as InitialCommission--, *
		from StaticData.sa_ows_HDRUI_QuestionBank q
		left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
		where q.ObjectModelProperty in ('DrawdownInitialCommissionSplitApplies', 'InitialCommissionSplitApplies')
	) as initCom on initCom.PolicyID = pol.PolicyRef
	left join
	(	
		select *
		from
		(
			--initial split percentage 1
			select distinct r.PolicyID, r.AnswerText as SplitPercentage1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 1

	) as InitSplit on InitSplit.PolicyID = pol.PolicyRef

	left join
	(	
		select *
		from
		(
			--initial split percentage 2
			select distinct r.PolicyID, r.AnswerText as SplitPercentage2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 2

	) as InitSplit2 on InitSplit2.PolicyID = pol.PolicyRef
	left join
	(	
		select *
		from
		(
			--initial split percentage 3
			select distinct r.PolicyID, r.AnswerText as SplitPercentage3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum--, R.*, q.*
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialPercentage', 'DrawdownInitialPercentage')  
		
		
		) as sub1
		where sub1.rownum = 3

	) as InitSplit3 on InitSplit3.PolicyID = pol.PolicyRef
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 1
			select distinct r.PolicyID, r.AnswerText as Advisor1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where rownum = 1
	) as Advisor1 on Advisor1.PolicyID = pol.PolicyRef
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 2
			select distinct r.PolicyID, r.AnswerText as Advisor2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where sub1.rownum = 2
	) as Advisor2 on Advisor2.PolicyID = pol.PolicyRef
	left join
	(
		select *
		from
		(
			-- initial commision Advisor 3
			select distinct r.PolicyID, r.AnswerText as Advisor3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty in ('InitialAgentID', 'DrawdownInitialAgentID')
			
		) as sub1
		where sub1.rownum = 3
	) as Advisor3 on Advisor3.PolicyID = pol.PolicyRef
	left join
	(

		-- RenewalCommissionSplitApplies
		select distinct r.PolicyID, case when r.AnswerText = '1' then 'yes' when r.AnswerText = '2' then 'no' else null end as RenewalCommissionSplit
		from StaticData.sa_ows_HDRUI_QuestionBank q
		left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
		where q.ObjectModelProperty = 'RenewalCommissionSplitApplies'
		
	) as renewal on renewal.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalAgentID 1
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 1
	) as renewalAdvisor1 on renewalAdvisor1.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalAgentID 2
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 2
	) as renewalAdvisor2 on renewalAdvisor2.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalAgentID 2
		select *
		from
		(
			-- RenewalAgentID
			select distinct r.PolicyID, r.AnswerText as RenewalAdvisor3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalAgentID'
			
		) as sub1
		where rownum = 3
	) as renewalAdvisor3 on renewalAdvisor3.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalPercentage 1
		select *
		from
		(
			-- RenewalPercentage 1
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage1, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 1
	) as RenewalPercentage1 on RenewalPercentage1.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalPercentage 2
		select *
		from
		(
			-- RenewalPercentage 2
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage2, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 2
	) as RenewalPercentage2 on RenewalPercentage2.PolicyID = pol.PolicyRef
	left join
	(
		--RenewalPercentage 3
		select *
		from
		(
			-- RenewalPercentage 3
			select distinct r.PolicyID, r.AnswerText as RenewalPercentage3, row_number() over(partition by r.PolicyID order by r.QuestionRepeatNumber asc) as rownum
			from StaticData.sa_ows_HDRUI_QuestionBank q
			left join sa_ows_HDRUI_QuestionnaireResponses as r on r.QuestionID = q.QuestionID
			where q.ObjectModelProperty = 'RenewalPercentage'
			
		) as sub1
		where rownum = 3
	) as RenewalPercentage3 on RenewalPercentage3.PolicyID = pol.PolicyRef
	where uh.BusinessUID = @TPGBusinessUID
	and pol.PolicyRef like '8000%'

	
	UNION ALL

	Select
	ps.SwiftCaseID,
	pers.PersonID,
	part.PersonID,
	cases.DateSubmitted,
	null,
	null,
	cases.AdviserID,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	cases.ABSCaseID,
	null,
	pers.Title,
	pers.FirstName,
	pers.LastName,
	try_cast(pers.DOB as datetime),
	pers.Gender,
	pers.Address1,
	pers.Address2,
	null,
	null,
	null,
	pers.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	part.Title,
	part.FirstName,
	part.LastName,
	try_cast(part.DOB as datetime),
	part.Gender,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	qr.AnswerText,
	prod.DisplayName,
	qr1.AnswerText + ' Years',
	try_cast(qr7.AnswerText as float),
	case when qr2.AnswerText = 3 then try_cast(qr7.AnswerText as decimal(10,2))*12 else try_cast(qr7.AnswerText as decimal(10,2)) end,
	ab.AnswerText,
	ab.AnswerText,
	null,
	null,
	cases.CreatedDate,
	ps.CommencementDate,
	prov.DisplayName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	case when qr8.AnswerText = 50 then 'IT' when qr8.AnswerText = 51 then 'Accr' end,
	EmpType.Code_Description,
	null as SubmittedByUserName,
	null as 'Splitting Initial Commission',
	null as 'Selling Adviser Initial Split',
	null as 'Initial Split 1',
	null as'Initial Split 1 Percentage',
	null as 'Initial Split 2',
	null as 'Initial Split 2 Percentage',
	null as 'Splitting Renewal',
	null as 'Selling Adviser Renewal Split',
	null as 'Renewal Split 1',
	null as 'Renewal Split 1 Percentage',
	null as 'Renewal Split 2',
	null as 'Renewal Split 2 Percentage'
	from sa_abs_ABS_Person pers
	left join sa_abs_ABS_Person part on part.ABSCaseID = pers.ABSCaseID and part.PersonType = 'Partner'
	left join sa_abs_ABS_Cases cases on cases.ABSCaseID = pers.ABSCaseID
	left join sa_abs_ABS_ProductSales ps on ps.ABSCaseID = cases.ABSCaseID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = cases.AdviserID and convert(date,cases.DateSubmitted) between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_abs_ABS_UIQuestionnaireResponses qr on qr.SwiftCaseID = ps.SwiftCaseID and qr.QuestionID in (30,58,420)
	left join sa_abs_ABS_Products prod on prod.ABSProductID = ps.ProductID
	left join sa_abs_ABS_UIQuestionnaireResponses qr1 on qr1.SwiftCaseID = ps.SwiftCaseID and qr1.QuestionID in (421)
	left join sa_abs_ABS_UIQuestionnaireResponses qr7 on qr7.SwiftCaseID = ps.SwiftCaseID and qr7.QuestionID = 378
	left join sa_abs_ABS_UIQuestionnaireResponses qr2 on qr2.SwiftCaseID = ps.SwiftCaseID and qr2.QuestionID = 379
	left join sa_abs_ABS_UIAnswerBank ab on convert(varchar(250),ab.AnswerID) = qr2.AnswerText
	left join sa_abs_ABS_Providers prov on prov.ABSProviderID = ps.ProviderID
	left join sa_abs_ABS_UIQuestionnaireResponses qr3 on qr3.SwiftCaseID = ps.SwiftCaseID and qr3.QuestionID = 36
	left join sa_abs_ABS_UIQuestionnaireResponses qr4 on qr4.SwiftCaseID = ps.SwiftCaseID and qr4.QuestionID = 37
	left join mstt_agents agt on agt.CODE = qr3.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr5 on qr5.SwiftCaseID = ps.SwiftCaseID and qr5.QuestionID = 115
	left join sa_abs_ABS_UIQuestionnaireResponses qr6 on qr6.SwiftCaseID = ps.SwiftCaseID and qr6.QuestionID = 116
	left join mstt_agents agt2 on agt2.CODE = qr5.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr8 on qr8.SwiftCaseID = ps.SwiftCaseID and qr8.QuestionID = 423
	where uh.BusinessUID = '2000978'
	
	set @RowCount = @@rowcount
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	set @ProcessMessage = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[pr_ProcessLog]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS OFF
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	pr_ProcessLog	(copied from dbo.msp_ProcessLog)
	  Author:	A Groves
Date created:	03/09/2021

		Type:	Generic logging
		
 Description:   This proc populates table BI.ProcessLog with generic logging info.
				
				It is called as follows:

				exec BI.pr_ProcessLog @Phase, @Process, @Module, @Type, @RowCount, @ErrorMessage
				or
				exec BI.pr_ProcessLog @Phase, @Process, @Module, @Type
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [BI].[pr_ProcessLog] 
 @Phase         nvarchar(50),
 @Process       nvarchar(100),
 @Module		nvarchar(50),
 @Type          nvarchar(50),
 @RowCount		int = null,
 @ErrorMessage	nvarchar(4000) = null

AS

declare @DtTm      datetime,
        @ProcessId integer

select @DtTm      = getdate(),
       @ProcessId = (select isnull(max(ProcessId), 0) + 1 from BI.ProcessLog)

insert into
 BI.ProcessLog
values
 (@DtTm, @ProcessId, @Phase, @Process, isnull(@Module,''), isnull(@Type, ''), @Rowcount, @ErrorMessage)
GO
/****** Object:  StoredProcedure [BI].[pr_Profitability]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  Openwork Profitability Report.
  	 					
	  Author:	Akin Yavuz

Date created:	28/10/2021
													
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [BI].[pr_Profitability]
	--@ProfStartDate datetime,
	--@ProfEndDate datetime

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.
SET DATEFIRST 1 
SET DATEFORMAT DMY

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@Client						varchar(50),
		@Module						varchar(50),
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'MI Team Profitability Report'
set @DateLastUpdated	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	SET NOCOUNT ON

IF OBJECT_ID('tempdb..#ProfitB') IS NOT NULL
DROP TABLE #ProfitB
IF OBJECT_ID('tempdb..#ProfitC') IS NOT NULL
DROP TABLE #ProfitC
IF OBJECT_ID('tempdb..#ProfitD') IS NOT NULL
DROP TABLE #ProfitD
IF OBJECT_ID('tempdb..#Prof1') IS NOT NULL
DROP TABLE #Prof1
IF OBJECT_ID('tempdb..#ProfitBb') IS NOT NULL
DROP TABLE #ProfitBb
IF OBJECT_ID('tempdb..#FinalBSCRebate') IS NOT NULL
DROP TABLE #FinalBSCRebate

SET DATEFIRST 1

DECLARE
@ProfStartDate varchar(30),
@ProfEndDate varchar(30)
DECLARE
@ProfPaymentMonth date;
--SET @ProfPaymentMonth = '01-Mar-2020'
--SET @ProfStartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102) 
--SET @ProfEndDate = CONVERT(DATETIME, '2021-09-30 23:59:59', 102); ---ENSURE END DATE IS LAST DAY OF REPORTING MONTH

-------------------------------------------------------BSC REBATE QUERY ---------------------------------------------------------------------
--Create Agent Uplift Rate table with start and end date

WITH AgentUpliftTable AS(
SELECT 
ROW_NUMBER() OVER(partition by au.agentcode, au.productcode order by au.dateinforce) as RowNum,
au.AgentCode,
au.DateInForce,
au.ProductCode,
au.UpliftRate,
au.Status,
au.PolicyType
from sa_swift_AgentUplifts au
join mstt_ProductHierarchy ph on ph.ProductCode = au.ProductCode and ph.ProductCategoryCode = 1
where status = 0),

FranchiseUpliftRate AS(
Select
aut.RowNum,
aut.AgentCode,
aut.DateInForce,
aut.UpliftRate,
aut.ProductCode,
isnull(dateadd(day,-1,aut2.dateinforce),'31-Dec-3099')  as EndDate,
aut2.RowNum as NewRow
from AgentUpliftTable aut
left join AgentUpliftTable aut2 on aut2.AgentCode = aut.AgentCode 
								and aut2.ProductCode = aut.ProductCode
								and aut2.RowNum = aut.RowNum +1),

pacc AS (
Select
pacc_id
from mstt_PaymentsPending
where AGENT_CODE = '1011587'
and CommissionMonth >= @ProfPaymentMonth),

DAAmount AS (
Select
pp.PACC_ID,
sum(amount) as DA
from mstt_PaymentsPending pp
join pacc pc on pc.PACC_ID = pp.PACC_ID
where CommissionMonth >= @ProfPaymentMonth
Group by pp.PACC_ID),


-- Create Table of all payments in month
FirmPayments AS (
Select pp.ID, pacc_id, AGENT_CODE, AGENT_PERC, isnull(franchiseagentcode,AccessAgentCode) as franchiseagentcode, TransactionID, CaseID, ProviderRef
from mstt_paymentspending pp
join mstt_clients clt on clt.client_num = firstclientid 
where 
manager2code != '1011671' and
CommissionMonth >= @ProfPaymentMonth),


--Create split of payments across BSC/Margin/Other Splits
Payment AS (
Select
ROW_Number() over (Partition By fp.pacc_ID order by fp.Agent_Code) as Row_Num,
fp.ID,
fp.Pacc_id, 
fp.AGENT_CODE,
fp.Agent_Perc,
fp.franchiseagentcode,
fp.TransactionID,
fp.CaseID,
fp.ProviderRef,
convert(date,pp.createdatetime) as CreateDate,
case when ph.rdrtype is not null then 'Wealth' else ProductCategoryName end as Product,
sum(case when pp.franchiseagentcode = fp.FranchiseAgentcode then pp.Amount end) as FirmPayment,
sum(case when pp.franchiseagentcode != fp.franchiseAgentcode and pp.franchiseAgentCode is not null then pp.Amount end) as OtherFirmPayment,
sum(case when pp.franchiseagentcode != fp.franchiseAgentcode and pp.franchiseAgentCode is not null then pp.Agent_perc end) as OtherFirmPct,
sum(case when pp.agent_code = '10002' then pp.Amount end) as OWMargin,
sum(case when pp.agent_code = '1011543' then pp.Amount end) as OWFeeMargin,
sum(case when pp.agent_code = '1011543' then pp.AGent_perc end) as OWFeePct,
sum(case when pp.agent_code = '1011587' then pp.Amount end) as BSC,
sum(case when pp.agent_code = '1011587' then pp.agent_perc end) as BSCPct,
pp.FirstClientID
from FirmPayments fp
Join mstt_paymentspending pp on pp.pacc_id = fp.pacc_id
join mstt_producthierarchy ph on ph.productcode = pp.tranproduct
group by fp.id, fp.Pacc_id, 
fp.AGENT_CODE,
convert(date,pp.createdatetime),
fp.franchiseagentcode, 
pp.FirstClientID,
case when ph.rdrtype is not null then 'Wealth' else ProductCategoryName end,
fp.TransactionID, fp.CaseID, fp.ProviderRef, fp.agent_perc),

--Limit to only where there is BSC present and calculate splits
FinalRebateTable AS (
Select
p.id,
p.AGENT_CODE,
p.agent_perc,
p.FranchiseAgentCode,
agt.Descn,
agt.CompetentStatusDescription,
p.TransactionID,
p.CaseID,
p.ProviderRef,
p.PACC_ID,
p.firmpayment,
p.OtherFirmPayment,
p.OWFeeMargin,
p.BSC,
p.BSCPct,
p.OWFeePct,
com.FranchiseUpliftPercent,
pt.ProposalDate,
p3.Agent_code as agent3Code,
p3.Agent_perc as agent3pct,
com3.franchiseupliftpercent as agent3uplift,
p3.Agent_Perc/(com3.franchiseupliftpercent-20)*100 as Agent3Gross,
p2.Agent_code as Agent2Code,
p2.Agent_perc as Agent2Pct,
com2.franchiseupliftpercent as agent2uplift,
p2.Agent_Perc/(com2.franchiseupliftpercent-20)*100 as Agent2Gross,
p.Agent_Perc/(com.franchiseupliftpercent-20)*100 as Agent1Gross,
100 - p.BSCPct as RemainingSplit,
p.AGENT_PERC/(isnull(com.franchiseupliftpercent,fur.upliftrate)-20)*100 as TruePCt,
round(((p.AGENT_PERC/(isnull(com.franchiseupliftpercent,fur.upliftrate)-20))*100)/(100 - p.BSCPct)*100,0)
 as AgentTruePct,
isnull(com.franchiseupliftpercent,fur.upliftrate)-20 as PaymentUpliftRate,
da.DA,
p.FirstClientID,
p.CreateDate
from Payment p
join mstt_agents agt on agt.code = franchiseagentcode
join mstt_PolicyTransactions pt on pt.id = p.TransactionID
left join DAAmount da on da.PACC_ID = p.PACC_ID
left join mstt_Commissions com on com.TransactionID = p.transactionid and com.CommissionType = 1 and p.AGENT_CODE = com.AGENT_CODE
left join payment p2 on p2.pacc_id = p.pacc_id and p2.Row_num =  case when p.Row_Num = 1 then 2
																	   when p.Row_Num = 2 then 1
																	   when p.Row_num = 3 then 1 end
left join payment p3 on p3.pacc_id = p.pacc_id and p3.Row_num =  case when p.Row_Num = 1 then 3
																	   when p.Row_Num = 2 then 3
																	   when p.Row_num = 3 then 2 end
left join mstt_Commissions com2 on com2.TransactionID = p2.transactionid and com2.CommissionType = 1 and p2.AGENT_CODE = com2.AGENT_CODE
left join mstt_Commissions com3 on com3.TransactionID = p3.transactionid and com3.CommissionType = 1 and p3.AGENT_CODE = com3.AGENT_CODE
left join FranchiseUpliftRate fur on fur.AgentCode = p.franchiseagentcode and pt.ProposalDate between fur.DateInForce and fur.EndDate and pt.CommProductCode = fur.ProductCode
left join FranchiseUpliftRate fur2 on fur2.AgentCode = p2.franchiseagentcode and pt.ProposalDate between fur2.DateInForce and fur2.EndDate and pt.CommProductCode = fur2.ProductCode
left join FranchiseUpliftRate fur3 on fur3.AgentCode = p3.franchiseagentcode and pt.ProposalDate between fur3.DateInForce and fur3.EndDate and pt.CommProductCode = fur3.ProductCode
where p.BSC is not null),


--Calculate Rebate Amount
QuickCheck AS (
Select 
ID,
Agent_code,
Agent_perc,
FranchiseAgentCode,
Descn,
CompetentStatusDescription,
CaseID,
ProviderRef,
Pacc_ID,
FirmPayment,
BSC,
BSCPct,
ProposalDate,
RemainingSplit,
AgentTruePct,
PaymentUpliftRate,
case when FranchiseUpliftPercent is null then 'Derived' else 'Actual' end as CalcType,
BSC*(AgentTruePct/100)*(PaymentUpliftRate/100)*0.5 as AmountDue,
BSC*(AgentTruePct/100) as BSCSplitAmount,
frt.DA as OngoingDA,
frt.TransactionID,
FirstClientID,
frt.CreateDate
from FinalRebateTable frt

UNION
Select pp.id, com.agent_code, com.agent_perc,com.franchiseagentcode,agt.descn,agt.competentstatusdescription, pp.caseid, pp.providerref,pp.pacc_id,0, pp.Amount, pp.Agent_perc, com.proposaldate,0,com.agent_perc,com.franchiseupliftpercent-20,'Derived - All BSC',pp.Amount*(com.franchiseupliftpercent-20)/100*0.5,
pp.Amount*(com.agent_perc/100) as BSCSplitAmount,pp.AMOUNT,pp.TransactionID, pp.FirstClientID, convert(date,pp.CreateDateTime)
from mstt_paymentspending pp
join mstt_commissions com on com.transactionid = pp.transactionid and com.commissiontype = 1 and com.agent_code != '10002'
join mstt_agents agt on agt.code = com.franchiseagentcode
where pp.commissionmonth >= @ProfPaymentMonth and pp.agent_code = '1011587' and pp.Agent_perc = 100 and pp.agent_code != '1006886'),


FinalBSCRebate as (
Select
cast((Month(qc.createdate)) as nvarchar(max)) + cast((Year(qc.Createdate)) as nvarchar(max)) + 'Recurring Income' AS 'Concat',
cast((year(qc.createdate)) as nvarchar(max)) + (case when month(qc.createdate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,qc.createdate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,qc.createdate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
ah.AgentCode,
ah.AgentDesc,
ah.FirmCode,
ah.FirmDescn,
Month(qc.createdate) as Month,
Year(qc.Createdate) as Year,
'Recurring Income' AS ProductGroupName,
'BSC Rebate' AS ProductSubGroup,
0 as APE,
sum(AmountDue)*-1 as DA, --BSCRebate,
0 as DA_Claw,
0 as Commission,
0 as Commission_Claw,
0 as Net_Commission,
sum(AmountDue)*-1 as Margin, --BSCRebate,
0 as Net_Charges,
0 as NewPolicies,
0 as WrittenNBAPE,
0 as WrittenNBCases,
0 as Paid

from QuickCheck qc
join mstt_Clients clt on CLIENT_NUM = FirstClientID
join mstt_PolicyTransactions pt on pt.ID = TransactionID
join mstt_agents agt on agt.CODE = qc.AGENT_CODE
join cscv_AgentsHierarchy ah ON ah.AgentCode = qc.AGENT_CODE
WHERE (agt.Manager2Code <> '4010386' or Firm <> '2016789')
AND Firm NOT IN ('1002524', '2004449', '1001031', '2005309')
Group by
DAY(qc.CreateDate),
Month(qc.createdate),
Year(qc.Createdate),
qc.CreateDate,
agt.DESCN,
ah.AgentCode,
ah.AgentDesc,
ah.FirmCode,
ah.FirmDescn)

----Add in BSC Rebate Value
SELECT * into #FinalBSCRebate FROM FinalBSCRebate
---------------------------------------------------------------------------END OF BSC REBATE -------------------------------------------------------------------------

--DEDUCE ISSUED NEW POLICIES (I.E IF TRANSACTIONID IS 1ST ACTIVE POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #ProfitBb

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')	
and co.commissiontype = 1
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM				  dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
--and co.businessreason in ('NB','NI')
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

select transactionid,policyref,cont_num into #ProfitB from #ProfitBb where left(cont_num,2) <> 'ZR' or cont_num is null
union all
select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
from #ProfitBb where left(cont_num,2) = 'ZR'group by  policyref, cont_num

drop table #ProfitBb

