-----------------------------ISSUED APE------------------------------------------------------------------------------------------------------------------

-- APE FIX FOR CROSS CHARGE ASSUMING DA IS 2.5% OF PREMIUM / 10 FOR APE
sum(Case when (d.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then d.CorrectAPE else
((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
-- ENSURE MORTGAGES APE IS THE SAME AS DA
(case when 
ph.productgroupname = 'mortgage'
then (case when (
ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) END))End) as "IssuedAPE",

-----------------------------GROSS DA------------------------------------------------------------------------------------------------------------------

sum(
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount+ag.derivedmarginamount) ElSE

(Case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then 
    (ag.amount + isnull(derivedmarginamount,0)) else 0 END)END) as 'GrossDA',


-----------------------------DA CLAW------------------------------------------------------------------------------------------------------------------

sum(case when ph.productgroupname = 'Mortgage' then 0 
when (ag.commissiontype in ('2') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then (ag.amount / (8.0/10))
-- DA CLAW POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontypedesc like '%claw%') then (ag.amount + isnull(derivedmarginamount,0)) 
else 0 end) as 'DAClaw',

-----------------------------GROSS COMMISSION------------------------------------------------------------------------------------------------------------------

-- GROSS COMM INITIAL
sum (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then 
		(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
		 WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
		 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
		 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
		 ELSE ag.Amount END) ElSE

(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
     WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
     WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
	 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
	 when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.INIssued)

-- GROSS COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then ag.amount
-- GROSS COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ag.amount
else 0 end)END) as 'GrossComm',

-----------------------------COMMISSION CLAW------------------------------------------------------------------------------------------------------------------

-- COMM CLAW INITIAL
sum(CASE  WHEN ph.productgroupname = 'Mortgage' then 0 

when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid')) and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN ((cs.INIssued) * 10.0)/ 9 
when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
when ((ag.commissiontype in ('2') and cs.oastatus = 'valid')) then (cs.INIssued)

-- COMM CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then ag.amount
-- COMM CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then ag.amount
else 0 end) as 'CommClaw',

-----------------------------NET COMMISSION------------------------------------------------------------------------------------------------------------------

-- NET COMM INITIAL
sum (CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
    WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
    WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
	when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
	when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount)
	when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName <> 'Mortgage') then (cs.INIssued)
-- NET COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- NET COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end) as 'NetComm',

-----------------------------GROSS MARGIN------------------------------------------------------------------------------------------------------------------

-- NET MARGIN INITIAL
sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
         when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
         WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
		 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) 
		 when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.productgroupname = 'Mortgage') then (ag.derivedmarginamount)
		 when ((ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid')) then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)

-- NET MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 

-- NET MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'GrossMargin',

