sum(CASE WHEN b.policyref = 0 then 0 else (case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end)END) as "NBCases",
--sum(case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end) as "NBCases",

