cast((month(oa.month)) as nvarchar) + cast((year(oa.month)) as nvarchar) + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end,
cast((year(oa.month)) as nvarchar(max)) + (case when month(oa.month) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
