cast((month(ag.createdatetime)) as nvarchar) + cast((year(ag.createdatetime)) as nvarchar) + isnull(('SO' + (case when ag.standingordercodedesc like 'Ex Gratia%' then 'Ex Gratia' when ag.standingordercodedesc like 'Regulatory%' then 'Regulatory' else ag.standingordercodedesc end)),'SOWeb Mail'),
