when wr.firm = '1001374' then '2001538' when wr.firm = '1000981' then '2000425' when wr.firm = '2000522' then '2001536' when wr.firm = '1009210' then '2001543' when wr.firm = '1001167' then '2001540' when wr.firm = '1001789' then '2001395' when wr.firm = '1002076' then '2001475' when wr.firm = '1001058' then '2001549' when wr.firm = '1011487' then '2001497' when wr.firm = '1000821' then '1011541' when wr.firm = '1000692' then '2001575' when wr.firm = '1007638' then '2001578' when wr.firm = '1001804' then '2001582' when wr.firm = '1000794' then '2001580' when wr.firm = '1001492' then '2001584' when wr.firm = '1011448' then '2001585' when wr.firm = '1011540' then '1001897' when wr.firm = '1002178' then '2001613'
when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '1000995' then '2004732' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353'
