"Gross Comm" = 0, 
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0, 
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
"Net Comm" = 0, 
-----------------------------Gross Margin------------------------------------------------------------------------------------------------------------------
"Gross Margin" = 0, 
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
"Net Charges" = 0, 
