sum(wr.writtencases),
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
"Paid" = 0

--"Cases" = 0, 

--"Net DA" = 0, 

--"Gross Margin (Pre Claw)" = 0, 
--"Margin Claw" = 0, 
--"Comm Adj" = 0, 

--"Contribution" = 0
--"Elite_Points" = 0,




from

-- IN ORDER TO REMOVE DUPLICATES OF SAME ADVISERCODE/POLICY/CASEID/APE/WRITTEN DATE IN SAME WEEK

(SELECT 
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm, 
min(co.transactionid) as transactionid, 
min(pt.writtendate) as "writtendate",
datepart(week,(pt.writtendate)) as writtenweek, 
year(pt.writtendate) as writtenyear,
--Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') 
--then 0 else 

round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as WrittenAPE, -- END as WrittenAPE,

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2)End AS NBI, 

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2)End as margin, 

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max((co.agent_perc/100))End as "Old Cases", 

CASE WHEN (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End as "WrittenCases", 

min(pt.FrequencyDescription) as frequency, 
po.PolicyRef AS CaseID,
po.CONT_NUM AS Policy,
min(co.BusinessReason) as businessreason, min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
--min(CASE WHEN ph.productsubgroupname like '%Annuity' THEN 'COB Off Platform' when ph.productgroupname = 'Other' then 'Pensions' ELSE ph.ProductGroupName END) as "productgroupname",
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",

min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD
, min(ah.agentdesc) as agentdesc

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #ProfitC c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and po.COMP_CODE NOT LIKE '%Owl%'
and (rtrim(ah.ASDName) NOT In ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ph.productgroupname,ph.productgroupname,co.agent_code) wr

