wr.adviser, rtrim(wr.agentdesc), 
case when wr.firm = '1000941' then '1007791' when wr.firm = '1000976' then '2001040' when wr.firm = '1001619' then '2001460' when wr.firm = '1001747' then '1006123' when wr.firm = '1001860' then '2000914' when wr.firm = '1001931' then '2001142' when wr.firm = '1002683' then '2001252' when wr.firm = '1002866' then '2001140' when wr.firm = '1002958' then '1002961' when wr.firm = '1003038' then '2001543' when wr.firm = '1003450' then '2001454' when wr.firm = '1004284' then '1000392' when wr.firm = '1005445' then '2001002' when wr.firm = '1010723' then '1001338' when wr.firm = '1000746' then '1011544' when wr.firm = '1002578' then '2001476' when wr.firm = '1002580' then '1011548' when wr.firm = '2000508' then '1004215'
when wr.firm = '1001374' then '2001538' when wr.firm = '1000981' then '2000425' when wr.firm = '2000522' then '2001536' when wr.firm = '1009210' then '2001543' when wr.firm = '1001167' then '2001540' when wr.firm = '1001789' then '2001395' when wr.firm = '1002076' then '2001475' when wr.firm = '1001058' then '2001549' when wr.firm = '1011487' then '2001497' when wr.firm = '1000821' then '1011541' when wr.firm = '1000692' then '2001575' when wr.firm = '1007638' then '2001578' when wr.firm = '1001804' then '2001582' when wr.firm = '1000794' then '2001580' when wr.firm = '1001492' then '2001584' when wr.firm = '1011448' then '2001585' when wr.firm = '1011540' then '1001897' when wr.firm = '1002178' then '2001613'
when wr.firm = '1000967' then '2001653' when wr.firm = '2001040' then '2001655' when wr.firm = '1001891' then '2001714' when wr.firm = '1002112' then '2001807' when wr.firm = '1000867' then '1011604' when wr.firm = '1011608' then '1010815' when wr.firm = '1001049' then '2001995' when wr.firm = '1000724' then '1004141' when wr.firm = '1001346' then '1009425' when wr.firm = '1000678' then '2004388' when wr.firm = '1000704' then '1003010' when wr.firm = '1008026' then '1001546' when wr.firm = '1002702' then '2001504' when wr.firm = '2000988' then '1001249' when wr.firm = '2001397' then '2004449' when wr.firm = '1000995' then '2004732' when wr.firm = '2001518' then '2006569' when wr.firm = '2005389' then '2006353'
when wr.firm = '1002174' then '2006794' when wr.firm = '1009620' then '2010099' when wr.firm = '1007327' then '2011344'

Else wr.firm End, 
rtrim(wr.agentdesc),
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT'or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) end,
month(wr.writtendate),
year(wr.writtendate),
wr.productgroupname

UNION ALL

