case when MBF.FirmUID = '1000941' then '1007791' when MBF.FirmUID = '1000976' then '2001040' when MBF.FirmUID = '1001619' then '2001460' when MBF.FirmUID = '1001747' then '1006123' when MBF.FirmUID = '1001860' then '2000914' when MBF.FirmUID = '1001931' then '2001142' when MBF.FirmUID = '1002683' then '2001252' when MBF.FirmUID = '1002866' then '2001140' when MBF.FirmUID = '1002958' then '1002961' when MBF.FirmUID = '1003038' then '2001543' when MBF.FirmUID = '1003450' then '2001454' when MBF.FirmUID = '1004284' then '1000392' when MBF.FirmUID = '1005445' then '2001002' when MBF.FirmUID = '1010723' then '1001338' when MBF.FirmUID = '1000746' then '1011544' when MBF.FirmUID = '1002578' then '2001476' when MBF.FirmUID = '1002580' then '1011548' when MBF.FirmUID = '2000508' then '1004215'
when MBF.FirmUID = '1001374' then '2001538' when MBF.FirmUID = '1000981' then '2000425' when MBF.FirmUID = '2000522' then '2001536' when MBF.FirmUID = '1009210' then '2001543' when MBF.FirmUID = '1001167' then '2001540' when MBF.FirmUID = '1001789' then '2001395' when MBF.FirmUID = '1002076' then '2001475' when MBF.FirmUID = '1001058' then '2001549' when MBF.FirmUID = '1011487' then '2001497' when MBF.FirmUID = '1000821' then '1011541' when MBF.FirmUID = '1000692' then '2001575' when MBF.FirmUID = '1007638' then '2001578' when MBF.FirmUID = '1001804' then '2001582' when MBF.FirmUID = '1000794' then '2001580' when MBF.FirmUID = '1001492' then '2001584' when MBF.FirmUID = '1011448' then '2001585' when MBF.FirmUID = '1011540' then '1001897' when MBF.FirmUID = '1002178' then '2001613'
when MBF.FirmUID = '1000967' then '2001653' when MBF.FirmUID = '2001040' then '2001655' when MBF.FirmUID = '1001891' then '2001714' when MBF.FirmUID = '1002112' then '2001807' when MBF.FirmUID = '1000867' then '1011604' when MBF.FirmUID = '1011608' then '1010815' when MBF.FirmUID = '1001049' then '2001995' when MBF.FirmUID = '1000724' then '1004141' when MBF.FirmUID = '1001346' then '1009425' when MBF.FirmUID = '1000678' then '2004388' when MBF.FirmUID = '1000704' then '1003010' when MBF.FirmUID = '1008026' then '1001546' when MBF.FirmUID = '1002702' then '2001504' when MBF.FirmUID = '2000988' then '1001249' when MBF.FirmUID = '2001397' then '2004449' when MBF.FirmUID = '1000995' then '2004732' when MBF.FirmUID = '2001518' then '2006569' when MBF.FirmUID = '2005389' then '2006353'
when MBF.FirmUID = '1002174' then '2006794' when MBF.FirmUID = '1009620' then '2010099' when MBF.FirmUID = '1007327' then '2011344'

Else MBF.FirmUID End as 'Firm Code',
mbf.FirmName as FirmName, 
Month(MBF.PaymentMatchedDate) as "Month", 
Year(MBF.PaymentMatchedDate) as "Year",
'Mortgage Broker Fee' as productgroupname,
'Mortgage Broker Fee' as productgroupname2,



SUM(MBF.APE) as 'Issued APE', 

SUM(MBF.APE) as 'Gross DA', 

0 as 'DA Claw',

SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.DeductionAmount)  as 'Gross Comm',

0 as 'Comm Claw',

--SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.AdviceFeeAmount+MBF.DeductionAmount) as 'Net Comm',
SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.DeductionAmount) as 'Net Comm',

SUM(MBF.DeductionAmount*-1) as 'Gross Margin',

0 as 'Net Charges',

SUM(MBF.AgentSplit)/100 as 'NB Cases',

0 as 'Written NB APE',

0 as 'Written NB Cases',

case when sum(mbf.AdviceFeeAmount) is null then 0 else sum(mbf.AdviceFeeAmount) end as 'Paid'

FROM dbo.owt_MortgageBrokerFees MBF 
where
(MBF.PaymentMatchedDate) >= @ProfStartDate
and (MBF.PaymentMatchedDate) <= @ProfEndDate
and MBF.AdviceFeeCharged = 'Yes'
and transactionID = (select max(TransactionID)
								from dbo.owt_MortgageBrokerFees MBF2
								where MBF2.policyID = MBF.PolicyID)
GROUP BY MBF.AdviserUID, MBF.FirmUID, Month(MBF.PaymentMatchedDate), 
Year(MBF.PaymentMatchedDate),
cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
mbf.AdviserName,mbf.FirmName  

UNION ALL

SELECT * FROM #FinalBSCRebate

UNION ALL

--------------Written Mortgage Broker Fee ------------------------------------

select
cast((month(sale.datesubmitted)) as nvarchar(max)) + cast((year(sale.datesubmitted)) as nvarchar(max)) + 'Mortgage Broker Fee' AS Concat,
cast((year(sale.datesubmitted)) as nvarchar(max)) + (case when month(sale.datesubmitted) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
CAST(potr.AgentCode AS VARCHAR (7)) as 'AdviserUID',
ah.AgentDesc as 'AgentName',
case when ah.FirmCode = '1000941' then '1007791' when ah.FirmCode = '1000976' then '2001040' when ah.FirmCode = '1001619' then '2001460' when ah.FirmCode = '1001747' then '1006123' when ah.FirmCode = '1001860' then '2000914' when ah.FirmCode = '1001931' then '2001142' when ah.FirmCode = '1002683' then '2001252' when ah.FirmCode = '1002866' then '2001140' when ah.FirmCode = '1002958' then '1002961' when ah.FirmCode = '1003038' then '2001543' when ah.FirmCode = '1003450' then '2001454' when ah.FirmCode = '1004284' then '1000392' when ah.FirmCode = '1005445' then '2001002' when ah.FirmCode = '1010723' then '1001338' when ah.FirmCode = '1000746' then '1011544' when ah.FirmCode = '1002578' then '2001476' when ah.FirmCode = '1002580' then '1011548' when ah.FirmCode = '2000508' then '1004215'
when ah.FirmCode = '1001374' then '2001538' when ah.FirmCode = '1000981' then '2000425' when ah.FirmCode = '2000522' then '2001536' when ah.FirmCode = '1009210' then '2001543' when ah.FirmCode = '1001167' then '2001540' when ah.FirmCode = '1001789' then '2001395' when ah.FirmCode = '1002076' then '2001475' when ah.FirmCode = '1001058' then '2001549' when ah.FirmCode = '1011487' then '2001497' when ah.FirmCode = '1000821' then '1011541' when ah.FirmCode = '1000692' then '2001575' when ah.FirmCode = '1007638' then '2001578' when ah.FirmCode = '1001804' then '2001582' when ah.FirmCode = '1000794' then '2001580' when ah.FirmCode = '1001492' then '2001584' when ah.FirmCode = '1011448' then '2001585' when ah.FirmCode = '1011540' then '1001897' when ah.FirmCode = '1002178' then '2001613'
when ah.FirmCode = '1000967' then '2001653' when ah.FirmCode = '2001040' then '2001655' when ah.FirmCode = '1001891' then '2001714' when ah.FirmCode = '1002112' then '2001807' when ah.FirmCode = '1000867' then '1011604' when ah.FirmCode = '1011608' then '1010815' when ah.FirmCode = '1001049' then '2001995' when ah.FirmCode = '1000724' then '1004141' when ah.FirmCode = '1001346' then '1009425' when ah.FirmCode = '1000678' then '2004388' when ah.FirmCode = '1000704' then '1003010' when ah.FirmCode = '1008026' then '1001546' when ah.FirmCode = '1002702' then '2001504' when ah.FirmCode = '2000988' then '1001249' when ah.FirmCode = '2001397' then '2004449' when ah.FirmCode = '1000995' then '2004732' when ah.FirmCode = '2001518' then '2006569' when ah.FirmCode = '2005389' then '2006353'
when ah.FirmCode = '1002174' then '2006794' when ah.FirmCode = '1009620' then '2010099' when ah.FirmCode = '1007327' then '2011344'
Else ah.FirmCode End as 'Firm Code', 
--ah.FirmCode as 'FirmUID'
ah.Firmdescn as 'FirmName',


--CONVERT(varchar(10),sale.datesubmitted,103) as Date,
--day(sale.datesubmitted) as Day,
Month(sale.datesubmitted) as Month,
Year(sale.datesubmitted) as Year,
'Mortgage Broker Fee' as ProductGroupName,
'Mortgage Broker Fee' as ProductGroupName2,


"Issued APE" = 0, 

"Gross DA" = 0, 

"DA Claw" = 0, 

"Gross Comm" = 0, 

"Comm Claw" = 0, 

"Net Comm" = 0, 

"Gross Margin" = 0, 

"Net Charges" = 0,

"NB Cases" = 0,

sum(mdaf.brokerfeeamount*AGENT_PERC/100) as 'Written NB APE',

sum(AGENT_PERC/100) as 'Written NB Cases',

"Paid" = 0
 
--"Cases" = 0, 

--"Net DA" = 0, 

--"Gross Margin (Pre Claw)" = 0, 
--"Margin Claw" = 0, "Comm Adj" = 0, 
 
--"Contribution" = 0



from sa_swift_S_POLMAI polm
join sa_swift_PolicyTransactions potr on potr.PolicyID = polm.POL_NUM
join sa_swift_S_AGTCOM agtc on agtc.TransactionID = potr.ID
join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf on mdaf.PolicyId = polm.PolicyRef 
join sa_ows_Sale sale on sale.SaleID = mdaf.saleid
join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId
join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
join  cscv_AgentsHierarchy ah ON potr.AgentCode = ah.agentcode
where 1=1 --polm.PolicyRef = 550477913
and potr.ID = (select min(potr1.ID)
                        from sa_swift_S_POLMAI polm1
                       join sa_swift_PolicyTransactions potr1 on potr1.PolicyID = polm1.POL_NUM
                       where polm.PolicyRef = polm1.PolicyRef)
and AGENT_CODE != '10002' and agtc.CommissionType = 1
and mdaf.HasBrokerFeeCharged = 19
and (sale.datesubmitted) >= @ProfStartDate--DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
and (sale.datesubmitted) <= @ProfEndDate--(dateadd(day,datediff(day,0,GETDATE()),0))
Group by month(datesubmitted), year(datesubmitted), 
case when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
potr.AgentCode, ah.AgentDesc, ah.FirmCode, ah.Firmdescn


order by [year], [month]

drop table #ProfitB
drop table #ProfitC
drop table #ProfitD

------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------

--------------------------------------------------------
-- Calculation Report JB 22/05/17
--------------------------------------------------------

--declare @ProfStartDate VARCHAR(30),@ProfEndDate varchar(30); --<------- Testing
--set @ProfStartDate = CONVERT(varchar(30), '2015-01-01 00:00:00', 102)  --<------- Testing
--set @ProfEndDate = CONVERT(varchar(30), '2017-04-30 23:59:59', 102) --<------- Testing

DECLARE @CMD AS VARCHAR(MAX)
DECLARE @COL AS VARCHAR(MAX)

--declare @ProfEndDate varchar(30)  --<----- Testing
--set @ProfEndDate =  DATEADD(yy, DATEDIFF(yy, 0, GETDATE()), 0) --<------- Testing
--select top 1000 * from #Prof1 --<------- Testing
--SELECT * FROM tempdb.INFORMATION_SCHEMA.[COLUMNS]  --<------- Testing
BEGIN
SET @CMD = 'SELECT '
DECLARE COLUMN_CURSOR CURSOR FOR
SELECT COLUMN_NAME FROM tempdb.INFORMATION_SCHEMA.[COLUMNS] 
WHERE TABLE_NAME like '%#Prof1%'
	   --and column_name NOT like 'agent%' 
	   and column_name not like '%Desc%' and column_name not like '%Month%'
	   and column_name not like'%year%' and column_name not like'%rolling%' and column_name not like '%concat%'
	   and column_name not like'YTD' 
OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0
BEGIN 

	 IF @COL like '%Cases%' or @COL like '%DA%' or @COL like '%Comm%' or @COL like '%APE%'
	 or @COL like '%Margin%' or @COL like '%Con%' or @COL like '%paid%' or @COL like '%Charges%'		
	 BEGIN
	 -- Current Year YTD

			BEGIN
				SET @CMD = @CMD + 'sum(case when #Prof1.year = year(''' + @ProfEndDate +''') and #Prof1.month <= month(''' + @ProfEndDate +''') then #Prof1.' + @COL + ' else 0 end)  CurrYTD_' + @COL + ',' --YTD
			END	

	 --Previous 2 Years YTD

			BEGIN
				SET @CMD = @CMD + 'sum(case when #Prof1.year = year(''' + @ProfEndDate +''')-1 and #Prof1.month <= month(''' + @ProfEndDate +''') then #Prof1.' + @COL + ' else 0 end) PrevYTD_' + @COL + ',' --Previous YTD
				SET @CMD = @CMD + 'sum(case when #Prof1.year = year(''' + @ProfEndDate +''')-2 and #Prof1.month <= month(''' + @ProfEndDate +''') then #Prof1.' + @COL + ' else 0 end) Prev2YTD_' + @COL + ',' --Previous 2YTD
			END	

	 --Rolling 12
			
			Begin
				SET @CMD = @CMD + 'sum(case when #Prof1.rolling = ''CurrR'' then #Prof1.' + @COL + ' else 0 end) CurrR12_' + @COL + ',' --Current Rolling 12
				SET @CMD = @CMD + 'sum(case when #Prof1.rolling = ''PrevR'' then #Prof1.' + @COL + ' else 0 end) PrevR12_' + @COL + ',' --Previous Rolling 12
			End
	 --Previous 2 Years Full

			BEGIN
				SET @CMD = @CMD + 'sum(case when #Prof1.year = year(''' + @ProfEndDate +''')-1 then #Prof1.' + @COL + ' else 0 end) PrevFull_' + @COL + ',' --Previous Full
				SET @CMD = @CMD + 'sum(case when #Prof1.year = year(''' + @ProfEndDate +''')-2 then #Prof1.' + @COL + ' else 0 end) Prev2Full_' + @COL + ',' --Previous 2Full
			END

	 

		END
	 --ELSE IF @COL IN ('%Date%')
		--BEGIN
		--SET @CMD = @CMD + 'CONVERT(varchar(10),' + @COL + ',103) Date,'
		--END
	 ELSE
		BEGIN
		SET @CMD = @CMD + @COL + ','
		END
	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL	 
	 END

------------------------------------------------------
BEGIN
	 SET	@CMD = left(@CMD,len(@CMD)-1)
	 SET	@CMD = @CMD + ' FROM #Prof1 GROUP BY '
END

print @cmd
CLOSE COLUMN_CURSOR

OPEN COLUMN_CURSOR
FETCH NEXT FROM COLUMN_CURSOR INTO @COL
WHILE @@FETCH_STATUS = 0
BEGIN
	 IF @COL IN ('%Date%')
		SET @CMD = @CMD + 'CONVERT(varchar(10),' + @COL + ',103),' 
	 ELSE IF @COL not like '%Cases%' and @COL not like '%DA%' and @COL not like '%Comm%' and @COL not like '%APE%'
	 and @COL not like '%Margin%' and @COL not like '%Con%' and @COL not like '%paid%' and @COL not like '%Charges%'

		SET @CMD = @CMD + @COL + ','

	 FETCH NEXT FROM COLUMN_CURSOR INTO @COL
END

SET	@CMD = left(@CMD,len(@cmd)-1)
CLOSE COLUMN_CURSOR
DEALLOCATE COLUMN_CURSOR
---- run final table
print @cmd
EXEC (@CMD)
END




	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	exec BI.pr_ProcessLog @PhaseError, @Process, @Module, @Client, null, @ErrMsg

	RAISERROR(@ErrMsg, @ErrSev, 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[pr_ProfitabilityHistoric]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  Openwork Profitability Report.
  	 					
	  Author:	Akin Yavuz

Date created:	28/10/2021
													
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			

************************************************************************************************/
CREATE PROCEDURE [BI].[pr_ProfitabilityHistoric]

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.
SET DATEFIRST 1 
SET DATEFORMAT DMY

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@Client						varchar(50),
		@Module						varchar(50),
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'MI Team Profitability Report Historic'
set @DateLastUpdated	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION
SET NOCOUNT ON

IF OBJECT_ID('tempdb..#b') IS NOT NULL
DROP TABLE #b
IF OBJECT_ID('tempdb..#c') IS NOT NULL
DROP TABLE #c
IF OBJECT_ID('tempdb..#d') IS NOT NULL
DROP TABLE #d
IF OBJECT_ID('tempdb..#e') IS NOT NULL
DROP TABLE #e
IF OBJECT_ID('tempdb..#bb') IS NOT NULL
DROP TABLE #bb
IF OBJECT_ID('tempdb..#FinalBSCRebate') IS NOT NULL
DROP TABLE #FinalBSCRebate


SET DATEFIRST 1

--CALENDER DATES
declare
@ProfStartDate varchar(30),
@ProfEndDate varchar(30)
DECLARE @ProfPaymentMonth date;
--SET @ProfPaymentMonth = '01-Mar-2020'
--set @ProfStartDate = CONVERT(DATETIME, '2018-01-01 00:00:00', 102) 
--set @ProfEndDate = CONVERT(DATETIME, '2021-09-30 23:59:59', 102); ---ENSURE END DATE IS LAST DAY OF REPORTING MONTH

-------------------------------------------------------BSC REBATE QUERY ---------------------------------------------------------------------
--Create Agent Uplift Rate table with start and end date

WITH AgentUpliftTable AS(
Select 
ROW_NUMBER() over(partition by au.agentcode, au.productcode order by au.dateinforce) as RowNum,
au.AgentCode,
au.DateInForce,
au.ProductCode,
au.UpliftRate,
au.Status,
au.PolicyType
from sa_swift_AgentUplifts au
join mstt_ProductHierarchy ph on ph.ProductCode = au.ProductCode and ph.ProductCategoryCode = 1
where status = 0),

FranchiseUpliftRate AS(
Select
aut.RowNum,
aut.AgentCode,
aut.DateInForce,
aut.UpliftRate,
aut.ProductCode,
isnull(dateadd(day,-1,aut2.dateinforce),'31-Dec-3099')  as EndDate,
aut2.RowNum as NewRow
from AgentUpliftTable aut
left join AgentUpliftTable aut2 on aut2.AgentCode = aut.AgentCode 
								and aut2.ProductCode = aut.ProductCode
								and aut2.RowNum = aut.RowNum +1),

pacc AS (
Select
pacc_id
from mstt_PaymentsPending
where AGENT_CODE = '1011587'
and CommissionMonth >= @ProfPaymentMonth),

DAAmount AS (
Select
pp.PACC_ID,
sum(amount) as DA
from mstt_PaymentsPending pp
join pacc pc on pc.PACC_ID = pp.PACC_ID
where CommissionMonth >= @ProfPaymentMonth
Group by pp.PACC_ID),


-- Create Table of all payments in month
FirmPayments AS (
Select pp.ID, pacc_id, AGENT_CODE, AGENT_PERC, isnull(franchiseagentcode,AccessAgentCode) as franchiseagentcode, TransactionID, CaseID, ProviderRef
from mstt_paymentspending pp
join mstt_clients clt on clt.client_num = firstclientid 
where 
manager2code != '1011671' and
CommissionMonth >= @ProfPaymentMonth),


--Create split of payments across BSC/Margin/Other Splits
Payment AS (
Select
ROW_Number() over (Partition By fp.pacc_ID order by fp.Agent_Code) as Row_Num,
fp.ID,
fp.Pacc_id, 
fp.AGENT_CODE,
fp.Agent_Perc,
fp.franchiseagentcode,
fp.TransactionID,
fp.CaseID,
fp.ProviderRef,
convert(date,pp.createdatetime) as CreateDate,
case when ph.rdrtype is not null then 'Wealth' else ProductCategoryName end as Product,
sum(case when pp.franchiseagentcode = fp.FranchiseAgentcode then pp.Amount end) as FirmPayment,
sum(case when pp.franchiseagentcode != fp.franchiseAgentcode and pp.franchiseAgentCode is not null then pp.Amount end) as OtherFirmPayment,
sum(case when pp.franchiseagentcode != fp.franchiseAgentcode and pp.franchiseAgentCode is not null then pp.Agent_perc end) as OtherFirmPct,
sum(case when pp.agent_code = '10002' then pp.Amount end) as OWMargin,
sum(case when pp.agent_code = '1011543' then pp.Amount end) as OWFeeMargin,
sum(case when pp.agent_code = '1011543' then pp.AGent_perc end) as OWFeePct,
sum(case when pp.agent_code = '1011587' then pp.Amount end) as BSC,
sum(case when pp.agent_code = '1011587' then pp.agent_perc end) as BSCPct,
pp.FirstClientID
from FirmPayments fp
Join mstt_paymentspending pp on pp.pacc_id = fp.pacc_id
join mstt_producthierarchy ph on ph.productcode = pp.tranproduct
group by fp.id, fp.Pacc_id, 
fp.AGENT_CODE,
convert(date,pp.createdatetime),
fp.franchiseagentcode, 
pp.FirstClientID,
case when ph.rdrtype is not null then 'Wealth' else ProductCategoryName end,
fp.TransactionID, fp.CaseID, fp.ProviderRef, fp.agent_perc),

--Limit to only where there is BSC present and calculate splits
FinalRebateTable AS (
Select
p.id,
p.AGENT_CODE,
p.agent_perc,
p.FranchiseAgentCode,
agt.Descn,
agt.CompetentStatusDescription,
p.TransactionID,
p.CaseID,
p.ProviderRef,
p.PACC_ID,
p.firmpayment,
p.OtherFirmPayment,
p.OWFeeMargin,
p.BSC,
p.BSCPct,
p.OWFeePct,
com.FranchiseUpliftPercent,
pt.ProposalDate,
p3.Agent_code as agent3Code,
p3.Agent_perc as agent3pct,
com3.franchiseupliftpercent as agent3uplift,
p3.Agent_Perc/(com3.franchiseupliftpercent-20)*100 as Agent3Gross,
p2.Agent_code as Agent2Code,
p2.Agent_perc as Agent2Pct,
com2.franchiseupliftpercent as agent2uplift,
p2.Agent_Perc/(com2.franchiseupliftpercent-20)*100 as Agent2Gross,
p.Agent_Perc/(com.franchiseupliftpercent-20)*100 as Agent1Gross,
100 - p.BSCPct as RemainingSplit,
p.AGENT_PERC/(isnull(com.franchiseupliftpercent,fur.upliftrate)-20)*100 as TruePCt,
round(((p.AGENT_PERC/(isnull(com.franchiseupliftpercent,fur.upliftrate)-20))*100)/(100 - p.BSCPct)*100,0)
 as AgentTruePct,
isnull(com.franchiseupliftpercent,fur.upliftrate)-20 as PaymentUpliftRate,
da.DA,
p.FirstClientID,
p.CreateDate
from Payment p
join mstt_agents agt on agt.code = franchiseagentcode
join mstt_PolicyTransactions pt on pt.id = p.TransactionID
left join DAAmount da on da.PACC_ID = p.PACC_ID
left join mstt_Commissions com on com.TransactionID = p.transactionid and com.CommissionType = 1 and p.AGENT_CODE = com.AGENT_CODE
left join payment p2 on p2.pacc_id = p.pacc_id and p2.Row_num =  case when p.Row_Num = 1 then 2
																	   when p.Row_Num = 2 then 1
																	   when p.Row_num = 3 then 1 end
left join payment p3 on p3.pacc_id = p.pacc_id and p3.Row_num =  case when p.Row_Num = 1 then 3
																	   when p.Row_Num = 2 then 3
																	   when p.Row_num = 3 then 2 end
left join mstt_Commissions com2 on com2.TransactionID = p2.transactionid and com2.CommissionType = 1 and p2.AGENT_CODE = com2.AGENT_CODE
left join mstt_Commissions com3 on com3.TransactionID = p3.transactionid and com3.CommissionType = 1 and p3.AGENT_CODE = com3.AGENT_CODE
left join FranchiseUpliftRate fur on fur.AgentCode = p.franchiseagentcode and pt.ProposalDate between fur.DateInForce and fur.EndDate and pt.CommProductCode = fur.ProductCode
left join FranchiseUpliftRate fur2 on fur2.AgentCode = p2.franchiseagentcode and pt.ProposalDate between fur2.DateInForce and fur2.EndDate and pt.CommProductCode = fur2.ProductCode
left join FranchiseUpliftRate fur3 on fur3.AgentCode = p3.franchiseagentcode and pt.ProposalDate between fur3.DateInForce and fur3.EndDate and pt.CommProductCode = fur3.ProductCode
where p.BSC is not null),


--Calculate Rebate Amount
QuickCheck AS (
Select 
ID,
Agent_code,
Agent_perc,
FranchiseAgentCode,
Descn,
CompetentStatusDescription,
CaseID,
ProviderRef,
Pacc_ID,
FirmPayment,
BSC,
BSCPct,
ProposalDate,
RemainingSplit,
AgentTruePct,
PaymentUpliftRate,
case when FranchiseUpliftPercent is null then 'Derived' else 'Actual' end as CalcType,
BSC*(AgentTruePct/100)*(PaymentUpliftRate/100)*0.5 as AmountDue,
BSC*(AgentTruePct/100) as BSCSplitAmount,
frt.DA as OngoingDA,
frt.TransactionID,
FirstClientID,
frt.CreateDate
from FinalRebateTable frt

UNION
Select pp.id, com.agent_code, com.agent_perc,com.franchiseagentcode,agt.descn,agt.competentstatusdescription, pp.caseid, pp.providerref,pp.pacc_id,0, pp.Amount, pp.Agent_perc, com.proposaldate,0,com.agent_perc,com.franchiseupliftpercent-20,'Derived - All BSC',pp.Amount*(com.franchiseupliftpercent-20)/100*0.5,
pp.Amount*(com.agent_perc/100) as BSCSplitAmount,pp.AMOUNT,pp.TransactionID, pp.FirstClientID, convert(date,pp.CreateDateTime)
from mstt_paymentspending pp
join mstt_commissions com on com.transactionid = pp.transactionid and com.commissiontype = 1 and com.agent_code != '10002'
join mstt_agents agt on agt.code = com.franchiseagentcode
where pp.commissionmonth >= @ProfPaymentMonth and pp.agent_code = '1011587' and pp.Agent_perc = 100 and pp.agent_code != '1006886'),


FinalBSCRebate as (
Select
cast((Month(qc.createdate)) as nvarchar(max)) + cast((Year(qc.Createdate)) as nvarchar(max)) + 'Recurring Income' AS 'Concat',
cast((year(qc.createdate)) as nvarchar(max)) + (case when month(qc.createdate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,qc.createdate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,qc.createdate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
Month(qc.createdate) as Month,
Year(qc.Createdate) as Year,
'Recurring Income' AS ProductGroupName,
'BSC Rebate' AS ProductSubGroup,
0 as APE,
sum(AmountDue)*-1 as DA, --BSCRebate,
0 as DA_Claw,
0 as Commission,
0 as Commission_Claw,
0 as Net_Commission,
sum(AmountDue)*-1 as Margin, --BSCRebate,
0 as Net_Charges,
0 as NewPolicies,
0 as WrittenNBAPE,
0 as WrittenNBCases,
0 as Paid,
0 as commadj

from QuickCheck qc
join mstt_Clients clt on CLIENT_NUM = FirstClientID
join mstt_PolicyTransactions pt on pt.ID = TransactionID
join mstt_agents agt on agt.CODE = qc.AGENT_CODE
join cscv_AgentsHierarchy ah ON ah.AgentCode = qc.AGENT_CODE
WHERE (agt.Manager2Code <> '4010386' or Firm <> '2016789')
AND Firm NOT IN ('1002524', '2004449', '1001031', '2005309')
Group by
Month(qc.createdate),
Year(qc.Createdate),
qc.CreateDate)

----Add in BSC Rebate Value
SELECT * into #FinalBSCRebate FROM FinalBSCRebate
---------------------------------------------------------------------------END OF BSC REBATE -------------------------------------------------------------------------

--DEDUCE ISSUED NEW POLICIES (I.E IF TRANSACTIONID IS 1ST ACTIVE POLICY THEN IT IS A NEW POLICY)
select
min(transactionid) as transactionid, po.policyref, po.cont_num, co.productcode
into #bb

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode

where co.poltrantranstype <> 39
and co.agent_code not in ('10002','1011542','10004')	
and co.commissiontype = 1
and((left(ltrim(po.policyref),4) <> '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by po.policyref, po.cont_num, co.productcode

union all

select
min(transactionid) as transactionid, '', '','L&G' provider

FROM				  dbo.mstt_Commissions co INNER JOIN
                      dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
                      dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
                      dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
                      dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
                      dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
                      cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
where
co.agent_code not in ('10002','1011542','10004')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and((left(ltrim(po.policyref),4) = '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
group by co.CLIENT_NUM,po.comp_code,case po.plan_code when 'IPP' then 'IPP' else 'OTHER' end

select transactionid,policyref,cont_num into #b from #bb where left(cont_num,2) <> 'ZR' or cont_num is null
union all
select case when left(cont_num,2) = 'ZR' then min(transactionid) end transactionid, policyref, cont_num
from #bb where left(cont_num,2) = 'ZR'group by  policyref, cont_num

drop table #bb

