sum(Case when (d.PolicyNumber = ag.providerRef AND ag.createdatetime < '10-Jul-2017') then d.CorrectAPE else
((case when (ag.commissiontype in ('1','17') and left(ccs.description,3) = 'IMP') then ((cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount))) / 0.025 / 10) else
	
-- ENSURE MORTGAGES APE IS THE SAME AS DA
(case when 
ph.productgroupname = 'mortgage'
then (case when (
ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end)
else (case when ag.commissiontypedesc like '%claw%' then 0 else coalesce(cs.ape,co2.turnover,0) end) end) END))End) as "IssuedAPE",
-----------------------------GROSS DA------------------------------------------------------------------------------------------------------------------

sum(
case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount+ag.derivedmarginamount) ElSE

(Case when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- GROSS DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- GROSS DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then (ag.amount / (8.0/10))
-- GROSS DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','2','3','7','8','14','15','16','20','21')) then 
    (ag.amount + isnull(derivedmarginamount,0)) else 0 END)END) as 'GrossDA',
-----------------------------DA CLAW------------------------------------------------------------------------------------------------------------------

sum(case when ph.productgroupname = 'Mortgage' then 0 
when (ag.commissiontype in ('2') and cs.oastatus = 'valid') then (cs.inissued + ((round((cs.inissued/ag.amount),0) *ag.derivedmarginamount)))
-- DA CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then (ag.amount + isnull(derivedmarginamount,0))
-- DA CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then (ag.amount / (8.0/10))
-- DA CLAW POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontypedesc like '%claw%') then (ag.amount + isnull(derivedmarginamount,0)) 
else 0 end) as 'DAClaw',
-----------------------------GROSS COMMISSION------------------------------------------------------------------------------------------------------------------

-- GROSS COMM INITIAL
sum (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then 
		(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
		 WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
		 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
		 WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
		 ELSE ag.Amount END) ElSE

(CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
     WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
     WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
	 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
	 when (ag.commissiontype in ('1','17') and cs.oastatus = 'valid') then (cs.INIssued)
-- GROSS COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','18','19')) then ag.amount
-- GROSS COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','19')) then ag.amount
else 0 end)END) as 'GrossComm',

-----------------------------COMMISSION CLAW------------------------------------------------------------------------------------------------------------------

-- COMM CLAW INITIAL
sum(CASE  WHEN ph.productgroupname = 'Mortgage' then 0 

when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('2') and cs.oastatus = 'valid')) and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN (cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN ((cs.INIssued) * 10.0)/ 9 
when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('2') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
when ((ag.commissiontype in ('2') and cs.oastatus = 'valid')) then (cs.INIssued)

-- COMM CLAW SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('15','16')) then ag.amount
-- COMM CLAW TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('16')) then ag.amount
else 0 end) as 'CommClaw',

-----------------------------NET COMMISSION------------------------------------------------------------------------------------------------------------------

-- NET COMM INITIAL
sum (CASE WHEN (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN cs.INIssued + (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7 
    WHEN ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005' THEN cs.INIssued + ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6)
    WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN ((cs.INIssued) * 10.0)/ 9 
	when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((cs.INIssued) + (cs.inissued * 0.1655)) 
	when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName = 'Mortgage') then (ag.Amount)
	when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.ProductGroupName <> 'Mortgage') then (cs.INIssued)
-- NET COMM SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then ag.amount
-- NET COMM TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ag.amount
else 0 end) as 'NetComm',

-----------------------------GROSS MARGIN------------------------------------------------------------------------------------------------------------------

 -- NET MARGIN INITIAL
sum(CASE when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.7) 
         when (ag.firm <> 1010904 AND RTRIM(ah.ASDName) = 'GHL' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount) - ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) * 0.6) 
         WHEN (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and left((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),3) <> '005' ) THEN (round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - ((((cs.INIssued)*10.0)/9) - (cs.INIssued)) 
		 when (RTRIM(ah.ASDName) = 'First Affinity' and (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') and ph.productgroupname = 'Protection' and left((replace((replace((replace(ccs.description,'do not use - ','')),'do not use - ','')),'do not use - ','')),3) = '005') THEN ((round((cs.INIssued / ag.AMOUNT),0) * ag.DerivedMarginAmount) - (cs.INIssued * 0.1655)) 
		 when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid' AND ph.productgroupname = 'Mortgage') then (ag.derivedmarginamount)
		 when ((ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid')) then (round(cs.INIssued / ag.AMOUNT,0) * ag.DerivedMarginAmount)

-- NET MARGIN TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then ((ag.amount / (8.0/10)) - ag.amount) 

-- NET MARGIN POT ACCOUNT/SERVICING
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) as 'GrossMargin',

-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------

"NetCharges" = 0,

-----------------------------New Policies------------------------------------------------------------------------------------------------------------------

sum(CASE WHEN b.policyref = 0 then 0 else (case when ag.commissiontypedesc like '%claw%' then 0 when b.transactionid is null then 0 when (ag.caseid is NULL AND ph.productgroupname = 'Protection' AND ag.agent_code <> '1000312') then 0 when ((coalesce(co.businessreason,co2.businessreason) = ('I')) and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Not Sold By This Office' and coalesce(co.adminmethoddescription,co2.adminmethoddescription,'Advisory Tracked') <> 'Execution Only Increase') then 0 when cs.ape < 0 and ag.transactionid = b.transactionid then -ag.derivedagentsplit/100 when cs.ape = 0 then 0 when cs.ape > 0 and ag.transactionid = b.transactionid then ag.derivedagentsplit/100 else 0 end)END) as "NBCases",

-----------------------------Written APE------------------------------------------------------------------------------------------------------------------

"WrittenNBAPE" = 0, 

-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------

"WrittenNBCases" = 0,

-----------------------------Paid------------------------------------------------------------------------------------------------------------------

sum(oa.totalpayment) as 'Paid',


"CommAdj" = 0

into #e


from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
msit_openworkadviserlisting oa ON oa.sourceid = cs.id AND oa.Source = 'Openwork 2006' LEFT OUTER JOIN
mstt_commissions co ON cs.commissionsid = co.id LEFT OUTER JOIN
mstt_Commissions co2 on co2.transactionid = ag.transactionid 
and co2.agent_code = ag.agent_code 
and co2.commissiontype = case when ag.commissiontype in (1,2,17) then 1 
when ag.commissiontype in (4,15,18) then 4 
when ag.commissiontype in (10,16,19) then 10 end LEFT OUTER JOIN
mstt_PolicyTransactions pt ON pt.ID = ag.TransactionID LEFT OUTER JOIN
mstt_Commissions co3 on co3.transactionid = ag.transactionid 
and co3.agent_code = pt.agentcode
and co3.commissiontype = ag.commissiontype 
and co3.firm <> '1011543' LEFT OUTER JOIN
mstt_ProductHierarchy ph ON ag.tranproduct = ph.ProductCode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = ag.transactionid
LEFT OUTER JOIN #d d on (d.PolicyNumber = ag.providerref) AND (d.TransID = ag.TransactionID)
left join PolicyOneLink.sa_ows_MortgageProductSummary mps on mps.PolicyId = ag.CaseID
left join StaticData.sa_ows_InputValues inp on inp.InputID = mps.TransactionTypeId
where 
ag.createdatetime >= @ProfStartDate
and ag.createdatetime <= @ProfEndDate		
and (ag.agent_code <> '10002' or ag.agent_code <> '1011623')
and ag.amount <> 0
and (co2.id not in ('17797514','17797515') or co2.id is NULL)
and (co3.id not in ('17797514','17797515') or co3.id is NULL)
and (cs.oastatus = 'valid' or cs.oastatus is NULL)
and isnull(ag.Manager2Code,'1111') <> '1011671' -- EXCLUDES OWL ADVISERS
--ENSURE NO TRAIL WHERE OPENWORK DO NOT TAKE A MARGIN IS INCLUDED
and (case when (cs.oastatus = 'valid' and ag.commissiontype in ('4','10','15','16','18','19') and ag.tranproduct not like '%INCOME%' and ag.tranproduct not like '%PRUFUND%' and ag.tranproduct not like '%FIA%' and ag.tranproduct not like 'OW%' and ag.tranproduct not like 'OF%' and ag.tranproduct not like 'OZ%') then 'NonTrail' else 'Other' end) <> 'NonTrail' 

--ENSURE NO ZERO DA TRANSACTIONS ARE INCLUDED AS UNNEEDED
and (case when (ag.commissiontype in ('1','2','17') and cs.oastatus = 'valid') then (ag.Amount+ag.derivedmarginamount)
-- NET DA SERVICING
when (cs.oastatus = 'valid' and left(tranproduct,2) in ('OW','OF','OZ') and ag.commissiontype in ('4','10','15','16','18','19')) then (ag.amount + isnull(derivedmarginamount,0))
-- NET DA TRAIL
when (cs.oastatus = 'valid' and tranproduct in ('PRUFUND','INCOME','FIA') and ag.commissiontype in ('10','16','19')) then (ag.amount / (8.0/10))
-- NET DA POT ACCOUNT
when ((cs.oastatus <> 'valid' or cs.oastatus is NULL) and ag.agent_code in ('1011543','1006886','1011587') and ag.commissiontype not in ('0','3','7','8','14','20','21')) then (ag.amount + isnull(derivedmarginamount,0)) else 0 end) <> 0
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(ag.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by
cast((month(ag.createdatetime)) as nvarchar(max)) + cast((year(ag.createdatetime)) as nvarchar(max)) + case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(ag.tranproduct,2) in ('OW','OZ')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' when ph.productgroupname = 'Other' then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end,
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
month(ag.createdatetime), year(ag.createdatetime),
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT'  or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' when ph.productgroupname = 'Other' then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Recurring Income' when ag.agent_code = '1011587' then 'Recurring Income' when ag.commissiontype in ('10','16','19') then 'Recurring Income' else 'Recurring Income' end,
case when ag.commissiontype in ('1','2','17') then (case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(ag.tranproduct,2) in ('OW','OZ') AND ag.tranproduct NOT IN ('OWADHOC','OWADVICE')) or ag.tranproduct = 'OFHBSIPP' or isnull(co.productprovidercode,ag.comp_code) = 'Zurich PLT' or isnull(co.productprovidercode,ag.comp_code) = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' when ph.productgroupname = 'Other' then 'COB Off Platform' else ph.productgroupname end) when (ag.commissiontype in ('4','10','15','16','18','19') and ag.agent_code <> '1011587' and ((left(ag.tranproduct,2) in ('OW','OF','OZ')) or ag.agent_code = '1011543')) then 'Servicing Fee' when ag.agent_code = '1011587' then 'BSC' when ag.commissiontype in ('10','16','19') then 'Legacy Recurring' else 'Legacy Recurring' end

UNION ALL

---INSERT ZERO UPFRONT APE AS DOES NOT EXIST IN MSTT_PAYMENTSPENDING/OPEN ACCESS

select 
cast((month(pt.createdatetime)) as nvarchar(max)) + cast((year(pt.createdatetime)) as nvarchar(max)) + (case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end) as "Concat",
cast((year(pt.createdatetime)) as nvarchar(max)) + (case when month(pt.createdatetime) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
month(pt.createdatetime)as month, year(pt.createdatetime) as year,
case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end as "Productgroupname",
case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end as "Productgroupname2",


-----------------------------ISSUED APE------------------------------------------------------------------------------------------------------------------
sum(co.ape),
-----------------------------GROSS DA------------------------------------------------------------------------------------------------------------------
"Gross DA" = 0, 
-----------------------------DA Claw------------------------------------------------------------------------------------------------------------------
"DA Claw" = 0,
-----------------------------GROSS Commission------------------------------------------------------------------------------------------------------------------
"Gross Comm" = 0, 
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0,
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
"Net Comm" = 0,
-----------------------------GROSS Margin------------------------------------------------------------------------------------------------------------------
"Gross Margin" = 0,
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
"Net Charges" = 0,
-----------------------------NB Cases------------------------------------------------------------------------------------------------------------------
sum(case when b.transactionid is null then 0 when (co.businessreason = 'I' and co.adminmethoddescription <> 'Not Sold By This Office' and co.adminmethoddescription <> 'Execution Only Increase') then 0 when co.ape = 0 then 0 when co.ape > 0 and co.transactionid = b.transactionid then co.agent_perc/100 else 0 end) as "NB Cases",
-----------------------------Written APE------------------------------------------------------------------------------------------------------------------
"Written NB APE" = 0, 
-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------
"Written NB Cases" = 0,
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
"Paid" = 0,
"CommAdj" = 0


from 
mstt_Commissions co LEFT OUTER JOIN
mstt_Policytransactions pt on co.transactionid = pt.id LEFT OUTER JOIN
mstt_Policies po on pt.policyid = po.pol_num LEFT OUTER JOIN
mstt_ProductHierarchy ph ON co.ProductCode = ph.productcode LEFT OUTER JOIN
msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
msit_CodeCommissionShape ccs ON ccs.id = pt.codecommissionshapeid LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT OUTER JOIN
#b b on b.transactionid = co.transactionid


where
co.agent_code <> '10002'
and pt.createdatetime >= @ProfStartDate
and pt.createdatetime <= @ProfEndDate
and co.commissiontype = 1
and ph.rdrtype is not null
and pt.comminitialamount <= 0 and pt.amount > 0
and co.poltrantranstype = 17
--and (rtrim(ah.ASDName) <> 'Pat Mckenna' or co.agent_code <> '1011623' or ah.ASDName is Null )
and (rtrim(ah.ASDName) NOT IN ('Pat Mckenna','Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.createdatetime) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by 
cast((month(pt.createdatetime)) as nvarchar(max)) + cast((year(pt.createdatetime)) as nvarchar(max)) + (case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end),
cast((year(pt.createdatetime)) as nvarchar(max)) + (case when month(pt.createdatetime) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,pt.createdatetime),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
month(pt.createdatetime), year(pt.createdatetime),
case when ph.productsubgroupname like '%Annuity%' then 'COB Off Platform' when ((left(co.productcode,2) in ('OW','OZ')) or co.productcode = 'OFHBSIPP' or co.productprovidercode = 'Zurich PLT' or co.productprovidercode = 'Pru PLT') then 'COB Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else ph.productgroupname end

UNION ALL

---LEGACY (OPENWORK 2005) COMMISSIONS, THESE DO NOT EXIST IN MSTT_PAYMENTSPENDING

select 
cast((month(oa.month)) as nvarchar) + cast((year(oa.month)) as nvarchar) + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end as concat,
cast((year(oa.month)) as nvarchar(max)) + (case when month(oa.month) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
month(oa.month) as "month", year(oa.month) as "year", 
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end as productgroupname,
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end as productgroupname2,



-----------------------------Issued APE------------------------------------------------------------------------------------------------------------------
sum(oa.ape) as "Issued APE",
-----------------------------Gross DA------------------------------------------------------------------------------------------------------------------
sum(case when ph.productgroupname = 'Mortgage' then oa.ape else oa.totdue_enhd/0.8163 end) as "Gross DA",
-----------------------------DA Claw------------------------------------------------------------------------------------------------------------------
"DA Claw" = 0,
-----------------------------Gross Commission------------------------------------------------------------------------------------------------------------------
sum(oa.totdue_enhd) as "Gross Comm",
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0,
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
sum(oa.totdue_enhd) as "Net Comm",
-----------------------------Gross Margin------------------------------------------------------------------------------------------------------------------
sum(case when ph.productgroupname = 'Mortgage' then oa.ape - oa.totdue_enhd else ((oa.totdue_enhd/0.8163) - oa.totdue_enhd) end) as "Gross Margin",
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
"Net Charges" = 0,
-----------------------------New Business Cases------------------------------------------------------------------------------------------------------------------
"NB Cases" = 0,
-----------------------------Written APE------------------------------------------------------------------------------------------------------------------
"Written NB APE" = 0, 
-----------------------------Awritten Cases------------------------------------------------------------------------------------------------------------------
"Written NB Cases" = 0,
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
sum(oa.totalpayment) as 'Paid',
"CommAdj" = 0

from msit_openworkadviserlisting oa left outer join 
msit_feesNonSwiftFeeListing fnsfl on fnsfl.ID = oa.sourceID left outer join
mstt_producthierarchy ph on 'NBI_'+ fnsfl.productCode = ph.productCode left outer join
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode left outer join
cscv_AgentsHierarchy ah1 ON oa.sellercode = ah1.agentcode

where
(oa.month
BETWEEN @ProfStartDate
AND @ProfEndDate)
and oa.feetype <> 'RC'
and oa.feetype <> 'Trail'
and oa.feetype <> 'TF'
and oa.source = 'openwork 2005'
and oa.providercode <> 'GI'
and ((ape + totdue_enhd) <> 0)
and (fnsfl.id <> '27617494' or fnsfl.id is NULL)
--and (rtrim(ah.ASDName) <> 'Pat Mckenna' or oa.sellercode <> '1011623' or ah.ASDName is Null)
and (rtrim(ah.ASDName) NOT IN ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(oa.month) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------
--and oa.sellercode in ('1001291','1001293','1006912','1001292')
group by
cast((month(oa.month)) as nvarchar) + cast((year(oa.month)) as nvarchar) + case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end,
cast((year(oa.month)) as nvarchar(max)) + (case when month(oa.month) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
oa.month, month(oa.month), year(oa.month),
case when oa.provider='General Insurance' then 'GI' when oa.provider='SIML' then 'COB Off Platform' when oa.provider='Sterling' then 'COB Off Platform' when oa.provider='Scottish Equitable' then 'COB Off Platform' when oa.prodtype = 'PE' then 'COB Off Platform' when ph.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else isNull(ph.productgroupname,'Protection') end 


UNION ALL

--GI COMMISSIONS, THESE DO NOT EXIST IN MSTT_PAYMENTSPENDING

--GI
select 
cast((month((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar) + cast((year((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar) + 'GI' as "Concat",
cast((year((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar(max)) + (case when month((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD", 
case when convert(datetime, dateadd(month,datediff(Month,0,(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
month(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as 'month', year(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end) as 'year',
"ProductGroupName" = 'GI',
"ProductGroupName2" = 'GI',


-----------------------------Issued APE------------------------------------------------------------------------------------------------------------------
sum(case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end) as "Issued APE",
-----------------------------Gross DAE------------------------------------------------------------------------------------------------------------------
sum(case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end) as "Gross DA",
-----------------------------DA Claw------------------------------------------------------------------------------------------------------------------
"DA Claw" = 0,
-----------------------------Gross Commission------------------------------------------------------------------------------------------------------------------
sum(case when (businesscode <> '1010904' AND rtrim(ah.asdname) = 'GHL') then (totdue_enhd)+ ((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd))*0.7) when rtrim(ah.asdname) = 'First Affinity' then (totdue_enhd)*(10.0/9) else (totdue_enhd) end) as "Gross Comm",
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0,
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
sum(case when (businesscode <> '1010904' AND rtrim(ah.asdname) = 'GHL') then (totdue_enhd)+ ((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end - (totdue_enhd))*0.7) when rtrim(ah.asdname) = 'First Affinity' then (totdue_enhd)*(10.0/9) else (totdue_enhd) end) as "Net Comm",
-----------------------------Gross Margin------------------------------------------------------------------------------------------------------------------
sum(case when (businesscode <> '1010904' AND rtrim(ah.asdname) = 'GHL') then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end-(totdue_enhd))-((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end-(totdue_enhd)) *0.7) when rtrim(ah.asdname) = 'First Affinity' then (case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end-(totdue_enhd)) -((totdue_enhd)*(10.0/9)-(totdue_enhd)) else case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end-(totdue_enhd) end) as "Gross Margin", 
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
"Net Charges" = 0,
-----------------------------New Business Cases------------------------------------------------------------------------------------------------------------------
sum((case when oa.providercode = 'GI' then ((totdue_base/27.5)*35) else (ape) end)/121) as "NB Cases",
-----------------------------Written APE------------------------------------------------------------------------------------------------------------------
"Written NB APE" = 0, 
-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------
"Written NB Cases" = 0,
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
sum(oa.totalpayment) as 'Paid',
"CommAdj" = 0

from msit_openworkadviserlisting oa LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON oa.businesscode = ah.agentcode

where
(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end
BETWEEN @ProfStartDate
AND @ProfEndDate)
and oa.providercode in ('GI', 'Payment shield', 'PYMTSHLD')
and feetype <> 'RC'
and feetype <> 'Trail'
and feetype <> 'TF'
and APE <> 0
and (rtrim(ah.ASDName) NOT IN ('Pat Mckenna', 'Owl Sales Director') or oa.sellercode <> '1011623' or ah.ASDName is Null)

group by 
cast((month((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar) + cast((year((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar) + 'GI',
cast((year((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end))) as nvarchar(max)) + (case when month((case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end), 
case when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,oa.month),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
oa.providercode, oa.month,
month(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end), year(case when oa.providercode in ('Payment shield', 'PYMTSHLD') then month - 27 else month end)


UNION ALL

-------STANDING ORDERS FOR CHARGES

select
cast((month(ag.createdatetime)) as nvarchar) + cast((year(ag.createdatetime)) as nvarchar) + isnull(('SO' + (case when ag.standingordercodedesc like 'Ex Gratia%' then 'Ex Gratia' when ag.standingordercodedesc like 'Regulatory%' then 'Regulatory' else ag.standingordercodedesc end)),'SOWeb Mail'),
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
month(ag.createddate) as month, year(ag.createddate) as year, 
isnull(('SO' + (case when ag.standingordercodedesc like 'Ex Gratia%' then 'Ex Gratia' when ag.standingordercodedesc like 'Regulatory%' then 'Regulatory' else ag.standingordercodedesc end)),'SOWeb Mail') as "ProductGroupName",
isnull(('SO' + (case when ag.standingordercodedesc like 'Ex Gratia%' then 'Ex Gratia' when ag.standingordercodedesc like 'Regulatory%' then 'Regulatory' else ag.standingordercodedesc end)),'SOWeb Mail') as "ProductGroupName2",


-----------------------------Issued APE------------------------------------------------------------------------------------------------------------------
"Issued APE" = 0, 
-----------------------------Gross DA------------------------------------------------------------------------------------------------------------------
"Gross DA" = 0, 
-----------------------------DA Claw------------------------------------------------------------------------------------------------------------------
"DA Claw" = 0, 
-----------------------------Gross Commission------------------------------------------------------------------------------------------------------------------
"Gross Comm" = 0, 
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0,
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
case when ag.standingordercode = 49 then sum(ag.amount) else 0 end as 'Net Comm',
-----------------------------Gross Margin------------------------------------------------------------------------------------------------------------------
sum(case when ag.standingordercode = 49 then (-ag.amount) else 0 end) as 'Gross Margin',
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
sum(case when ag.standingordercode <> 49 then (-ag.amount) else 0 end) as 'Net Charges',
-----------------------------New Business Cases------------------------------------------------------------------------------------------------------------------
"NB Cases" = 0, 
-----------------------------Written APE------------------------------------------------------------------------------------------------------------------
"Written NB APE" = 0, 
-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------
"Written NB Cases" = 0,
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
 "Paid" = 0,

sum(case when ag.standingordercode = 49 then (-ag.amount) else 0 end) as 'Comm Adj'

from mstt_paymentspending ag LEFT OUTER JOIN
msit_commissionstatement cs ON cs.PendingPaymentID = ag.id LEFT OUTER JOIN
cscv_AgentsHierarchy ah ON ag.firm = ah.agentcode

where 
(ag.createdatetime
BETWEEN @ProfStartDate
AND @ProfEndDate)
and ag.commissiontype = 8
and ag.standingordercode in (2,4,66,52,67,53,32,49,6,7,17)
and cs.oastatus = 'valid'
and (ag.firm <> 1010904 or ag.standingordercode <> 49) --GHL Amendment
and (ag.firm <> 1011323 or ag.standingordercode not in (7,49)) -- First Affinity Amendment
and ag.id not in ('15598178')
and (rtrim(ah.ASDName) NOT IN ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)

group by 
cast((month(ag.createdatetime)) as nvarchar) + cast((year(ag.createdatetime)) as nvarchar) + isnull(('SO' + (case when ag.standingordercodedesc like 'Ex Gratia%' then 'Ex Gratia' when ag.standingordercodedesc like 'Regulatory%' then 'Regulatory' else ag.standingordercodedesc end)),'SOWeb Mail'),
cast((year(ag.createdatetime)) as nvarchar(max)) + (case when month(ag.createdatetime) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,ag.createdatetime),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
month(ag.createddate), year(ag.createddate), ag.standingordercodedesc, ag.standingordercode

UNION ALL


--WRITTEN BUSINESS (PROPOSAL STATUS)

select 
cast((month(wr.writtendate)) as nvarchar) + cast((year(wr.writtendate)) as nvarchar)  + (case when wr.adminmethod <> 'Advised' then 'NonWri' + wr.productgroupname else 'Advised' + wr.productgroupname end) as Concat,
cast((year(wr.writtendate)) as nvarchar(max)) + (case when month(wr.writtendate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
month(wr.writtendate),
year(wr.writtendate),
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT'or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) end as productgroupname,
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT'or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) end as productgroupname2,


-----------------------------Issued APE------------------------------------------------------------------------------------------------------------------
"Issued APE" = 0, 
-----------------------------Gross DA------------------------------------------------------------------------------------------------------------------
"Gross DA" = 0, 
-----------------------------DA Claw------------------------------------------------------------------------------------------------------------------
"DA Claw" = 0, 
-----------------------------Gross Commission------------------------------------------------------------------------------------------------------------------
"Gross Comm" = 0, 
-----------------------------Commission Claw------------------------------------------------------------------------------------------------------------------
"Comm Claw" = 0, 
-----------------------------Net Commission------------------------------------------------------------------------------------------------------------------
"Net Comm" = 0, 
-----------------------------Gross Margin------------------------------------------------------------------------------------------------------------------
"Gross Margin" = 0, 
-----------------------------Net Charges------------------------------------------------------------------------------------------------------------------
"Net Charges" = 0, 
-----------------------------New Policies------------------------------------------------------------------------------------------------------------------
"NB Cases" = 0, 
-----------------------------Written APE------------------------------------------------------------------------------------------------------------------
sum(wr.writtenape),
-----------------------------Written Cases------------------------------------------------------------------------------------------------------------------
sum(wr.writtencases),
-----------------------------Paid------------------------------------------------------------------------------------------------------------------
"Paid" = 0
,"CommAdj" = 0

from

-- IN ORDER TO REMOVE DUPLICATES OF SAME ADVISERCODE/POLICY/CASEID/APE/WRITTEN DATE IN SAME WEEK

(SELECT 
cast(co.AGENT_CODE as int) as Adviser,
min(coalesce(co.firm,co.agent_code)) as Firm, 
min(co.transactionid) as transactionid, 
min(pt.writtendate) as "writtendate",
datepart(week,(pt.writtendate)) as writtenweek, 
year(pt.writtendate) as writtenyear,

round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2) as WrittenAPE, -- END as WrittenAPE,

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.7) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.9) else (co.baseamount + co.upliftamount) end),2)End AS NBI, 

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else round(min(case when (ph.productgroupname = 'Protection' and ccs.description is null) then ((co.turnover * 2.2) *0.3) 
when (ph.productgroupname = 'Mortgage' and ccs.description is null) then (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) else (co.salesmargin) end),2)End as margin, 

Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max((co.agent_perc/100))End as "Old Cases", 

CASE WHEN (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0 else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100) else 0 end)End as "WrittenCases", 

min(pt.FrequencyDescription) as frequency, 
po.PolicyRef AS CaseID,
po.CONT_NUM AS Policy,
min(co.BusinessReason) as businessreason, min(co.AdminMethodDescription) as adminmethoddescription, min(co.ProductCode) as productcode, min(po.COMP_CODE) AS Provider, min(rp.ReportingProductName) as reportingproductname, 
min(ph.ProductSubGroupName) as productsubgroupname, 
min(case when ph.productgroupname = 'Other' then 'Pensions' else ph.productgroupname end) as "ProductGroupName",

min(po.originatingsource) as originatingsource, min(case when ((ph.productgroupname <> 'Mortgage' and co.adminmethod NOT IN ('A','G')) or ph.productsubgroupname like '%Guaranteed Account%' or rp.reportingproductname = 'Zurich Bank Structured Product' or ph.productsubgroupname like '%Group Pension%' or po.comp_code = 'Zurich Leg' or co.productcode = 'ZGUA' or po.comp_code = 'Close' or po.comp_code = 'MSQ') then 'Non Advised' else 'Advised' end) as "Adminmethod", min(ccs.calculationcode) as calculationcode, min(ccs.description) as description, min(rtrim(ah.asdname)) as ASD
, min(ah.agentdesc) as agentdesc

FROM          dbo.mstt_Commissions co INNER JOIN
			  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
			  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
			  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
		      dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
			  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
			  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
			  #C c on c.transactionid = co.transactionid LEFT OUTER JOIN
			  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
			  left join sa_swift_PolicyTransactions spt on spt.PolicyID = po.Pol_Num

where  
co.agent_code not in ('10002','1011542','10004','1011623')
and co.commissiontype = 1
and co.poltrantranstype = 39
and (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription is NULL)
and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
and po.COMP_CODE NOT LIKE '%Owl%'
and (rtrim(ah.ASDName) NOT IN ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName is Null)
----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
and (case when ph.productsubgroupname NOT IN ('Group Pension') then 1 when (ph.productsubgroupname = 'Group Pension'and year(pt.writtendate) <2016) then 1 else 0 end) = 1
-----------------------------------------------------------------------

group by cast(co.AGENT_CODE as int), round((case when (ph.productgroupname = 'Mortgage' and ccs.description is null) then ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) else co.Turnover end),2), po.policyref, po.cont_num, datepart(week,(pt.writtendate)), year(pt.writtendate), ph.productgroupname,ph.productgroupname,co.agent_code) wr

where 
wr.writtendate >= @ProfStartDate
and wr.writtendate <= @ProfEndDate	
and (wr.caseid not in ('500020430','500020431') or wr.caseid is null)

group by
cast((month(wr.writtendate)) as nvarchar) + cast((year(wr.writtendate)) as nvarchar)  + (case when wr.adminmethod <> 'Advised' then 'NonWri' + wr.productgroupname else 'Advised' + wr.productgroupname end),
cast((year(wr.writtendate)) as nvarchar(max)) + (case when month(wr.writtendate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,wr.writtendate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end,
case when wr.adminmethod <> 'Advised' then 'NonWri' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT' or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) else 'Advised' + (case when wr.productsubgroupname like '%Annuity' then 'COB Off Platform' when ((left(wr.productcode,2) in ('OW','OZ')) or wr.productcode = 'OFHBSIPP' or wr.provider = 'Zurich PLT'or wr.provider = 'Pru PLT') then 'COB Platform' when wr.productgroupname in ('Pensions','Investment') then 'COB Off Platform' else wr.productgroupname end) end,
month(wr.writtendate),
year(wr.writtendate),
wr.productgroupname

UNION ALL

-------Issued Mortgage Broker Fee ---------------------------------

Select Distinct 
cast((month(MBF.PaymentMatchedDate)) as nvarchar(max)) + cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + 'Mortgage Broker Fee' AS Concat,
cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
Month(MBF.PaymentMatchedDate) as "Month", 
Year(MBF.PaymentMatchedDate) as "Year",
'Mortgage Broker Fee' as productgroupname,
'Mortgage Broker Fee' as productgroupname2,



SUM(MBF.APE) as 'Issued APE', 

SUM(MBF.APE) as 'Gross DA', 

0 as 'DA Claw',

SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.DeductionAmount)  as 'Gross Comm',

0 as 'Comm Claw',

SUM((MBF.AdviceFeeAmount*(MBF.AgentSplit/100))+MBF.DeductionAmount) as 'Net Comm',

SUM(MBF.DeductionAmount*-1) as 'Gross Margin',

0 as 'Net Charges',

SUM(MBF.AgentSplit)/100 as 'NB Cases',

0 as 'Written NB APE',

0 as 'Written NB Cases',

case when sum(mbf.AdviceFeeAmount) is null then 0 else sum(mbf.AdviceFeeAmount) end as 'Paid'
,"CommAdj" = 0
FROM dbo.owt_MortgageBrokerFees MBF 
where
(MBF.PaymentMatchedDate) >= @ProfStartDate
and (MBF.PaymentMatchedDate) <= @ProfEndDate
and MBF.AdviceFeeCharged = 'Yes'
and transactionID = (select max(TransactionID)
								from dbo.owt_MortgageBrokerFees MBF2
								where MBF2.policyID = MBF.PolicyID)
GROUP BY 
Month(MBF.PaymentMatchedDate), 
Year(MBF.PaymentMatchedDate),
cast((year(MBF.PaymentMatchedDate)) as nvarchar(max)) + (case when month(MBF.PaymentMatchedDate) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end),
case when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,MBF.PaymentMatchedDate),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end

UNION ALL

SELECT * FROM #FinalBSCRebate

UNION ALL

--------------Written Mortgage Broker Fee ------------------------------------

select
cast((month(sale.datesubmitted)) as nvarchar(max)) + cast((year(sale.datesubmitted)) as nvarchar(max)) + 'Mortgage Broker Fee' AS Concat,
cast((year(sale.datesubmitted)) as nvarchar(max)) + (case when month(sale.datesubmitted) > month(@ProfEndDate) then 'NOT YTD' else 'YTD' end) as "YTD",
case when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end as "Rolling",
Month(sale.datesubmitted) as Month,
Year(sale.datesubmitted) as Year,
'Mortgage Broker Fee' as ProductGroupName,
'Mortgage Broker Fee' as ProductGroupName2,


"Issued APE" = 0, 

"Gross DA" = 0, 

"DA Claw" = 0, 

"Gross Comm" = 0, 

"Comm Claw" = 0, 

"Net Comm" = 0, 

"Gross Margin" = 0, 

"Net Charges" = 0,

"NB Cases" = 0,

sum(mdaf.brokerfeeamount*AGENT_PERC/100) as 'Written NB APE',

sum(AGENT_PERC/100) as 'Written NB Cases',

"Paid" = 0
 ,"CommAdj" = 0
 
from sa_swift_S_POLMAI polm
join sa_swift_PolicyTransactions potr on potr.PolicyID = polm.POL_NUM
join sa_swift_S_AGTCOM agtc on agtc.TransactionID = potr.ID
join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdaf on mdaf.PolicyId = polm.PolicyRef 
join sa_ows_Sale sale on sale.SaleID = mdaf.saleid
join sa_ows_Policies pol on pol.PolicyID = mdaf.PolicyId
join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
join  cscv_AgentsHierarchy ah ON potr.AgentCode = ah.agentcode
where 1=1 
and potr.ID = (select min(potr1.ID)
                        from sa_swift_S_POLMAI polm1
                       join sa_swift_PolicyTransactions potr1 on potr1.PolicyID = polm1.POL_NUM
                       where polm.PolicyRef = polm1.PolicyRef)
and AGENT_CODE != '10002' and agtc.CommissionType = 1
and mdaf.HasBrokerFeeCharged = 19
and (sale.datesubmitted) >= @ProfStartDate--DATEADD(yy, DATEDIFF(yy, 0, GETDATE()) - 2, 0)
and (sale.datesubmitted) <= @ProfEndDate--(dateadd(day,datediff(day,0,GETDATE()),0))
Group by month(datesubmitted), year(datesubmitted), 
case when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-12,@ProfEndDate) then 'CurrR' when convert(datetime, dateadd(month,datediff(Month,0,sale.datesubmitted),0), 102) >= dateadd(month,-24,@ProfEndDate) then 'PrevR' else 'NOR12' end


order by [year], [month]

drop table #b
drop table #c
drop table #d


select #e.month, #e.year, #e.ProductGroupName, #e.ProductGroupName2, sum(#e.WrittenNBAPE) AS WrittenNBAPE, Sum(#e.WrittenNBCases) AS WrittenNBCases, Sum(#e.ISSUEDAPE) AS ISSUEDAPE, Sum(#e.NBCases) AS NBCases, Sum(#e.GrossDA) AS GrossDA,
	Sum(#e.DAClaw) AS DAClaw, Sum(#e.GrossComm) AS GrossComm, Sum(#e.CommClaw) AS CommClaw, Sum(#e.NetComm) AS NetComm, Sum(#e.GrossMargin) AS GrossMargin, Sum(#e.NetCharges) AS NetCharges, Sum (#e.CommAdj) as CommAdj
 from #e

 Group By
  #e.month,
 #e.year,
 #e.ProductGroupName,
 #e.ProductGroupName2






	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	exec BI.pr_ProcessLog @PhaseError, @Process, @Module, @Client, null, @ErrMsg

	RAISERROR(@ErrMsg, @ErrSev, 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[pr_WrittenBusinessCaseByCase]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	pr_WrittenBusinessCaseByCase
  	 					
	  Author:	John Homer - SQL (23/08/2021)
				A Groves - Stored procedure 

Date created:	23/08/2021
													
 Description:   This stored proc implements the "Written Business Case by Case" scan to populate table
				[BI].[WrittenBusinessCBC].

				It is called as follows:

				declare @StartDate datetime = convert(datetime,'01/01/2006', 103)
				declare @EndDate datetime = DATEADD(day,datediff(day,0,GETDATE()),0)
				exec BI.pr_WrittenBusinessCaseByCase @StartDate, @EndDate
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------		
12/10/21	John Homer	Removed Transaction ID from Results and added in Owl CBC code	
