28/02/2022	J Homer		Corrected Code for NB Cases to ignore Multi-Benefit case IDs
25/04/2022	J Homer		Corrected Code for NB Cases as previous change not fully working
02/10/2022	J Homer		Added 7IM to Product Group and Sub Group definitions
28/02/2023	J Homer		Update code for Multi Benefit cases so that cases now leading 8001 do not count as 
						New Business Cases
16/08/2023	J Homer		Amend NBI and other areas of code to include new Embark (Scottish Widows Product
						Code prefix of OE.  Products are: 
							OEGIAS Scottish Widows General Investment Account
							OEISA Scottish Widows Individual Savings Account
							OEPENACC Scottish Widows Personal Pension
							OEBONDOF Utmost Bond (Scottish Widows)
10/06/2024	J Homer		CHANGE TO NBCASES TO FIX THE ISSUE WITH SCOTTISH WIDOWS CASES, POST PLATFORM MIGRATION,  
						BEING INCORRECTLY CLASSIFIED AS NEW BUSINESS WHEN WE RECEIVE AN INCREASE TO AN OLD ZR POLICY NUMBER 
						UNDER THE NEW SCOTTISH WIDOWS EM POLICY NUMBER

************************************************************************************************/
CREATE PROCEDURE [BI].[pr_WrittenBusinessCaseByCase]
	@StartDate datetime,
	@EndDate datetime

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.
SET DATEFIRST 1 
SET DATEFORMAT DMY

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@Client						varchar(50),
		@Module						varchar(50),
		@DateLastUpdated			datetime

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @Client				= 'Openwork'
set @Module				= 'MI Team Written Business CBC'
set @DateLastUpdated	= getdate()

/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec BI.pr_ProcessLog @PhaseStart, @Process, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	--BEGIN TRANSACTION

	/****************************************************************************

		truncate the Written Business Case By Case table
																		
	****************************************************************************/
	
	truncate table BI.WrittenBusinessCBC

	/****************************************************************************

		Populate temp table

	****************************************************************************/
	
	;WITH All_Trans1 AS
	(
		SELECT
		MIN(transactionid) AS transactionid, 
		po.policyref, 
		po.cont_num, 
		--co.productcode,
		ph.productgroupname,
		COMP_CODE
		,co.poltrantranstype

		FROM          dbo.mstt_Commissions co INNER JOIN
					  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
					  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
					  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
					  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
					  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
					  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
		WHERE
		co.agent_code not in ('10002','1011542','10004')
		and co.commissiontype = 1
		and co.poltrantranstype = 39
		and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
		and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
		and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
		and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
		and((left(ltrim(po.policyref),4) < '8000' or left(ltrim(po.policyref),4) is null) or ph.productgroupname not like 'Protection')

		GROUP BY po.policyref, po.cont_num, co.productcode, ph.productgroupname,COMP_CODE,co.poltrantranstype

		UNION ALL

		SELECT
		min(transactionid) AS transactionid, 
		'' t1, 
		'' t2,
		--'' t3,
		ph.productgroupname,
		COMP_CODE,
		co.poltrantranstype

		FROM          dbo.mstt_Commissions co INNER JOIN
							  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
							  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
							  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
							  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
							  dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
							  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
							  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode
		WHERE
		co.agent_code not in ('10002','1011542','10004')
		and co.commissiontype = 1
		and co.poltrantranstype = 39
		and (ph.productgroupname <> 'GI' or ph.productgroupname is NULL)
		and (left(ccs.description,3) <> 'IMP' or ccs.description is NULL)
		and (left(ccs.description,2) <> 'UA' or ccs.description is NULL)
		and (co.productcode not in ('OWADVICE','OWADHOC') or co.productcode is NULL)
		and((left(ltrim(po.policyref),4) >= '8000' or left(ltrim(po.policyref),4) is null) and ph.productgroupname like 'Protection')
		and pt.writtendate is not null -- Zurich Cases Fix JB 05/10/18
		GROUP BY co.CLIENT_NUM,po.comp_code,
		CASE po.plan_code WHEN 'IPP' THEN 'IPP' ELSE 'OTHER' END,
		ph.productgroupname,
		COMP_CODE,
		co.poltrantranstype
	),

	All_Trans AS
	(
		select transactionid,policyref,cont_num
		from All_Trans1
		where (left(cont_num,2) NOT IN ('ZR','EM') or cont_num is null)

		union all

		select case when left(cont_num,2) IN ('ZR','EM') then min(transactionid) end transactionid, policyref, cont_num
		from All_Trans1
		where left(cont_num,2) IN ('ZR','EM')
		group by  policyref, cont_num
	),
	------------ MAIN OPENWORK WRITTEN BUSINESS SCAN ---------------------------------------------------------

	-------------WRITTEN BUSINESS EXCLUDING MORTGAGE BROKER FEE ----------------------------------------------
	OW_Prod AS 
	(
		SELECT
		'Written' AS "Type", 
		--MIN(co.transactionid) AS transactionid, 
		MIN(po.PolicyRef) AS CaseID, 
		Replace(Min(po.CONT_NUM), ',','') AS Policy, 
		CAST(co.AGENT_CODE AS int) AS Adviser,
		MIN(COALESCE(co.firm,co.agent_code)) AS Firm,
		CAST(MIN(pt.writtendate)AS DATE) AS writtendate,
		DAY(MIN(pt.writtendate)) AS Day,
		MONTH(MIN(pt.writtendate)) AS Month,
		YEAR(MIN(pt.writtendate)) AS Year,
		CASE WHEN MIN(pt.FrequencyDescription) = 'Single' THEN ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) * 10
														  ELSE ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) 
														  END AS Premium,

		ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) AS APE,

		--CASE WHEN (MIN(po.PolicyRef) IS NULL AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') THEN 0 ELSE MAX(CASE WHEN co.transactionid = c.transactionid AND (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) THEN (co.agent_perc/100) ELSE 0 END)End AS "NBCases",
		
		--CASE WHEN min(c.policyref) = 0 then 0																																		--
		--else (Case when (min(po.PolicyRef) is null AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0													--
		--	  else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) then (co.agent_perc/100)		-- CHANGE TO NEW BUSINESS CASE COUNT TO IGNORE THE MULTI
		--			   else 0																																						-- BENEFIT CASES WIHICH START 800
		--			   end)																																							--
		--	  End)																																									--
		--End as "NBCases",
		
		CASE WHEN (min(c.policyref) = 0 and min(po.CONT_NUM) is null) then 0  
			 WHEN em.TargetAccountId IS NOT NULL then 0 
		else (Case when ((min(po.PolicyRef) is null OR min(c.PolicyRef) =0) AND ph.productgroupname = 'Protection' AND co.agent_code <> '1000312') then 0  
						else max(case when co.transactionid = c.transactionid and (spt.CommNotes NOT LIKE '%IFDL to Zurich Transfer%' OR spt.CommNotes IS NULL) 
									then (co.agent_perc/100) else 0 end)
			   End)
		End as "NBCases",																																							--

		ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN co.turnover * 2.2 
		WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.distributionallowance END),2) AS distributionallowance,

		ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN ((co.turnover * 2.2) *0.3) 
		WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) ELSE (co.salesmargin) END),2) AS Margin,

		CASE WHEN MIN(ph.ProductSubGroupName) LIKE '%Annuity' THEN 'COB Off Platform' WHEN ((LEFT(MIN(co.ProductCode),2) IN ('OW','OZ','OE')) OR MIN(co.ProductCode) = 'OFHBSIPP' OR MIN(po.COMP_CODE) = 'Zurich PLT' OR MIN(po.COMP_CODE) = 'Pru PLT' OR MIN(po.COMP_CODE) = '7IM1') THEN 'COB Platform' WHEN MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) IN ('Pensions','Investment') THEN 'COB Off Platform' ELSE MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) END AS 'ProductGroupName',

		-------------------------PRODUCT SUB GROUP DEFINITIONS ---------------------------------------------------------------------------------------------------------------------
		CASE WHEN MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) = 'Protection' THEN (CASE WHEN MIN(po.COMP_CODE) in ('Zurich New','Zurich Leg','Zurich PNL') THEN 'Zurich' WHEN MIN(po.COMP_CODE) = 'Scot Eq' THEN 'Aegon' 
																															WHEN MIN(po.COMP_CODE) = 'Axa' THEN 'Friends Life' 
																															ELSE MIN(po.COMP_CODE) 
																															END) 
		-- Platform
		WHEN ((LEFT(MIN(co.ProductCode) ,2) IN ('OW') AND LEFT(MIN(ph.ProductSubGroupName),3) <> 'FEE') OR MIN(co.ProductCode) = 'OFHBSIPP' OR MIN(po.COMP_CODE) = 'Pru PLT' OR MIN(po.COMP_CODE) = 'IFDL') THEN 'IFDL'
		WHEN ((LEFT(MIN(co.ProductCode) ,2) IN ('OZ') AND LEFT(MIN(ph.ProductSubGroupName),3) <> 'FEE') OR MIN(po.COMP_CODE) = 'Zurich PLT') THEN 'ZIP'
		WHEN ((LEFT(MIN(co.productcode),3) IN ('7IM') AND (LEFT(MIN(ph.productsubgroupname),3) <> 'FEE' OR LEFT(MIN(ph.productsubgroupname),3) <> '7IM')) OR min(po.COMP_CODE) = '7IM1') THEN '7IM'
		WHEN ((LEFT(MIN(co.ProductCode) ,2) IN ('OE') AND LEFT(MIN(ph.ProductSubGroupName),3) <> 'FEE') OR MIN(ph.ProductProviderCode) = 'EMBARK') THEN 'Embark'

		-- Annuities
		WHEN (MIN(po.COMP_CODE) = 'PTSP') THEN 'Partnership' 
		WHEN (MIN(po.COMP_CODE) = 'MGMA') THEN 'MGMA'
		WHEN (MIN(po.COMP_CODE) = 'PRU' AND (CASE WHEN MIN(ph.ProductSubGroupName) LIKE '%Annuity' THEN 'Annuities' 
									   ELSE MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) 
									   END) = 'Annuities') THEN 'Pru Ann'
		WHEN (CASE WHEN MIN(ph.ProductSubGroupName) LIKE '%Annuity' THEN 'Annuities' 
			  ELSE MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) 
			  END) = 'Annuities' THEN MIN(po.COMP_CODE)

		-- Off Platform
		WHEN MIN(po.COMP_CODE) = 'MetLife' THEN 'MetLife'
		WHEN MIN(po.COMP_CODE) = 'PRU' THEN 'Pru'
		WHEN MIN(po.COMP_CODE) = 'Octopus' THEN 'Octopus'
		WHEN (MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) = 'Investment' AND MIN(ph.ProductSubGroupName) LIKE '%Guaranteed Account%') THEN 'Structured'
		WHEN (LEFT(MIN(ph.ProductSubGroupName),3)) = 'FEE' THEN 'Other Fee'
		WHEN MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) IN ('Pensions','Investment') THEN 'Other Comm'

		-- Mortgages
		WHEN MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) = 'Mortgage' THEN 
		(CASE WHEN MIN(rp.ReportingProductName) LIKE '%Leeds & Holbeck Mortgages%' THEN 'Leeds Building Society' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Nationwide Mortgages%' THEN 'Nationwide Building Society' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Natwest Mortgages%' THEN 'Natwest' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Progressive Mortgages%' THEN 'Progressive Building Society' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Abbey Mortgages%' THEN 'Santander for Intermediaries' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Santander%' THEN 'Santander for Intermediaries' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Skipton Mortgages%' THEN 'Skipton Building Society' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Skipton (Buildstore)%' THEN 'Skipton Building Society'  
		 WHEN MIN(rp.ReportingProductName) LIKE '%Northern Rock%' THEN 'Virgin Money' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Platform%' THEN 'Platform (Co-op Bank)' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%BM Solutions%' THEN 'BM Solutions (LBG)' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%The Mortgage Works%' THEN 'The Mortgage Works (NBS)' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Godiva%' THEN 'Coventry' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Principality%' THEN 'Principality' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%lloyds TSB%' THEN 'TSB' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Precise%' THEN 'Precise' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Newcastle%' THEN 'Newcastle Building Society' 
		 WHEN MIN(rp.ReportingProductName) = 'BOI' THEN 'Bank of Ireland' 
		 WHEN MIN(rp.ReportingProductName) LIKE '%Woolwich%' THEN 'Barclays' 
		 ELSE REPLACE(REPLACE(MIN(rp.ReportingProductName),' Mortgages',''),' (TBMC)','') 
		 END)
		ELSE (CASE WHEN MIN(ph.ProductSubGroupName) LIKE '%Annuity' THEN 'Annuities' ELSE MIN(CASE WHEN ph.productgroupname = 'Other' THEN 'Pensions' ELSE ph.productgroupname END) END) END AS "ProductSubGroup",
		----------------------END OF PRODUCT SUB GROUP DEFINITIONS ------------------------------------------------------------------------
	
		MIN(CASE WHEN ((ph.productgroupname <> 'Mortgage' AND co.adminmethod NOT IN ('A','G')) OR ph.productsubgroupname LIKE '%Guaranteed Account%' OR rp.reportingproductname = 'Zurich Bank Structured Product' OR ph.productsubgroupname LIKE '%Group Pension%' OR po.comp_code = 'Zurich Leg' OR co.productcode = 'ZGUA' OR po.comp_code = 'Close' OR po.comp_code = 'MSQ') THEN 'Non Advised' ELSE 'Advised' END) AS "Adminmethod", 
		MIN(pt.mortgageamount) AS MortgageLoanAmount,
		CASE WHEN MIN(pt.FrequencyDescription) = 'Single' THEN 'Single' ELSE 'Regular' END AS 'Frequency',
		CASE WHEN (ah.ASDCode in('4019902') OR MIN(COALESCE(co.firm,co.agent_code)) = '2016789') THEN 'Owl AR' ELSE 'Openwork' END AS Channel

		FROM          dbo.mstt_Commissions co INNER JOIN
					  dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
					  dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
					  dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
					  dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
					  dbo.msit_CodeReportingProductCode rp ON rp.Code = ph.ReportingProductCode LEFT OUTER JOIN
					  dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
					  All_Trans c ON c.transactionid = co.transactionid LEFT OUTER JOIN
					  cscv_AgentsHierarchy ah ON co.firm = ah.agentcode LEFT JOIN 
					  sa_swift_PolicyTransactions spt ON spt.PolicyID = po.Pol_Num LEFT OUTER JOIN
					  dbo.sa_ows_policies opol ON opol.PolicyID = po.policyref LEFT OUTER JOIN
					  Policy.sa_ows_MortgageProduct mo ON mo.InternalProductID = opol.InternalProductID LEFT OUTER JOIN
					  vw_ows_MortgageProductSummary mps ON mps.PolicyID = po.policyref LEFT JOIN 
					  policy.sa_ows_MortgageRecommendedSolution mrs ON mrs.PolicyID = mps.PolicyID LEFT JOIN 
					  policyonelink.sa_ows_MortgageProductSummary olmps ON olmps.PolicyId = mps.PolicyID LEFT JOIN 
					  policy.sa_ows_MortgageProductSummary pmps ON pmps.PolicyID = mps.PolicyID LEFT JOIN 
					  StaticData.sa_ows_InputValues invTrans ON invtrans.InputID = CASE WHEN olmps.PolicyId IS NULL THEN mrs.TransactionTypeID ELSE olmps.TransactionTypeId END LEFT JOIN 
					  StaticData.sa_ows_InputValues invTrans2 ON invtrans2.InputID = mps.mortgagecategoryID
					  LEFT JOIN dbo.EmbarkMigration em ON em.TargetAccountId  = po.CONT_NUM  --JOIN TO NEW EMBARKL MIGRATION TABLE

		WHERE  
		co.agent_code NOT IN ('10002','1011542','10004','1011623')
		AND co.commissiontype = 1
		AND co.poltrantranstype = 39
		AND (co.adminmethoddescription <> 'Indexation' OR co.adminmethoddescription IS NULL)
		AND (ph.productgroupname <> 'GI' OR ph.productgroupname IS NULL)
		AND (left(ccs.description,3) <> 'IMP' OR ccs.description IS NULL)
		AND (left(ccs.description,2) <> 'UA' OR ccs.description IS NULL)
		AND (co.productcode NOT IN ('OWADVICE','OWADHOC') or co.productcode IS NULL)
		AND po.COMP_CODE NOT LIKE '%Owl%'
		AND (RTRIM(ah.ASDName) NOT IN ('Pat Mckenna', 'Owl Sales Director') or ah.ASDName IS NULL)
		----------EXCLUDE ALL GROUP PENSION BUSINESS---------------------------
		AND (CASE WHEN ph.productsubgroupname NOT IN ('Group Pension') THEN 1 WHEN (ph.productsubgroupname = 'Group Pension'AND YEAR(pt.writtendate) <2016) THEN 1 ELSE 0 END) = 1
		-----------------------------------------------------------------------
		AND (pt.writtendate) >= @StartDate 
		AND (pt.writtendate) <= @EndDate

		GROUP BY
		CAST(co.AGENT_CODE AS INT), 
		ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2), 
		po.policyref, 
		po.cont_num, 
		DATEPART(WEEK,(pt.writtendate)), 
		YEAR(pt.writtendate), 
		ph.productgroupname,
		co.agent_code, 
		ah.ASDCode, 
		co.firm,
		co.agent_perc, 
		invtrans.ValueName,
		invtrans2.ValueName,
		em.TargetAccountId
	),
	------------------------- END OF MAIN OPENWORK WRITTEN BUSINESS SCAN --------------------------------------------------------------------------

	-------------- START OF OWL SCAN ------------------------------------------------------------------------------

	PMargin AS (

	SELECT
	comm.TransactionID,
	FixedAmount*((cr.UpfrontASM+cr.UpfrontESM+cr.UpfrontIntro+cr.DeferredASM+cr.DeferredESM+cr.DeferredIntro)/100) AS AdditionalPayaway

	FROM dbo.mstt_Commissions comm
	JOIN mstt_transagentsplithierarchyhistory tashh ON tashh.TransactionID = comm.TransactionID AND tashh.AgentCode = comm.AGENT_CODE AND comm.CommissionType = tashh.CommissionType
	JOIN
			(SELECT DISTINCT [EnterpriseUID],Panel FROM [prod_zurich_openwork_datawarehouse].[BI].[OwlEvoSwiftUpliftRates]) ol
			 ON ol.EnterpriseUID = tashh.FranchiseAgentCode
	JOIN OwlEvolution.ConfigRates cr ON cr.Panel = ol.Panel AND cr.UpliftRate = franchiseupliftpercent AND cr.ProductOrganization != 'Accruals'

	WHERE comm.Commissiontype = 1 
	AND poltrantranstype IN (39) 
	AND comm.ProductProviderCode NOT LIKE '%Owl'),

	---------------------END OF PANEL MARGIN ADJUSTMENTS ------------------------------------------------------------------------------

	C AS (

	SELECT
	MIN(transactionid) AS transactionid, 
	po.policyref, 
	po.cont_num, 
	co.productcode

	FROM        dbo.mstt_Commissions co INNER JOIN
				dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
				dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT OUTER JOIN             
				dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT OUTER JOIN               
				dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT OUTER JOIN
				dbo.msit_CodeReportingProductCode wr ON wr.Code = ph.ReportingProductCode LEFT OUTER JOIN
				dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT OUTER JOIN
				mstt_agents ag ON pt.agentcode = ag.code

	WHERE
	co.agent_code NOT IN ('10002','1011542','10004')
	AND co.commissiontype = 1
	AND co.poltrantranstype = 39
	AND (ph.productgroupname <> 'GI' OR ph.productgroupname IS NULL)
	AND (left(ccs.description,3) <> 'IMP' OR ccs.description IS NULL)
	AND (left(ccs.description,2) <> 'UA' OR ccs.description IS NULL)
	AND po.policyref NOT LIKE '800%' -- ignoring split multi-protect cases

	GROUP BY 
	po.policyref, 
	po.cont_num, 
	co.productcode),

	--------------- OWL MANAGER PROMOTION DATES -----------------------------
	Prom AS (

	SELECT DISTINCT ud.Usr_login
		   ,UPS_Jobtitle
		   ,MAX(UPS_Createddate) PromotionDate
		   ,ups_userid	
	FROM  sa_insight_UserDetails ud LEFT JOIN
		  sa_insight_UserPositionHistory uph ON uph.ups_userid = ud.Usr_id LEFT JOIN
		  mi_insight_UserHierarchy uh ON uh.useruid = ud.Usr_login

	WHERE
	UPS_Jobtitle = 54 
	AND UserJobTitleCodeSalesMgr = 54	

	GROUP BY 
	ud.Usr_login,
	UPS_Jobtitle,
	ups_userid	

	HAVING 
	MAX(UPS_Createddate) < @startdate),

	--------------- END OF OWL MANAGER PROMOTION DATES -----------------------------

	---------------- STANDARD OWL WRITTEN SCAN -------------------------------------------------------------------------

	Owl_Prod_Initial AS(

	SELECT 'Written' AS "Type", 
	--wr.transactionID,
	wr.CaseID,
	wr.PriAdviser,
	wr.Firm,
	wr.adminmethod,
	wr.productgroupname AS 'ProductGroupName',
	CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END AS 'Productsubgroup',
	wr.writtendate AS Date,
	DAY(wr.writtendate) AS "Day", 
	MONTH(wr.writtendate) AS "Month", 
	YEAR(wr.writtendate) AS "Year",
	SUM(CASE WHEN wr.frequency = 'Single' THEN wr.ape * 10 ELSE wr.ape END) AS Premium, 
	SUM(wr.ape) AS APE, 
	SUM(wr.NBcases) AS NewPolicies,
	SUM(wr.distributionallowance) AS DA, 
	SUM(wr.margin) AS Margin,
	CASE WHEN YEAR(wr.writtendate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		wr.writtendate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' ELSE
		'Not YTD' 
	END AS YTD,
	wr.startdate,
	pr.PromotionDate,
	wr.frequency

	FROM

	(
	SELECT 
	CAST(co.AGENT_CODE AS INT) AS Adviser,
	CAST(pt.AGENTCODE AS INT) AS PriAdviser,
	CAST(ah.FirmCode AS INT) AS Firm,
	CAST(MIN(ISNULL(s.DateSubmitted,pt.writtendate)) AS DATE) AS writtendate,
	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2) AS APE,
	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN co.turnover * 2.2 
				   WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) 
				   ELSE co.distributionallowance 
			   END),2) AS distributionallowance, 
	ROUND(MIN(CASE WHEN (ph.productgroupname = 'Protection' AND ccs.description IS NULL) THEN ((co.turnover * 2.2) *0.3) 
				   WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN (((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) * 0.1) 
				   ELSE (co.salesmargin) END),2) - ISNULL(SUM(pm.additionalpayaway),0)	as Margin,
	MAX(CASE WHEN co.transactionid = c.transactionid THEN (co.agent_perc/100) ELSE 0 END) AS "NBCases", 
	MAX((co.agent_perc/100)) AS "AllCases",
	MIN(pt.FrequencyDescription) AS frequency,
	MIN(co.AdminMethodDescription) AS adminmethoddescription,
	MIN(co.ProductCode) AS productcode,
	MIN(ph.ProductSubGroupName) AS productsubgroupname, 
	MIN(ph.productgroupname) AS "ProductGroupName",
	MIN(CASE WHEN ((ph.productgroupname <> 'Mortgage' AND co.adminmethod NOT IN ('A','G'))) THEN 'Non Advised' ELSE 'Advised' END) AS "Adminmethod",
	ah.agentstartdate AS startdate,
	--MIN(co.transactionid) AS transactionid,
	MIN(po.PolicyRef) AS CaseID

	FROM                   dbo.mstt_Commissions co INNER JOIN
						   dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID INNER JOIN
						   dbo.mstt_Policies po ON po.POL_NUM = co.PolicyID LEFT JOIN             
						   dbo.mstt_ProductHierarchy ph ON ph.ProductCode = co.ProductCode LEFT JOIN               
						   dbo.mstt_ProductProviders pp ON pp.ProductProviderCode = po.COMP_CODE LEFT JOIN
						   dbo.msit_CodeCommissionShape ccs ON ccs.id = pt.CodeCommissionShapeID LEFT JOIN
						   c ON c.transactionid = co.transactionid LEFT JOIN
						   cscv_AgentsHierarchy ah ON ah.agentcode = pt.AgentCode LEFT JOIN
						   sa_ows_Policies p ON p.PolicyID = po.PolicyRef LEFT JOIN
						   sa_ows_Sale s ON s.SaleID = p.SaleID LEFT JOIN
						   mi_insight_userhierarchyallusers uh2 ON uh2.useruid = pt.agentcode AND pt.writtendate BETWEEN uh2.effectivestartdate AND uh2.effectiveenddate LEFT JOIN
						   PMargin pm ON pm.transactionid = pt.id

	WHERE  
	co.agent_code NOT IN ('10002','1011542','10004')
	AND co.commissiontype = 1
	AND co.poltrantranstype = 39
	AND (co.adminmethoddescription <> 'Indexation' or co.adminmethoddescription IS NULL)
	AND (LEFT(ccs.description,3) <> 'IMP' or ccs.description IS NULL)
	AND (LEFT(ccs.description,2) <> 'UA' or ccs.description IS NULL)
	AND ((RTRIM(uh2.ADName) in('Pat Mckenna', 'Owl Sales Director') OR rtrim(ah.ASDName) in( 'Pat Mckenna', 'Owl Sales Director')) OR co.agent_code IN ('1011623','1011629','1011630','1011631','1011632','1011633','1011634','1011635'))---OWL POT ACCOUNT NOT COUNTED
	AND (po.PolicyRef NOT IN ('500020430','500020431') OR po.PolicyRef IS NULL)
	AND ISNULL(s.DateSubmitted,pt.writtendate) >= @startdate
	AND ISNULL(s.DateSubmitted,pt.writtendate) <= @enddate

	GROUP BY
	CAST(co.AGENT_CODE AS INT),
	CAST(pt.AGENTCODE AS INT),
	CAST(ah.FirmCode AS INT),
	ROUND((CASE WHEN (ph.productgroupname = 'Mortgage' AND ccs.description IS NULL) THEN ((pt.mortgageamount * (co.agent_perc/100)) * 0.0045) ELSE co.Turnover END),2),
	po.policyref,
	po.cont_num,
	ah.agentstartdate
	--co.transactionid	

	HAVING
	NOT (MIN(co.ProductCode) NOT LIKE '%owl%' AND MIN(ISNULL(s.DateSubmitted,pt.writtendate)) <= '2018-12-01')
	) wr


	LEFT JOIN prom pr ON pr.Usr_login = wr.PriAdviser 

	WHERE
	(wr.writtendate) >=  @startdate 
	AND (wr.writtendate) <= @enddate


	GROUP BY
	--wr.transactionID,
	wr.CaseID,
	wr.writtendate, 
	DAY(wr.writtendate), 
	MONTH(wr.writtendate), 
	YEAR(wr.writtendate),
	wr.PriAdviser,
	wr.Firm,
	wr.productgroupname,
	CASE WHEN wr.productcode LIKE '%AVIP OWL%' THEN 'AVIVA OWL' ELSE wr.productcode END,
	wr.adminmethod,
	wr.startdate,
	pr.Promotiondate,
	wr.frequency,
	CASE WHEN YEAR(wr.writtendate) = YEAR(GETDATE()) THEN 'Curr YTD' 
		 WHEN wr.writtendate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		 ELSE 'Not YTD'
	END

	---------------- END OF STANDARD OWL WRITTEN SCAN ---------------------------------------------------------------------------------------------------------------------------------------

	UNION all

	----------------- OWS L&G ASU Product Added 20/03/17 ------------------------------------------------------------------

	SELECT 
	'Written' AS Type,
	--co.transactionID,
	po.PolicyRef,
	sale.AdviserUID AS priadviser,
	uh.BusinessUID AS Firm,
	'Advised' AS adminmethod,
	'Protection' AS ProductGroupName,
	'L&GASU OWL' AS ProductSubGroup,
	CAST(pol.ApplicationDate AS DATE) AS Date,
	DAY(pol.ApplicationDate) AS Day,
	MONTH(pol.ApplicationDate) AS Month,
	YEAR(pol.ApplicationDate) AS Year,
	SUM(pps.PremiumAmount*12) AS Premium,
	SUM(pps.PremiumAmount*12) AS APE,
	SUM(1) AS NewPolicies,
	SUM(pps.PremiumAmount*12*0.35) AS DA,
	SUM(pps.PremiumAmount*12*0.10) AS Margin,
	CASE WHEN YEAR(pol.ApplicationDate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		pol.ApplicationDate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		ELSE 'Not YTD' 
	END AS YTD,
	ah.agentstartdate AS startdate,
	pr.Promotiondate,
	pt.FrequencyDescription

	FROM sa_ows_Policies  pol 
	JOIN policy.sa_ows_ProtectionProductSummary pps ON pps.PolicyID = pol.PolicyID
	JOIN sa_ows_sale sale ON sale.SaleID = pol.SaleID
	JOIN mi_insight_UserHierarchy uh ON uh.UserUID = sale.AdviserUID
	JOIN cscv_AgentsHierarchy ah ON agentcode = sale.adviseruid
	LEFT JOIN prom pr ON pr.Usr_login = sale.adviseruid 
	LEFT JOIN dbo.mstt_Policies po ON po.PolicyRef = pol.PolicyID 
	LEFT JOIN dbo.mstt_Commissions co ON co.PolicyID = po.POL_NUM 
	LEFT JOIN dbo.mstt_PolicyTransactions pt ON pt.ID = co.TransactionID

	WHERE
	InternalProductID = 10000063
	AND SaleStatusID = 2 AND pol.Status = 2
	AND sale.adviserUID <> '4006226' -- Excluding the test UID
	AND pol.ApplicationDate >=	@startdate
	AND pol.ApplicationDate <= @enddate

	GROUP BY 
	--co.transactionID,
	po.PolicyRef,
	pol.ApplicationDate,
	DAY(pol.ApplicationDate),
	MONTH(pol.ApplicationDate),
	YEAR(pol.ApplicationDate),
	sale.AdviserUID,
	uh.BusinessUID,
	ah.agentstartdate,
	pr.Promotiondate,
	pt.FrequencyDescription,
	CASE WHEN YEAR(pol.ApplicationDate) = YEAR(GETDATE()) THEN 'Curr YTD' WHEN
		pol.ApplicationDate BETWEEN DATEADD(YEAR, -1, DATEADD(YEAR, DATEDIFF(YEAR, 0, GETDATE()), 0)) AND DATEADD(YEAR, -1, DATEADD(DAY, DATEDIFF(DAY, 0, GETDATE()), 0)) THEN 'Prior YTD' 
		ELSE 'Not YTD' 
	END),
	-------------- END OF OWS L&G ASU Product Added 20/03/17 ------------------------------------------------------------------------------------------------------------------------------

	-------------- ADDING HIERARCHY AND DUPLICATE APE (FOR INCENTIVES)----------------------------------------------------------

	i AS (

	SELECT h.* 
	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6
	,CASE WHEN h.promotiondate IS NULL or h.date <= CONVERT(DATE, h.promotiondate) THEN 'Adviser' 
		  WHEN h.date > CONVERT(DATE, h.promotiondate) THEN 'Manager'
		  END PriStatus
	,0 dupe

	FROM Owl_Prod_Initial h LEFT JOIN
	mi_insight_UserHierarchyAllUsers hier ON CONVERT(VARCHAR,hier.UserUID) = CONVERT(VARCHAR,h.Priadviser)
																			 AND ((CONVERT(DATE,h.date) >= hier.effectivestartdate 
																			 AND CONVERT(DATE,h.date) <= hier.effectiveenddate ))

	-------------- END OF ADDING HIERARCHY AND DUPLICATE APE (FOR INCENTIVES) -------------------------------------------------------
				 		 
	UNION ALL

	-------------- DUPLICATE APE FOR NEW MANAGERS IN INCENTIVE PERIOD ------------------------------

	SELECT h.*
	,hier.owlasmuid1 asm1
	,hier.owlasmuid2 asm2
	,hier.owlasmuid3 asm3
	,hier.owlasmuid4 asm4
	,hier.owlasmuid5 asm5
	,hier.owlasmuid6 asm6

	,CASE WHEN h.promotiondate IS NULL or h.date <= CONVERT(DATE, h.promotiondate) THEN 'Manager' 
		  WHEN h.date > CONVERT(DATE, h.promotiondate) THEN 'Adviser'
		  END PriStatus
	,1 dupe

	FROM Owl_Prod_Initial h LEFT JOIN
	mi_insight_UserHierarchyAllUsers hier ON CONVERT(VARCHAR,hier.UserUID) = CONVERT(VARCHAR,h.Priadviser)
																			 AND ((CONVERT(DATE,h.date) >= hier.effectivestartdate 
																			 AND CONVERT(DATE,h.date) <= hier.effectiveenddate))
				 		 
	WHERE  h.promotiondate BETWEEN @startdate AND @enddate),
	-------------- END DUPLICATE APE FOR NEW MANAGERS IN INCENTIVE PERIOD ------------------------------
	
	-------------- FINAL OWL SUMMARY TABLE -------------------------------------------------
	Owl_Prod AS (

	SELECT 
	Type
	--,TransactionID
	,CaseID
	,PriAdviser AS Adviser
	,Firm AS Firm
	,Date
	,Day
	,Month
	,Year 
	,(Premium) AS Premium
	,(APE) AS APE
	,(Newpolicies) AS Newpolicies
	,(DA) AS DA
	,(Margin) AS Margin
	,Productgroupname
	,ProductSubGroup
	,Adminmethod
	,0 AS 'Mortgage Loan Amount'
	,Frequency
	,'Owl' AS Channel

	FROM i LEFT JOIN 
		(SELECT UserUID UID FROM  mi_insight_userhierarchyallusers WHERE userjobtitlecodeseller = 61 AND effectiveenddate > GETDATE()) Panel	
		ON panel.UID = CASE WHEN i.Priadviser = '4007583' THEN '4007584' ELSE i.Priadviser END
		
	)
	-------------- END OF FINAL OWL SUMMARY TABLE -------------------------------------------------

	-------------- END OF OWL SCAN-------------------------------------------------

	-------------- FINAL WRITTEN BUSINESS OUTPUT CREATION ------------------------------

	/****************************************************************************

		Populate the Written Business Case By Case Table
																		
	****************************************************************************/	
		
	insert into BI.WrittenBusinessCBC
	(
		BusinessType,
		--TransactionID,
		CaseID,
		AdviserUID,
		FirmUID,
		WrittenDate,
		WDDay,
		WDMonth,
		WDYear,
		Premium,
		APE,
		NBCases,
		DistributionAllowance,
		Margin,
		ProductGroupName,
		ProductSubGroup,
		AdminMethod,
		MortgageLoanAmount,
		Frequency,
		Channel,
		DateInserted,
		DateLastUpdated
	)
	SELECT	Type as BusinessType,
			--TransactionID,
			CaseID,
			Adviser as AdviserUID,
			Firm as FirmUID,
			WrittenDate,
			Day as WDDay,
			Month as WDMonth,
			Year as WDYear,
			Premium,
			APE,
			NBCases,
			DistributionAllowance,
			Margin,
			ProductGroupName,
			ProductSubGroup,
			AdminMethod,
			MortgageLoanAmount,
			Frequency,
			Channel,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	FROM	OW_Prod

	UNION ALL
	
	SELECT	Type as BusinessType,
			--TransactionID,
			CaseID,
			Adviser,
			Firm,
			Date,
			Day,
			Month,
			Year,
			Premium,
			APE,
			NewPolicies,
			DA,
			Margin,
			ProductGroupName,
			ProductSubGroup,
			AdminMethod,
			[Mortgage Loan Amount],
			Frequency,
			Channel,
			@DateLastUpdated,
			@DateLastUpdated
	FROM	Owl_Prod

	
	set @RowCount = @@rowcount
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	exec BI.pr_ProcessLog @PhaseEnd, @Process, @Module, @Client, @RowCount

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	--COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	--IF @@TRANCOUNT <> 0
	--	ROLLBACK TRANSACTION
		
	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))

	exec BI.pr_ProcessLog @PhaseError, @Process, @Module, @Client, null, @ErrMsg

	RAISERROR(@ErrMsg, @ErrSev, 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
