-- =============================================
-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents and their paths for specific clients in ABS
-- =============================================
CREATE PROCEDURE [BI].[SAR_ABSOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM 

/* Display document details for Client */

SELECT
 a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,b.ABSCaseID
,d.FileName
,'\\openwork.local\Infrastructure\ABS_Filedrop\ABS_FILE_DATA\' + e.AdviserID + '\' + CAST((b.ABSCaseID) AS VARCHAR(50)) + '\' AS WorkingFileLocation
FROM #Trace_1 a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_ProductSales] b ON a.PolicyRef = b.SwiftCaseID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_Person] c ON b.ABSCaseID  = c.ABSCaseID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_CaseDocuments] d ON c.ABSCaseID  = d.CaseID
JOIN [dbo].[sa_abs_ABS_Cases] e ON c.ABSCaseID = e.ABSCaseID

/* Display document details for Partner */

SELECT
 a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,b.ABSCaseID
,d.FileName
,'\\openwork.local\Infrastructure\ABS_Filedrop\ABS_FILE_DATA\' + e.AdviserID + '\' + CAST((b.ABSCaseID) AS VARCHAR(50)) + '\' AS WorkingFileLocation
FROM #Trace_2 a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_ProductSales] b ON a.PolicyRef = b.SwiftCaseID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_Person] c ON b.ABSCaseID  = c.ABSCaseID 
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_CaseDocuments] d ON c.ABSCaseID  = d.CaseID
JOIN [dbo].[sa_abs_ABS_Cases] e ON c.ABSCaseID = e.ABSCaseID
GO
