-- Create date:	15/10/2018
-- Description:	SSRS usage audit - for SAR report
-- =============================================
CREATE PROCEDURE [BI].[SAR_Audit]

	 @StartDate DATETIME
	,@EndDate DATETIME


AS
SET NOCOUNT ON;

SELECT
	 ReportName
	,ReportPath
	,RunBy
	,RunDateTime
FROM	dbo.SARAudit
WHERE	RunDateTime BETWEEN @StartDate AND @EndDate
ORDER BY RunDateTime DESC;
GO
