-- =============================================
-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents for specific clients in OBP
-- =============================================
CREATE PROCEDURE [BI].[SAR_OBPOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM 

/* Displaying document details */
/* Create a unique name in OBP and select the name matching the input */

SELECT DISTINCT 
 Title
 ,Forename
 ,Surname
 ,HouseNumber
 ,AddressLine1
 ,AddressLine2
 ,AddressLine3
 ,AddressLine4
 ,AddressLine5
 ,PostCode
 ,DOB
 ,EntityId
 ,uniqueID = SUBSTRING(Forename,1,1) + SUBSTRING(Surname, 1,1) + SUBSTRING(PostCode,1,3) + CONVERT(VARCHAR,DOB ,121)
 ,EntityId AS ClientEntityID
INTO #Temp_Table_1
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_OBP_ClientData] 
WHERE Forename LIKE '%' + @FirstName + '%' AND Surname LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode 

/* Obtain the ClientID to join with the matched name */
/* Obtain document details for Client */

SELECT
 a.FIRSTNAMES 
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,uniqueID = SUBSTRING(FIRSTNAMES ,1,1) + SUBSTRING(NAME , 1,1) + SUBSTRING(PostCode,1,3) + CONVERT(VARCHAR,BIRTHDATE  ,121)
INTO #Temp_Table_2
FROM #Trace_1 a

/* Display document details for Client */

SELECT
 a.FIRSTNAMES 
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,a.uniqueID
,b.ClientEntityID
,c.DocumentDescr
,c.DocumentName
,c.Document
FROM #Temp_Table_2 a
JOIN #Temp_Table_1 b ON a.uniqueID = b.uniqueID
JOIN [OBPArchive].[dbo].[OBPArchiveDocuments] c ON b.ClientEntityID = c.ClientEntityId

/* Obtain document details for Partner */

SELECT
 a.FIRSTNAMES 
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,uniqueID = SUBSTRING(FIRSTNAMES ,1,1) + SUBSTRING(NAME , 1,1) + SUBSTRING(PostCode,1,3) + CONVERT(VARCHAR,BIRTHDATE  ,121)
INTO #Temp_Table_3
FROM #Trace_2 a

/* Display document details for Partner */

SELECT
 a.FIRSTNAMES 
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,a.uniqueID
,b.ClientEntityID
,c.DocumentDescr
,c.DocumentName
,c.Document
FROM #Temp_Table_3 a
JOIN #Temp_Table_1 b ON a.uniqueID = b.uniqueID
JOIN [OBPArchive].[dbo].[OBPArchiveDocuments] c ON b.ClientEntityID = c.ClientEntityId
