-- =============================================
-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents and their paths for specific clients in OTP/ETI
-- =============================================
CREATE PROCEDURE [BI].[SAR_OTPETIOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
--///* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND substring(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM 

/* Check for documents from OTP/ETI in YODA */

SELECT DISTINCT 
 c.ExternalCode AS Description
 ,b.ExternalCode AS Type
 ,a.DocumentPK
 ,d.DocumentFK AS DocumentClientDetailsDocumentPK
 ,a.PolicyNumber AS Refer
 ,e.CurrentInitials
 ,e.CurrentSurname
 ,e.DateOfBirth
INTO #Temp_SAR 
FROM [DocumentArchive].[dbo].[Document] a
JOIN [DocumentArchive].[dbo].[MimeType] b ON a.MimetypeFK= b.MimetypePK
JOIN [DocumentArchive].[dbo].[BusinessDocumentType] c ON a.DocTypeFK = c.DocTypePK 
JOIN [DocumentArchive].[dbo].[DocumentClientDetails] d ON a.DocumentPK = d.DocumentFK
JOIN [DocumentArchive].[dbo].[Client] e ON d.ClientSWIFTFK = e.ClientSWIFTPK
WHERE e.CurrentInitials LIKE SUBSTRING(@FirstName,1,1) + '%' AND e.CurrentSurname LIKE '%' + @Lastname + '%'

/* Display document details for Client */

SELECT 
 a.CurrentInitials
 ,a.CurrentSurname
 ,a.DateOfBirth
 ,a.DocumentClientDetailsDocumentPK
 ,a.DocumentPK
 ,a.Type
 ,a.Description
 --,b.FIRSTNAMES
 --,b.NAME
 --,b.ADDRESS1 
 --,b.ADDRESS2 
 --,b.POSTCODE
 --,b.BIRTHDATE 
 --,b.CLIENT_NUM
 --,c.PolicyRef
 --,c.CLIENT_NUM AS POLMAICLIENT_NUM
 --,c.JOINT_NUM
 --,b.CLIENT_NUM AS DuplicateCLIENT_NUM
FROM #Temp_SAR a
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT] b ON a.Refer = b.REFER
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] c ON b.CLIENT_NUM = c.client_num

/* Display document details for Partner */

SELECT 
 a.CurrentInitials
 ,a.CurrentSurname
 ,a.DateOfBirth
 ,a.DocumentClientDetailsDocumentPK
 ,a.DocumentPK
 ,a.Type
 ,a.Description
 --,b.FIRSTNAMES
 --,b.NAME
 --,b.ADDRESS1 
 --,b.ADDRESS2 
 --,b.POSTCODE
 --,b.BIRTHDATE 
 --,b.CLIENT_NUM
 --,c.PolicyRef
 --,c.CLIENT_NUM AS POLMAICLIENT_NUM
 --,c.JOINT_NUM
 --,b.CLIENT_NUM AS DuplicateCLIENT_NUM
FROM #Temp_SAR a
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT] b ON a.Refer  = b.REFER
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] c ON b.CLIENT_NUM  = c.JOINT_NUM 
GO
