@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND substring(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM 

/* Display document details for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.JOINT_NUM
,a.PolicyRef
,a.systemSource
,b.SaleID
,c.PersonID
,d.FileName AS SaleBasedFileName
,d.WorkingFileLocation,REVERSE(RIGHT(REVERSE(d.WorkingFileLocation), LEN(d.WorkingFileLocation) - CHARINDEX('\',REVERSE(d.WorkingFileLocation),1) + 1)) AS SaleBasedWorkingFileLocation
,d.DateUpdated AS SaleBasedDateUpdated
,e.FileName AS ContextBasedFileName
,e.WorkingFileLocation,REVERSE(RIGHT(REVERSE(e.WorkingFileLocation), LEN(e.WorkingFileLocation) - CHARINDEX('\',REVERSE(e.WorkingFileLocation),1) + 1)) AS ContextBasedWorkingFileLocation
,e.DateUpdated AS ContextBasedDateUpdated
