,e.DateUpdated AS ContextBasedDateUpdated
FROM #Trace_2 a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Policies] b ON a.PolicyRef = b.PolicyID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] c ON b.SaleID = c.SaleID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_CaseDocuments_SaleBased] d ON c.SaleID = d.SaleID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_CaseDocuments_ContextBased] e ON c.PersonID = e.PersonID
