-- =============================================
-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents and their paths for prospect clients in ABS
-- =============================================
CREATE PROCEDURE [BI].[SAR_ProspectABSOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND substring(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM  

/* Gather prospects from ABS */

SELECT 
 DISTINCT a.ABSCaseID
,a.Title
,a.Gender
,a.PersonType
,a.[FirstName]
,a.[LastName]
,a.[DOB]
,a.[Address1]
,a.[Address2]
,a.[PostCode]
INTO #tempperson_abs
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_Person] a
WHERE a.FirstName LIKE '%' + @FirstName + '%' AND a.LastName LIKE '%'+ @Lastname + '%' AND SUBSTRING(a.PostCode,1,4) = @PostCode
 
/* Create and instert a Unique ID into a temporary table */

SELECT 
 UniqueID = SUBSTRING(FirstName,1,1) + SUBSTRING(LastName,1,1)+ SUBSTRING(Address1,1,2)+ SUBSTRING(PostCode,1,3)+ CONVERT(VARCHAR,DOB,121)
,*
INTO #tempperson1_abs
FROM #tempperson_abs
ORDER BY UniqueID

/* Review the counts based on the Unique ID */

SELECT 
 UniqueID
,COUNT (UniqueID) AS records
INTO #temperson2_abs
FROM #tempperson1_abs 
GROUP BY UniqueID
ORDER BY records desc

/* Update the data with the Unique ID created, into a temporary table */

SELECT DISTINCT
 a.UniqueID
,b.records
,a.ABSCaseID
,a.Title
,a.FirstName
,a.LastName
,a.Gender
,a.DOB 
,a.Address1
,a.Address2
,a.PostCode
INTO #testtrace_abs
FROM #temperson2_abs b
LEFT JOIN #tempperson1_abs a
ON a.UniqueID = b.UniqueID
ORDER BY records DESC

/* Review the temporary table trace created as a master record */
SELECT
 *
FROM #testtrace_abs 
ORDER BY records DESC, ABSCaseID

/* Count the rows based on the Unique ID */

SELECT DISTINCT
 UniqueID
,records
FROM #testtrace_abs 
ORDER BY records DESC

/* Flow the information to Swift to get the desired output based on the joins in the query below */

SELECT
 a.UniqueID
,a.records
,a.ABSCaseID
,a.Title AS 'Tit'
,a.FirstName  
,a.LastName
,a.Gender AS 'Sex'
,a.DOB 
,a.Address1 AS 'Add1'
,a.Address2 AS 'Add2'
,a.PostCode AS 'PCode'
,b.SwiftCaseID AS 'CaseID'
,b.ApplicationDate AS 'CaseDateCreated'
,b.ApplicationDate 'ApplicationDate'
,d.CLIENT_NUM AS 'CNum'
,d.START_DATE AS 'PolicyStartDate'
,d.CONT_NUM AS'ActPolicyNo'
,(CASE WHEN b.SwiftCaseID >= 550000000 THEN 'OWS'         
 WHEN b.SwiftCaseID >= 500000000 THEN 'ABS' 
 WHEN b.SwiftCaseID >= 100000000 THEN 'OWS' 
 WHEN b.SwiftCaseID >= 3000000 THEN 'OBP' 
 WHEN b.SwiftCaseID is null then 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #tracetable_abs
FROM #testtrace_abs a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_ProductSales] b ON a.ABSCaseID = b.ABSCaseID
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] d ON b.SwiftCaseID = d.PolicyRef

/* Select the desired output */

SELECT
 *
FROM #tracetable_abs 
ORDER BY records DESC

SELECT
 *
FROM sa_abs_ABS_Cases b
JOIN #tracetable_abs a ON a.ABSCaseID = b.ABSCaseID
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_abs_ABS_CaseDocuments] c ON a.ABSCaseID = c.CaseID

/* Check with the Client table in Swift */

SELECT
 * 
INTO #checks_abs 
FROM #tracetable_abs a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client] b ON a.CNUM = b.CLIENT_NUM

SELECT 
 TITLE
,FirstName
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
FROM #checks_abs
GO
