-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents for prospect clients in OBP
-- =============================================
CREATE PROCEDURE [BI].[SAR_ProspectOBPOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM 

/* Select the name from the OBP Client table and dump into temporary table */

SELECT DISTINCT
 Title
,Forename
,Surname
,HouseNumber
,AddressLine1
,AddressLine2
,AddressLine3
,AddressLine4
,AddressLine5
,PostCode
,DOB
,EntityId
,uniqueID = SUBSTRING(Forename,1,1) + SUBSTRING (Surname, 1,1) + SUBSTRING(PostCode,1,3) + CONVERT(VARCHAR,DOB ,121)
,EntityId AS ClientEntityID
INTO #Temp_Table_1_obp
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_OBP_ClientData] 
WHERE Forename LIKE '%' + @FirstName + '%' AND Surname LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode 

/* Select the client details from switch and match with the temporary tables and pick relevant client num to match the policy ID */
SELECT 
 b.PolicyRef
,a.CLIENT_NUM 
,a.FirstNames
,a.NAME
,a.CorrAddress1
,a.POSTCODE
,a.BIRTHDATE
,uniqueID = SUBSTRING(ISNULL(a.FIRSTNAMES,0),1,1) + SUBSTRING(ISNULL(a.NAME ,0),1,1) + SUBSTRING(ISNULL(a.PostCode,0),1,3) + CONVERT(VARCHAR,ISNULL(BIRTHDATE,0) ,121)
INTO #TempTable2_obp
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT] a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM
WHERE SUBSTRING(a.FirstNames,1,LEN(@FirstName)) LIKE '%' + @FirstName + '%' AND SUBSTRING(a.name,1,LEN(@Lastname)) LIKE '%' + @Lastname + '%' AND SUBSTRING(a.PostCode,1,4) = @PostCode

/* Merge the table to review the desired output */
SELECT 
 b.client_num 
,b.PolicyRef
,a.Title
,a.Forename
,a.Surname
,a.HouseNumber
,a.AddressLine1
,a.AddressLine2
,a.AddressLine3
,a.AddressLine4
,a.AddressLine5
,a.PostCode
,a.DOB
,a.uniqueID
,(CASE WHEN b.PolicyRef >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef is null THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
,a.ClientEntityID
 INTO #OBP_Trace
 FROM #Temp_Table_1_obp a 
 LEFT JOIN #TempTable2_obp b ON a.uniqueID = b.uniqueID
      
SELECT
 *
FROM #OBP_Trace a
JOIN [OBPArchive].[dbo].[OBPArchiveDocuments] b ON a.ClientEntityID = b.ClientEntityId
GO
