INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM

/* To pick the relevant information of the combination from ows_person table and update into a temp table */

SELECT 
 DISTINCT a.PersonID
,b.ValueName AS Title
,a.[FirstName]
,a.[MiddleName]
,a.[LastName]
,a.[DateOfBirth]
,a.[Address1]
,a.[Address2]
,a.[Address3]
,a.[Address4]
,a.[Address5]
,a.[PostCode]
,a.[NINo]
,a.[EmailAddress]
,a.[TelephoneHome]
,a.[TelephoneMobile]
,a.[BusinessUid]
,a.[AdditionalInformation]
,c.AdviserDimName AS Adviser
INTO #tempperson_ows
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] a
LEFT JOIN [prod_zurich_openwork_datawarehouse].StaticData.sa_ows_InputValues b ON a.TitleID = b.InputID 
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[msdv_Adviser]c ON a.BusinessUid = c.AgentCode 
WHERE a.FirstName LIKE '%' + @FirstName + '%' AND a.LastName LIKE '%' + @Lastname + '%' AND SUBSTRING(a.PostCode,1,4) = @PostCode

/* To pick the reference for gender into a temp table Gender */

SELECT DISTINCT
 a.personID
,b.ValueName AS Gender
INTO #Gender_ows
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Person] a
LEFT JOIN [prod_zurich_openwork_datawarehouse].StaticData.sa_ows_InputValues b ON a.GenderID = b.InputID 

/* To update the reference for gender and validate into a temp table person */

SELECT DISTINCT
 a.PersonID
,a.Title
,a.FirstName
,a.MiddleName
,a.LastName
,b.Gender
,a.DateOfBirth
,a.Address1
,a.Address2
,a.Address3
,a.Address4
,a.Address5
,a.PostCode
,a.TelephoneHome
,a.TelephoneMobile
,a.AdditionalInformation
,a.NINo 
,a.Adviser
INTO #person_ows
FROM #tempperson_ows a
INNER JOIN #Gender_ows b ON a.PersonID = b.personID
ORDER BY a.PersonID, a.LastName

/* Create a uniqueID in to a temp table */

SELECT 
 UniqueID = SUBSTRING(FirstName,1,1) + SUBSTRING(LastName,1,1)+ SUBSTRING(Address1,1,2)+ SUBSTRING(PostCode,1,3)+ CONVERT(VARCHAR,DateofBirth,121)
,*
INTO #tempperson1_ows
FROM #person_ows 
ORDER BY UniqueID

/* Review the counts based on uniqueID */

SELECT 
 UniqueID
,COUNT(UniqueID) AS records
INTO #temperson2_ows 
FROM #tempperson1_ows 
GROUP BY UniqueID
ORDER BY records DESC

/* Update the data with uniqueID created into a temp table */

SELECT DISTINCT
 a.UniqueID
,b.records
,a.PersonID
,a.Title
,a.FirstName
,a.MiddleName
,a.LastName
,a.Gender
,a.DateOfBirth
,a.Address1
,a.Address2
,a.Address3
,a.Address4
,a.Address5
,a.PostCode
,a.TelephoneHome
,a.TelephoneMobile
,a.AdditionalInformation
,a.NINo 
,a.Adviser
INTO #testtrace_ows
FROM #temperson2_ows b
LEFT JOIN #tempperson1_ows a ON a.UniqueID = b.UniqueID
ORDER BY records DESC

/* Review the temp table trace created as a master record */

SELECT
 *
FROM #testtrace_ows 
ORDER BY records DESC, PersonID

/* Count the rows based on uniqueID */

SELECT DISTINCT
 UniqueID
,records
FROM #testtrace_ows 
ORDER BY records DESC

/* Flow the information to swift to get the desired output based on the joins in the query below */

SELECT
 a.UniqueID
,a.records
,a.PersonID
,a.Title AS 'Tit'
,a.FirstName 
,a.MiddleName 
,a.LastName
,a.Gender AS 'Sex'
,a.DateOfBirth
,a.Address1 AS 'Add1'
,a.Address2 AS 'Add2'
,a.Address3 AS 'Add3'
,a.Address4 AS 'Add4'
,a.Address5 AS 'Add5'
,a.PostCode AS 'PCode'
,a.TelephoneHome
,a.TelephoneMobile
,a.AdditionalInformation
,a.NINo 
,a.Adviser 
,b.SaleID AS 'Event'
,b.DateCreated AS 'EventCreated'
,b.DateSubmitted AS 'EventSubmitted'
,c.PolicyID AS 'CaseID'
,c.DateCreated AS 'CaseDateCreated'
,c.ApplicationDate AS 'ApplicationDate'
,c.IsSubmitted
,d.CLIENT_NUM AS 'CNum'
,d.START_DATE AS 'PolicyStartDate'
,d.CONT_NUM AS'ActPolicyNo'
,(CASE WHEN c.PolicyID >= 550000000 THEN 'OWS'         
 WHEN c.PolicyID >= 500000000 THEN 'ABS' 
 WHEN c.PolicyID >= 100000000 THEN 'OWS' 
 WHEN c.PolicyID >= 3000000 THEN 'OBP' 
 WHEN c.PolicyID is null THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #tracetable_ows 
FROM #testtrace_ows a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Sale] b ON a.PersonID = b.PersonID
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_Policies] c ON b.SaleID = c.SaleID 
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] d ON c.PolicyID = d.PolicyRef

/* Select the desrired output */

SELECT
 *
FROM #tracetable_ows 

SELECT DISTINCT
 *
FROM #tracetable_ows a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_CaseDocuments_SaleBased] b ON a.Event = b.saleID

SELECT DISTINCT
 *
FROM #tracetable_ows a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_HDRUI_CaseDocuments_ContextBased] b ON a.PersonID = b.PersonID

/* Checks with client table in swift */

SELECT
 * 
INTO #checks_ows 
FROM #tracetable_ows a
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client] b ON a.CNUM = b.CLIENT_NUM 

SELECT 
 TITLE
,FirstName
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
FROM #checks_ows 
GO
/****** Object:  StoredProcedure [BI].[SAR_ProspectYODAOutput]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Imran Mastoor
-- Create date: 09/07/2018
-- Description:	Return details on documents for prospect clients in YODA
-- =============================================
CREATE PROCEDURE [BI].[SAR_ProspectYODAOutput]
@Title VARCHAR(50)
,@FirstName VARCHAR(50)
,@Lastname VARCHAR(50)
,@PostCode VARCHAR(50)

AS
SET NOCOUNT ON;
	
/* Look at the active customers in the Swift Client table */

SELECT 
 TITLE
,FIRSTNAMES
,NAME
,BIRTHDATE
,POSTCODE
,CorrAddress1
,CorrAddress2
,CorrAddress3
,CLIENT_NUM
,REFER
INTO #Client_Sar
FROM [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_s_client]
WHERE FirstNames LIKE '%' + @FirstName + '%' AND Name LIKE '%' + @Lastname + '%' AND SUBSTRING(PostCode,1,4) = @PostCode

/* Assigning system source and mapping the policy numbers for Client */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_1
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.CLIENT_NUM

/* Assigning system source and mapping the policy numbers for Partner */

SELECT 
 a.FIRSTNAMES
,a.NAME
,a.BIRTHDATE
,a.POSTCODE
,a.CorrAddress1
,a.CorrAddress2
,a.CorrAddress3
,a.CLIENT_NUM
,a.REFER
,b.JOINT_NUM
,b.PolicyRef
,(CASE WHEN b.PolicyRef  >= 550000000 THEN 'OWS'         
 WHEN b.PolicyRef >= 500000000 THEN 'ABS' 
 WHEN b.PolicyRef >= 100000000 THEN 'OWS' 
 WHEN b.PolicyRef >= 3000000 THEN 'OBP' 
 WHEN b.PolicyRef IS NULL THEN 'Null'
 ELSE 'Manual' 
 END) AS 'systemSource'
INTO #Trace_2
FROM #Client_Sar a
JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] b ON a.CLIENT_NUM = b.JOINT_NUM
  
/* Gather prospects from YODA */

 SELECT DISTINCT 
 c.ExternalCode as Description
,b.ExternalCode as Type
,a.DocumentPK
,d.DocumentFK
,a.PolicyNumber as Refer
,e.CurrentInitials
,e.CurrentSurname
,e.DateOfBirth
INTO #Temp_yoda
FROM [DocumentArchive].[dbo].[Document] a
JOIN [DocumentArchive].[dbo].[MimeType] b ON a.MimetypeFK= b.MimetypePK
JOIN [DocumentArchive].[dbo].[BusinessDocumentType] c ON a.DocTypeFK = c.DocTypePK 
JOIN [DocumentArchive].[dbo].[DocumentClientDetails] d ON a.DocumentPK = d.DocumentFK
JOIN [DocumentArchive].[dbo].[Client] e ON d.ClientSWIFTFK = e.ClientSWIFTPK
WHERE e.CurrentInitials LIKE SUBSTRING(@FirstName,1,1) + '%' AND e.CurrentSurname LIKE '%' + @Lastname + '%'
  
SELECT 
 a.CurrentInitials
,a.CurrentSurname
,a.DateOfBirth
,a.DocumentFK
,a.DocumentPK
,a.Type
,a.Description
--,b.FIRSTNAMES
--,b.NAME
--,b.ADDRESS1 
--,b.ADDRESS2 
--,b.POSTCODE
--,b.BIRTHDATE 
--,b.CLIENT_NUM
--,c.PolicyRef
--,c.CLIENT_NUM AS POLMAICLIENT_NUM
--,c.JOINT_NUM
--,b.CLIENT_NUM AS DuplicateCLIENT_NUM
FROM #Temp_yoda a
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_CLIENT] b ON a.Refer  = b.REFER
--JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_swift_S_POLMAI] c ON b.CLIENT_NUM  = ISNULL(c.JOINT_NUM, c.client_num)
GO
/****** Object:  StoredProcedure [BI].[testingPM]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE PROCEDURE [BI].[testingPM]
AS
SET NOCOUNT ON;
select
ri.ID ReviewItemID,
e.commissionreceiveddate as EDIRecDate, -- Payment received date
DATEDIFF(DAY, GETDATE() , e.commissionreceiveddate) As DaysInSuspense,  -- to count how many days in suspense
ri.SuspenseID, 
ri.EDIContentID, 
e.PolicyNumber, 
OriginalSuspenseReason.Code OriginalSuspenseCode, 
       OriginalSuspenseReason.Description OriginalSuspenseReason, 
       ReviewSuspenseReason.Code NewSuspenseCode, 
       ReviewSuspenseReason.Description NewSuspenseReason, 
       -- case statement to categorise change (to be tested)
       Case when OriginalSuspenseReason.Description = ReviewSuspenseReason.Description AND ReviewSuspenseReason.Description IS NOT NULL THEN 'No Change' WHEN ReviewSuspenseReason.Description IS NULL THEN 'New Match' ELSE 'Change but no Match' END as Result,
       ri.ReviewClientID, 
       ri.ReviewPolicyID, 
       p.CONT_NUM PolicyNumber, 
       p.PolicyRef, 
       ri.ReviewTransactionID, 
       pt.TransactionNumber, 
       pt.TransactionDate, 
       ri.ReviewExpectationID, 
       SuspenseItem.AMOUNT_DUE SuspenseAmount, 
       MatchItem.AMOUNT_DUE MatchedAmountDue, 
       ri.ReviewNotes, 
       --ADDED EXTRA FIELDS
       coalesce(pa.servicingagentcode,pa.sellingagentcode) as AgentUID, 
       a1.firm as AgentBusUID,  
coalesce (a2.tradingname,a2.descn) as AgentBusName, 
a1.descn as AgentName,case when ex.amount_rec < 0 then 'Accrual Clawback'  
when e.CommissionType = 'Y' then 'Initial Indemnity'  
when e.CommissionType = 'I' then 'Initial Accrual'  
when e.CommissionType = 'R' then 'Renewal'  
when e.CommissionType = 'X' then 'Trail'  
when e.PaymentType = '04' then 'Clawback'  
Else 'Unknown' end as EDIPaymentType  ,
case e.paymenttype   
when 1 then 'Comm'  
when 4 then 'Claw'  
when 99 then 'Adj'  
--else 'Unk'  
end as EDIPayType,
case when len(e.memberreferencenumber) > 0 then e.memberreferencenumber   
when len(e.policynumber) > 0 then e.policynumber end as EDIPolicy,  
E.initials as EDInits,  
case when e.Fullname is not null and len(e.Fullname) > 0 then e.FullName else E.Surname end as EDISurname,  
e.PremiumType as EDIPremTyp,e.PremiumAmount as EDIPremium
from dbo.sa_swift_EDISuspenseReview r
inner join [dbo].[sa_swift_EDISuspenseReviewItem] ri on ri.EDISuspenseReviewID = r.ID
inner join dbo.sa_swift_S_PACC SuspenseItem on SuspenseItem.ID = ri.SuspenseID
inner join dbo.sa_swift_EDIFACTCommissionStatementContents e on e.ID = ri.EDIContentID
inner join msit_S_PACC ex ON e.Pacc_ID = ex.ID  
left join dbo.sa_swift_CodeUnallocatedReasons OriginalSuspenseReason on OriginalSuspenseReason.Code = SuspenseItem.UnallocatedReasonCode
left join dbo.sa_swift_CodeUnallocatedReasons ReviewSuspenseReason on ReviewSuspenseReason.Code = ri.ReviewSuspenseReasonCode
left join dbo.sa_swift_S_POLMAI p on p.POL_NUM = ri.ReviewPolicyID
--added extra joins to obtain firm and adviser data
left join msit_policyagentsb30 pa on  pa.policyid = p.pol_num 
left outer join msit_s_agents a1 on a1.code = coalesce(pa.servicingagentcode,pa.sellingagentcode)  
left outer join msit_s_agents a2 on a2.code = a1.firm 
-- end of extra joins
left join dbo.sa_swift_PolicyTransactions pt on pt.ID = ri.ReviewTransactionID
left join dbo.sa_swift_S_PACC MatchItem on MatchItem.ID = ri.ReviewExpectationID
where r.ID = (select max(id) from [dbo].[sa_swift_EDISuspenseReview]) -- latest run
order by ri.EDIContentID desc
 
RETURN;
GO
/****** Object:  StoredProcedure [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_Andrews_Mortgage]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	pr_mi_Andrews_Mortgage
  	 					
	  Author:	A Bryant - Stored procedure 

Date created:	23/11/2021
													
 Description:   
				
				It is called as follows:

				exec bi.pr_mi_Andrews_Mortgage
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROC [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_Andrews_Mortgage]

AS


;With CTE_GrossIncome as (
	Select Distinct
	PersonID
	,case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID
	,sum(case when invIF.ValueName = 'Annually' then (GrossIncome/12)
			  when invIF.ValueName = 'Quarterly' then (GrossIncome/3)
			  when invIF.ValueName = 'Half-Yearly' then (GrossIncome/6)
			  else GrossIncome end) as MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	join staticdata.sa_ows_InputValues invIF on invIF.InputID = cdid.IncomeFrequencyID

	Group by PersonID, case when PersonTypeID = 1 then 1 else 2 end 

	),

	--EmployerDetails
	CTE_Employer as (
	select
	cdid.PersonID,
	cdid.PersonTypeID,
	invEmpSt.ValueName,
	occ.JobTitle,
	LEFT(replace(cdid.IncomeSource COLLATE Latin1_General_BIN,N'􀆟','') ,50) as IncomeSource, -- Changed because of illegal characters and size of the source
	grin.MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	left join StaticData.sa_ows_InputValues invEmpSt on invEmpSt.InputID = cdid.EmploymentStatusID
	left join StaticData.sa_ows_OwlOccupations occ on occ.OrigoCode = OccupationOrigoCode
	left join CTE_GrossIncome grin on grin.PersonID = cdid.PersonID and grin.PersonTypeID = cdid.PersonTypeID
	where cdid.ClientDetailIncomeDetailID = (select min(clientdetailincomedetailID)
											 from sa_ows_ClientDetailIncomeDetail cdid1
											 where cdid1.PersonID = cdid.PersonID
											 and   cdid1.PersonTypeID = cdid.PersonTypeID)
	),
	--IncomeDetails
	CTE_NetIncomeDetails as (
	select
	saleID,
	case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID,
	sum(totalNetMonthlyIncome) TotalNetIncome
	from sa_ows_FactFindIncome
	Group by SaleID, case when PersonTypeID = 1 then 1 else 2 end
	),
	--MortgageDetails--
	CTE_MortgageDetails as (
	select
	mps.PolicyId,
	case when obr.PurchasePrice is null then obr.PropertyValuation else obr.PurchasePrice end as PropertyValue,
	mps.LoanToValueRatio,
	mps.TotalMortgageAmount,
	invMortCatID.ValueName as MortgageCategory,
	invTranType.ValueName as TransactionType,
	invMortType.ValueName as MortgageType,
	invIntRate.ValueName as InterestRateType,
	invIRP.ValueName as InitialRatePeriod,
	mdf.MortgageApplicationDate,
	mdf.ArrangementFeeAmount,
	mdf.BrokerFeeAmount,
	mdf.MortgageExchangeDate,
	mdf.MortgageCompletionDate,
	mdf.MortgageAbortedDate,
	qr.AnswerText as ProcFee,
	mps.MortgageTermYears,
	addr.AddressLine1,
	addr.AddressLine2,
	addr.AddressLine3,
	addr.AddressLine4,
	addr.AddressLine5,
	addr.Postcode,
	case when invIRP.ValueName = '2 Years' then dateadd(year,2,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '3 Years' then dateadd(year,3,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '4 Years' then dateadd(year,4,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '5 Years' then dateadd(year,5,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '10 Years' then dateadd(year,10,mdf.MortgageApplicationDate)
		 else '01-Jan-1800' end as EndDate,
	case when isnull(pep.NewBuildID,20) = 19 then 'Yes' else 'No' end as NewBuild			
	from PolicyOneLink.sa_ows_MortgageProductSummary mps
	join sa_ows_Policies pol on pol.PolicyID = mps.PolicyId
	join Objectives.sa_ows_ObjectivesBorrowingRequirements obr on obr.SaleID = pol.SaleID
						and obr.ObjectivesBorrowingRequirementsId = (select max(obr1.ObjectivesBorrowingRequirementsId)
																	 from objectives.sa_ows_ObjectivesBorrowingRequirements obr1
																	 where obr.SaleID = obr1.SaleID)
	left join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdf on mdf.PolicyId = mps.PolicyId
	left join StaticData.sa_ows_InputValues invMortCatID on invMortCatID.InputID = mps.MortgageCategoryId
	left join StaticData.sa_ows_InputValues invTranType on invTranType.InputID = mps.TransactionTypeId
	left join StaticData.sa_ows_InputValues invMortType on invMortType.InputID = mps.MortgageTypeId
	left join StaticData.sa_ows_InputValues invIntRate on invIntRate.InputID = mps.InterestRateTypeId
	left join StaticData.sa_ows_InputValues invIRP on invIRP.InputID = mps.InitialRatePeriodId
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = mps.PolicyID and QuestionID = 2110
	left join sa_ows_ClientDetailPropertiesExistingProperties ffpep on ffpep.ExistingPropertyID = mps.RelatedPropertyID
	left join sa_ows_FactFindPropertiesExistingProperties pep on pep.ExistingPropertyID = mps.RelatedPropertyId							
	left join sa_ows_addresses addr on addr.AddressID = case when ffpep.AddressID is null then pep.AddressID else ffpep.AddressID end),

	--Protection Details--
	CTE_ProtectionDetails as (
	select 
	pps.PolicyId,
	pps.ApplicationDated
	,pps.ProtectionOnRiskDate
	,pps.ProtectionAbortedDate
	,convert(varchar,ppbd.ProductTermYears) + ' Years' + ' ' + convert(varchar,ppbd.ProductTermMonths) + ' Months' as LifeCoverTerm
	,pps.PremiumAmount as TotalRegularPremium
	,case when PremiumFrequencyID = 10100 then (pps.PremiumAmount * 12)
			when PremiumFrequencyID = 10101 then (pps.PremiumAmount * 4)
			when PremiumFrequencyID = 10102 then (pps.PremiumAmount * 2)				
			else pps.PremiumAmount end as AnnualisedPremium
	,invPF.ValueName as CurrentRegularPremiumFrequency
	,invPF.ValueName as 'Current Regular Premium (Self) Frequency'
	,case when ppbd.SumAssuredForDeath IS null then ppbd.SumAssuredForCriticalIllness else ppbd.SumAssuredForDeath end as LifeCoverSumAssured
	,ppbd.LifeAssuredId
	from PolicyOneLink.sa_ows_ProtectionProductSummary pps
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = pps.PolicyId and qr.QuestionID = 2510
	left join StaticData.sa_ows_InputValues invPF on pps.PremiumFrequencyID = invPF.InputID
	left join PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd on ppbd.ProtectionProductSummaryId = pps.ProtectionProductSummaryId
																	and ppbd.ProtectionProductBenefitId = (select min(ppbd1.protectionProductBenefitID)
																										   from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																										   where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId) 
																	and ppbd.BenefitTypeID = (select top 1 ppbd1.BenefitTypeID
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																							  where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
																	and ppbd.LifeAssuredId = (select top 1 ppbd2.LifeAssuredId
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd2
																							  where ppbd2.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
	)

	--Basic Policy Details, Client Name, Address, DOB--
	select
	pol.PolicyID as SequentialRef,
	pers.PersonID As Owner1ID,
	pers.PartnerPersonID As Owner2ID,
	sale.DateSubmitted As SubmittedDate,
	pd.ProtectionOnRiskDate as InForceDate,					
	pd.ProtectionAbortedDate as NTUDate,					
	sale.BusinessUID,
	frm.MIName as BusinessCompanyName,
	sale.AdviserUID as SellingAdviserID,
	uh.UserName as SellingAdviserFullName,
	advadd.ADD_Line1 as SellingAdviserAddressLine1,
	advadd.ADD_Line2 as SellingAdviserAddressLine2,
	advadd.ADD_Line3 as SellingAdviserAddressLine3,
	advadd.ADD_Postcode as SellingAdviserPostcode,
	cd.CD_Telephone as SellingAdviserWorkTelephoneNumber,
	cd.CD_Mobile as SellingAdviserMobileNumber,
	cd.CD_email as SellingAdviserEmailAddress,
	staf.STAF_NINumber	as SellingAdviserNINumber,
	sale.SaleID as AdviceCaseSequentialReference,
	pers.DateCreated As Owner1CreationDate,
	case when md.PolicyId is not null 
	then
		(case when md.MortgageAbortedDate Is NOT null then 'Aborted' 
			 when md.MortgageCompletionDate IS NOT null then 'Completed' 
			 when md.MortgageExchangeDate IS NOT NULL then 'Exchanged' else Null End)
	else (case when pd.ProtectionAbortedDate IS NOT null then 'Aborted' 
				when pd.ProtectionOnRiskDate IS NOT null then 'On Risk' 
				else NULL end) end as PlanStatus,			
	invP1T.ValueName As Owner1Title,
	pers.FirstName As Owner1FirstName,
	pers.LastName As Owner1LastName,
	pers.DateOfBirth As Owner1DateOfBirth,
	invP1G.ValueName As Owner1Gender,
	pers.Address1 As Owner1AddressLine1,
	pers.Address2 As Owner1AddressLine2,
	pers.Address3 As Owner1AddressLine3,
	pers.Address4 As Owner1AddressLine4,
	pers.Address5 As Owner1AddressLine5,
	pers.PostCode As Owner1PostCode,
	pers.TelephoneHome As Owner1HomeTelephoneNumber,
	pers.TelephoneMobile As Owner1MobileNumber,
	pers.EmailAddress As Owner1EmailAddress,
	emp.JobTitle as Owner1Occupation,
	emp.IncomeSource as Owner1EmployerName,
	emp.ValueName as Owner1EmploymentStatus,
	emp.MonthlyGrossIncome as Owner1TotalGrossMonthlyIncome,
	nid.TotalNetIncome as Owner1TotalNetMonthlyIncome,
	pers.NINo as Owner1NINumber,
	invMS.ValueName as Owner1MaritalStatus,
	ffog.IntroducerDetails as Owner1DescriptionReference,	
	invP2T.ValueName As Owner2Title,
	pers1.FirstName As Owner2FirstName,
	pers1.LastName As Owner2Surname,
	pers1.DateOfBirth As Owner2DateOfBirth,
	invP2G.ValueName As Owner2Gender,
	pers1.TelephoneHome As Owner2HomeTelephoneNumber,
	pers1.TelephoneMobile As Owner2MobileNumber,
	pers1.EmailAddress  As Owner2EmailAddress,
	emp2.JobTitle As Owner2Occupation,
	emp2.IncomeSource As Owner2EmployerName,
	emp2.MonthlyGrossIncome As Owner2TotalGrossMonthlyIncome,
	nid2.TotalNetIncome as Owner2TotalNetMonthlyIncome,
	polm.cont_Num as PolicyNumber,
	ppr.DisplayName as ProtectionProductName,
	pd.LifeCoverTerm,
	pd.TotalRegularPremium,
	pd.AnnualisedPremium,
	pd.CurrentRegularPremiumFrequency,
	pd.[Current Regular Premium (Self) Frequency],
	pd.LifeCoverSumAssured,
	case when md.PolicyId is not null then
	(case when md.MortgageAbortedDate Is NOT null then md.MortgageAbortedDate 
	when md.MortgageCompletionDate IS NOT null then md.MortgageCompletionDate 
	when md.MortgageExchangeDate IS NOT NULL then md.MortgageExchangeDate else convert(datetime,Null) End)
	else (case when pd.ProtectionAbortedDate IS NOT null then pd.ProtectionAbortedDate 
	when pd.ProtectionOnRiskDate IS NOT null 
		then pd.ProtectionOnRiskDate 
		else convert(datetime,Null) end) 
	end as PlanStatusDate,									
	sale.DateCreated as AdviceCaseCreatedOn,
	pol.ApplicationDate as PolicyStartDate,
	case when pp.DisplayName is null then mp.DisplayName else pp.DisplayName end as ProviderName,
	case when pd.LifeAssuredId = 10110 then pers.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10111 then pers1.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10112 then 'Joint Policy'
			when pd.LifeAssuredId = 10113 then 'Life of Another' end as LifeAssured1FullName,
	md.TransactionType as MortgageTransactionType,
	polm.cont_Num as MortgageRefNo,
	md.MortgageCategory as MortgageMortgageType,
	md.InterestRateType as MortgageRateType,
	md.MortgageType as MortgageRepaymentMethod,
	md.EndDate as MortgageFeatureExpires,
	md.MortgageTermYears,
	md.MortgageExchangeDate as MortgageExchangeDate,		
	md.MortgageCompletionDate as MortgageCompletionDate,	
	md.PropertyValue as MortgagePriceValuation,
	md.TotalMortgageAmount as MortgageLoanAmount,
	md.ArrangementFeeAmount as MortgageLenderFees,
	md.LoanToValueRatio as MortgageLTV,
	md.MortgageApplicationDate as MortgageApplicationSubmitted,
	md.ProcFee as ExpectedCommissionProcurement,
	md.BrokerFeeAmount,
	md.AddressLine1 as MortgageAddressLine1,
	md.AddressLine2 as MortgageAddressLine2,
	md.AddressLine3 as MortgageAddressLine3,
	md.AddressLine4 as MortgageAddressLine4,
	md.AddressLine5 as MortgageAddressLine5,
	md.Postcode as MortgagePostcode,
	md.NewBuild,									
	case											
		when pt.CommType = 'F' then 'Accr' 
		when pt.CommType = 'T' then 'IT' 
		when pt.CommType = 'L' then 'Level'
		else 'Unknown' 
	end as PayBasis,
	isnull(EmpType.Code_Description,'Unknown') as EmploymentType,	--AG 29/09/2020
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitAdv.AdviserUID 
	end as InitialAdviserUID,										--AG 06/11/2020
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitAdv.AdviserName
	end as InitialAdviserName,										
	case when sale.AdviserUID = InitAdv.AdviserUID
		then null					--Do not include in splits if the selling adviser and split adviser are the same
		else InitPct.AdviserPct
	end as InitialSplitPct,											
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'		
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitAdv.AdviserUID end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenAdv.AdviserUID end
	end as RenewalAdviserUID,
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'								
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitAdv.AdviserName end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenAdv.AdviserName end
	end as RenewalAdviserName,			
	case when RenSameInit.RenewalCommissionSameAsInitial = '1'		
		then case when sale.AdviserUID = InitAdv.AdviserUID then null else InitPct.AdviserPct end
		else case when sale.AdviserUID = RenAdv.AdviserUID then null else RenPct.AdviserPct end
	end as RenewalSplitPct
	from sa_ows_sale sale
	join sa_ows_Policies pol on pol.SaleID = sale.SaleID
	join sa_ows_Person pers on pers.PersonID = sale.PersonID
	join StaticData.sa_ows_InputValues invP1G on invP1G.InputID = pers.GenderID
	join StaticData.sa_ows_InputValues invP1T on invP1T.InputID = pers.TitleID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = sale.AdviserUID and sale.datesubmitted between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join mstt_agents frm on frm.code = sale.businessuid
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_ows_Person pers1 on pers.PartnerPersonID = pers1.PersonID
	left join StaticData.sa_ows_InputValues invP2G on invP2G.InputID = pers1.GenderID
	left join StaticData.sa_ows_InputValues invP2T on invP2T.InputID = pers1.TitleID
	left join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_ows_ProtectionProvider pp on pp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_OWS_ProtectionProduct ppr on ppr.InternalProductID = pol.InternalProductID
	left join sa_swift_S_POLMAI polm on polm.PolicyRef = pol.PolicyID
	left join (select PolicyID, max(ID) as MaxID from mstt_PolicyTransactions where TransType <> 117 group by PolicyID) LatestTxn on LatestTxn.PolicyID = polm.POL_NUM	
	left join mstt_PolicyTransactions pt on pt.ID = LatestTxn.MaxID	
	left join sa_ows_ClientDetailOverviewClientDetails cdocd on cdocd.PersonID = pers.personid and cdocd.PersonTypeID = 1
															 and cdocd.DateUpdated = (select max(cdocd1.DateUpdated)
																					  from sa_ows_ClientDetailOverviewClientDetails cdocd1
																					  where cdocd.PersonID = cdocd1.PersonID
																					  and cdocd1.PersonTypeID = 1)
	left join StaticData.sa_ows_InputValues invMS on invMS.inputid = cdocd.MaritalStatusID
	left join CTE_Employer emp on emp.PersonID = pers.PersonID and emp.PersonTypeID = 1
	left join CTE_Employer emp2 on emp2.PersonID = pers.PersonID and emp2.PersonTypeID = 2
	left join CTE_NetIncomeDetails nid on nid.SaleID = sale.SaleID and nid.PersonTypeID = 1
	left join CTE_NetIncomeDetails nid2 on nid2.SaleID = sale.SaleID and nid2.PersonTypeID = 2
	left join CTE_MortgageDetails md on md.PolicyId = pol.PolicyID
	left join CTE_ProtectionDetails pd on pd.PolicyId = pol.PolicyID
	left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = pol.SaleID
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'InitialAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as InitAdv on InitAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'InitialPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as InitPct on InitPct.PolicyID = pol.PolicyID
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as RenAdv on RenAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'RenewalPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as RenPct on RenPct.PolicyID = pol.PolicyID
	left join (	select	distinct qrUID.PolicyID, qrUID.AnswerText as RenewalCommissionSameAsInitial
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalCommissionSameAsInitial'
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				) as RenSameInit on RenSameInit.PolicyID = pol.PolicyID
	where sale.DateSubmitted is not null
	and pol.Status in (0,1,2)
	and (md.PolicyId is not null or pd.PolicyId is not null)
	and sale.BusinessUid in ('2017659','2017969','2017751','2017657')

	UNION ALL

	Select
	ps.SwiftCaseID,
	pers.PersonID,
	part.PersonID,
	cases.DateSubmitted,
	null,
	null,
	uh.businessUID,
	frm.MIName,
	cases.AdviserID,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	cases.ABSCaseID,
	null,
	null,
	pers.Title,
	pers.FirstName,
	pers.LastName,
	convert(date,pers.DOB,103),
	pers.Gender,
	pers.Address1,
	pers.Address2,
	null,
	null,
	null,
	pers.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	part.Title,
	part.FirstName,
	part.LastName,
	convert(date,part.DOB,103),
	part.Gender,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	qr.AnswerText,
	prod.DisplayName,
	qr1.AnswerText + ' Years',
	qr7.AnswerText,
	case when qr2.AnswerText = 3 then convert(decimal(10,2),qr7.AnswerText)*12 else qr7.AnswerText end,
	ab.AnswerText,
	ab.AnswerText,
	null,
	null,
	cases.CreatedDate,
	ps.CommencementDate,
	prov.DisplayName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	case when qr8.AnswerText = 50 then 'IT' when qr8.AnswerText = 51 then 'Accr' end,
	EmpType.Code_Description,
	qr3.AnswerText,
	agt.Descn,
	qr4.AnswerText,
	qr5.AnswerText,
	agt2.DESCN,
	qr6.AnswerText
	from sa_abs_ABS_Person pers
	left join sa_abs_ABS_Person part on part.ABSCaseID = pers.ABSCaseID and part.PersonType = 'Partner'
	left join sa_abs_ABS_Cases cases on cases.ABSCaseID = pers.ABSCaseID
	left join sa_abs_ABS_ProductSales ps on ps.ABSCaseID = cases.ABSCaseID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = cases.AdviserID and cases.DateSubmitted between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_abs_ABS_UIQuestionnaireResponses qr on qr.SwiftCaseID = ps.SwiftCaseID and qr.QuestionID in (30,58,420)
	left join sa_abs_ABS_Products prod on prod.ABSProductID = ps.ProductID
	left join sa_abs_ABS_UIQuestionnaireResponses qr1 on qr1.SwiftCaseID = ps.SwiftCaseID and qr1.QuestionID in (421)
	left join sa_abs_ABS_UIQuestionnaireResponses qr7 on qr7.SwiftCaseID = ps.SwiftCaseID and qr7.QuestionID = 378
	left join sa_abs_ABS_UIQuestionnaireResponses qr2 on qr2.SwiftCaseID = ps.SwiftCaseID and qr2.QuestionID = 379
	left join sa_abs_ABS_UIAnswerBank ab on convert(varchar(250),ab.AnswerID) = qr2.AnswerText
	left join sa_abs_ABS_Providers prov on prov.ABSProviderID = ps.ProviderID
	left join sa_abs_ABS_UIQuestionnaireResponses qr3 on qr3.SwiftCaseID = ps.SwiftCaseID and qr3.QuestionID = 36
	left join sa_abs_ABS_UIQuestionnaireResponses qr4 on qr4.SwiftCaseID = ps.SwiftCaseID and qr4.QuestionID = 37
	left join mstt_agents agt on agt.CODE = qr3.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr5 on qr5.SwiftCaseID = ps.SwiftCaseID and qr5.QuestionID = 115
	left join sa_abs_ABS_UIQuestionnaireResponses qr6 on qr6.SwiftCaseID = ps.SwiftCaseID and qr6.QuestionID = 116
	left join mstt_agents agt2 on agt2.CODE = qr5.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr8 on qr8.SwiftCaseID = ps.SwiftCaseID and qr8.QuestionID = 423
	left join mstt_agents frm on frm.code = uh.businessuid
	where pers.PersonType = 'Client'
	and uh.BusinessUID in ('2017659','2017969','2017751','2017657')
GO
/****** Object:  StoredProcedure [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_kalon_mortgage_and_protection]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/************************************************************************************************
  	 Program:  	pr_mi_kalon_mortgage_and_protection
  	 					
	  Author:	A Bryant - Stored procedure 

Date created:	17/11/2021
													
 Description:   
				
				It is called as follows:

				exec BI.pr_mi_kalon_mortgage_and_protection
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/
CREATE PROC [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_kalon_mortgage_and_protection]

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@RowCount					int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@Client						varchar(50),
		@Module						varchar(50)

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)
set @Client			= 'Openwork'
set @Module			= 'OutboundMI-Kalon'


/****************************************************************************

	Log start - we want this whether or not a rollback occurs
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start - beyond this point everything should be capable of rollback
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION


DECLARE @Date DATE = '1905-01-01';
declare @EndOfTheWeek datetime = (SELECT CAST(DATEADD(WEEK, DATEDIFF(WEEK, @Date, CURRENT_TIMESTAMP), @Date) as datetime) + '01:00:00:000' as StartOfTheWeek);
declare @StartOfTheWeek datetime = DATEADD(DAY,-7,@EndOfTheWeek)

Declare @KalonBusinessUID varchar(7)
Set @KalonBusinessUID = '2016789'

;With CTE_GrossIncome as (
	Select Distinct
	PersonID
	,case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID
	,sum(case when invIF.ValueName = 'Annually' then (GrossIncome/12)
			  when invIF.ValueName = 'Quarterly' then (GrossIncome/3)
			  when invIF.ValueName = 'Half-Yearly' then (GrossIncome/6)
			  else GrossIncome end) as MonthlyGrossIncome
	--,invIF.ValueName
	--,cdid.*
	from sa_ows_ClientDetailIncomeDetail cdid
	join staticdata.sa_ows_InputValues invIF on invIF.InputID = cdid.IncomeFrequencyID
	--where PersonID = 17890
	Group by PersonID, case when PersonTypeID = 1 then 1 else 2 end 
	--order by PersonID
	),

	--EmployerDetails
	CTE_Employer as (
	select
	cdid.PersonID,
	cdid.PersonTypeID,
	invEmpSt.ValueName,
	occ.JobTitle,
	LEFT(replace(cdid.IncomeSource COLLATE Latin1_General_BIN,N'􀆟','') ,50) as IncomeSource, -- Changed because of illegal characters and size of the source
	grin.MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	left join StaticData.sa_ows_InputValues invEmpSt on invEmpSt.InputID = cdid.EmploymentStatusID
	left join StaticData.sa_ows_OwlOccupations occ on occ.OrigoCode = OccupationOrigoCode
	left join CTE_GrossIncome grin on grin.PersonID = cdid.PersonID and grin.PersonTypeID = cdid.PersonTypeID
	where cdid.ClientDetailIncomeDetailID = (select min(clientdetailincomedetailID)
											 from sa_ows_ClientDetailIncomeDetail cdid1
											 where cdid1.PersonID = cdid.PersonID
											 and   cdid1.PersonTypeID = cdid.PersonTypeID)
	),
	--IncomeDetails
	CTE_NetIncomeDetails as (
	select
	saleID,
	case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID,
	sum(totalNetMonthlyIncome) TotalNetIncome
	from sa_ows_FactFindIncome
	Group by SaleID, case when PersonTypeID = 1 then 1 else 2 end
	),
	--MortgageDetails--
	CTE_MortgageDetails as (
	select
	mps.PolicyId,
	case when obr.PurchasePrice is null then obr.PropertyValuation else obr.PurchasePrice end as PropertyValue,
	mps.LoanToValueRatio,
	mps.TotalMortgageAmount,
	invMortCatID.ValueName as MortgageCategory,
	invTranType.ValueName as TransactionType,
	invMortType.ValueName as MortgageType,
	invIntRate.ValueName as InterestRateType,
	invIRP.ValueName as InitialRatePeriod,
	mdf.MortgageApplicationDate,
	mdf.ArrangementFeeAmount,
	mdf.BrokerFeeAmount,
	mdf.MortgageExchangeDate,
	mdf.MortgageCompletionDate,
	mdf.MortgageAbortedDate,
	qr.AnswerText as ProcFee,
	mps.MortgageTermYears,
	addr.AddressLine1,
	addr.AddressLine2,
	addr.AddressLine3,
	addr.AddressLine4,
	addr.AddressLine5,
	addr.Postcode,
	case when invIRP.ValueName = '2 Years' then dateadd(year,2,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '3 Years' then dateadd(year,3,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '4 Years' then dateadd(year,4,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '5 Years' then dateadd(year,5,mdf.MortgageApplicationDate)
		 when invIRP.ValueName = '10 Years' then dateadd(year,10,mdf.MortgageApplicationDate)
		 else '01-Jan-1800' end as EndDate,
	case when isnull(pep.NewBuildID,20) = 19 then 'Yes' else 'No' end as NewBuild		--AG 05/06/2019			
	from PolicyOneLink.sa_ows_MortgageProductSummary mps
	join sa_ows_Policies pol on pol.PolicyID = mps.PolicyId
	--join sa_ows_Sale sale on sale.SaleID = pol.SaleID
	join Objectives.sa_ows_ObjectivesBorrowingRequirements obr on obr.SaleID = pol.SaleID
						and obr.ObjectivesBorrowingRequirementsId = (select max(obr1.ObjectivesBorrowingRequirementsId)
																	 from objectives.sa_ows_ObjectivesBorrowingRequirements obr1
																	 where obr.SaleID = obr1.SaleID)
	left join PolicyOneLink.sa_ows_MortgageDisclosureAndFee mdf on mdf.PolicyId = mps.PolicyId
	left join StaticData.sa_ows_InputValues invMortCatID on invMortCatID.InputID = mps.MortgageCategoryId
	left join StaticData.sa_ows_InputValues invTranType on invTranType.InputID = mps.TransactionTypeId
	left join StaticData.sa_ows_InputValues invMortType on invMortType.InputID = mps.MortgageTypeId
	left join StaticData.sa_ows_InputValues invIntRate on invIntRate.InputID = mps.InterestRateTypeId
	left join StaticData.sa_ows_InputValues invIRP on invIRP.InputID = mps.InitialRatePeriodId
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = mps.PolicyID and QuestionID = 2110
	left join sa_ows_ClientDetailPropertiesExistingProperties ffpep on ffpep.ExistingPropertyID = mps.RelatedPropertyID
	left join sa_ows_FactFindPropertiesExistingProperties pep on pep.ExistingPropertyID = mps.RelatedPropertyId							--S Inglis 03/05/2016
	left join sa_ows_addresses addr on addr.AddressID = case when ffpep.AddressID is null then pep.AddressID else ffpep.AddressID end),	--S Inglis 03/05/2016

	--Protection Details--
	CTE_ProtectionDetails as (
	select 
	pps.PolicyId,
	pps.ApplicationDated
	,pps.ProtectionOnRiskDate
	,pps.ProtectionAbortedDate
	,convert(varchar,ppbd.ProductTermYears) + ' Years' + ' ' + convert(varchar,ppbd.ProductTermMonths) + ' Months' as LifeCoverTerm
	,pps.PremiumAmount as TotalRegularPremium
	,case when PremiumFrequencyID = 10100 then (pps.PremiumAmount * 12)
			when PremiumFrequencyID = 10101 then (pps.PremiumAmount * 4)
			when PremiumFrequencyID = 10102 then (pps.PremiumAmount * 2)				
			else pps.PremiumAmount end as AnnualisedPremium
	,invPF.ValueName as CurrentRegularPremiumFrequency
	,invPF.ValueName as 'Current Regular Premium (Self) Frequency'
	,case when ppbd.SumAssuredForDeath IS null then ppbd.SumAssuredForCriticalIllness else ppbd.SumAssuredForDeath end as LifeCoverSumAssured
	,ppbd.LifeAssuredId
	from PolicyOneLink.sa_ows_ProtectionProductSummary pps
	left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = pps.PolicyId and qr.QuestionID = 2510
	left join StaticData.sa_ows_InputValues invPF on pps.PremiumFrequencyID = invPF.InputID
	left join PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd on ppbd.ProtectionProductSummaryId = pps.ProtectionProductSummaryId
																	and ppbd.ProtectionProductBenefitId = (select min(ppbd1.protectionProductBenefitID)
																										   from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																										   where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId) 
																	and ppbd.BenefitTypeID = (select top 1 ppbd1.BenefitTypeID
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd1
																							  where ppbd1.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
																	and ppbd.LifeAssuredId = (select top 1 ppbd2.LifeAssuredId
																							  from PolicyOneLink.sa_ows_ProtectionProductBenefit ppbd2
																							  where ppbd2.ProtectionProductSummaryId = ppbd.ProtectionProductSummaryId)
	)

	--Basic Policy Details, Client Name, Address, DOB--
	select
	pol.PolicyID as CaseID,
	pers.PersonID As Owner1ID,
	pers.FirstName,
	pers.PartnerPersonID As Owner2ID,
	sale.DateSubmitted As SubmittedDate,
	pd.ProtectionOnRiskDate as InForceDate,					--AG 21/04/2016
	pd.ProtectionAbortedDate as NTUDate,					--AG 21/04/2016
	sale.AdviserUID as SellingAdviserID,
	uh.UserName as SellingAdviserFullName,
	advadd.ADD_Line1 as SellingAdviserAddressLine1,
	advadd.ADD_Line2 as SellingAdviserAddressLine2,
	advadd.ADD_Line3 as SellingAdviserAddressLine3,
	advadd.ADD_Postcode as SellingAdviserPostcode,
	cd.CD_Telephone as SellingAdviserWorkTelephoneNumber,
	cd.CD_Mobile as SellingAdviserMobileNumber,
	cd.CD_email as SellingAdviserEmailAddress,
	staf.STAF_NINumber	as SellingAdviserNINumber,
	sale.SaleID as AdviceCaseSequentialReference,
	pers.DateCreated As Owner1CreationDate,
	invP1T.ValueName As Owner1Title,
	pers.FirstName As Owner1FirstName,
	pers.LastName As Owner1LastName,
	pers.DateOfBirth As Owner1DateOfBirth,
	invP1G.ValueName As Owner1Gender,
	pers.Address1 As Owner1AddressLine1,
	pers.Address2 As Owner1AddressLine2,
	pers.Address3 As Owner1AddressLine3,
	pers.Address4 As Owner1AddressLine4,
	pers.Address5 As Owner1AddressLine5,
	pers.PostCode As Owner1PostCode,
	pers.TelephoneHome As Owner1HomeTelephoneNumber,
	pers.TelephoneMobile As Owner1MobileNumber,
	pers.EmailAddress As Owner1EmailAddress,
	emp.JobTitle as Owner1Occupation,
	emp.IncomeSource as Owner1EmployerName,
	emp.ValueName as Owner1EmploymentStatus,
	emp.MonthlyGrossIncome as Owner1TotalGrossMonthlyIncome,
	nid.TotalNetIncome as Owner1TotalNetMonthlyIncome,
	pers.NINo as Owner1NINumber,
	invMS.ValueName as Owner1MaritalStatus,
	ffog.IntroducerDetails as Owner1DescriptionReference,	--AG 21/04/2016
	invP2T.ValueName As Owner2Title,
	pers1.FirstName As Owner2FirstName,
	pers1.LastName As Owner2Surname,
	pers1.DateOfBirth As Owner2DateOfBirth,
	invP2G.ValueName As Owner2Gender,
	pers1.TelephoneHome As Owner2HomeTelephoneNumber,
	pers1.TelephoneMobile As Owner2MobileNumber,
	pers1.EmailAddress  As Owner2EmailAddress,
	emp2.JobTitle As Owner2Occupation,
	emp2.IncomeSource As Owner2EmployerName,
	emp2.MonthlyGrossIncome As Owner2TotalGrossMonthlyIncome,
	nid2.TotalNetIncome as Owner2TotalNetMonthlyIncome,
	polm.cont_Num as PolicyNumber,
	ppr.DisplayName as ProtectionProductName,
	pd.LifeCoverTerm,
	pd.TotalRegularPremium,
	pd.AnnualisedPremium,
	pd.CurrentRegularPremiumFrequency,
	pd.[Current Regular Premium (Self) Frequency],
	pd.LifeCoverSumAssured,
	case when md.PolicyId is not null then
	(case when md.MortgageAbortedDate Is NOT null then md.MortgageAbortedDate 
	when md.MortgageCompletionDate IS NOT null then md.MortgageCompletionDate 
	when md.MortgageExchangeDate IS NOT NULL then md.MortgageExchangeDate else convert(datetime,Null) End)
	else (case when pd.ProtectionAbortedDate IS NOT null then pd.ProtectionAbortedDate 
	when pd.ProtectionOnRiskDate IS NOT null 
		then pd.ProtectionOnRiskDate 
		else convert(datetime,Null) end) 
	end as PlanStatusDate,									--AG 21/04/2016
	sale.DateCreated as AdviceCaseCreatedOn,
	pol.ApplicationDate as PolicyStartDate,
	case when pp.DisplayName is null then mp.DisplayName else pp.DisplayName end as ProviderName,
	case when pd.LifeAssuredId = 10110 then pers.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10111 then pers1.FirstName +' '+pers.LastName
			when pd.LifeAssuredId = 10112 then 'Joint Policy'
			when pd.LifeAssuredId = 10113 then 'Life of Another' end as LifeAssured1FullName,
	md.TransactionType as MortgageTransactionType,
	polm.cont_Num as MortgageRefNo,
	md.MortgageCategory as MortgageMortgageType,
	md.InterestRateType as MortgageRateType,
	md.MortgageType as MortgageRepaymentMethod,
	md.EndDate as MortgageFeatureExpires,
	md.MortgageTermYears,
	md.MortgageExchangeDate as MortgageExchangeDate,		--AG 21/04/2016
	md.MortgageCompletionDate as MortgageCompletionDate,	--AG 21/04/2016
	md.PropertyValue as MortgagePriceValuation,
	md.TotalMortgageAmount as MortgageLoanAmount,
	md.ArrangementFeeAmount as MortgageLenderFees,
	md.LoanToValueRatio as MortgageLTV,
	md.MortgageApplicationDate as MortgageApplicationSubmitted,
	md.ProcFee as ExpectedCommissionProcurement,
	md.BrokerFeeAmount,
	md.AddressLine1 as MortgageAddressLine1,
	md.AddressLine2 as MortgageAddressLine2,
	md.AddressLine3 as MortgageAddressLine3,
	md.AddressLine4 as MortgageAddressLine4,
	md.AddressLine5 as MortgageAddressLine5,
	md.Postcode as MortgagePostcode,
	md.NewBuild,									--AG 05/06/2019
	case											--AG 29/09/2020
		when pt.CommType = 'F' then 'Accr' 
		when pt.CommType = 'T' then 'IT' 
		when pt.CommType = 'L' then 'Level'
		else 'Unknown' 
	end as PayBasis,
	isnull(EmpType.Code_Description,'Unknown') as EmploymentType
	from sa_ows_sale sale
	join sa_ows_Policies pol on pol.SaleID = sale.SaleID
	join sa_ows_Person pers on pers.PersonID = sale.PersonID
	join StaticData.sa_ows_InputValues invP1G on invP1G.InputID = pers.GenderID
	join StaticData.sa_ows_InputValues invP1T on invP1T.InputID = pers.TitleID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = sale.AdviserUID and uh.LatestRowInd = 1	--AG 29/09/2020
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_ows_Person pers1 on pers.PartnerPersonID = pers1.PersonID
	left join StaticData.sa_ows_InputValues invP2G on invP2G.InputID = pers1.GenderID
	left join StaticData.sa_ows_InputValues invP2T on invP2T.InputID = pers1.TitleID
	left join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_ows_ProtectionProvider pp on pp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_OWS_ProtectionProduct ppr on ppr.InternalProductID = pol.InternalProductID
	left join sa_swift_S_POLMAI polm on polm.PolicyRef = pol.PolicyID
	left join (select PolicyID, max(ID) as MaxID from mstt_PolicyTransactions where TransType <> 117 group by PolicyID) LatestTxn on LatestTxn.PolicyID = polm.POL_NUM	--AG 29/09/2020
	left join mstt_PolicyTransactions pt on pt.ID = LatestTxn.MaxID	--AG 29/09/2020
	left join sa_ows_ClientDetailOverviewClientDetails cdocd on cdocd.PersonID = pers.personid and cdocd.PersonTypeID = 1
															 and cdocd.DateUpdated = (select max(cdocd1.DateUpdated)
																					  from sa_ows_ClientDetailOverviewClientDetails cdocd1
																					  where cdocd.PersonID = cdocd1.PersonID
																					  and cdocd1.PersonTypeID = 1)
	left join StaticData.sa_ows_InputValues invMS on invMS.inputid = cdocd.MaritalStatusID
	left join CTE_Employer emp on emp.PersonID = pers.PersonID and emp.PersonTypeID = 1
	left join CTE_Employer emp2 on emp2.PersonID = pers.PersonID and emp2.PersonTypeID = 2
	left join CTE_NetIncomeDetails nid on nid.SaleID = sale.SaleID and nid.PersonTypeID = 1
	left join CTE_NetIncomeDetails nid2 on nid2.SaleID = sale.SaleID and nid2.PersonTypeID = 2
	left join CTE_MortgageDetails md on md.PolicyId = pol.PolicyID
	left join CTE_ProtectionDetails pd on pd.PolicyId = pol.PolicyID
	left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = pol.SaleID
	--AG 06/11/2020 Start
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'InitialAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as InitAdv on InitAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'InitialPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as InitPct on InitPct.PolicyID = pol.PolicyID
	left join (select	distinct qrUID.PolicyID, qrUID.AnswerText as AdviserUID, ag.Descn as AdviserName
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalAgentID'
						inner join mstt_Agents ag on ag.Code = qrUID.AnswerText
				where	qrUID.QuestionRepeatNumber = 100
				) as RenAdv on RenAdv.PolicyID = pol.PolicyID
	left join (select	distinct qrPct.PolicyID, qrPct.AnswerText as AdviserPct
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrPct
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbPct on qbPct.QuestionID = qrPct.QuestionID and qbPct.ObjectModelProperty = 'RenewalPercentage'
				where	qrPct.QuestionRepeatNumber = 100
				) as RenPct on RenPct.PolicyID = pol.PolicyID
	left join (	select	distinct qrUID.PolicyID, qrUID.AnswerText as RenewalCommissionSameAsInitial
				from	dbo.sa_ows_HDRUI_QuestionnaireResponses qrUID
						inner join StaticData.sa_ows_HDRUI_QuestionBank qbUID on qbUID.QuestionID = qrUID.QuestionID and qbUID.ObjectModelProperty = 'RenewalCommissionSameAsInitial'
				where	isnull(qrUID.QuestionRepeatNumber,100) = 100
				) as RenSameInit on RenSameInit.PolicyID = pol.PolicyID
	--AG 06/11/2020 End
	where sale.DateSubmitted is not null
	and sale.DateSubmitted between @StartOfTheWeek and @EndOfTheWeek
	and pol.Status in (0,1,2)
	and (md.PolicyId is not null or pd.PolicyId is not null)
	and sale.BusinessUid = @KalonBusinessUID

	UNION ALL

	Select
	ps.SwiftCaseID,
	pers.PersonID,
	pers.FirstName,
	part.PersonID,
	cases.DateSubmitted,
	null,
	null,
	cases.AdviserID,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	cases.ABSCaseID,
	null,
	pers.Title,
	pers.FirstName,
	pers.LastName,
	try_cast(pers.DOB as date),
	pers.Gender,
	pers.Address1,
	pers.Address2,
	null,
	null,
	null,
	pers.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	part.Title,
	part.FirstName,
	part.LastName,
	try_cast(part.DOB as date),
	part.Gender,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	qr.AnswerText,
	prod.DisplayName,
	qr1.AnswerText + ' Years',
	qr7.AnswerText,
	case when qr2.AnswerText = 3 then convert(decimal(10,2),qr7.AnswerText)*12 else qr7.AnswerText end,
	ab.AnswerText,
	ab.AnswerText,
	null,
	null,
	cases.CreatedDate,
	ps.CommencementDate,
	prov.DisplayName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	case when qr8.AnswerText = 50 then 'IT' when qr8.AnswerText = 51 then 'Accr' end,
	EmpType.Code_Description
	from sa_abs_ABS_Person pers
	left join sa_abs_ABS_Person part on part.ABSCaseID = pers.ABSCaseID and part.PersonType = 'Partner'
	left join sa_abs_ABS_Cases cases on cases.ABSCaseID = pers.ABSCaseID
	left join sa_abs_ABS_ProductSales ps on ps.ABSCaseID = cases.ABSCaseID
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = cases.AdviserID and cases.DateSubmitted between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_abs_ABS_UIQuestionnaireResponses qr on qr.SwiftCaseID = ps.SwiftCaseID and qr.QuestionID in (30,58,420)
	left join sa_abs_ABS_Products prod on prod.ABSProductID = ps.ProductID
	left join sa_abs_ABS_UIQuestionnaireResponses qr1 on qr1.SwiftCaseID = ps.SwiftCaseID and qr1.QuestionID in (421)
	left join sa_abs_ABS_UIQuestionnaireResponses qr7 on qr7.SwiftCaseID = ps.SwiftCaseID and qr7.QuestionID = 378
	left join sa_abs_ABS_UIQuestionnaireResponses qr2 on qr2.SwiftCaseID = ps.SwiftCaseID and qr2.QuestionID = 379
	left join sa_abs_ABS_UIAnswerBank ab on convert(varchar(250),ab.AnswerID) = qr2.AnswerText
	left join sa_abs_ABS_Providers prov on prov.ABSProviderID = ps.ProviderID
	left join sa_abs_ABS_UIQuestionnaireResponses qr3 on qr3.SwiftCaseID = ps.SwiftCaseID and qr3.QuestionID = 36
	left join sa_abs_ABS_UIQuestionnaireResponses qr4 on qr4.SwiftCaseID = ps.SwiftCaseID and qr4.QuestionID = 37
	left join mstt_agents agt on agt.CODE = qr3.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr5 on qr5.SwiftCaseID = ps.SwiftCaseID and qr5.QuestionID = 115
	left join sa_abs_ABS_UIQuestionnaireResponses qr6 on qr6.SwiftCaseID = ps.SwiftCaseID and qr6.QuestionID = 116
	left join mstt_agents agt2 on agt2.CODE = qr5.AnswerText
	left join sa_abs_ABS_UIQuestionnaireResponses qr8 on qr8.SwiftCaseID = ps.SwiftCaseID and qr8.QuestionID = 423
	where pers.PersonType = 'Client'
	and cases.DateSubmitted between @StartOfTheWeek and @EndOfTheWeek
	and uh.BusinessUID = @KalonBusinessUID
	
	UNION ALL

	Select
	pol.PolicyRef,
	pol.CLIENT_NUM,
	null,
	pol.JOINT_NUM,
	pol.CreateDate,
	null,
	null,
	pol.SellingAgentCode,
	uh.UserName,
	advadd.ADD_Line1,
	advadd.ADD_Line2,
	advadd.ADD_Line3,
	advadd.ADD_Postcode,
	cd.CD_Telephone,
	cd.CD_Mobile,
	cd.CD_email,
	staf.STAF_NINumber,
	null,
	null,
	clt.Title,
	clt.FIRSTNAMES,
	clt.Name,
	clt.BIRTHDATE,
	clt.Gender,
	clt.Address1,
	clt.Address2,
	null,
	null,
	null,
	clt.PostCode,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	jt.Title,
	jt.FIRSTNAMES,
	jt.Name,
	jt.BIRTHDATE,
	jt.Gender,
	null,
	null,
	null,
	null,
	null,
	null,
	null,
	pol.CONT_NUM,
	pol.ProductCodeDescription,
	convert(varchar(3),pol.TERM_Y) + ' Years '+ convert(varchar(3),pol.TERM_M) + ' Months',
	pt.Amount,
	pt.APE,
	pt.FrequencyDescription,
	pt.FrequencyDescription,
	null,
	null,
	pol.CreateDate,
	pol.START_DATE,
	pol.CompanyName,
	null,
	null,
	null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,
	pt.CommissionTypeDesc,
	EmpType.Code_Description
	from mstt_Policies pol
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = pol.SellingAgentCode and pol.CreateDate between uh.EffectiveStartDate and uh.EffectiveEndDate
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join mstt_PolicyTransactions pt on pt.PolicyID = pol.POL_NUM and pt.TransactionNumber = 1
	left join mstt_Clients clt on clt.CLIENT_NUM = pol.CLIENT_NUM
	left join mstt_Clients jt on jt.CLIENT_NUM = pol.JOINT_NUM
	where uh.BusinessUID = @KalonBusinessUID
	and pol.CreateDate between @StartOfTheWeek and @EndOfTheWeek
	and pol.PolicyRef like '8000%'

	set @RowCount = @@rowcount
	
	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	set @ProcessMessage = @Process + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	COMMIT TRANSACTION   

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

GO
/****** Object:  StoredProcedure [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_kalon_Wealth]    Script Date: 7/3/2026 3:34:43 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/************************************************************************************************
  	 Program:  	pr_mi_kalon_Wealth
  	 					
	  Author:	A Bryant - Stored procedure 

Date created:	09/11/2021
													
 Description:   
				
				It is called as follows:

				exec bi.pr_mi_kalon_Wealth
													
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
************************************************************************************************/

CREATE PROC [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_kalon_Wealth]

AS

SET ANSI_WARNINGS OFF	
set nocount on
set xact_abort on	-- Ensures all SQL statements are rolled back in the event of an error.

DECLARE @Date DATE = '1905-01-01';
declare @EndOfTheWeek datetime = (SELECT CAST(DATEADD(WEEK, DATEDIFF(WEEK, @Date, CURRENT_TIMESTAMP), @Date) as datetime) + '01:00:00:000' as StartOfTheWeek);
declare @StartOfTheWeek datetime = DATEADD(DAY,-7,@EndOfTheWeek)


Declare @KalonBusinessUID varchar(7)
Set @KalonBusinessUID = '2016789'

Select distinct
PersonID,
case when InternalProductID = -2 then 3 else OwnerID end as OwnerID,
InternalProductID,
OngoingServiceFee,
CreatedDate as LatestDate
into #OngoingFee
from  submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs
where CreatedDate = (select max(ogs1.CreatedDate)
					 from Submission.sa_ows_SubmittedProductCurrentOngoingServiceFee ogs1
					 where ogs1.InternalProductID = ogs.InternalProductID and ogs.PersonID = ogs1.PersonID)

Select Distinct
poli.PolicyID,
poty.TypeName,
prov.DisplayName as ProviderName,
prod.DisplayName as ProductName,
atrr.ValueName as ClientAttitudeToRisk,
atrr1.ValueName as PartnerAttitudeToRisk, --added 150518 SI
qr.AnswerText as InitialFee,
try_convert(decimal(18,2),REPLACE(isnull(qr1.AnswerText,0), ',', ''))  as Amount ,
case when qb.questiontext like '%new money%' then 'New Money' 
	 when qb.QuestionText like '%legacy%' then 'Legacy' 
	 when qb.QuestionText like '%regular%' then 'Regular' 
	 when qb.questiontext like '%employer%' then 'Regular Employer' else 'Investment' end as PaymentType,
--qr2.AnswerText as NewAmount, 
--qr5.AnswerText as RegularAmount,
case when qr3.AnswerText = 2 then 'No' when qr3.AnswerText = 1 then 'Yes' else 'N/A' end as InTrust,
case when qb.QuestionText like '%legacy%' then 'Yes' else 'No' end as Replacement,
ogs.OngoingServiceFee,
ab.AnswerText as FundChoice,
case when uanda.FeeType = 65 then uanda.FeeAmount else uanda.FeeAmount*uanda.Hours end as UandAAmount,
poli.CrmSourceId
into #COB
from sa_ows_Policies poli
join sa_ows_Sale sale on sale.SaleID = poli.SaleID
join prod_zurich_openwork_datawarehouse.StaticData.sa_ows_PolicyOwnerTypes poty on poty.PolicyOwnerTypeId = poli.PolicyOwnerType
join StaticData.sa_ows_Provider prov on prov.InternalProviderID = poli.InternalProviderID
join StaticData.sa_ows_Product prod on prod.InternalProductID = poli.InternalProductID
left join sa_ows_FactFindATRInvestorExperiences atr on atr.SaleID = poli.SaleID and atr.PersonTypeID = 1
left join sa_ows_ClientDetailATRInvestorExperiences catr on catr.PersonID = sale.PersonID and catr.PersonTypeID = 1
left join StaticData.sa_ows_InputValues atrr on atrr.InputID = isnull(atr.AgreedAttitudeToRiskID,catr.AgreedAttitudeToRiskID)
left join sa_ows_FactFindATRInvestorExperiences atr1 on atr1.SaleID = poli.SaleID and atr1.PersonTypeID = 2
left join sa_ows_ClientDetailATRInvestorExperiences catr1 on catr1.PersonID = sale.PersonID and catr1.PersonTypeID = 2
left join StaticData.sa_ows_InputValues atrr1 on atrr1.InputID = isnull(atr1.AgreedAttitudeToRiskID,catr1.AgreedAttitudeToRiskID)
left join sa_ows_HDRUI_QuestionnaireResponses qr on qr.PolicyID = poli.PolicyID and qr.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where QuestionText like '%Enter%Advice &%')
left join sa_ows_HDRUI_QuestionnaireResponses qr1 on qr1.PolicyID = poli.PolicyID and qr1.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where (QuestionText like '%Amount%' or QuestionText like '%Employer Contribution%')
																								and (qr1.ParentQuestionID = qr.ParentQuestionID or qr1.QuestionID = 497 or qr1.QuestionID = 34)
																								)
left join StaticData.sa_ows_HDRUI_QuestionBank qb on qb.QuestionID = qr1.QuestionID
left join sa_ows_HDRUI_QuestionnaireResponses qr3 on qr3.PolicyID = poli.PolicyID and qr3.QuestionID in (select QuestionID 
																								from StaticData.sa_ows_HDRUI_QuestionBank 
																								where QuestionText like '%Trust?'
																								)
left join #OngoingFee ogs on ogs.PersonID = sale.PersonID and ogs.InternalProductID = (case when prod.ProductCodeSwift like 'OZ%' or ProductCodeSwift like 'OW%' then -2 else poli.InternalProductID end) and (ogs.OwnerID = poli.PolicyOwnerType or (ogs.OwnerID = 3 and poli.PolicyOwnerType in (1,2)))
LEFT JOIN [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_cli on sale.SaleID = ffocd_cli.SaleID
																									and ffocd_cli.PersonTypeID = 1
																			and ffocd_cli.DateUpdated = (Select max(ffocd1.DateUpdated)
																			from sa_ows_FactFindOverviewClientDetails ffocd1
																			where ffocd1.SaleID = ffocd_cli.SaleID and ffocd1.PersonTypeID = ffocd_cli.PersonTypeID)
LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_FactFindOverviewSpecialCare ffosp on ffosp.SaleID = sale.SaleID																									  
LEFT JOIN  [prod_zurich_openwork_datawarehouse].[dbo].[sa_ows_FactFindOverviewClientDetails] ffocd_par on sale.SaleID = ffocd_par.SaleID
																									and ffocd_par.PersonTypeID = 2
																				and ffocd_par.DateUpdated = (Select max(ffocd2.DateUpdated)
																											from sa_ows_FactFindOverviewClientDetails ffocd2
																											where ffocd2.SaleID = ffocd_par.SaleID and ffocd2.PersonTypeID = ffocd_par.PersonTypeID)
LEFT JOIN prod_zurich_openwork_datawarehouse.dbo.sa_ows_addresses addr on addr.AddressID = ffosp.ThirdPartyPOAAddressID
LEFT JOIN sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = sale.SaleID
LEFT JOIN StaticData.sa_ows_InputValues mtgv on mtgv.InputID = ffog.MeetingVenueID
Left Join sa_ows_HDRUI_QuestionnaireResponses Fund on fund.PolicyID = poli.PolicyID and fund.QuestionID = 2630
Left join StaticData.sa_ows_HDRUI_AnswerBank ab on ab.AnswerID = fund.AnswerText
left join sa_ows_HDRUI_SubmissionFeeUnderstandingDetails uanda on uanda.SaleID = poli.SaleID --and HaveYouChargedUnderstandingAnalysisFee = 19
where poli.Status in (0,1,2,3)
and sale.BusinessUid = @KalonBusinessUID
--and poli.PolicyID = 552158838
	
	--GrossIncomeDetails
	;With CTE_GrossIncome as (
	Select Distinct
	PersonID
	,case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID
	,sum(case when invIF.ValueName = 'Annually' then (GrossIncome/12)
			  when invIF.ValueName = 'Quarterly' then (GrossIncome/3)
			  when invIF.ValueName = 'Half-Yearly' then (GrossIncome/6)
			  else GrossIncome end) as MonthlyGrossIncome
	--,invIF.ValueName
	--,cdid.*
	from sa_ows_ClientDetailIncomeDetail cdid
	join staticdata.sa_ows_InputValues invIF on invIF.InputID = cdid.IncomeFrequencyID
	--where PersonID = 17890
	Group by PersonID, case when PersonTypeID = 1 then 1 else 2 end 
	--order by PersonID
	),

	--EmployerDetails
	CTE_Employer as (
	select
	cdid.PersonID,
	cdid.PersonTypeID,
	invEmpSt.ValueName,
	occ.JobTitle,
	LEFT(replace(cdid.IncomeSource COLLATE Latin1_General_BIN,N'􀆟','') ,50) as IncomeSource, -- Changed because of illegal characters and size of the source
	grin.MonthlyGrossIncome
	from sa_ows_ClientDetailIncomeDetail cdid
	left join StaticData.sa_ows_InputValues invEmpSt on invEmpSt.InputID = cdid.EmploymentStatusID
	left join StaticData.sa_ows_OwlOccupations occ on occ.OrigoCode = OccupationOrigoCode
	left join CTE_GrossIncome grin on grin.PersonID = cdid.PersonID and grin.PersonTypeID = cdid.PersonTypeID
	where cdid.ClientDetailIncomeDetailID = (select min(clientdetailincomedetailID)
											 from sa_ows_ClientDetailIncomeDetail cdid1
											 where cdid1.PersonID = cdid.PersonID
											 and   cdid1.PersonTypeID = cdid.PersonTypeID)
	),
	--IncomeDetails
	CTE_NetIncomeDetails as (
	select
	saleID,
	case when PersonTypeID = 1 then 1 else 2 end as PersonTypeID,
	sum(totalNetMonthlyIncome) TotalNetIncome
	from sa_ows_FactFindIncome
	Group by SaleID, case when PersonTypeID = 1 then 1 else 2 end
	)



	--Basic Policy Details, Client Name, Address, DOB--
	select
--	ROW_NUMBER() over (partition by sale.SaleID order by pol.PolicyId) as RowNu,
	--Case when ROW_NUMBER() over (partition by pol.PolicyId order by sale.saleid, pol.PolicyId) = 1 then 1 else 0 end as CaseCount,
	--pol.PolicyID as CaseID,
	--pers.PersonID As Owner1ID,
	--pers.PartnerPersonID As Owner2ID,
	sale.DateSubmitted As SubmittedDate,
	--sale.AdviserUID as SellingAdviserID,
	uh.UserName as SellingAdviserFullName,
	--advadd.ADD_Line1 as SellingAdviserAddressLine1,
	--advadd.ADD_Line2 as SellingAdviserAddressLine2,
	--advadd.ADD_Line3 as SellingAdviserAddressLine3,
	--advadd.ADD_Postcode as SellingAdviserPostcode,
	--cd.CD_Telephone as SellingAdviserWorkTelephoneNumber,
	--cd.CD_Mobile as SellingAdviserMobileNumber,
	--cd.CD_email as SellingAdviserEmailAddress,
	--staf.STAF_NINumber	as SellingAdviserNINumber,
	--sale.SaleID as AdviceCaseSequentialReference,
	--pers.DateCreated As Owner1CreationDate,	
	--invP1T.ValueName As Owner1Title,
	--pers.FirstName As Owner1FirstName,
	--pers.LastName As Owner1LastName,
	--pers.DateOfBirth As Owner1DateOfBirth,
	--invP1G.ValueName As Owner1Gender,
	--pers.Address1 As Owner1AddressLine1,
	--pers.Address2 As Owner1AddressLine2,
	--pers.Address3 As Owner1AddressLine3,
	--pers.Address4 As Owner1AddressLine4,
	--pers.Address5 As Owner1AddressLine5,
	--pers.PostCode As Owner1PostCode,
	--pers.TelephoneHome As Owner1HomeTelephoneNumber,
	--pers.TelephoneMobile As Owner1MobileNumber,
	--pers.EmailAddress As Owner1EmailAddress,
	--emp.JobTitle as Owner1Occupation,
	--emp.IncomeSource as Owner1EmployerName,
	--emp.ValueName as Owner1EmploymentStatus,
	--emp.MonthlyGrossIncome as Owner1TotalGrossMonthlyIncome,
	--nid.TotalNetIncome as Owner1TotalNetMonthlyIncome,
	--pers.NINo as Owner1NINumber,
	--invMS.ValueName as Owner1MaritalStatus,
	--ffog.IntroducerDetails as Owner1DescriptionReference,	--AG 21/04/2016
	--invP2T.ValueName As Owner2Title,
	--pers1.FirstName As Owner2FirstName,
	--pers1.LastName As Owner2Surname,
	--pers1.DateOfBirth As Owner2DateOfBirth,
	--invP2G.ValueName As Owner2Gender,
	--pers1.TelephoneHome As Owner2HomeTelephoneNumber,
	--pers1.TelephoneMobile As Owner2MobileNumber,
	--pers1.EmailAddress  As Owner2EmailAddress,
	--emp2.JobTitle As Owner2Occupation,
	--emp2.IncomeSource As Owner2EmployerName,
	--emp2.MonthlyGrossIncome As Owner2TotalGrossMonthlyIncome,
	--nid2.TotalNetIncome as Owner2TotalNetMonthlyIncome,
	--polm.cont_Num as PolicyNumber,
	--cob.TypeName,
	cob.ProviderName,
	--cob.ProductName,
	--cob.ClientAttitudeToRisk,
	--cob.PartnerAttitudeToRisk,
	--cob.InitialFee,
	try_convert(decimal(15,2),cob.Amount) as Amount,
	cob.PaymentType
	--cob.InTrust,
	--cob.Replacement,
	--cob.OngoingServiceFee,
	--cob.FundChoice,
	--try_convert(decimal(15,2),cob.UandAAmount) as UandAAmount,
	--sale.DateCreated as AdviceCaseCreatedOn,
	--pol.ApplicationDate as PolicyStartDate,
	--isnull(EmpType.Code_Description,'Unknown') as EmploymentType	--AG 29/09/2020
	from sa_ows_sale sale
	join sa_ows_Policies pol on pol.SaleID = sale.SaleID
	join sa_ows_Person pers on pers.PersonID = sale.PersonID
	left join StaticData.sa_ows_InputValues invP1G on invP1G.InputID = pers.GenderID
	left join StaticData.sa_ows_InputValues invP1T on invP1T.InputID = pers.TitleID
	join #COB cob on cob.PolicyID = pol.PolicyID
	--left join mi_insight_userhierarchy uh on uh.UserUID = sale.AdviserUID									  AG 29/09/2020
	left join mi_insight_UserHierarchyAllUsers uh on uh.UserUID = sale.AdviserUID and uh.LatestRowInd = 1	--AG 29/09/2020
	left join sa_insight_Staff staf on staf.STAF_UserID = uh.UserGUID
	left join sa_insight_CodeDescription EmpType on EmpType.Code_CodeType = 531 and EmpType.Code_Code = staf.STAF_EmploymentType
	left join sa_insight_Address advadd on advadd.ADD_ParentID = staf.STAF_ID and ADD_Default = 1
	left join sa_insight_ContactDetails cd on cd.CD_ParentID = staf.STAF_ID
	left join sa_ows_Person pers1 on pers.PartnerPersonID = pers1.PersonID
	left join StaticData.sa_ows_InputValues invP2G on invP2G.InputID = pers1.GenderID
	left join StaticData.sa_ows_InputValues invP2T on invP2T.InputID = pers1.TitleID
	left join policy.sa_ows_MortgageProvider mp on mp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_ows_ProtectionProvider pp on pp.InternalProviderID = pol.InternalProviderID
	left join policy.sa_OWS_ProtectionProduct ppr on ppr.InternalProductID = pol.InternalProductID
	left join sa_swift_S_POLMAI polm on polm.PolicyRef = pol.PolicyID
	left join (select PolicyID, max(ID) as MaxID from mstt_PolicyTransactions where TransType <> 117 group by PolicyID) LatestTxn on LatestTxn.PolicyID = polm.POL_NUM	--AG 29/09/2020
	left join mstt_PolicyTransactions pt on pt.ID = LatestTxn.MaxID	--AG 29/09/2020
	left join sa_ows_ClientDetailOverviewClientDetails cdocd on cdocd.PersonID = pers.personid and cdocd.PersonTypeID = 1
															 and cdocd.DateUpdated = (select max(cdocd1.DateUpdated)
																					  from sa_ows_ClientDetailOverviewClientDetails cdocd1
																					  where cdocd.PersonID = cdocd1.PersonID
																					  and cdocd1.PersonTypeID = 1)
	left join StaticData.sa_ows_InputValues invMS on invMS.inputid = cdocd.MaritalStatusID
	left join CTE_Employer emp on emp.PersonID = pers.PersonID and emp.PersonTypeID = 1
	left join CTE_Employer emp2 on emp2.PersonID = pers.PersonID and emp2.PersonTypeID = 2
	left join CTE_NetIncomeDetails nid on nid.SaleID = sale.SaleID and nid.PersonTypeID = 1
	left join CTE_NetIncomeDetails nid2 on nid2.SaleID = sale.SaleID and nid2.PersonTypeID = 2
	left join sa_ows_FactFindOverviewGeneral ffog on ffog.SaleID = pol.SaleID
	left join sa_ows_HDRUI_FeeSplits fs on fs.saleid = sale.saleid
				and (fs.InternalProductID = pol.InternalProductID or fs.InternalProductID is null) and (fs.PolicyID = pol.PolicyID or fs.PolicyID is null)
				and fs.FeeSplitTypeID in (1,2,3,4) and fs.AdviserUID != sale.AdviserUID
    left join sa_ows_HDRUI_FeeSplits fs1 on fs1.saleid = sale.saleid
				and (fs1.InternalProductID = pol.InternalProductID or fs1.InternalProductID is null) and (fs1.PolicyID = pol.PolicyID or fs1.PolicyID is null)
				and fs1.FeeSplitTypeID in (8,9) and fs1.AdviserUID != sale.AdviserUID
	where sale.DateSubmitted is not null
	and pol.Status in (0,1,2)
	and sale.BusinessUid = @KalonBusinessUID
	and sale.DateSubmitted between @StartOfTheWeek and @EndOfTheWeek


	Drop table #OngoingFee,#COB


	
GO
