CREATE PROC [BI].[ZZZ_REDUNDANT_2022_11_16_pr_mi_TPG_ClientScan]

AS

Select Distinct
pers.PersonID, 
pt.Description, 
pers.FirstName, 
pers.LastName, 
pers.DateOfBirth, 
pers.AdviserUID, 
pers.Address1, 
pers.Address2, 
pers.PostCode, 
pers.EmailAddress, 
pers.TelephoneHome, 
pers.TelephoneMobile, 
case isnull(dpmp.ByEmail,0) when 1 then 'Yes' else '' end as 'Contact by Email',
case isnull(dpmp.ByPhone,0) when 1 then 'Yes' else '' end as 'Contact by Phone',
case isnull(dpmp.ByPost,0) when 1 then 'Yes' else '' end as 'Contact by Post',
case isnull(dpmp.BySms,0) when 1 then 'Yes' else '' end as 'Contact by SMS',
pep.PremiumAmount,
pf.ValueName PremiumFrequency, 
rep.ValueName Replaced, 
pep.PercentageOfIncomeProvided, 
replace(prov.DisplayName,'Other',pep.ProtectionProvider) ProviderName, 
pbt.ValueName, 
IsAccidentHealthPolicy, 
ba.ValueName BenefitArea, 
bt.ValueName BenefitType, 
pepb.BenefitAmount, 
bf.ValueName BenefitFrequency, 
tr.ValueName InTrust, 
wop.ValueName WaiverOfPremium, 
RenewableID, 
prt.ValueName PremiumType, 
ind.ValueName IndexLinked, 
la.ValueName LifeAssured, 
LifeOfAnotherDetails, 
PolicyEndDate, 
WholeOfLife, 
OtherBenefitDetails, 
cicsp.ValueName as CICStartPeriod, 
mem.MonthlyMortgageRepayment,
mem.TotalOutstandingAmount,
mem.InterestOnlyAmount, 
mem.EndDate, 
mem.ProductExpiryDate,
sl.Name,
sl.OngoingServiceValue,
inp.ValueName as ReportFrequency,
inp2.ValueName as ReviewFrequency,
case when csla.OscReasonID is not NULL then 'Y' end as 'OGS Cancelled',
case csla.OscReasonID
when 1
then 'Client initiated cancellation via firm'
when 2
then 'Client initiated cancellation via Openwork'
when 3
then 'Client initiated cancellation via provider'
when 4
then 'Firm initiated cancellation'
when 5
then 'Openwork initiated cancellation'
when 6
then 'Other'
when 7
then 'Client death – via firm or Openwork'
when 8
then 'Client death – via provider'
end as 'Cancellation Reason',
csla.OscReasonOtherDetail as'"Other Cancellation" Reason',
poli.client_Num
From sa_ows_Person pers
left join sa_ows_ClientDetailProtectionsExistingProtections pep on pep.PersonID = pers.PersonID
left join StaticData.sa_ows_PersonType pt on pt.PersonTypeID = pers.PersonType
left join staticdata.sa_ows_ExistingProductProvider prov on prov.ExistingProductProviderId = pep.ExistingProductProviderId
left join sa_ows_ClientDetailProtectionsExistingProtectionsBenefits pepb on pepb.ExistingProtectionID = pep.ExistingProtectionID
left join StaticData.sa_ows_InputValues pf on pf.InputID = pep.PremiumFrequencyID
left join StaticData.sa_ows_InputValues rep on rep.InputID = pep.ReplacedAsPartOfAdviceID
left join StaticData.sa_ows_InputValues pbt on pbt.InputID = pep.PolicyBenefitTypeId
left join StaticData.sa_ows_InputValues ba on ba.InputID = pepb.BenefitAreaID
left join StaticData.sa_ows_InputValues bt on bt.InputID = pepb.BenefitTypeID
left join StaticData.sa_ows_InputValues bf on bf.InputID = pepb.BenefitFrequencyID
left join StaticData.sa_ows_InputValues tr on tr.InputID = pepb.InTrustID
left join StaticData.sa_ows_InputValues wop on wop.InputID = pepb.WaiverOfPremiumID
left join StaticData.sa_ows_InputValues prt on prt.InputID = pepb.PremiumTypeID
left join StaticData.sa_ows_InputValues ind on ind.InputID = pepb.IndexLinkedID
left join StaticData.sa_ows_InputValues la on la.InputID = pepb.LifeAssuredID
left join StaticData.sa_ows_InputValues cicsp on cicsp.InputID = pepb.CriticalIllnessCoverStartPeriodId
left join sa_ows_ClientDetailMortgagesExistingMortgages mem on mem.PersonID = pers.PersonID
left join sa_ows_ClientServiceLevel csla on csla.PersonID = pers.PersonID
left join Proposition.sa_ows_ServiceLevel sl on sl.ServiceLevelId = csla.ServiceLevelId
left join StaticData.sa_ows_InputValues inp on inp.InputID = sl.ReportFrequencyId
left join StaticData.sa_ows_InputValues inp2 on inp2.InputID = sl.ReviewFrequencyId
left join sa_ows_Sale sale on sale.PersonID = csla.PersonID
left join sa_ows_Policies pol on pol.SaleID = sale.SaleID
left join mstt_Policies poli on poli.PolicyRef = pol.PolicyID
left join gdpr.sa_ows_DataProtectionMarketingPreferences dpmp on dpmp.PersonId = pers.PersonID
where pers.businessuid = '2000978'


UNION ALL



Select Distinct
pers.PersonID, 
